def _ui_text(raw: Any) -> str:
    return sanitize_display_text("" if raw is None else str(raw))


def _ui_join(parts: Sequence[Any], sep: str = " | ") -> str:
    cleaned = [_ui_text(part) for part in parts]
    return sep.join(part for part in cleaned if part)


