_BG_IMAGE_FIT_CHOICES: List[Tuple[str, str]] = [
    ("contain", "Contain (Center)"),
    ("cover", "Cover / Crop"),
    ("stretch", "Stretch"),
    ("actual", "Actual Size"),
    ("fit_width", "Fit Width"),
    ("fit_height", "Fit Height"),
    ("tile", "Tile"),
]

_BG_VIDEO_FIT_CHOICES: List[Tuple[str, str]] = [
    ("contain", "Contain (Center)"),
    ("cover", "Cover / Crop"),
    ("stretch", "Stretch"),
]

_BG_ANCHOR_CHOICES: List[Tuple[str, str]] = [
    ("center", "Center"),
    ("top", "Top"),
    ("bottom", "Bottom"),
    ("left", "Left"),
    ("right", "Right"),
    ("top_left", "Top Left"),
    ("top_right", "Top Right"),
    ("bottom_left", "Bottom Left"),
    ("bottom_right", "Bottom Right"),
]

_BG_ANCHOR_FACTORS: Dict[str, Tuple[float, float]] = {
    "center": (0.5, 0.5),
    "top": (0.5, 0.0),
    "bottom": (0.5, 1.0),
    "left": (0.0, 0.5),
    "right": (1.0, 0.5),
    "top_left": (0.0, 0.0),
    "top_right": (1.0, 0.0),
    "bottom_left": (0.0, 1.0),
    "bottom_right": (1.0, 1.0),
}


def _background_target_rect(container: QRect, content_w: int, content_h: int, fit_mode: str, anchor: str) -> QRect:
    cw = max(1, int(container.width()))
    ch = max(1, int(container.height()))
    iw = max(1, int(content_w))
    ih = max(1, int(content_h))

    if fit_mode == "stretch":
        return QRect(0, 0, cw, ch)

    scale = 1.0
    if fit_mode == "contain":
        scale = min(float(cw) / float(iw), float(ch) / float(ih))
    elif fit_mode == "cover":
        scale = max(float(cw) / float(iw), float(ch) / float(ih))
    elif fit_mode == "fit_width":
        scale = float(cw) / float(iw)
    elif fit_mode == "fit_height":
        scale = float(ch) / float(ih)
    elif fit_mode == "actual":
        scale = 1.0
    else:
        scale = min(float(cw) / float(iw), float(ch) / float(ih))

    draw_w = max(1, int(round(float(iw) * scale)))
    draw_h = max(1, int(round(float(ih) * scale)))
    ax, ay = _BG_ANCHOR_FACTORS.get(str(anchor or "center"), (0.5, 0.5))
    x = int(round(float(cw - draw_w) * float(ax)))
    y = int(round(float(ch - draw_h) * float(ay)))
    return QRect(x, y, draw_w, draw_h)


class BackgroundArtWidget(QWidget):
    def __init__(self, parent: Optional[QWidget] = None):
        super().__init__(parent)
        self._pixmap = QPixmap()
        self._display_blurred_pixmap = QPixmap()
        self._display_blurred_key = ""
        self._blurred_backdrop = QPixmap()
        self._blurred_backdrop_key = ""
        self._fit_mode = "contain"
        self._anchor = "center"
        self._display_blur_strength = 0
        self._matte = QColor("#000000")
        self.setAttribute(Qt.WA_TransparentForMouseEvents, True)
        self.setAttribute(Qt.WA_StyledBackground, True)
        self.setStyleSheet("background: transparent;")

    def setPixmap(self, pixmap: QPixmap) -> None:
        self._pixmap = QPixmap(pixmap) if pixmap is not None and not pixmap.isNull() else QPixmap()
        self._display_blurred_pixmap = QPixmap()
        self._display_blurred_key = ""
        self._blurred_backdrop = QPixmap()
        self._blurred_backdrop_key = ""
        self.update()

    def clear(self) -> None:
        self._pixmap = QPixmap()
        self._display_blurred_pixmap = QPixmap()
        self._display_blurred_key = ""
        self._blurred_backdrop = QPixmap()
        self._blurred_backdrop_key = ""
        self.update()

    def setPresentation(self, fit_mode: str, anchor: str, matte_hex: str, blur_strength: int = 0) -> None:
        self._fit_mode = str(fit_mode or "contain")
        self._anchor = str(anchor or "center")
        self._display_blur_strength = max(0, int(blur_strength))
        matte = QColor(str(matte_hex or "#000000"))
        self._matte = matte if matte.isValid() else QColor("#000000")
        self.update()

    def _display_pixmap(self) -> QPixmap:
        if self._pixmap.isNull():
            return QPixmap()
        if self._display_blur_strength <= 0:
            return self._pixmap
        cache_key = f"{int(self._pixmap.cacheKey())}:{int(self._display_blur_strength)}"
        if self._display_blurred_key != cache_key or self._display_blurred_pixmap.isNull():
            self._display_blurred_pixmap = _soft_blur_pixmap(self._pixmap, self._display_blur_strength)
            self._display_blurred_key = cache_key
        return self._display_blurred_pixmap if not self._display_blurred_pixmap.isNull() else self._pixmap

    def _backdrop_blur_pixmap(self) -> QPixmap:
        if self._pixmap.isNull():
            return QPixmap()
        cache_key = f"{int(self._pixmap.cacheKey())}:26"
        if self._blurred_backdrop_key != cache_key or self._blurred_backdrop.isNull():
            self._blurred_backdrop = _soft_blur_pixmap(self._pixmap, 26)
            self._blurred_backdrop_key = cache_key
        return self._blurred_backdrop

    def paintEvent(self, _event) -> None:
        painter = QPainter(self)
        full_rect = self.rect()
        painter.fillRect(full_rect, self._matte)
        if self._pixmap.isNull():
            return
        painter.setRenderHint(QPainter.SmoothPixmapTransform, True)
        if self._fit_mode == "tile":
            painter.drawTiledPixmap(full_rect, self._pixmap)
            return
        target = _background_target_rect(full_rect, self._pixmap.width(), self._pixmap.height(), self._fit_mode, self._anchor)
        if target.width() <= 0 or target.height() <= 0:
            return
        painter.drawPixmap(target, self._pixmap)

def _rounded_region_for_size(width: int, height: int, radius: int) -> QRegion:
    w = max(1, int(width))
    h = max(1, int(height))
    r = max(0, int(radius))
    if r <= 0:
        return QRegion(0, 0, w, h)
    path = QPainterPath()
    path.addRoundedRect(QRectF(0.5, 0.5, max(1.0, float(w) - 1.0), max(1.0, float(h) - 1.0)), float(r), float(r))
    return QRegion(path.toFillPolygon().toPolygon())


def _soft_blur_pixmap(src: QPixmap, strength: int) -> QPixmap:
    if src is None or src.isNull():
        return QPixmap()
    blur_strength = max(0, int(strength))
    if blur_strength <= 0:
        return QPixmap(src)

    width = max(1, int(src.width()))
    height = max(1, int(src.height()))
    current = QPixmap(src)
    passes = 1 if blur_strength <= 8 else 2 if blur_strength <= 18 else 3
    for idx in range(passes):
        divisor = max(1.6, 1.0 + (float(blur_strength) / float(6 + (idx * 2))))
        small_w = max(1, int(round(float(width) / divisor)))
        small_h = max(1, int(round(float(height) / divisor)))
        current = current.scaled(small_w, small_h, Qt.IgnoreAspectRatio, Qt.SmoothTransformation)
        current = current.scaled(width, height, Qt.IgnoreAspectRatio, Qt.SmoothTransformation)
    return current


class GlassBackdropWidget(QWidget):
    def __init__(self, controller: "PlayerController", panel: QWidget):
        super().__init__(panel)
        self._controller = controller
        self._panel = panel
        self._cfg: Dict[str, Any] = {}
        self._cache_sig = ""
        self._cache_pixmap = QPixmap()
        self.setObjectName(f"{panel.objectName() or 'glassPanel'}Backdrop")
        self.setAttribute(Qt.WA_TransparentForMouseEvents, True)
        self.setAttribute(Qt.WA_StyledBackground, True)
        self.setStyleSheet("background: transparent; border: none;")
        self.lower()

    def setGlassConfig(self, cfg: Dict[str, Any]) -> None:
        self._cfg = dict(cfg or {})
        self.invalidate()

    def invalidate(self) -> None:
        self._cache_sig = ""
        self.update()

    def _signature(self) -> str:
        blur_strength = int(self._cfg.get("blur_strength", 18) or 18)
        radius = int(self._cfg.get("radius", 20) or 20)
        bg_key = 0
        try:
            if self._controller._bg_cached_pixmap is not None and not self._controller._bg_cached_pixmap.isNull():
                bg_key = int(self._controller._bg_cached_pixmap.cacheKey())
        except Exception:
            bg_key = 0
        video_key = str(getattr(self._controller, "_bg_active_video_path", "") or "")
        try:
            pos = self._panel.mapTo(self._controller._bg_layer, QPoint(0, 0)) if self._controller._bg_layer is not None else QPoint(0, 0)
        except Exception:
            pos = QPoint(0, 0)
        tick = int(time.time() * 8.0) if video_key else 0
        return f"{self.width()}x{self.height()}@{pos.x()},{pos.y()}|blur={blur_strength}|radius={radius}|bg={bg_key}|video={video_key}|tick={tick}"

    def _refresh_backdrop(self) -> None:
        sig = self._signature()
        if sig == self._cache_sig:
            return
        self._cache_sig = sig
        pixmap = self._controller._glass_backdrop_pixmap_for_widget(self._panel)
        blur_strength = int(self._cfg.get("blur_strength", 18) or 18)
        if pixmap is not None and not pixmap.isNull() and blur_strength > 0:
            pixmap = _soft_blur_pixmap(pixmap, blur_strength)
        self._cache_pixmap = pixmap if pixmap is not None else QPixmap()

    def paintEvent(self, _event) -> None:
        self._refresh_backdrop()
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing, True)
        radius = max(0.0, float(min(int(self._cfg.get("radius", 20) or 20), max(1, min(self.width(), self.height()) // 2))))
        rect = QRectF(0.5, 0.5, max(1.0, float(self.width()) - 1.0), max(1.0, float(self.height()) - 1.0))
        path = QPainterPath()
        path.addRoundedRect(rect, radius, radius)
        painter.setClipPath(path)
        if self._cache_pixmap is not None and not self._cache_pixmap.isNull():
            painter.drawPixmap(self.rect(), self._cache_pixmap)

        tint = QColor(str(self._cfg.get("tint", "#081018") or "#081018"))
        if not tint.isValid():
            tint = QColor("#081018")
        tint.setAlpha(max(0, min(255, int(self._cfg.get("fill_alpha", 14) or 14))))
        painter.fillPath(path, tint)

        highlight_alpha = max(0, min(255, int(self._cfg.get("highlight_alpha", 34) or 34)))
        if highlight_alpha > 0:
            gradient = QLinearGradient(0.0, 0.0, 0.0, max(1.0, float(self.height())))
            gradient.setColorAt(0.0, QColor(255, 255, 255, highlight_alpha))
            gradient.setColorAt(0.28, QColor(255, 255, 255, max(0, highlight_alpha // 3)))
            gradient.setColorAt(1.0, QColor(255, 255, 255, 0))
            painter.fillPath(path, gradient)

        painter.setClipping(False)
        border = QColor(255, 255, 255, max(0, min(255, int(self._cfg.get("border_alpha", 88) or 88))))
        painter.setPen(QPen(border, 1.2))
        painter.drawPath(path)
        painter.end()

class PlayerController(QObject):
    _searchPosterResultsQueued = Signal()
    _searchBatchBackdropResultsQueued = Signal()
    _homeCatalogResultsQueued = Signal()
    _thumbResultsQueued = Signal()
    _playerBackendPropertyChanged = Signal(str, object)

    # VIEWPORT / LAYOUT DEBUG (one-shot, high-signal)
    # ============================================================
    def _sp_name(self, w: QWidget) -> str:
        try:
            sp = w.sizePolicy()
            return f"H={int(sp.horizontalPolicy())} V={int(sp.verticalPolicy())} HS={int(sp.horizontalStretch())} VS={int(sp.verticalStretch())}"
        except Exception:
            return "H=? V=?"

    def _dbg_geom(self, tag: str, w: Optional[QWidget]):
        if w is None:
            print(f"[DBG][{tag}] <None>")
            return
        try:
            g = w.geometry()
            print(
                f"[DBG][{tag}] {w.__class__.__name__} name={w.objectName()} "
                f"geom=({g.x()},{g.y()},{g.width()}x{g.height()}) "
                f"size=({w.width()}x{w.height()}) "
                f"min=({w.minimumWidth()}x{w.minimumHeight()}) "
                f"max=({w.maximumWidth()}x{w.maximumHeight()}) "
                f"sp={self._sp_name(w)}"
            )
        except Exception as e:
            print(f"[DBG][{tag}] error: {e}")

    def _home_force_expand_policies(self):
        """
        Hard-override any Qt Designer size constraints that cause the Home page
        to render as a tiny 'island' inside a big black viewport.
        """
        hs = getattr(self, "homeScrollArea", None)
        hc = getattr(self, "homeScrollContents", None)
        hcontent = getattr(self, "homeContent", None)

        if hs is None or hc is None:
            print("[HOME][CRUNCH][WARN] homeScrollArea/homeScrollContents missing; cannot force expand policies.")
            return

        # 1) Make the scroll area behave like a real viewport host
        hs.setWidgetResizable(True)
        hs.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)

        # 2) Remove accidental fixed sizing from Designer (common cause of "crunch")
        for w in (hc, hcontent):
            if w is None:
                continue
            w.setMinimumSize(0, 0)
            w.setMaximumSize(16777215, 16777215)  # Qt "no real max" sentinel
            w.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)

        # 3) Also force the scroll-area internal widget (usually scrollAreaWidgetContents)
        try:
            internal = hs.widget()
            if internal is not None:
                internal.setMinimumSize(0, 0)
                internal.setMaximumSize(16777215, 16777215)
                internal.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
        except Exception:
            pass

    def _home_debug_crunch_snapshot(self, where: str):
        """
        Prints the exact widgets that matter for crunching.
        Send me this log after you run once.
        """
        print(f"\n[HOME][CRUNCH][SNAPSHOT] where={where}")
        hs = getattr(self, "homeScrollArea", None)
        vp = hs.viewport() if hs is not None else None
        self._dbg_geom("homeScrollArea", hs)
        self._dbg_geom("homeScrollArea.viewport", vp)
        self._dbg_geom("homeScrollContents", getattr(self, "homeScrollContents", None))
        self._dbg_geom("homeContent", getattr(self, "homeContent", None))

        # Useful: current scroll positions
        try:
            hbar = hs.horizontalScrollBar()
            vbar = hs.verticalScrollBar()
            print(f"[DBG][scrollbars] H={hbar.value()}/{hbar.maximum()} V={vbar.value()}/{vbar.maximum()}")
        except Exception:
            pass

    def _home_uncrunch_now(self, reason: str):
        """
        One function you can call safely multiple times:
        - forces expand policies
        - clamps any accidental minWidth islands
        - resets horizontal scroll to 0
        - prints one snapshot
        """
        self._home_force_expand_policies()

        hs = getattr(self, "homeScrollArea", None)
        if hs is not None:
            try:
                hs.horizontalScrollBar().setValue(0)
            except Exception:
                pass

        # If you have a center-lane width updater, run it AFTER forcing policies.
        if hasattr(self, "_home_update_center_lane_width"):
            try:
                self._home_update_center_lane_width()
            except Exception as e:
                print(f"[HOME][CRUNCH][WARN] _home_update_center_lane_width failed: {e}")

        self._home_debug_crunch_snapshot(where=reason)
