        self._thumb_result_poll_pending = False
        self._perf_window_seconds = 6.0
        self._perf_samples: deque[Tuple[float, str, float]] = deque()
        self._perf_lock = threading.Lock()
        self._perf_monitor_dialog: Optional[QDialog] = None
        self._perf_monitor_status_label: Optional[QLabel] = None
        self._perf_monitor_table: Optional[QTableWidget] = None
        self._perf_monitor_timer = QTimer(self)
        self._perf_monitor_timer.setInterval(1000)
        self._perf_monitor_timer.timeout.connect(self._perf_refresh_monitor)
