    def _shell_refresh_top_nav_context(self) -> None:
        meta = getattr(self, "_top_nav_brand_meta", None)
        if meta is None:
            return
        profile = self._viewer_active_profile_record()
        name = str(profile.get("name") or "Primary").strip() or "Primary"
        experience = self._theme_experience_payload()
        suffix = str(experience.get("brand_meta_suffix", "") or "").strip()
        meta.setText(f"For {name}" + (f"  {OMEGA_TEXT_SEPARATOR}  {suffix}" if suffix else ""))

    def _shell_setup_top_navigation(self) -> None:
        top_region = safe_find(self.win, "topRegion", QWidget, required=False)
        if top_region is None:
            return

        if getattr(self, "_top_nav_bar", None) is not None:
            return

        lay = top_region.layout()
        if lay is None:
            lay = QVBoxLayout(top_region)
            lay.setContentsMargins(0, 0, 0, 0)
            lay.setSpacing(0)

        shell = self.T.shell
        bar = QFrame(top_region)
        bar.setObjectName("topNavBar")
        bar.setAttribute(Qt.WA_StyledBackground, True)
        bar.setSizePolicy(QSizePolicy.Fixed, QSizePolicy.Preferred)
        bar.setMinimumWidth(int(shell.rail_min_width_px))
        bar.setMaximumWidth(int(shell.rail_max_width_px))
        bar.setMinimumHeight(62)
        bar.setMaximumHeight(16777215)

        h = QHBoxLayout(bar)
        h.setContentsMargins(
            int(shell.rail_inner_pad_x_px),
            int(shell.rail_inner_pad_y_px),
            int(shell.rail_inner_pad_x_px),
            int(shell.rail_inner_pad_y_px),
        )
        h.setSpacing(8)
        self._top_nav_layout = h

        brand = QWidget(bar)
        brand.setObjectName("topNavBrand")
        brand_l = QVBoxLayout(brand)
        brand_l.setContentsMargins(0, 0, 0, 0)
        brand_l.setSpacing(0)
        brand_title = QLabel("OMEGA", brand)
        brand_title.setObjectName("topNavBrandTitle")
        brand_meta = QLabel("For Primary", brand)
        brand_meta.setObjectName("topNavBrandMeta")
        brand_l.addWidget(brand_title)
        brand_l.addWidget(brand_meta)
        h.addWidget(brand, 0)
        self._top_nav_brand_meta = brand_meta

        defs = [
            ("home", "Home", self._nav_go_home),
            ("player", "Player", self._nav_go_player),
            ("settings", "Settings", self._nav_go_settings),
        ]

        self._top_nav_buttons = {}
        for key, label, fn in defs:
            btn = QPushButton(label, bar)
            btn.setObjectName("topNavBtn")
            btn.setCursor(Qt.PointingHandCursor)
            btn.setFocusPolicy(Qt.NoFocus)
            btn.setMinimumHeight(int(shell.rail_button_min_h_px))
            btn.setMinimumWidth(0)
            btn.clicked.connect(fn)
            h.addWidget(btn)
            self._top_nav_buttons[key] = btn

        h.addStretch(1)

        self._top_nav_bar = bar
        bar.hide()
        self._nav_mark_top_active("home")
        self._shell_refresh_top_nav_context()

