    # ============================================================
    # Home "best-app" scrolling + resize rebuild (UNIFIED eventFilter)
    # ============================================================
    # ============================================================
    # Home resize rebuild + wheel policy
    # ============================================================
    def _home_register_wheel_blocker(self, maybe_scrollarea: object) -> None:
        """
        Register a horizontal rail's QScrollArea so wheel input does NOT scroll it.
        If the rail ignores wheel events, Qt will pass the wheel to the parent
        (the Home vertical scroll area), which is exactly what we want.

        Also marks the viewport with the _omega_is_rail_viewport property so
        the unified eventFilter can intercept wheel events via either path.
        """
        if maybe_scrollarea is None:
            return

        # Only real QScrollArea instances have viewport()
        if not hasattr(maybe_scrollarea, "viewport"):
            return

        if not hasattr(self, "_home_wheel_blockers"):
            self._home_wheel_blockers = set()

        self._home_wheel_blockers.add(maybe_scrollarea)
        try:
            maybe_scrollarea.installEventFilter(self)
        except Exception:
            pass
        try:
            vp = maybe_scrollarea.viewport()
            vp.installEventFilter(self)
            # Mark with property so eventFilter can detect via _omega_is_rail_viewport
            # (sandbox-proven approach ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â works regardless of how the filter was registered)
            vp.setProperty("_omega_is_rail_viewport", True)
            vp.setProperty("_omega_rail_scrollarea", maybe_scrollarea)
        except Exception:
            pass

    def _home_is_wheel_blocker_obj(self, obj: object) -> bool:
        """
        True if obj is one of our registered rail QScrollAreas or their viewports.
        """
        blockers = getattr(self, "_home_wheel_blockers", None)
        if not blockers:
            return False

        for sa in blockers:
            if obj is sa:
                return True
            try:
                if obj is sa.viewport():
                    return True
            except Exception:
                pass

        return False

    def _install_rail_filters(self, scroll: QScrollArea) -> None:
        """
        Sandbox-proven helper: marks a horizontal rail scroll area so that:
          ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ wheel events are NOT consumed by the rail itself, and
          ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ the unified eventFilter can route them to the home vertical scrollbar.

        Calling this is equivalent to _home_register_wheel_blocker but uses
        the property-based detection path so both old and new code paths agree.
        """
        if scroll is None:
            return
        try:
            vp = scroll.viewport()
            vp.installEventFilter(self)
            vp.setProperty("_omega_is_rail_viewport", True)
            vp.setProperty("_omega_rail_scrollarea", scroll)
        except Exception:
            pass
        if not hasattr(self, "_home_wheel_blockers"):
            self._home_wheel_blockers = set()
        self._home_wheel_blockers.add(scroll)
        try:
            scroll.installEventFilter(self)
        except Exception:
            pass

    def _home_forward_wheel_to_home_scroll(self, event: QWheelEvent) -> bool:
        """
        Smooth wheel scrolling for the Home surface, including when the cursor
        is sitting over a horizontal rail viewport.
        """
        if self.homeScrollArea is None or event is None:
            return False

        try:
            vbar = self.homeScrollArea.verticalScrollBar()
        except Exception:
            return False

        try:
            px = event.pixelDelta()
            ang = event.angleDelta()
            dy = int(px.y() if not px.isNull() else ang.y())
        except Exception:
            dy = 0
        if dy == 0:
            return False

        try:
            step_px = max(40, min(160, int(self._home_get_viewport_height() * 0.11)))
        except Exception:
            step_px = 72

        if px is not None and not px.isNull():
            delta = int(dy)
        else:
            delta = int(round((float(dy) / 120.0) * float(step_px)))
        if delta == 0:
            delta = int(step_px if dy > 0 else -step_px)

        anim = getattr(self, "_home_vscroll_anim", None)
        if anim is None:
            try:
                anim = QPropertyAnimation(vbar, b"value", self)
                anim.setEasingCurve(QEasingCurve.OutCubic)
                self._home_vscroll_anim = anim
            except Exception:
                anim = None

        try:
            base = int(vbar.value())
            if anim is not None:
                try:
                    running = int(anim.state()) != 0
                except Exception:
                    running = False
                if running:
                    try:
                        base = int(anim.endValue())
                    except Exception:
                        base = int(vbar.value())
            target = max(int(vbar.minimum()), min(int(vbar.maximum()), int(base - delta)))
        except Exception:
            return False

        if anim is None:
            vbar.setValue(target)
            return True
        try:
            anim.stop()
            anim.setTargetObject(vbar)
            anim.setPropertyName(b"value")
            anim.setDuration(120 if px is not None and not px.isNull() else 150)
            anim.setStartValue(int(vbar.value()))
            anim.setEndValue(int(target))
            anim.start()
            return True
        except Exception:
            try:
                vbar.setValue(target)
                return True
            except Exception:
                return False

    # ============================================================
    # EVENT FILTER (single unified implementation)
    # - Resize: triggers responsive rebuild
    # - Wheel: routes wheel to horizontal rails ONLY when cursor is over a RailShell
    #          otherwise lets the Home QScrollArea do NORMAL vertical scrolling
    # ============================================================
    def eventFilter(self, obj, event):
        try:
            # ------------------------------------------------------------
            # MAIN WINDOW RESIZE ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¾ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ re-pin homeScrollArea immediately
            # (this is what makes the viewport follow the window edge-to-edge)
            # ------------------------------------------------------------
            if obj is self.win and event.type() in {QEvent.Show, QEvent.Hide, QEvent.WindowStateChange}:
                QTimer.singleShot(0, self._shell_apply_visibility_power_mode)
                QTimer.singleShot(0, self._home_update_startup_cover_geometry)
                return False

            if obj is self.win and event.type() == QEvent.Resize:
                self._home_update_startup_cover_geometry()
                if self._player_should_reduce_surface_fx():
                    self._viewer_layout_startup_gate()
                    self._position_top_nav_bar()
                    self._player_update_playlist_drawer_geometry()
                    self._page_layouts_reflow_runtime()
                    try:
                        self._player_resize_debounce.start()
                    except Exception:
                        self._player_apply_elite_layout()
                    return False
                self._viewer_layout_startup_gate()
                self._home_pin_scroll_area()
                self._home_position_show_selection_overlays()
                self._position_top_nav_bar()
                self._player_update_playlist_drawer_geometry()
                self._page_layouts_reflow_runtime()
                try:
                    self._player_resize_debounce.start()
                except Exception:
                    self._player_apply_elite_layout()
                try:
                    self._background_resize_debounce.start()
                except Exception:
                    self._background_apply_for_current_page()
                # Do NOT return True - let Qt process the window resize normally.
                return False

            if obj is self.playerPage and event.type() == QEvent.Resize:
                try:
                    self._player_resize_debounce.start()
                except Exception:
                    self._player_apply_elite_layout()
                self._player_update_playlist_drawer_geometry()
                return False

            if obj is self.playerPage and event.type() in {
                QEvent.Show,
                QEvent.Enter,
                QEvent.MouseMove,
                QEvent.MouseButtonPress,
                QEvent.Wheel,
            }:
                self._player_command_hovered = False
                self._player_end_command_center_idle_fade(restart_timer=True)
                return False

            if isinstance(obj, QWidget) and self._player_is_command_center_widget(obj):
                if event.type() in {
                    QEvent.Enter,
                    QEvent.HoverEnter,
                    QEvent.HoverMove,
                    QEvent.MouseMove,
                    QEvent.MouseButtonPress,
                    QEvent.MouseButtonRelease,
                    QEvent.Wheel,
                    QEvent.FocusIn,
                }:
                    self._player_command_hovered = True
                    self._player_end_command_center_idle_fade(restart_timer=False)
                    return False
                if event.type() in {
                    QEvent.Leave,
                    QEvent.HoverLeave,
                    QEvent.FocusOut,
                    QEvent.Hide,
                }:
                    self._player_command_hovered = False
                    self._player_restart_command_center_idle_timer()
                    return False

            if isinstance(obj, QWidget) and (
                self._player_is_command_chapter_widget(obj)
                or (
                    getattr(self, "playerControlsBar", None) is not None
                    and (
                        obj is self.playerControlsBar
                        or self.playerControlsBar.isAncestorOf(obj)
                    )
                )
            ):
                if event.type() in {
                    QEvent.Enter,
                    QEvent.HoverEnter,
                    QEvent.HoverMove,
                    QEvent.MouseMove,
                    QEvent.MouseButtonPress,
                    QEvent.MouseButtonRelease,
                    QEvent.Wheel,
                    QEvent.FocusIn,
                    QEvent.Show,
                }:
                    self._player_set_chapter_panel_hovered(True)
                    return False
                if event.type() in {
                    QEvent.Leave,
                    QEvent.HoverLeave,
                    QEvent.FocusOut,
                    QEvent.Hide,
                }:
                    self._player_set_chapter_panel_hovered(False)
                    return False

            if isinstance(obj, QWidget) and self._player_is_command_center_activity_widget(obj):
                if event.type() in {
                    QEvent.Show,
                    QEvent.Enter,
                    QEvent.MouseMove,
                    QEvent.MouseButtonPress,
                    QEvent.MouseButtonRelease,
                    QEvent.Wheel,
                    QEvent.KeyPress,
                }:
                    self._player_command_hovered = False
                    self._player_end_command_center_idle_fade(restart_timer=True)
                    return False

            discover_docks = tuple(getattr(self, "_search_discover_docks", {}).values())
            if isinstance(obj, QDockWidget) and obj in discover_docks:
                if event.type() in {
                    QEvent.Move,
                    QEvent.Resize,
                    QEvent.Show,
                    QEvent.Hide,
                    QEvent.WindowStateChange,
                    QEvent.ZOrderChange,
                }:
                    self._search_schedule_discover_layout_save()
                return False

            # ------------------------------------------------------------
            # SANDBOX-PROVEN: Rail viewport wheel intercept (fast path)
            # Any viewport marked with _omega_is_rail_viewport=True has its
            # wheel event redirected to the home vertical scrollbar, and
            # horizontal motion is blocked so rails only scroll via chevrons.
            # ------------------------------------------------------------
            if event.type() == QEvent.Wheel and isinstance(event, QWheelEvent):
                if isinstance(obj, QComboBox):
                    try:
                        combo_view = obj.view()
                    except Exception:
                        combo_view = None
                    if combo_view is None or not combo_view.isVisible():
                        event.ignore()
                        return True
                if isinstance(obj, (QSpinBox, QDoubleSpinBox)):
                    event.ignore()
                    return True
                if isinstance(obj, QWidget) and bool(obj.property("_omega_is_rail_viewport")):
                    self._home_forward_wheel_to_home_scroll(event)
                    event.accept()
                    return True
                    px = event.pixelDelta()
                    ang = event.angleDelta()
                    dx = int(px.x() if not px.isNull() else ang.x())
                    dy = int(px.y() if not px.isNull() else ang.y())

                    # Shift-wheel: some mice map vertical wheel ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¾ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ horizontal.  Block it.
                    if event.modifiers() & Qt.ShiftModifier:
                        dx = 1  # force "has horizontal intent" flag

                    # Always route vertical intent to home vertical scrollbar.
                    if dy != 0:
                        try:
                            vbar = self.homeScrollArea.verticalScrollBar()
                            step = dy if not px.isNull() else (dy // 3)
                            vbar.setValue(vbar.value() - step)
                        except Exception:
                            pass

                    # Block horizontal intent (trackpad swipe / shift-wheel)
                    event.accept()
                    return True

            # ------------------------------------------------------------
            # HOME viewport wheel routing (critical: do NOT swallow all wheel)
            # ------------------------------------------------------------
            if self.homeScrollArea is not None and obj is self.homeScrollArea.viewport():
                et = event.type()

                # -------------------------
                # 1) RESIZE -> responsive
                # -------------------------
                if et == QEvent.Resize:
                    vw = int(self.homeScrollArea.viewport().width())
                    vh = int(self.homeScrollArea.viewport().height())

                    # Prevent feedback loops: only react when the *viewport size* actually changes.
                    last = getattr(self, "_home_last_viewport_size", (-1, -1))
                    cur = (vw, vh)
                    if cur == last:
                        return False
                    self._home_last_viewport_size = cur

                    self._dprint(f"[EVT][HOME_VIEWPORT][RESIZE] vw={vw} vh={vh} obj={obj.objectName()}")

                    # Debounced responsive rebuild (correct method name)
                    if hasattr(self, "_home_on_viewport_resized"):
                        self._home_on_viewport_resized()
                    else:
                        # fallback: if you renamed it later
                        if hasattr(self, "_home_rebuild_responsive_debounced"):
                            self._home_rebuild_responsive_debounced()

                    self._home_position_show_selection_overlays()

                # -------------------------
                # 2) WHEEL -> route to rail only if cursor is actually over a RailShell
                # -------------------------
                if et == QEvent.Wheel:
                    # Global cursor position -> widgetAt -> climb parents to find RailShell
                    try:
                        from PySide6.QtWidgets import QApplication
                        gp = event.globalPosition().toPoint()  # Qt6: QPoint
                        w = QApplication.widgetAt(gp)
                    except Exception:
                        w = None

                    dy = event.angleDelta().y()
                    dx = event.angleDelta().x()

                    # Debug the wheel BEFORE deciding what to do
                    wname = getattr(w, "objectName", lambda: "")()
                    wcls = type(w).__name__ if w is not None else "None"
                    self._dprint(f"[EVT][HOME_VIEWPORT][WHEEL] dx={dx} dy={dy} under={wcls}:{wname}")

                    # Walk up parents to find a RailShell instance
                    rail = None
                    p = w
                    hop = 0
                    while p is not None and hop < 25:
                        if type(p).__name__ == "RailShell":
                            rail = p
                            break
                        p = p.parentWidget()
                        hop += 1

                    # If we found a rail under the cursor: consume and route horizontally
                    if rail is not None:
                        self._dprint(
                            f"[EVT][HOME_VIEWPORT][WHEEL] ROUTE -> RailShell id={getattr(rail, 'rail_id', 'unknown')}")
                        try:
                            # RailShell should already support wheel; if not, just pass event to its scroll area
                            if hasattr(rail, "handle_wheel"):
                                rail.handle_wheel(event)
                            else:
                                # Fallback: push horizontal scroll directly
                                sc = getattr(rail, "sc", None)
                                if sc is not None and sc.horizontalScrollBar() is not None:
                                    sb = sc.horizontalScrollBar()
                                    step = int(abs(dy) / 120) * 80
                                    if dy < 0:
                                        sb.setValue(sb.value() + step)
                                    else:
                                        sb.setValue(sb.value() - step)
                        except Exception as e:
                            self._dprint(f"[EVT][HOME_VIEWPORT][WHEEL][ERR] rail route failed: {e}")
                        return True  # we handled it; do NOT let vertical scroll happen in this case

                    # Otherwise: DO NOT CONSUME THE WHEEL.
                    # Use the same smooth Home scroll path everywhere so the page
                    # feels stable even when the pointer is hovering cards/rails.
                    self._dprint("[EVT][HOME_VIEWPORT][WHEEL] ROUTE -> smooth Home vertical scroll")
                    if self._home_forward_wheel_to_home_scroll(event):
                        event.accept()
                        return True
                    return False

            return super().eventFilter(obj, event)

        except Exception as e:
            # Never break event loopÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Âlog and fall through
            try:
                self._dprint(f"[EVT][ERR] eventFilter exception: {e}")
            except Exception:
                pass
            return super().eventFilter(obj, event)

    # ============================================================
    # CHEVRONS ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â polished floating overlay buttons (sandbox-proven)
    # ============================================================

    def _create_chevrons(self, scroll: QScrollArea):
        """
        Create a pair of ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â® ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¯ overlay buttons parented to self.win so they
        float above all content.  The buttons scroll `scroll` horizontally
        by T.home.chevron_step_px on each click.

        Returns (left_btn, right_btn).

        USAGE: call this for any horizontal QScrollArea that needs
        window-level chevrons (e.g. a RailShell sc that the shell doesn't
        already wrap with its own built-in arrows).
        """
        s        = int(self.T.home.chevron_size_px)
        font_px  = int(self.T.home.chevron_font_px)
        step_px  = int(self.T.home.chevron_step_px)

        left  = QPushButton("ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â®", self.win)
        right = QPushButton("ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚ÂÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¯", self.win)

        for btn in (left, right):
            btn.setFixedSize(s, s)
            btn.setFocusPolicy(Qt.NoFocus)
            btn.setCursor(Qt.PointingHandCursor)
            btn.setStyleSheet(f"""
                QPushButton {{
                    background-color: rgba(0,0,0,180);
                    color: white;
                    border-radius: {s // 2}px;
                    font-size: {font_px}px;
                    border: none;
                }}
                QPushButton:hover {{
                    background-color: rgba(30,30,30,210);
                }}
                QPushButton:pressed {{
                    background-color: rgba(50,50,50,230);
                }}
            """)
            btn.raise_()
            btn.show()

        left.clicked.connect(lambda: self._chevron_scroll(scroll, -step_px))
        right.clicked.connect(lambda: self._chevron_scroll(scroll, +step_px))

        return left, right

    def _chevron_scroll(self, scroll: QScrollArea, delta_px: int) -> None:
        """Scroll a QScrollArea horizontally by delta_px (negative = left)."""
        try:
            bar = scroll.horizontalScrollBar()
            bar.setValue(bar.value() + delta_px)
        except Exception:
            pass

    def _position_window_chevrons(self, scroll: QScrollArea, left_btn: QPushButton, right_btn: QPushButton) -> None:
        """
        Reposition floating window-level chevrons so they sit vertically
        centred on the given scroll area's visible rect.

        Call this after layout changes and on verticalScrollBar.valueChanged.
        """
        try:
            s = int(self.T.home.chevron_size_px)
            top_left = scroll.mapTo(self.win, QPoint(0, 0))
            center_y = top_left.y() + scroll.height() // 2 - (s // 2)
            left_btn.move(top_left.x(), center_y)
            right_btn.move(top_left.x() + scroll.width() - s, center_y)
            left_btn.raise_()
            right_btn.raise_()
        except Exception:
            pass

