    def _player_upgrade_seek_slider(self) -> None:
        slider = getattr(self, "playerSeekSlider", None)
        if slider is None or isinstance(slider, JumpSlider):
            return

        parent = slider.parentWidget()
        upgraded = JumpSlider(slider.orientation(), parent)
        upgraded.setObjectName(str(slider.objectName() or "playerSeekSlider"))
        upgraded.setRange(int(slider.minimum()), int(slider.maximum()))
        upgraded.setSingleStep(int(slider.singleStep()))
        upgraded.setPageStep(int(slider.pageStep()))
        upgraded.setTracking(bool(slider.hasTracking()))
        upgraded.setFocusPolicy(slider.focusPolicy())
        upgraded.setSizePolicy(slider.sizePolicy())
        upgraded.setMinimumSize(slider.minimumSize())
        upgraded.setMaximumSize(slider.maximumSize())
        upgraded.setStyleSheet(str(slider.styleSheet() or ""))
        try:
            upgraded.setValue(int(slider.value()))
        except Exception:
            pass

        layout = parent.layout() if parent is not None else None
        if layout is not None:
            try:
                layout.replaceWidget(slider, upgraded)
            except Exception:
                pass
        try:
            slider.hide()
        except Exception:
            pass
        try:
            slider.setParent(None)
        except Exception:
            pass
        try:
            slider.deleteLater()
        except Exception:
            pass
        self.playerSeekSlider = upgraded

    def _player_init_floating_mini_player(self) -> None:
        if self.win is None or getattr(self, "_player_floating_mini", None) is not None:
            return
        mini = FloatingMiniPlayer(self.win)
        mini.hide()
        mini.requestReturnToPlayer.connect(self._nav_go_player)
        mini.requestTogglePlayPause.connect(self._player_on_play_pause_clicked)
        mini.requestToggleMute.connect(self._player_on_mute_clicked)
        mini.requestSeekRelative.connect(self._player_seek_relative_ms)
        mini.requestPrevEpisode.connect(self._player_restart_or_prev_episode)
        mini.requestNextEpisode.connect(self._player_on_next_clicked)
        mini.requestFullscreen.connect(self._player_on_fullscreen_clicked)
        mini.requestCloseMini.connect(self._player_on_floating_mini_closed)
        mini.requestSeekToPos.connect(self._handle_ratio_seek)
        self._player_floating_mini = mini
        self._player_apply_floating_mini_default_geometry()

        try:
            self.playerPage.installEventFilter(self)
        except Exception:
            pass

        self._player_apply_elite_layout()
        smart_strip = getattr(self, "_smart_shuffle_live_strip", None)
        if smart_strip is None:
            self._smart_shuffle_live_strip = SmartShuffleNowPlayingStrip(self.playerPage)
            smart_strip = self._smart_shuffle_live_strip
            try:
                smart_strip.buttons["stay_on_show"].clicked.connect(lambda: self._smart_shuffle_handle_live_action("stay_on_show"))
                smart_strip.buttons["switch_sooner"].clicked.connect(lambda: self._smart_shuffle_handle_live_action("switch_sooner"))
                smart_strip.buttons["soft_landing"].clicked.connect(lambda: self._smart_shuffle_handle_live_action("soft_landing"))
                smart_strip.buttons["more_familiar"].clicked.connect(lambda: self._smart_shuffle_handle_live_action("more_familiar"))
                smart_strip.buttons["more_adventurous"].clicked.connect(lambda: self._smart_shuffle_handle_live_action("more_adventurous"))
            except Exception:
                pass
    def _player_controls_available_width(self) -> int:
        bar = self.playerControlsBar
        if bar is not None:
            try:
                width = int(bar.width())
                if width > 0:
                    return width
            except Exception:
                pass

        page_lay = self.playerPage.layout() if self.playerPage is not None else None
        if page_lay is not None:
            try:
                rect = page_lay.contentsRect()
                if rect.width() > 0:
                    return int(rect.width())
            except Exception:
                pass

        try:
            return max(0, int(self.playerPage.width())) if self.playerPage is not None else 0
        except Exception:
            return 0

    def _player_controls_layout_mode(self) -> str:
        available_w = max(0, int(self._player_controls_available_width()))
        stack_threshold_px = 1760
        return "stacked" if 0 < available_w < stack_threshold_px else "inline"

    def _player_apply_elite_layout(self) -> None:
        if self.playerPage is None:
            return

        page_lay = self.playerPage.layout()
        if page_lay is None:
            page_lay = QVBoxLayout(self.playerPage)
            self.playerPage.setLayout(page_lay)

        left, _top, right, _bottom = page_lay.getContentsMargins()
        page_lay.setContentsMargins(int(left), 0, int(right), int(self._player_page_base_bottom_margin))
        page_lay.setSpacing(0)
        self._apply_shell_page_insets()

        if self.videoFrame is not None:
            try:
                self.videoFrame.setParent(self.playerPage)
            except Exception:
                pass
            self.videoFrame.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
            self.videoFrame.setMinimumSize(0, 0)
            self.videoFrame.setMaximumSize(16777215, 16777215)

            vf_lay = self.videoFrame.layout()
            if vf_lay is None:
                vf_lay = QVBoxLayout(self.videoFrame)
                self.videoFrame.setLayout(vf_lay)
            vf_lay.setContentsMargins(0, 0, 0, 0)
            vf_lay.setSpacing(0)

            if self.videoHost is not None:
                try:
                    self.videoHost.setParent(self.videoFrame)
                except Exception:
                    pass
                self.videoHost.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
                self.videoHost.setMinimumSize(0, 0)
                self.videoHost.setMaximumSize(16777215, 16777215)
                if vf_lay.indexOf(self.videoHost) < 0:
                    vf_lay.addWidget(self.videoHost, 1)

        if self.playerControlsBar is not None:
            try:
                self.playerControlsBar.setParent(self.playerPage)
            except Exception:
                pass
            controls_mode = self._player_controls_layout_mode()
            controls_bar_height = int(CONTROLS_BAR_HEIGHT + (32 if controls_mode == "stacked" else 0))
            self.playerControlsBar.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
            self.playerControlsBar.setMinimumHeight(controls_bar_height)
            self.playerControlsBar.setMaximumHeight(int(controls_bar_height + 8))
            self.playerControlsBar.setMinimumWidth(0)
            self.playerControlsBar.setMaximumWidth(16777215)

        if self.videoFrame is not None and page_lay.indexOf(self.videoFrame) < 0:
            page_lay.insertWidget(0, self.videoFrame, 1)

        smart_strip = getattr(self, "_smart_shuffle_live_strip", None)
        if smart_strip is not None:
            try:
                smart_strip.setParent(self.playerPage)
            except Exception:
                pass
            smart_strip.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
            if page_lay.indexOf(smart_strip) < 0:
                page_lay.addWidget(smart_strip, 0)

        episode_label = getattr(self, "_player_episode_title_label", None)
        if episode_label is not None:
            try:
                episode_label.setParent(self.playerPage)
            except Exception:
                pass
            episode_label.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
            if page_lay.indexOf(episode_label) < 0:
                page_lay.addWidget(episode_label, 0)

        if self.playerControlsBar is not None and page_lay.indexOf(self.playerControlsBar) < 0:
            page_lay.addWidget(self.playerControlsBar, 0)

        self._apply_non_home_page_bottom_inset()
        self._apply_shell_page_insets()
        self._player_apply_controls_chrome()
        controls_mode = self._player_controls_layout_mode()
        host = self.playerControlsBar.findChild(QWidget, "playerControlsHost") if self.playerControlsBar is not None else None
        if (
            not self._player_layout_installed
            or getattr(self, "_player_controls_bar_layout_mode", None) != controls_mode
            or host is None
        ):
            self._player_rebuild_controls_bar_layout()
        self._player_apply_page_backdrop_chrome()
        self._player_layout_installed = True
        self._player_update_now_playing_title_label()
        self._player_update_playlist_drawer_contents()
        self._player_update_playlist_drawer_geometry()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_update_command_center_geometry()
        self._player_update_command_center(0, 0)
    def _player_rebuild_controls_bar_layout(self) -> None:
        bar = self.playerControlsBar
        if bar is None:
            return

        lay = bar.layout()
        if lay is None:
            lay = QHBoxLayout(bar)
            bar.setLayout(lay)

        def release_items(target_layout: QLayout) -> None:
            while target_layout.count():
                item = target_layout.takeAt(0)
                child_layout = item.layout()
                child_widget = item.widget()
                if child_layout is not None:
                    release_items(child_layout)
                    try:
                        child_layout.deleteLater()
                    except Exception:
                        pass
                    continue
                if child_widget is None:
                    continue
                if child_widget.objectName() == "playerControlsHost":
                    child_widget.deleteLater()
                    continue
                try:
                    child_widget.setParent(bar)
                except Exception:
                    pass

        def add_widget(target_layout: QBoxLayout, widget: Optional[QWidget], stretch: int = 0) -> None:
            if widget is None:
                return
            if stretch > 0:
                target_layout.addWidget(widget, stretch)
            else:
                target_layout.addWidget(widget)

        release_items(lay)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.setSpacing(0)

        mode = self._player_controls_layout_mode()
        host = QWidget(bar)
        host.setObjectName("playerControlsHost")
        host.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
        host_lay = QVBoxLayout(host)
        host_lay.setContentsMargins(8, 5, 8, 5)
        host_lay.setSpacing(5)

        if mode == "inline":
            row = QHBoxLayout()
            row.setContentsMargins(0, 0, 0, 0)
            row.setSpacing(5)
            for btn in (
                self.playerPrevBtn,
                self.playerBackBtn,
                self.playerPlayPauseBtn,
                self.playerFwdBtn,
                self.playerNextBtn,
            ):
                add_widget(row, btn)
            add_widget(row, self.playerTimeLabel)
            add_widget(row, self._player_prev_chapter_btn)
            add_widget(row, self._player_next_chapter_btn)
            add_widget(row, self._player_skip_intro_btn)
            add_widget(row, self._player_skip_outro_btn)
            if self.playerSeekSlider is not None:
                self.playerSeekSlider.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
                row.addWidget(self.playerSeekSlider, 1)
            add_widget(row, self.playerAudioBox)
            add_widget(row, self.playerSubtitlesBox)
            add_widget(row, self._player_subtitle_settings_btn)
            add_widget(row, self.playerVolumeLabel)
            if self.playerVolumeSlider is not None:
                self.playerVolumeSlider.setSizePolicy(QSizePolicy.Fixed, QSizePolicy.Fixed)
                row.addWidget(self.playerVolumeSlider)
            for btn in (
                self.playerMuteBtn,
                self.playerStopBtn,
                self.playerCloseBtn,
                self.playerFullscreenBtn,
            ):
                add_widget(row, btn)
            host_lay.addLayout(row)
        else:
            top_row = QHBoxLayout()
            top_row.setContentsMargins(0, 0, 0, 0)
            top_row.setSpacing(5)
            bottom_row = QHBoxLayout()
            bottom_row.setContentsMargins(0, 0, 0, 0)
            bottom_row.setSpacing(5)

            for btn in (
                self.playerPrevBtn,
                self.playerBackBtn,
                self.playerPlayPauseBtn,
                self.playerFwdBtn,
                self.playerNextBtn,
            ):
                add_widget(top_row, btn)
            add_widget(top_row, self.playerTimeLabel)
            add_widget(top_row, self._player_prev_chapter_btn)
            add_widget(top_row, self._player_next_chapter_btn)
            add_widget(top_row, self._player_skip_intro_btn)
            add_widget(top_row, self._player_skip_outro_btn)
            if self.playerSeekSlider is not None:
                self.playerSeekSlider.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
                top_row.addWidget(self.playerSeekSlider, 1)

            add_widget(bottom_row, self.playerAudioBox)
            add_widget(bottom_row, self.playerSubtitlesBox)
            add_widget(bottom_row, self._player_subtitle_settings_btn)
            bottom_row.addStretch(1)
            add_widget(bottom_row, self.playerVolumeLabel)
            if self.playerVolumeSlider is not None:
                self.playerVolumeSlider.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
                bottom_row.addWidget(self.playerVolumeSlider, 1)
            for btn in (
                self.playerMuteBtn,
                self.playerStopBtn,
                self.playerCloseBtn,
                self.playerFullscreenBtn,
            ):
                add_widget(bottom_row, btn)

            host_lay.addLayout(top_row)
            host_lay.addLayout(bottom_row)

        lay.addWidget(host, 1)
        self._player_controls_bar_layout_mode = mode

