        lbl.setAlignment(Qt.AlignLeft | Qt.AlignVCenter)
        lbl.setTextFormat(Qt.PlainText)
        lbl.setMinimumHeight(int(self.T.player.now_playing_title_min_h_px))
        lbl.setMaximumHeight(int(self.T.player.now_playing_title_min_h_px + 14))
        lbl.setStyleSheet(
            "color: rgba(245,245,245,235);"
            "background: rgba(0,0,0,120);"
            "padding: 6px 12px;"
            "font-size: 13px;"
            "font-weight: 600;"
        )
        lbl.hide()
        self._player_episode_title_label = lbl

