    def _player_update_chapter_buttons(self) -> None:
        chapters = tuple(getattr(self, "_player_cached_chapters", ()) or ())
        enabled = bool(chapters)
        for btn in (self._player_prev_chapter_btn, self._player_next_chapter_btn):
            if btn is not None:
                btn.setEnabled(enabled)

    def _player_skip_flash_status(self, message: str) -> None:
        text = str(message or "").strip()
        if not text:
            return
        try:
            bar = self.win.statusBar() if self.win is not None else None
        except Exception:
            bar = None
        if bar is not None:
            try:
                bar.showMessage(text, int(SEGMENT_SKIP_TUNING.capture_status_ms))
                return
            except Exception:
                pass
        dprint(f"[SKIP] {text}")

    def _player_skip_context_for_path(self, path: Path) -> Tuple[str, str, Optional[int]]:
        canon = self._home_canon_path_str(Path(str(path)))
        show_key = self._home_resolve_media_key_for_path(Path(str(path)))
        season_num, _episode_num = parse_season_episode(path.stem)
        if season_num is None:
            try:
                m = re.search(r"(?:season|s)[\s._-]*(\d{1,2})", str(path.parent.name), re.IGNORECASE)
                if m:
                    season_num = int(m.group(1))
            except Exception:
                season_num = None
        return canon, str(show_key or ""), season_num

    def _player_reset_segment_skip_state(self, path_key: str = "") -> None:
        self._player_skip_path_key = str(path_key or "")
        self._player_skip_segment_sig = tuple()
        self._player_skip_intro_segment = None
        self._player_skip_outro_segment = None
        self._player_cached_chapters = tuple()
        self._player_skip_consumed = {"intro": False, "outro": False}
        for kind in ("intro", "outro"):
            capture = self._player_skip_capture.get(kind, {})
            if isinstance(capture, dict):
                capture["start_ms"] = None
                capture["end_ms"] = None
        for btn in (self._player_skip_intro_btn, self._player_skip_outro_btn):
            if btn is not None:
                btn.hide()
        self._player_update_chapter_buttons()

    def _player_refresh_segment_skip_state(self, cur_ms: int, dur_ms: int) -> None:
        with self._perf_track("player_segment_state"):
            path = self._current_path
            if path is None or self._mpv is None:
                self._player_reset_segment_skip_state("")
                return
            p = Path(str(path))
            path_key, show_key, season_num = self._player_skip_context_for_path(p)
            if path_key != str(self._player_skip_path_key or ""):
                self._player_reset_segment_skip_state(path_key)

            chapters = tuple(getattr(self, "_player_cached_chapters", ()) or ())
            if not chapters:
                try:
                    chapters = tuple(self._mpv.get_chapters() or ())
                except Exception:
                    chapters = ()
                self._player_cached_chapters = chapters
            chapter_sig = tuple(
                (
                    int(item.get("start_ms", 0) or 0),
                    str(item.get("title", "") or ""),
                )
                for item in chapters
                if isinstance(item, dict)
            )
            segment_sig = (
                str(path_key),
                int(max(0, dur_ms or 0)),
                chapter_sig,
            )
            if segment_sig != tuple(getattr(self, "_player_skip_segment_sig", ()) or ()):
                intro, outro, _sources = self._segment_skip_store.get_effective_segments(
                    path_key=path_key,
                    path=str(p),
                    show_key=show_key,
                    season_number=season_num,
                    duration_ms=int(max(0, dur_ms or 0)),
                    chapters=chapters,
                )
                self._player_skip_intro_segment = intro
                self._player_skip_outro_segment = outro
                self._player_skip_segment_sig = segment_sig
            else:
                intro = self._player_skip_intro_segment
                outro = self._player_skip_outro_segment

            self._player_update_chapter_buttons()

            for kind, seg in (("intro", intro), ("outro", outro)):
                if seg is None:
                    self._player_skip_consumed[kind] = False
                    continue
                if int(cur_ms) < int(seg.start_ms) - 1500:
                    self._player_skip_consumed[kind] = False

            self._player_update_segment_skip_buttons(int(cur_ms), int(dur_ms))

    def _player_update_segment_skip_buttons(self, cur_ms: int, dur_ms: int) -> None:
        controls_visible = bool(self.playerControlsBar is not None and self.playerControlsBar.isVisible())
        intro = self._player_skip_intro_segment
        outro = self._player_skip_outro_segment
        pairs = (
            ("intro", self._player_skip_intro_btn, intro, int(SEGMENT_SKIP_TUNING.intro_button_min_ms)),
            ("outro", self._player_skip_outro_btn, outro, int(SEGMENT_SKIP_TUNING.outro_button_min_ms)),
        )
        for kind, btn, seg, min_ms in pairs:
            if btn is None:
                continue
            visible = False
            if seg is not None and (int(seg.end_ms) - int(seg.start_ms)) >= int(min_ms):
                inside = int(seg.start_ms) <= int(cur_ms) < int(seg.end_ms)
                visible = bool(controls_visible and inside and not bool(self._player_skip_consumed.get(kind, False)))
                if inside and self._segment_skip_store.get_auto_skip(kind):
                    self._player_skip_segment(kind)
                    visible = False
            btn.setVisible(bool(visible))

    def _player_skip_segment(self, kind: str) -> None:
        if self._mpv is None:
            return
        segment = self._player_skip_intro_segment if str(kind) == "intro" else self._player_skip_outro_segment
        if segment is None:
            return
        target_ms = max(0, int(segment.end_ms) + int(SEGMENT_SKIP_TUNING.auto_skip_fudge_ms))
        self._player_skip_consumed[str(kind)] = True
        self._player_engage_seek_lock(target_ms)
        self._player_seek_backend_ms(target_ms)
        self._player_last_progress_snapshot_ms = int(target_ms)
        self._player_update_segment_skip_buttons(target_ms, max(target_ms, int(segment.end_ms)))
        self._player_skip_flash_status(f"Skipped {str(kind).title()}")

    def _player_toggle_auto_skip(self, kind: str, enabled: bool) -> None:
        self._segment_skip_store.set_auto_skip(kind, bool(enabled))
        self._player_skip_flash_status(f"Auto-skip {kind} {'on' if enabled else 'off'}")
        act = self._player_skip_menu_actions.get(f"auto_{kind}")
        if act is not None:
            try:
                act.setChecked(bool(enabled))
            except Exception:
                pass

    def _player_capture_segment_boundary(self, kind: str, boundary: str) -> None:
        if self._mpv is None or self._current_path is None:
            return
        cur_ms = int(max(0, self._player_to_ms(self._mpv.get_time_raw())))
        dur_ms = int(max(0, self._player_to_ms(self._mpv.get_duration_raw())))
        slot = self._player_skip_capture.setdefault(str(kind), {"start_ms": None, "end_ms": None})
        if not isinstance(slot, dict):
            slot = {"start_ms": None, "end_ms": None}
            self._player_skip_capture[str(kind)] = slot
        slot[f"{boundary}_ms"] = int(cur_ms)
        start_ms = slot.get("start_ms")
        end_ms = slot.get("end_ms")
        if start_ms is None or end_ms is None:
            self._player_skip_flash_status(f"Saved {kind} {boundary} at {fmt_ms(cur_ms)}")
            return
        start_val = int(start_ms)
        end_val = int(end_ms)
        if end_val <= start_val:
            self._player_skip_flash_status(f"{kind.title()} end must be after start")
            return
        p = Path(str(self._current_path))
        path_key, show_key, season_num = self._player_skip_context_for_path(p)
        segment = self._segment_skip_store.set_segment(
            path_key=path_key,
            path=str(p),
            show_key=show_key,
            season_number=season_num,
            duration_ms=dur_ms,
            kind=str(kind),
            start_ms=start_val,
            end_ms=end_val,
            source="manual",
            confidence=1.0,
        )
        slot["start_ms"] = None
        slot["end_ms"] = None
        if segment is None:
            self._player_skip_flash_status(f"Could not save {kind} marker")
            return
        self._player_refresh_segment_skip_state(cur_ms, dur_ms)
        self._player_skip_flash_status(f"Saved {kind.title()} marker {fmt_ms(start_val)} to {fmt_ms(end_val)}")

    def _player_clear_segment_marker(self, kind: str) -> None:
        if self._current_path is None:
            return
        p = Path(str(self._current_path))
        path_key, _show_key, _season_num = self._player_skip_context_for_path(p)
        self._segment_skip_store.clear_segment(path_key, str(kind))
        slot = self._player_skip_capture.setdefault(str(kind), {"start_ms": None, "end_ms": None})
        if isinstance(slot, dict):
            slot["start_ms"] = None
            slot["end_ms"] = None
        self._player_refresh_segment_skip_state(0, int(self._player_to_ms(self._mpv.get_duration_raw())) if self._mpv is not None else 0)
        self._player_skip_flash_status(f"Cleared {kind} marker")
