    def _player_init_backend_or_warn(self) -> None:
        if self.videoHost is None:
            dprint("[PLAYER][WARN] videoHost not found. Skipping MPV embed.")
            return
        self._player_remove_backend_observers()

        try:
            if self.videoFrame is not None:
                self.videoFrame.setStyleSheet("background: black;")
            self.videoHost.setStyleSheet("background: black;")
        except Exception:
            pass

        try:
            self._mpv = MPVBackend()
        except Exception as e:
            dprint("[PLAYER][ERROR] MPV init failed:", e)
            self._player_schedule_backend_warning(
                "MPV Playback Unavailable",
                "MPV could not be initialized.\n\n"
                f"Details:\n{type(e).__name__}: {e}\n\n"
                "Fix:\n"
                "1) pip install python-mpv\n"
                "2) Ensure libmpv-2.dll is available\n"
                "   - Put MPV folder on PATH, OR\n"
                "   - Put libmpv-2.dll next to your app root\n",
            )
            self._mpv = None
            return

        self._player_install_backend_observers()
        self._player_apply_subtitle_settings_to_backend(respect_enabled_on_load=False)
        self._player_update_subtitle_menu_actions()
        QTimer.singleShot(0, self._player_attach_to_video_host)
        self._player_refresh_ui_timer_state()

    def _player_schedule_backend_warning(self, title: str, message: str) -> None:
        title_text = str(title or "Playback Unavailable")
        message_text = str(message or "Playback could not be initialized.")

        def _show_warning() -> None:
            existing = getattr(self, "_player_backend_warning_box", None)
            if existing is not None:
                try:
                    existing.close()
                except Exception:
                    pass
                self._player_backend_warning_box = None

            try:
                box = QMessageBox(self.win)
                box.setIcon(QMessageBox.Critical)
                box.setWindowTitle(title_text)
                box.setText(message_text)
                box.setStandardButtons(QMessageBox.Ok)
                box.setModal(False)
                box.setAttribute(Qt.WA_DeleteOnClose, True)
                try:
                    box.finished.connect(lambda *_args: setattr(self, "_player_backend_warning_box", None))
                except Exception:
                    pass
                self._player_backend_warning_box = box
                box.show()
                box.raise_()
                box.activateWindow()
            except Exception:
                pass

        QTimer.singleShot(0, _show_warning)

    def _player_attach_to_video_host(self) -> None:
        if self._mpv is None or self.videoHost is None:
            return
        try:
            self.videoHost.setAttribute(Qt.WA_NativeWindow, True)
            self.videoHost.setAttribute(Qt.WA_DontCreateNativeAncestors, True)
            self.videoHost.setAttribute(Qt.WA_OpaquePaintEvent, True)
            self.videoHost.show()
            wid = int(self.videoHost.winId())
            self._mpv.set_wid(wid)
            dprint(f"[PLAYER] MPV attached to videoHost winId={wid}")
        except Exception as e:
            dprint("[PLAYER][ERROR] Failed to attach MPV:", e)

    def _player_wire_controls(self) -> None:
        if self.playerSeekSlider is not None:
            try:
                self.playerSeekSlider.setRange(0, int(self.T.player.seek_slider_max))
                self.playerSeekSlider.setTracking(True)
                self.playerSeekSlider.setSingleStep(1)
                self.playerSeekSlider.setPageStep(int(self.T.player.seek_slider_page_step))
            except Exception:
                pass
            self.playerSeekSlider.sliderPressed.connect(self._player_on_seek_pressed)
            self.playerSeekSlider.sliderReleased.connect(self._player_on_seek_released)
            self.playerSeekSlider.actionTriggered.connect(self._player_on_seek_action_triggered)
            if isinstance(self.playerSeekSlider, JumpSlider):
                self.playerSeekSlider.jumpRequested.connect(self._player_on_seek_jump_requested)

        if self.playerVolumeSlider is not None:
            try:
                self.playerVolumeSlider.setRange(0, 100)
            except Exception:
                pass
            if self._mpv is not None:
                try:
                    self.playerVolumeSlider.setValue(self._mpv.get_volume())
                except Exception:
                    pass
            self.playerVolumeSlider.valueChanged.connect(self._player_on_volume_changed)
        if self.playerAudioBox is not None:
            self.playerAudioBox.currentIndexChanged.connect(self._player_on_audio_combo_changed)
            self.playerAudioBox.setEditable(False)
        if self.playerSubtitlesBox is not None:
            self.playerSubtitlesBox.currentIndexChanged.connect(self._player_on_subtitle_combo_changed)
            self.playerSubtitlesBox.setEditable(False)
        if self._player_subtitle_settings_btn is not None:
            self._player_subtitle_settings_btn.clicked.connect(self._player_open_subtitle_settings_dialog)

        if self.playerPlayPauseBtn is not None:
            self.playerPlayPauseBtn.clicked.connect(self._player_on_play_pause_clicked)
        if self.playerStopBtn is not None:
            self.playerStopBtn.clicked.connect(self._player_on_stop_clicked)
        if self.playerBackBtn is not None:
            self.playerBackBtn.clicked.connect(
                lambda: self._player_seek_relative_ms(-int(self.T.player.seek_jump_back_ms)))
        if self.playerFwdBtn is not None:
            self.playerFwdBtn.clicked.connect(
                lambda: self._player_seek_relative_ms(int(self.T.player.seek_jump_fwd_ms)))
        if self.playerPrevBtn is not None:
            self.playerPrevBtn.clicked.connect(self._player_on_prev_clicked)
        if self.playerNextBtn is not None:
            self.playerNextBtn.clicked.connect(self._player_on_next_clicked)
        if self.playerMuteBtn is not None:
            self.playerMuteBtn.clicked.connect(self._player_on_mute_clicked)
        if self.playerCloseBtn is not None:
            self.playerCloseBtn.clicked.connect(self._player_on_close_clicked)
        if self.playerFullscreenBtn is not None:
            self.playerFullscreenBtn.clicked.connect(self._player_on_fullscreen_clicked)
        if self.playerTimeLabel is not None:
            self.playerTimeLabel.setText("0:00 / 0:00")

        self._player_apply_controls_chrome()
        self._player_rebuild_audio_combo([], current_aid=None, loading=False)
        self._player_rebuild_subtitle_combo([], current_sid=None, visible=False, loading=False)
        self._player_update_subtitle_menu_actions()
        self._player_sync_play_pause_btn()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()

    def _player_subtitle_settings_default(self) -> Dict[str, Any]:
        return {
            "enabled_on_load": True,
            "force_override": True,
            "font_family": "Arial",
            "font_size": 42,
            "font_scale": 100,
            "bold": False,
            "italic": False,
            "text_color": "#FFFFFFFF",
            "background_color": "#8C000000",
            "border_color": "#FF000000",
            "shadow_color": "#AA000000",
            "border_size": 3.0,
            "shadow_offset": 1.5,
            "position": 92,
            "margin_y": 24,
        }

    def _player_normalize_subtitle_color(self, value: Any, fallback: str) -> str:
        color = QColor(str(value or "").strip())
        if not color.isValid():
            color = QColor(str(fallback or "#FFFFFFFF"))
        if not color.isValid():
            color = QColor("#FFFFFFFF")
        return color.name(QColor.HexArgb).upper()

    def _player_subtitle_settings_from_state(self) -> Dict[str, Any]:
        base = self._player_subtitle_settings_default()
        raw = self._home_state.get("subtitle_settings", {}) if isinstance(getattr(self, "_home_state", {}), dict) else {}
        if not isinstance(raw, dict):
            raw = {}

        out = dict(base)
        out["enabled_on_load"] = bool(raw.get("enabled_on_load", base["enabled_on_load"]))
        out["force_override"] = bool(raw.get("force_override", base["force_override"]))
        out["font_family"] = str(raw.get("font_family", base["font_family"]) or base["font_family"])
        out["text_color"] = self._player_normalize_subtitle_color(raw.get("text_color", base["text_color"]), base["text_color"])
        out["background_color"] = self._player_normalize_subtitle_color(raw.get("background_color", base["background_color"]), base["background_color"])
        out["border_color"] = self._player_normalize_subtitle_color(raw.get("border_color", base["border_color"]), base["border_color"])
        out["shadow_color"] = self._player_normalize_subtitle_color(raw.get("shadow_color", base["shadow_color"]), base["shadow_color"])
        out["bold"] = bool(raw.get("bold", base["bold"]))
        out["italic"] = bool(raw.get("italic", base["italic"]))

        for key, minimum, maximum in (
            ("font_size", 10, 96),
            ("font_scale", 50, 300),
            ("position", 0, 100),
            ("margin_y", 0, 180),
        ):
            try:
                out[key] = max(minimum, min(maximum, int(raw.get(key, base[key]))))
            except Exception:
                out[key] = int(base[key])

        for key, minimum, maximum in (
            ("border_size", 0.0, 12.0),
            ("shadow_offset", 0.0, 12.0),
        ):
            try:
                out[key] = max(minimum, min(maximum, float(raw.get(key, base[key]))))
            except Exception:
                out[key] = float(base[key])

        return out

    def _player_save_subtitle_settings(self) -> None:
        self._home_state["subtitle_settings"] = dict(self._subtitle_settings)
        self._home_state_save()

    def _player_mpv_color(self, value: Any, fallback: str) -> str:
        color = QColor(self._player_normalize_subtitle_color(value, fallback))
        return f"{color.redF():.3f}/{color.greenF():.3f}/{color.blueF():.3f}/{color.alphaF():.3f}"

    def _player_backend_subtitle_style_payload(self) -> Dict[str, Any]:
        settings = self._subtitle_settings if isinstance(self._subtitle_settings, dict) else self._player_subtitle_settings_default()
        font_size = int(settings.get("font_size", 42) or 42)
        font_scale = max(0.5, min(3.0, float(settings.get("font_scale", 100) or 100) / 100.0))
        return {
            "sub_font": str(settings.get("font_family", "Arial") or "Arial"),
            "sub_font_size": font_size,
            "sub_scale": font_scale,
            "sub_color": self._player_mpv_color(settings.get("text_color"), "#FFFFFFFF"),
            "sub_back_color": self._player_mpv_color(settings.get("background_color"), "#8C000000"),
            "sub_border_color": self._player_mpv_color(settings.get("border_color"), "#FF000000"),
            "sub_shadow_color": self._player_mpv_color(settings.get("shadow_color"), "#AA000000"),
            "sub_border_size": float(settings.get("border_size", 3.0) or 0.0),
            "sub_shadow_offset": float(settings.get("shadow_offset", 1.5) or 0.0),
            "sub_pos": int(settings.get("position", 92) or 92),
            "sub_margin_y": int(settings.get("margin_y", 24) or 24),
            "sub_bold": bool(settings.get("bold", False)),
            "sub_italic": bool(settings.get("italic", False)),
            "sub_ass_override": "force" if bool(settings.get("force_override", True)) else "no",
        }

    def _player_apply_subtitle_settings_to_backend(self, *, respect_enabled_on_load: bool = False) -> None:
        mpv_backend = getattr(self, "_mpv", None)
        if mpv_backend is None:
            return
        try:
            mpv_backend.apply_subtitle_settings(self._player_backend_subtitle_style_payload())
            if respect_enabled_on_load:
                enabled = bool(self._subtitle_settings.get("enabled_on_load", True))
                if enabled:
                    current_sid = mpv_backend.get_current_subtitle_id()
                    if current_sid in (None, "", "no"):
                        mpv_backend.set_subtitle_track("auto", visible=True)
                    else:
                        mpv_backend.set_subtitle_visible(True)
                else:
                    mpv_backend.set_subtitle_visible(False)
        except Exception as e:
            dprint("[PLAYER][SUB][WARN] applying subtitle settings failed:", e)
        self._player_schedule_subtitle_refresh(attempts=4, immediate=True)

    def _player_track_id_text(self, value: Optional[object]) -> str:
        if value is None:
            return ""
        return str(value).strip().casefold()

    def _player_audio_track_lang_text(self, track: Dict[str, Any]) -> str:
        raw = str(track.get("lang") or track.get("language") or "").strip().casefold().replace("_", "-")
        return raw

    def _player_audio_track_title_blob(self, track: Dict[str, Any]) -> str:
        bits = [
            str(track.get("title") or "").strip(),
            str(track.get("name") or "").strip(),
            str(track.get("handler_name") or "").strip(),
        ]
        return " ".join(bit for bit in bits if bit).casefold()

    def _player_audio_track_is_english(self, track: Dict[str, Any]) -> bool:
        lang = self._player_audio_track_lang_text(track)
        if lang in {"en", "eng", "english"} or lang.startswith("en-"):
            return True
        blob = self._player_audio_track_title_blob(track)
        return bool(re.search(r"\benglish\b|\beng\b", blob))

    def _player_audio_track_is_commentary(self, track: Dict[str, Any]) -> bool:
        blob = self._player_audio_track_title_blob(track)
        if not blob:
            return False
        return any(token in blob for token in ("commentary", "director", "descriptive", "described"))

    def _player_audio_track_priority(self, track: Dict[str, Any]) -> Tuple[int, int, int]:
        score = 0
        if self._player_audio_track_is_english(track):
            score += 1000
        if not self._player_audio_track_is_commentary(track):
            score += 220
        if bool(track.get("default", False)):
            score += 80
        if bool(track.get("selected", False)):
            score += 40
        if bool(track.get("external", False)):
            score -= 10
        channels = track.get("audio_channels", track.get("demux_channel_count", track.get("channels")))
        try:
            score += min(24, max(0, int(channels or 0)))
        except Exception:
            pass
        try:
            track_id = int(track.get("id") or 0)
        except Exception:
            track_id = 0
        return score, int(track.get("default", False)), -track_id

    def _player_pick_default_audio_track(self, tracks: List[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
        english_tracks = [dict(track) for track in (tracks or []) if self._player_audio_track_is_english(track)]
        if not english_tracks:
            return None
        return max(english_tracks, key=self._player_audio_track_priority)

    def _player_format_audio_track_label(self, track: Dict[str, Any]) -> str:
        track_id = track.get("id")
        title = str(track.get("title") or "").strip()
        lang = str(track.get("lang") or track.get("language") or "").strip()
        codec = str(track.get("codec") or "").strip().upper()

        lead = title or (lang.upper() if lang else f"Track {track_id}")
        bits: List[str] = [lead]
        if lang and lead.casefold() != lang.casefold():
            bits.append(lang.upper())
        channels = track.get("audio_channels", track.get("demux_channel_count", track.get("channels")))
        try:
            channels_int = int(channels or 0)
        except Exception:
            channels_int = 0
        if channels_int > 0:
            bits.append(f"{channels_int}ch")
        if bool(track.get("default", False)):
            bits.append("Default")
        if self._player_audio_track_is_commentary(track):
            bits.append("Commentary")
        if codec:
            bits.append(codec)
        bits.append("External" if bool(track.get("external", False)) else "Embedded")
        return "  |  ".join(bits)

    def _player_rebuild_audio_combo(
        self,
        tracks: List[Dict[str, Any]],
        *,
        current_aid: Optional[object],
        loading: bool,
    ) -> None:
        if self.playerAudioBox is None:
            return

        self._player_audio_combo_sync = True
        self.playerAudioBox.blockSignals(True)
        try:
            self.playerAudioBox.clear()
            if loading and not tracks:
                self.playerAudioBox.addItem("Looking for audio tracks...", "__loading__")
            elif not tracks:
                self.playerAudioBox.addItem("No alternate audio found", "__none__")
            else:
                for track in tracks:
                    self.playerAudioBox.addItem(self._player_format_audio_track_label(track), track.get("id"))

            select_idx = 0
            if tracks:
                aid_text = self._player_track_id_text(current_aid)
                for idx, track in enumerate(tracks):
                    track_id = track.get("id")
                    if aid_text and aid_text == self._player_track_id_text(track_id):
                        select_idx = idx
                        break
                    if not aid_text and bool(track.get("selected", False)):
                        select_idx = idx
                        break

            self.playerAudioBox.setCurrentIndex(select_idx)
            self.playerAudioBox.setEnabled(bool(tracks))
        finally:
            self.playerAudioBox.blockSignals(False)
            self._player_audio_combo_sync = False
        self._player_sync_fullscreen_audio_combo(tracks, current_aid=current_aid, loading=loading)

    def _player_format_subtitle_track_label(self, track: Dict[str, Any]) -> str:
        track_id = track.get("id")
        title = str(track.get("title") or "").strip()
        lang = str(track.get("lang") or track.get("language") or "").strip()
        codec = str(track.get("codec") or "").strip().upper()

        lead = title or (lang.upper() if lang else f"Track {track_id}")
        bits: List[str] = [lead]
        if lang and lead.casefold() != lang.casefold():
            bits.append(lang.upper())
        if bool(track.get("forced", False)):
            bits.append("Forced")
        if bool(track.get("default", False)):
                bits.append("Default")
        if codec:
            bits.append(codec)
        bits.append("External" if bool(track.get("external", False)) else "Embedded")
        return "  |  ".join(bits)

    def _player_active_backend_path_key(self) -> str:
        mpv_backend = getattr(self, "_mpv", None)
        if mpv_backend is not None:
            try:
                raw = str(mpv_backend.get_current_path() or "").strip()
                if raw:
                    return self._home_canon_path_str(Path(raw))
            except Exception:
                pass
        current_path = getattr(self, "_current_path", None)
        if current_path is None:
            return ""
        try:
            return self._home_canon_path_str(Path(str(current_path)))
        except Exception:
            return ""

    def _player_rebuild_subtitle_combo(
        self,
        tracks: List[Dict[str, Any]],
        *,
        current_sid: Optional[object],
        visible: bool,
        loading: bool,
    ) -> None:
        if self.playerSubtitlesBox is None:
            return

        self._player_subtitle_combo_sync = True
        self.playerSubtitlesBox.blockSignals(True)
        try:
            self.playerSubtitlesBox.clear()
            self.playerSubtitlesBox.addItem("Subtitles Off", "off")
            if loading and not tracks:
                self.playerSubtitlesBox.addItem("Looking for subtitles...", "__loading__")
            elif not tracks:
                self.playerSubtitlesBox.addItem("No subtitles found", "__none__")
            else:
                for track in tracks:
                    self.playerSubtitlesBox.addItem(self._player_format_subtitle_track_label(track), track.get("id"))

            select_idx = 0
            if visible and tracks:
                sid_text = str(current_sid or "").strip()
                for idx, track in enumerate(tracks, start=1):
                    track_id = track.get("id")
                    if sid_text and sid_text == str(track_id):
                        select_idx = idx
                        break
                    if current_sid in (None, "", "auto") and bool(track.get("selected", False)):
                        select_idx = idx
                        break
                if select_idx == 0 and tracks:
                    select_idx = 1

            self.playerSubtitlesBox.setCurrentIndex(select_idx)
            self.playerSubtitlesBox.setEnabled(bool(tracks))
        finally:
            self.playerSubtitlesBox.blockSignals(False)
            self._player_subtitle_combo_sync = False
        self._player_sync_fullscreen_subtitle_combo(tracks, current_sid=current_sid, visible=visible, loading=loading)

    def _player_sync_fullscreen_audio_combo(
        self,
        tracks: List[Dict[str, Any]],
        *,
        current_aid: Optional[object],
        loading: bool,
    ) -> None:
        fs = getattr(self, "_fs_window", None)
        if fs is None:
            return

        items: List[Tuple[str, object]] = []
        if loading and not tracks:
            items.append(("Looking for audio tracks...", "__loading__"))
        elif not tracks:
            items.append(("No alternate audio found", "__none__"))
        else:
            items = [(self._player_format_audio_track_label(track), track.get("id")) for track in tracks]

        try:
            fs.set_audio_choices(items)
            select_idx = 0
            if tracks:
                aid_text = self._player_track_id_text(current_aid)
                for idx, track in enumerate(tracks):
                    track_id = track.get("id")
                    if aid_text and aid_text == self._player_track_id_text(track_id):
                        select_idx = idx
                        break
                    if not aid_text and bool(track.get("selected", False)):
                        select_idx = idx
                        break
            fs.audio.blockSignals(True)
            fs.audio.setCurrentIndex(select_idx)
            fs.audio.setEnabled(bool(tracks))
            fs.audio.blockSignals(False)
        except Exception:
            pass

    def _player_sync_fullscreen_subtitle_combo(
        self,
        tracks: List[Dict[str, Any]],
        *,
        current_sid: Optional[object],
        visible: bool,
        loading: bool,
    ) -> None:
        fs = getattr(self, "_fs_window", None)
        if fs is None:
            return

        items: List[Tuple[str, object]] = [("Subtitles Off", "off")]
        if loading and not tracks:
            items.append(("Looking for subtitles...", "__loading__"))
        elif not tracks:
            items.append(("No subtitles found", "__none__"))
        else:
            items.extend((self._player_format_subtitle_track_label(track), track.get("id")) for track in tracks)

        try:
            fs.set_subtitle_choices(items)
            select_idx = 0
            if visible and tracks:
                sid_text = str(current_sid or "").strip()
                for idx, track in enumerate(tracks, start=1):
                    track_id = track.get("id")
                    if sid_text and sid_text == str(track_id):
                        select_idx = idx
                        break
                    if current_sid in (None, "", "auto") and bool(track.get("selected", False)):
                        select_idx = idx
                        break
                if select_idx == 0 and tracks:
                    select_idx = 1
            fs.subs.blockSignals(True)
            fs.subs.setCurrentIndex(select_idx)
            fs.subs.setEnabled(bool(tracks))
            fs.subs.blockSignals(False)
        except Exception:
            pass

    def _player_schedule_track_refresh(self, *, attempts: int = 4, immediate: bool = False) -> None:
        capped_attempts = max(0, min(2, int(attempts)))
        self._player_subtitle_refresh_attempts = max(
            int(getattr(self, "_player_subtitle_refresh_attempts", 0) or 0),
            capped_attempts,
        )
        if self._player_subtitle_refresh_timer is None:
            return
        try:
            if (not immediate) and self._player_subtitle_refresh_timer.isActive():
                return
            self._player_subtitle_refresh_timer.start(0 if immediate else int(self._player_subtitle_refresh_timer.interval()))
        except Exception:
            pass

    def _player_schedule_subtitle_refresh(self, *, attempts: int = 4, immediate: bool = False) -> None:
        self._player_schedule_track_refresh(attempts=attempts, immediate=immediate)

    def _player_clear_audio_state(self, *, loading: bool = False) -> None:
        self._player_audio_tracks = []
        self._player_rebuild_audio_combo([], current_aid=None, loading=loading)

    def _player_clear_media_track_state(self, *, loading: bool = False) -> None:
        self._player_audio_default_pending = bool(loading)
        self._player_audio_default_path_key = ""
        self._player_subtitle_refresh_attempts = 0
        self._player_clear_audio_state(loading=loading)
        self._player_clear_subtitle_state(loading=loading)

    def _player_clear_subtitle_state(self, *, loading: bool = False) -> None:
        self._player_subtitle_tracks = []
        self._player_subtitle_refresh_attempts = 0
        self._player_rebuild_subtitle_combo([], current_sid=None, visible=False, loading=loading)
        self._player_update_subtitle_menu_actions()

    def _player_apply_default_audio_track_if_needed(
        self,
        tracks: List[Dict[str, Any]],
        current_aid: Optional[object],
    ) -> Optional[object]:
        if self._mpv is None or not bool(self._player_audio_default_pending):
            return current_aid
        if not tracks:
            return current_aid

        path_key = self._player_active_backend_path_key()
        if not path_key:
            return current_aid

        preferred = self._player_pick_default_audio_track(tracks)
        self._player_audio_default_pending = False
        self._player_audio_default_path_key = path_key
        if preferred is None:
            return current_aid

        track_id = preferred.get("id")
        if self._player_track_id_text(current_aid) == self._player_track_id_text(track_id):
            return track_id

        try:
            self._mpv.set_audio_track(track_id)
        except Exception as e:
            dprint("[PLAYER][AUDIO][WARN] selecting preferred English audio failed:", e)
            return current_aid

        self._player_schedule_track_refresh(attempts=1, immediate=False)
        return track_id

    def _player_refresh_track_state(self) -> None:
        with self._perf_track("track_refresh"):
            mpv_backend = getattr(self, "_mpv", None)
            if mpv_backend is None:
                self._player_clear_audio_state(loading=False)
                self._player_clear_subtitle_state(loading=False)
                return

            try:
                all_tracks = [dict(track) for track in (mpv_backend.get_track_list() or [])]
            except Exception:
                all_tracks = []

            subtitle_tracks: List[Dict[str, Any]] = []
            audio_tracks: List[Dict[str, Any]] = []
            for track in all_tracks:
                kind = str(track.get("type") or "").strip().casefold()
                if kind == "sub":
                    subtitle_tracks.append(track)
                elif kind == "audio":
                    audio_tracks.append(track)

            try:
                visible = bool(mpv_backend.get_subtitle_visible())
            except Exception:
                visible = False
            try:
                current_sid = mpv_backend.get_current_subtitle_id()
            except Exception:
                current_sid = None
            try:
                current_aid = mpv_backend.get_current_audio_id()
            except Exception:
                current_aid = None

            loading = False
            if not subtitle_tracks and not audio_tracks and int(getattr(self, "_player_subtitle_refresh_attempts", 0) or 0) > 0:
                self._player_subtitle_refresh_attempts = max(0, int(self._player_subtitle_refresh_attempts) - 1)
                loading = self._player_subtitle_refresh_attempts > 0
                if loading and self._player_subtitle_refresh_timer is not None:
                    self._player_subtitle_refresh_timer.start(900)
            else:
                self._player_subtitle_refresh_attempts = 0

            if audio_tracks:
                current_aid = self._player_apply_default_audio_track_if_needed(audio_tracks, current_aid)

            self._player_audio_tracks = list(audio_tracks)
            self._player_subtitle_tracks = list(subtitle_tracks)
            self._player_rebuild_audio_combo(audio_tracks, current_aid=current_aid, loading=loading and not audio_tracks)
            self._player_rebuild_subtitle_combo(subtitle_tracks, current_sid=current_sid, visible=visible, loading=loading and not subtitle_tracks)
            self._player_update_subtitle_menu_actions()

    def _player_refresh_subtitle_tracks(self) -> None:
        self._player_refresh_track_state()

    def _player_on_audio_combo_changed(self, index: int) -> None:
        if self._player_audio_combo_sync or self._mpv is None or self.playerAudioBox is None:
            return

        data = self.playerAudioBox.itemData(int(index), Qt.UserRole)
        if data in ("__loading__", "__none__", None):
            return

        try:
            self._mpv.set_audio_track(data)
            self._player_audio_default_pending = False
            self._player_audio_default_path_key = self._player_active_backend_path_key()
        except Exception as e:
            dprint("[PLAYER][AUDIO][WARN] selecting audio track failed:", e)
        self._player_schedule_track_refresh(attempts=1, immediate=True)

    def _player_on_subtitle_combo_changed(self, index: int) -> None:
        if self._player_subtitle_combo_sync or self._mpv is None or self.playerSubtitlesBox is None:
            return

        data = self.playerSubtitlesBox.itemData(int(index), Qt.UserRole)
        if data in ("__loading__", "__none__", None):
            return

        try:
            if data == "off":
                self._mpv.set_subtitle_visible(False)
            else:
                self._mpv.set_subtitle_track(data, visible=True)
        except Exception as e:
            dprint("[PLAYER][SUB][WARN] selecting subtitle track failed:", e)
        self._player_schedule_track_refresh(attempts=2, immediate=True)

    def _player_on_fullscreen_audio_pick(self, data: object) -> None:
        if self._mpv is None or data in ("__loading__", "__none__", None):
            return
        try:
            self._mpv.set_audio_track(data)
            self._player_audio_default_pending = False
            self._player_audio_default_path_key = self._player_active_backend_path_key()
        except Exception as e:
            dprint("[PLAYER][AUDIO][WARN] selecting fullscreen audio track failed:", e)
        self._player_schedule_track_refresh(attempts=1, immediate=True)

    def _player_on_fullscreen_subtitle_pick(self, data: object) -> None:
        if self._mpv is None or data in ("__loading__", "__none__", None):
            return
        try:
            if data == "off":
                self._mpv.set_subtitle_visible(False)
            else:
                self._mpv.set_subtitle_track(data, visible=True)
        except Exception as e:
            dprint("[PLAYER][SUB][WARN] selecting fullscreen subtitle track failed:", e)
        self._player_schedule_track_refresh(attempts=2, immediate=True)

    def _player_toggle_subtitles_visible(self) -> None:
        mpv_backend = getattr(self, "_mpv", None)
        if mpv_backend is None:
            return

        try:
            visible = bool(mpv_backend.get_subtitle_visible())
        except Exception:
            visible = False

        if visible:
            mpv_backend.set_subtitle_visible(False)
            self._player_schedule_subtitle_refresh(attempts=1, immediate=True)
            return

        track_id: Optional[object] = None
        if self.playerSubtitlesBox is not None:
            current_data = self.playerSubtitlesBox.currentData(Qt.UserRole)
            if current_data not in (None, "off", "__loading__", "__none__"):
                track_id = current_data
        if track_id is None and self._player_subtitle_tracks:
            track_id = self._player_subtitle_tracks[0].get("id")
        if track_id is None:
            track_id = "auto"
        mpv_backend.set_subtitle_track(track_id, visible=True)
        self._player_schedule_subtitle_refresh(attempts=2, immediate=True)

    def _player_update_subtitle_menu_actions(self) -> None:
        actions = getattr(self, "_subtitle_menu_actions", {}) or {}
        toggle_action = actions.get("toggle")
        settings_action = actions.get("settings")

        tracks = list(getattr(self, "_player_subtitle_tracks", []) or [])
        mpv_backend = getattr(self, "_mpv", None)
        visible = False
        if mpv_backend is not None:
            try:
                visible = bool(mpv_backend.get_subtitle_visible())
            except Exception:
                visible = False

        if toggle_action is not None:
            toggle_action.setEnabled(mpv_backend is not None and bool(tracks))
            toggle_action.setText("Turn Subtitles Off" if visible else "Turn Subtitles On")
        if settings_action is not None:
            settings_action.setEnabled(True)

    def _player_open_subtitle_settings_dialog(self) -> None:
        defaults = self._player_subtitle_settings_default()

        def handle_apply(settings: Dict[str, Any]) -> None:
            merged = dict(defaults)
            merged.update(dict(settings or {}))
            self._home_state["subtitle_settings"] = merged
            self._subtitle_settings = self._player_subtitle_settings_from_state()
            self._player_save_subtitle_settings()
            self._player_apply_subtitle_settings_to_backend(respect_enabled_on_load=False)
            self._player_update_subtitle_menu_actions()

        dialog = SubtitleSettingsDialog(
            dict(self._subtitle_settings or {}),
            defaults=defaults,
            parent=self.win,
            on_apply=handle_apply,
            theme=dict(self._personalization.get("colors", {}) or {}),
        )
        dialog.exec()

    def _player_sync_current_media_path_from_backend(self) -> None:
        with self._perf_track("player_sync_path"):
            mpv_backend = getattr(self, "_mpv", None)
            if mpv_backend is None:
                return
            path_raw = str(mpv_backend.get_current_path() or "").strip()
            if not path_raw:
                return

            p = Path(path_raw)
            path_key = self._home_canon_path_str(p)
            if not path_key or path_key == str(getattr(self, "_player_last_backend_path_key", "") or ""):
                return

            previous_key = self._home_canon_path_str(self._current_path) if self._current_path is not None else ""
            self._player_last_backend_path_key = path_key
            self._current_path = p
            self._player_cached_chapters = tuple()
            self._finish_mark_path_key = ""
            self._player_reset_tick_cadence()
            if path_key != previous_key and not self._shuffle_active:
                self._home_state_record_play_start(p)
            if path_key != previous_key:
                self._player_clear_media_track_state(loading=True)
            self._player_apply_subtitle_settings_to_backend(respect_enabled_on_load=True)
            self._player_schedule_subtitle_refresh(attempts=5, immediate=True)
            self._player_session_active = True
            self._player_update_now_playing_title_label()
            self._player_update_playlist_drawer_contents()
            self._player_apply_low_cpu_mode()
            self._player_refresh_ui_timer_state()

    # ============================================================
    # PLAYER MODULE: actions + seek logic + public play_path
    # ============================================================

    def _player_on_play_pause_clicked(self) -> None:
        if self._mpv is None:
            return
        self._mpv.toggle_pause()
        self._player_session_active = True
        self._player_sync_play_pause_btn()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_apply_low_cpu_mode()
        self._player_refresh_ui_timer_state()

    def _player_on_stop_clicked(self) -> None:
        if self._mpv is None:
            return
        self._player_flush_progress_snapshot()
        self._mpv.stop()
        self._player_last_backend_path_key = ""
        self._player_clear_media_track_state(loading=False)
        self._shuffle_deactivate(clear_queue=True)
        self._player_reset_segment_skip_state("")
        self._player_session_active = False
        self._current_path = None
        self._active_media_key = ""
        self._active_media_path_key = ""
        self._player_last_progress_snapshot_ms = 0
        self._player_last_progress_snapshot_dur_ms = 0
        self._player_last_time_label_text = ""
        self._player_last_now_playing_text = ""
        self._player_reset_tick_cadence()
        self._player_reset_progress_persist_window()
        self._player_sync_play_pause_btn()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_update_command_center(0, 0)
        self._player_sync_floating_mini_player()
        self._player_apply_low_cpu_mode(force=True)
        self._player_refresh_ui_timer_state()

    def _player_seek_relative_ms(self, delta_ms: int) -> None:
        if self._mpv is None:
            return
        cur_ms = self._player_to_ms(self._mpv.get_time_raw())
        dur_ms = self._player_to_ms(self._mpv.get_duration_raw())
        target_ms = max(0, cur_ms + int(delta_ms))
        if dur_ms > 0:
            target_ms = min(dur_ms, target_ms)
        self._player_engage_seek_lock(target_ms)
        self._player_seek_backend_ms(target_ms)
        self._player_last_progress_snapshot_ms = int(target_ms)
        if dur_ms > 0:
            self._player_last_progress_snapshot_dur_ms = int(dur_ms)
        self._player_tick_ui()

    def _player_ordered_episode_paths_for_current_show(self) -> List[Path]:
        sg = self._player_current_show_group()
        if sg is None:
            return []
        refs = self._home_explicit_episode_refs_for_group(sg)
        if not refs:
            show_dirs = [Path(str(p)) for p in (getattr(sg, "all_dirs", ()) or []) if str(p).strip()]
            if not show_dirs:
                primary = Path(str(getattr(sg, "primary_dir", "") or ""))
                if str(primary):
                    show_dirs = [primary]
            refs = self._home_list_episode_files_multi(show_dirs, show_dirs)
        out: List[Path] = []
        seen: set[str] = set()
        for ref in refs:
            ep = Path(str(getattr(ref, "episode_path", "") or ""))
            key = self._home_canon_path_str(ep)
            if not key or key in seen or not ep.exists():
                continue
            seen.add(key)
            out.append(ep)
        out.sort(key=self._home_episode_sort_key)
        return out

    def _player_play_relative_episode(self, direction: int) -> bool:
        current = getattr(self, "_current_path", None)
        if current is None:
            return False
        cur_key = self._home_canon_path_str(Path(str(current)))
        episodes = self._player_ordered_episode_paths_for_current_show()
        if not episodes:
            return False
        keys = [self._home_canon_path_str(path) for path in episodes]
        try:
            index = keys.index(cur_key)
        except ValueError:
            return False
        target_index = index + (1 if int(direction) > 0 else -1)
        if target_index < 0 or target_index >= len(episodes):
            return False
        self.play_path(str(episodes[target_index]))
        return True

    def _player_current_backend_matches_current_path(self) -> bool:
        if self._mpv is None or self._current_path is None:
            return False
        try:
            backend_path = self._mpv.get_current_path()
        except Exception:
            backend_path = ""
        if not str(backend_path or "").strip():
            return False
        return self._home_canon_path_str(Path(str(backend_path))) == self._home_canon_path_str(Path(str(self._current_path)))

    def _player_on_prev_clicked(self) -> None:
        if self._mpv is None:
            return
        try:
            self._player_last_backend_path_key = ""
            self._player_clear_media_track_state(loading=True)
            self._mpv.playlist_prev()
            self._player_schedule_subtitle_refresh(attempts=6, immediate=True)
            QTimer.singleShot(180, lambda: self._player_play_relative_episode(-1) if self._player_current_backend_matches_current_path() else None)
        except Exception:
            if not self._player_play_relative_episode(-1):
                self._player_seek_relative_ms(-int(self.T.player.seek_jump_back_ms))

    def _player_on_next_clicked(self) -> None:
        if self._mpv is None:
            return
        try:
            self._player_last_backend_path_key = ""
            self._player_clear_media_track_state(loading=True)
            self._mpv.playlist_next()
            self._player_schedule_subtitle_refresh(attempts=6, immediate=True)
            QTimer.singleShot(180, lambda: self._player_play_relative_episode(1) if self._player_current_backend_matches_current_path() else None)
        except Exception:
            if not self._player_play_relative_episode(1):
                self._player_seek_relative_ms(int(self.T.player.seek_jump_fwd_ms))

    def _player_on_mute_clicked(self) -> None:
        if self._mpv is None:
            return
        self._muted = self._mpv.toggle_mute()
        try:
            if self.playerMuteBtn is not None:
                self.playerMuteBtn.setText("Muted" if self._muted else "Mute")
        except Exception:
            pass

    def _player_on_close_clicked(self) -> None:
        self._player_flush_progress_snapshot()
        try:
            if self._mpv is not None:
                self._mpv.stop()
        except Exception:
            pass
        self._player_last_backend_path_key = ""
        self._player_clear_media_track_state(loading=False)
        self._shuffle_deactivate(clear_queue=True)
        self._player_reset_segment_skip_state("")
        self._player_session_active = False
        self._current_path = None
        self._active_media_key = ""
        self._active_media_path_key = ""
        self._player_last_progress_snapshot_ms = 0
        self._player_last_progress_snapshot_dur_ms = 0
        self._player_last_time_label_text = ""
        self._player_last_now_playing_text = ""
        self._player_reset_tick_cadence()
        self._player_reset_progress_persist_window()
        try:
            self.pages.setCurrentWidget(self.homePage)
        except Exception:
            pass
        self._player_update_command_center(0, 0)
        self._player_sync_floating_mini_player()
        self._player_apply_low_cpu_mode(force=True)
        self._player_refresh_ui_timer_state()

    def _player_on_fullscreen_clicked(self) -> None:
        if getattr(self, "_fs_window", None):
            return

        if self._mpv is None:
            return

        from omega.player.fullscreen_window import FullscreenVideoWindow
        from PySide6.QtCore import QTimer

        self._fs_window = FullscreenVideoWindow()
        self._fs_window.requestExitFullscreen.connect(self._exit_fullscreen)
        self._fs_window.requestTogglePlayPause.connect(self._player_on_play_pause_clicked)
        self._fs_window.requestSeekRelative.connect(self._player_seek_relative_ms)
        self._fs_window.requestStop.connect(self._player_on_stop_clicked)
        self._fs_window.requestPrev.connect(self._player_on_prev_clicked)
        self._fs_window.requestNext.connect(self._player_on_next_clicked)
        self._fs_window.requestSeekToPos.connect(self._handle_ratio_seek)
        self._fs_window.requestVolume.connect(self._player_on_volume_changed)
        self._fs_window.requestSubtitlePick.connect(self._player_on_fullscreen_subtitle_pick)
        self._fs_window.requestAudioPick.connect(self._player_on_fullscreen_audio_pick)
        self._fs_window.controlsVisibilityChanged.connect(self._player_on_fullscreen_controls_visibility_changed)

        self._fs_window.showFullScreen()

        QTimer.singleShot(
            0,
            lambda: self._mpv.set_wid(int(self._fs_window.videoSurface.winId()))
        )

        try:
            if self.playerVolumeSlider is not None:
                self._fs_window.vol.blockSignals(True)
                self._fs_window.vol.setValue(int(self.playerVolumeSlider.value()))
                self._fs_window.vol.blockSignals(False)
        except Exception:
            pass

        self._player_apply_fullscreen_controls_chrome()
        self._player_sync_play_pause_btn()
        self._player_refresh_track_state()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_sync_floating_mini_player()
        self._player_apply_low_cpu_mode(force=True)
        self._player_tick_ui()
        self._player_refresh_ui_timer_state()
        self._position_top_nav_bar()

    def _player_on_volume_changed(self, v: int) -> None:
        if self._mpv is None:
            return

        vol = int(max(0, min(100, int(v))))
        self._mpv.set_volume(vol)

        try:
            if self.playerVolumeSlider is not None and int(self.playerVolumeSlider.value()) != vol:
                self.playerVolumeSlider.blockSignals(True)
                self.playerVolumeSlider.setValue(vol)
                self.playerVolumeSlider.blockSignals(False)
        except Exception:
            pass

        fs = getattr(self, "_fs_window", None)
        if fs is not None:
            try:
                if int(fs.vol.value()) != vol:
                    fs.vol.blockSignals(True)
                    fs.vol.setValue(vol)
                    fs.vol.blockSignals(False)
            except Exception:
                pass

    def _player_maybe_detect_unit(self, dur_raw) -> None:
        if self._mpv_time_unit is not None:
            return
        try:
            d = float(dur_raw)
        except Exception:
            return
        if d <= 0:
            return
        self._mpv_time_unit = "ms" if d >= 100_000 else "seconds"
        dprint(f"[PLAYER] Detected MPV time unit: {self._mpv_time_unit} (dur_raw={dur_raw})")

    def _player_to_ms(self, value_raw) -> int:
        if value_raw is None:
            return 0
        try:
            v = float(value_raw)
        except Exception:
            return 0
        if v <= 0:
            return 0
        unit = self._mpv_time_unit
        if unit is None:
            unit = "ms" if v >= 100_000 else "seconds"
        return int(v * 1000.0) if unit == "seconds" else int(v)

    def _player_seek_backend_ms(self, target_ms: int) -> None:
        if self._mpv is None:
            return
        target_ms = max(0, int(target_ms))
        self._mpv.seek_seconds(float(target_ms) / 1000.0)

    def _player_request_seek_ratio(self, ratio: float) -> None:
        if self._mpv is None:
            return
        ratio = max(0.0, min(1.0, float(ratio)))

        dur_raw = self._mpv.get_duration_raw()
        self._player_maybe_detect_unit(dur_raw)
        dur_ms = self._player_to_ms(dur_raw)

        if dur_ms <= 0:
            self._pending_seek_ratio = ratio
            dprint(f"[PLAYER] Seek requested before duration ready; pending ratio={ratio:.3f}")
            return

        target_ms = max(0, min(dur_ms, int(ratio * dur_ms)))
        self._player_engage_seek_lock(target_ms)
        self._player_seek_backend_ms(target_ms)
        self._player_last_progress_snapshot_ms = int(target_ms)
        self._player_last_progress_snapshot_dur_ms = int(dur_ms)
        self._player_tick_ui()

    def _player_ratio_from_slider_value(self, value: int, slider: Optional[QAbstractSlider] = None) -> float:
        target = slider if slider is not None else getattr(self, "playerSeekSlider", None)
        minimum = int(target.minimum()) if target is not None else 0
        maximum = int(target.maximum()) if target is not None else int(self.T.player.seek_slider_max)
        span = float(max(1, maximum - minimum))
        return max(0.0, min(1.0, (float(value) - float(minimum)) / span))

    def _player_engage_seek_lock(self, target_ms: int) -> None:
        self._seek_lock_active = True
        self._seek_lock_target_ms = int(max(0, target_ms))
        try:
            self._seek_lock_timer.start(int(self.T.player.seek_lock_release_ms))
        except Exception:
            pass

    def _player_release_seek_lock(self) -> None:
        self._seek_lock_active = False
        self._seek_lock_target_ms = 0

    def _player_on_seek_pressed(self) -> None:
        self._slider_dragging = True
        self._player_refresh_ui_timer_state()
        self._player_tick_ui()

    def _player_on_seek_action_triggered(self, action: int) -> None:
        self._slider_dragging = True
        self._player_refresh_ui_timer_state()
        QTimer.singleShot(0, self._player_commit_seek_action_if_needed)

    def _player_commit_seek_action_if_needed(self) -> None:
        if self.playerSeekSlider is None:
            self._slider_dragging = False
            return
        try:
            if bool(self.playerSeekSlider.isSliderDown()):
                return
        except Exception:
            pass
        self._player_on_seek_released()

    def _player_on_seek_jump_requested(self, value: int) -> None:
        self._slider_dragging = False
        self._player_request_seek_ratio(self._player_ratio_from_slider_value(int(value), self.playerSeekSlider))

    def _player_on_seek_released(self) -> None:
        if self._mpv is None or self.playerSeekSlider is None:
            self._slider_dragging = False
            return

        try:
            val = int(self.playerSeekSlider.value())
        except Exception:
            val = 0

        self._player_request_seek_ratio(self._player_ratio_from_slider_value(val, self.playerSeekSlider))
        self._slider_dragging = False

    def _player_tick_ui(self) -> None:
        if self._mpv is None:
            return
        with self._perf_track("player_tick_ui"):
            player_ui_visible = self._player_is_ui_visible()
            now = time.perf_counter()
            if not self._player_backend_observes("path") and self._player_tick_due("_player_last_path_sync_at", 12000, now):
                self._player_sync_current_media_path_from_backend()
            cur_ms, dur_ms, sampled_progress = self._player_sample_backend_progress(
                now,
                player_ui_visible=player_ui_visible,
            )

            if (
                self._shuffle_active
                and not self._player_backend_observes("playlist-pos")
                and not self._player_backend_observes("path")
                and self._player_tick_due("_player_last_shuffle_refresh_at", int(self.T.player.ui_shuffle_refresh_interval_ms), now)
            ):
                with self._perf_track("player_shuffle_sync"):
                    self._shuffle_sync_from_playback()
            if sampled_progress and self._player_tick_due("_player_last_segment_refresh_at", int(self.T.player.ui_segment_refresh_interval_ms), now):
                with self._perf_track("player_segment_refresh"):
                    self._player_refresh_segment_skip_state(cur_ms, dur_ms)

            if dur_ms > 0 and self._player_tick_due("_player_last_progress_refresh_at", int(self.T.player.ui_progress_refresh_interval_ms), now):
                try:
                    with self._perf_track("player_progress_update"):
                        self._home_state_update_progress(cur_ms, dur_ms)
                except Exception:
                    pass

            if dur_ms > 0 and self._pending_seek_ratio is not None:
                ratio = float(self._pending_seek_ratio)
                self._pending_seek_ratio = None
                target_ms = max(0, min(dur_ms, int(ratio * dur_ms)))
                dprint(f"[PLAYER] Applying pending seek: {target_ms}ms (ratio={ratio:.3f})")
                self._player_engage_seek_lock(target_ms)
                self._player_seek_backend_ms(target_ms)

            if sampled_progress and player_ui_visible and self.playerTimeLabel is not None:
                time_text = f"{fmt_ms(cur_ms)} / {fmt_ms(dur_ms)}"
                if time_text != str(getattr(self, "_player_last_time_label_text", "") or ""):
                    self.playerTimeLabel.setText(time_text)
                    self._player_last_time_label_text = time_text

            fs = getattr(self, "_fs_window", None)
            if (
                fs is not None
                and bool(getattr(fs, "_controlsVisible", False))
                and sampled_progress
                and self._player_tick_due("_player_last_fullscreen_refresh_at", int(self.T.player.ui_fullscreen_refresh_interval_ms), now)
            ):
                try:
                    with self._perf_track("player_fullscreen_overlay"):
                        fs.set_time(cur_ms, dur_ms)
                except Exception:
                    pass

            mini = getattr(self, "_player_floating_mini", None)
            if mini is not None and mini.isVisible() and sampled_progress:
                try:
                    paused = bool(self._mpv.is_paused()) if self._mpv is not None else False
                except Exception:
                    paused = False
                try:
                    mini.set_playback_state(paused=paused, muted=bool(getattr(self, "_muted", False)))
                    mini.set_time(cur_ms, dur_ms)
                except Exception:
                    pass

            self._player_update_command_center(cur_ms, dur_ms)
            if sampled_progress and self.playerSeekSlider is not None:
                if self._slider_dragging:
                    return

                if self._seek_lock_active and dur_ms > 0:
                    target = int(self._seek_lock_target_ms)
                    if abs(cur_ms - target) <= int(self.T.player.seek_lock_release_tolerance_ms):
                        self._player_release_seek_lock()
                    else:
                        ratio = (target / dur_ms) if dur_ms > 0 else 0.0
                        pos = int(max(0.0, min(1.0, ratio)) * int(self.T.player.seek_slider_max))
                        if int(self.playerSeekSlider.value()) != pos:
                            self.playerSeekSlider.setValue(pos)
                        return

                pos = int((cur_ms / dur_ms) * int(self.T.player.seek_slider_max)) if dur_ms > 0 else 0
                if int(self.playerSeekSlider.value()) != pos:
                    self.playerSeekSlider.setValue(pos)

            self._player_refresh_ui_timer_state()

    def _player_sync_play_pause_btn(self) -> None:
        if self._mpv is None:
            return

        txt = "Play" if self._mpv.is_paused() else "Pause"

        try:
            if self.playerPlayPauseBtn is not None:
                if self.playerPlayPauseBtn.text() != txt:
                    self.playerPlayPauseBtn.setText(txt)
        except Exception:
            pass

        fs = getattr(self, "_fs_window", None)
        if fs is not None:
            try:
                if fs.playPauseBtn.text() != txt:
                    fs.playPauseBtn.setText(txt)
            except Exception:
                pass

    def play_path(self, path: str) -> None:
        self._shuffle_deactivate(clear_queue=True)
        p = Path(path)
        self._current_path = p
        self._finish_mark_path_key = ""
        self._player_session_active = True
        self._player_last_progress_snapshot_ms = 0
        self._player_last_progress_snapshot_dur_ms = 0
        self._player_last_time_label_text = ""
        self._player_reset_tick_cadence()
        self._home_state_record_play_start(p)
        dprint("[PLAY] Requested:", p)
        self._player_set_playlist_drawer_open(False)
        self._player_reset_segment_skip_state(self._home_canon_path_str(p))
        self._player_update_now_playing_title_label()
        self._player_update_playlist_drawer_contents()
        self._player_update_command_center(0, 0)

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()
        try:
            self.pages.setCurrentWidget(self.playerPage)
        except Exception:
            pass

        if self._mpv is not None and self.videoHost is not None:
            try:
                self._mpv.set_wid(int(self.videoHost.winId()))
            except Exception:
                pass

        if self._mpv is None:
            dprint("[PLAY][WARN] MPV backend not available.")
            return

        self._player_release_seek_lock()
        self._pending_seek_ratio = None
        self._mpv_time_unit = None
        self._player_cached_chapters = tuple()
        self._player_clear_media_track_state(loading=True)

        try:
            self._mpv.load(str(p))
            self._mpv.play()
        except Exception as e:
            dprint("[PLAY][ERROR] Failed to load:", e)

        self._player_last_backend_path_key = self._home_canon_path_str(p)
        self._player_apply_subtitle_settings_to_backend(respect_enabled_on_load=True)
        self._player_schedule_subtitle_refresh(attempts=6, immediate=True)
        self._player_sync_play_pause_btn()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_apply_low_cpu_mode()
        self._player_refresh_ui_timer_state()
        self._player_tick_ui()

    def _handle_relative_seek(self, delta_ms: int) -> None:
        self._player_seek_relative_ms(int(delta_ms))

    def _handle_ratio_seek(self, ratio: int) -> None:
        self._player_request_seek_ratio(max(0.0, min(1.0, float(ratio) / 1000.0)))

    def _exit_fullscreen(self) -> None:
        if not getattr(self, "_fs_window", None):
            return

        if self.videoHost and self._mpv:
            self._mpv.set_wid(int(self.videoHost.winId()))

        self._fs_window.close()
        self._fs_window = None

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()
        self._player_sync_play_pause_btn()
        self._player_sync_now_playing_title_visibility()
        self._player_sync_playlist_drawer_visibility()
        self._player_sync_floating_mini_player()
        self._player_apply_low_cpu_mode(force=True)
        self._position_top_nav_bar()

    def _player_on_fullscreen_controls_visibility_changed(self, visible: bool) -> None:
        self._player_refresh_ui_timer_state()
        if bool(visible):
            self._player_tick_ui()

    def _force_player_edge_to_edge(self) -> None:
        from PySide6.QtWidgets import QSizePolicy

        widget = self.playerPage
        while widget is not None:
            lay = widget.layout()
            if lay:
                lay.setContentsMargins(0, 0, 0, 0)
                lay.setSpacing(0)
            widget = widget.parentWidget()

        if hasattr(self, "pages") and self.pages and self.pages.layout():
            self.pages.layout().setContentsMargins(0, 0, 0, 0)
            self.pages.layout().setSpacing(0)

        if self.videoFrame:
            self.videoFrame.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
        if self.videoHost:
            self.videoHost.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)
        if self.playerControlsBar:
            self.playerControlsBar.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()


