    def _home_install_window_pin(self) -> None:
        """
        Install the main-window resize listener used by Home.

        The listener no longer forces raw geometry. It now performs a
        layout-sanity pass so the existing scroll host stays expansive
        and the normal Qt layout tree remains in control.
        """
        try:
            self.win.installEventFilter(self)
            dprint("[HOME][PIN] Installed window resize listener on QMainWindow.")
        except Exception as e:
            dprint(f"[HOME][PIN][WARN] Could not install window event filter: {e}")

        # Fire once right now so the geometry is correct on first show.
        QTimer.singleShot(0, self._home_pin_scroll_area)

