    def _home_update_scroll_hint(self) -> None:
        """Reposition + show/hide the bottom chevron based on viewport size and scroll position."""
        hint: QLabel | None = getattr(self, "_homeScrollHint", None)
        if hint is not None:
            try:
                hint.hide()
            except Exception:
                pass
        if hint is None:
            return
        if self.homeScrollArea is None:
            return

        vp = self.homeScrollArea.viewport()
        rect = vp.rect()

        vbar = self.homeScrollArea.verticalScrollBar()
        maxv = vbar.maximum()
        val = vbar.value()

        # If there's nothing to scroll, hide.
        if maxv <= 0:
            hint.hide()
            return

        # Show if we're not basically at the bottom yet.
        threshold_px = 12
        should_show = val < (maxv - threshold_px)

        if not should_show:
            hint.hide()
            return

        # Bottom-center placement inside the viewport.
        margin_bottom = 18
        hint.adjustSize()
        w = hint.width()
        h = hint.height()
        x = int(rect.center().x() - (w / 2))
        y = int(rect.bottom() - margin_bottom - h)

        hint.move(x, y)
        hint.show()
        hint.raise_()

    def _home_on_scroll_value_changed(self, _value: int = 0) -> None:
        try:
            self._home_update_scroll_hint()
        except Exception:
            pass
        timer = getattr(self, "_home_scroll_prefetch_timer", None)
        if timer is None:
            self._home_schedule_deferred_rows_if_needed()
            return
        try:
            timer.start()
        except Exception:
            self._home_schedule_deferred_rows_if_needed()

    def _home_should_render_more_rows(self, *, force: bool = False) -> bool:
        if not self._home_row_render_queue or self._home_rows_layout is None:
            return False
        if not self._app_window_is_interactively_visible():
            return False
        if force:
            return True
        try:
            if self.pages is not None and self.pages.currentWidget() is not self.homePage:
                return False
        except Exception:
            pass
        if self.homeScrollArea is None:
            return True
        try:
            vbar = self.homeScrollArea.verticalScrollBar()
            maxv = int(vbar.maximum())
            curv = int(vbar.value())
            if maxv <= 0:
                return True
            vp_h = int(self.homeScrollArea.viewport().height())
        except Exception:
            return True
        margin = max(
            int(max(0.0, float(self.T.home.home_row_render_prefetch_margin_viewports)) * max(0, vp_h)),
            int(self.T.home.home_row_render_prefetch_min_px),
        )
        return (maxv - curv) <= margin

    def _home_schedule_deferred_rows_if_needed(self, *, force: bool = False) -> None:
        timer = getattr(self, "_home_deferred_row_timer", None)
        if timer is None:
            return
        if self._home_should_render_more_rows(force=force):
            try:
                if not timer.isActive():
                    timer.start()
            except Exception:
                pass
        else:
            try:
                timer.stop()
            except Exception:
                pass

    def _home_refresh_scroll_geometry(self) -> None:
        for layout in (self._home_rows_layout, self._home_layout):
            if layout is None:
                continue
            try:
                layout.invalidate()
                layout.activate()
            except Exception:
                pass

        for widget in (
            getattr(self, "_home_rows_host", None),
            getattr(self, "homeContent", None),
            getattr(self, "homeScrollContents", None),
        ):
            if widget is None:
                continue
            try:
                widget.adjustSize()
            except Exception:
                pass
            try:
                widget.updateGeometry()
            except Exception:
                pass

        if self.homeScrollArea is None:
            return

        try:
            scroll_widget = self.homeScrollArea.widget()
        except Exception:
            scroll_widget = None

        viewport = None
        viewport_h = 0
        try:
            viewport = self.homeScrollArea.viewport()
            if viewport is not None:
                viewport_h = max(0, int(viewport.height()))
        except Exception:
            viewport = None
            viewport_h = 0

        content_hints: List[int] = []

        def _collect_height(candidate: object) -> None:
            try:
                value = int(candidate)
            except Exception:
                return
            if value > 0:
                content_hints.append(value)

        for layout in (
            self._home_layout,
            self._home_rows_layout,
            scroll_widget.layout() if scroll_widget is not None else None,
        ):
            if layout is None:
                continue
            for getter_name in ("totalMinimumSize", "minimumSize", "sizeHint"):
                getter = getattr(layout, getter_name, None)
                if getter is None:
                    continue
                try:
                    size = getter()
                    _collect_height(size.height())
                except Exception:
                    pass

        for widget in (
            getattr(self, "_home_rows_host", None),
            getattr(self, "homeContent", None),
            getattr(self, "homeScrollContents", None),
            scroll_widget,
        ):
            if widget is None:
                continue
            for getter_name in ("minimumSizeHint", "sizeHint"):
                getter = getattr(widget, getter_name, None)
                if getter is None:
                    continue
                try:
                    size = getter()
                    _collect_height(size.height())
                except Exception:
                    pass

        preferred_h = max([viewport_h, *content_hints]) if content_hints or viewport_h > 0 else 0
        if preferred_h > 0:
            seen_root_widgets = set()
            for widget in (
                scroll_widget,
                getattr(self, "homeScrollContents", None),
                getattr(self, "homeContent", None),
            ):
                if widget is None:
                    continue
                key = id(widget)
                if key in seen_root_widgets:
                    continue
                seen_root_widgets.add(key)
                try:
                    widget.setMinimumHeight(preferred_h)
                except Exception:
                    pass
                try:
                    widget.setMaximumHeight(16777215)
                except Exception:
                    pass

        if scroll_widget is not None:
            try:
                scroll_widget.adjustSize()
            except Exception:
                pass
            try:
                scroll_widget.updateGeometry()
            except Exception:
                pass

        if viewport is not None:
            try:
                viewport.updateGeometry()
                viewport.update()
            except Exception:
                pass

        try:
            self.homeScrollArea.updateGeometry()
            self.homeScrollArea.update()
        except Exception:
            pass

        try:
            vbar = self.homeScrollArea.verticalScrollBar()
            if vbar is not None and viewport is not None:
                vbar.setPageStep(max(1, int(viewport.height())))
        except Exception:
            pass

    def _home_stabilize_scroll_state(self, *, phase: str = "runtime", schedule_deferred: bool = True) -> None:
        if self.homeScrollArea is None:
            return

        try:
            dprint(f"[HOME][SCROLL][STABILIZE] phase={phase}")
        except Exception:
            pass

        try:
            self._home_apply_scroll_policies()
        except Exception:
            pass

        try:
            self._apply_shell_page_insets()
        except Exception:
            pass

        try:
            self._home_update_center_lane_width()
        except Exception:
            pass

        self._home_refresh_scroll_geometry()

        try:
            self._home_position_show_selection_overlays()
        except Exception:
            pass

        try:
            self._home_update_scroll_hint()
        except Exception:
            pass

        if schedule_deferred:
            try:
                force = bool(self._home_is_active_page())
            except Exception:
                force = False
            try:
                self._home_schedule_deferred_rows_if_needed(force=force)
            except Exception:
                pass

    def _home_stabilize_scroll_state_deferred(self) -> None:
        self._home_stabilize_scroll_state(phase="deferred", schedule_deferred=True)

    def _home_canon_path_str(self, p: Path) -> str:
        try:
            return str(Path(str(p)).resolve()).rstrip("\\/").casefold()
        except Exception:
            return str(p).rstrip("\\/").casefold()

    def _home_show_key_from_dirs(self, show_dirs: List[Path], fallback_title: str = "") -> str:
        for p in show_dirs:
            if p is None:
                continue
            ps = str(p).strip()
            if ps:
                return self._home_canon_path_str(Path(ps))
        return (str(fallback_title) or "unknown-show").strip().casefold()

    def _home_episode_sort_key(self, episode_path: Path) -> Tuple[int, int, int, str]:
        name = Path(str(episode_path)).stem
        s_num, e_num = parse_season_episode(name)
        if s_num is not None and e_num is not None:
            return (0, int(s_num), int(e_num), name.casefold())
        if e_num is not None:
            return (1, 0, int(e_num), name.casefold())
        match = re.match(r"0*(\d{1,3})", name)
        if match:
            return (2, 0, int(match.group(1)), name.casefold())
        return (9, 0, 0, name.casefold())

    def _home_explicit_episode_refs_for_group(self, sg: Optional[ShowGroup]) -> List[EpisodeRef]:
        if sg is None:
            return []

        raw_paths = list(getattr(sg, "episode_paths", ()) or ())
        if not raw_paths:
            return []

        root = Path(str(getattr(sg, "primary_dir", "")))
        if not root.exists() or not root.is_dir():
            root = root.parent

        out: List[EpisodeRef] = []
        seen: set[str] = set()
        for raw in raw_paths:
            try:
                episode_path = Path(str(raw))
            except Exception:
                continue
            if not episode_path.exists() or not episode_path.is_file():
                continue
            if episode_path.suffix.lower() not in self.VIDEO_EXTS:
                continue
            key = self._home_canon_path_str(episode_path)
            if not key or key in seen:
                continue
            seen.add(key)
            out.append(EpisodeRef(root, episode_path))

        out.sort(key=lambda ref: self._home_episode_sort_key(Path(str(ref.episode_path))))
        return out

    def _home_install_show_selection_ui(self) -> None:
        if self.homePage is None:
            return

        if self._home_show_select_tray is None:
            tray = ShowSelectionTray(self.homePage)
            tray.hide()
            tray.removeRequested.connect(self._home_on_show_select_remove_requested)
            tray.clearRequested.connect(self._home_clear_selected_shows)
            tray.startRequested.connect(self._home_start_selected_shuffle)
            tray.smartStartRequested.connect(self._home_start_selected_smart_shuffle)
            tray.closeRequested.connect(self._home_close_show_select_tray)
            self._home_show_select_tray = tray
            self._touch_prepare_widget_tree(tray)

        if self._home_show_select_toggle_btn is None:
            btn = QPushButton("Select Shows", self.homePage)
            btn.setObjectName("homeShowSelectToggleBtn")
            btn.setCursor(Qt.PointingHandCursor)
            btn.setFocusPolicy(Qt.NoFocus)
            btn.setStyleSheet(
                "background: rgba(0,0,0,0.70); color: white;"
                "border: 1px solid rgba(255,255,255,0.24); border-radius: 10px;"
                "padding: 8px 14px;"
            )
            btn.clicked.connect(self._home_toggle_show_select_mode)
            self._home_show_select_toggle_btn = btn
            self._touch_prepare_widget_tree(btn)

        self._home_set_show_select_mode(False)
        self._home_position_show_selection_overlays()
        self._glass_apply_surface_chrome()

    def _home_show_selection_margin_px(self) -> int:
        return 12

    def _home_show_selection_tray_width(self, area_width: int) -> int:
        tray = self._home_show_select_tray
        base_width = max(1, int(area_width))
        min_w = int(tray.minimumWidth()) if tray is not None else 400
        max_w = int(tray.maximumWidth()) if tray is not None else 520
        if max_w <= 0 or max_w >= 16777215:
            max_w = max(min_w, int(base_width * 0.34))
        target = int(round(float(base_width) * 0.31))
        return int(max(min_w, min(max_w, target)))

    def _home_show_selection_reserved_width(self, area_width: int = 0) -> int:
        if not bool(getattr(self, "_home_select_mode_enabled", False)):
            return 0
        tray = self._home_show_select_tray
        if tray is None:
            return 0
        if area_width <= 0:
            try:
                if self.homeScrollArea is not None:
                    area_width = int(self.homeScrollArea.width())
            except Exception:
                area_width = 0
        if area_width <= 0 and self.homePage is not None:
            area_width = int(self.homePage.width())
        if area_width <= 0:
            return 0
        return int(self._home_show_selection_tray_width(int(area_width)) + self._home_show_selection_margin_px())

    def _home_position_show_selection_overlays(self) -> None:
        tray = self._home_show_select_tray
        btn = self._home_show_select_toggle_btn
        area = self.homeScrollArea if self.homeScrollArea is not None else self.homePage

        if area is None:
            return

        if area.parentWidget() is self.homePage:
            area_rect = area.geometry()
        else:
            area_rect = self.homePage.rect()

        margin = self._home_show_selection_margin_px()

        tray_x = area_rect.x() + max(0, int(area_rect.width()) - 360 - margin)
        if tray is not None:
            tray_w = self._home_show_selection_tray_width(int(area_rect.width()))
            tray_h = int(max(300, area_rect.height() - (margin * 2)))
            tray_x = int(area_rect.x() + area_rect.width() - tray_w - margin)
            tray_y = int(area_rect.y() + margin)
            tray.setGeometry(tray_x, tray_y, tray_w, tray_h)
            if tray.isVisible():
                tray.raise_()

        if btn is not None:
            if bool(getattr(self, "_home_select_mode_enabled", False)):
                btn.hide()
            else:
                bw = int(max(130, btn.sizeHint().width() + 14))
                bh = int(max(38, btn.sizeHint().height() + 8))
                bx = int(area_rect.x() + area_rect.width() - bw - margin)
                by = int(area_rect.y() + margin)
                btn.setGeometry(max(area_rect.x() + margin, bx), by, bw, bh)
                btn.show()
                btn.raise_()

        self._home_update_rail_chevron_insets_for_selection_ui()
        self._glass_refresh_surface_backdrops()

    def _home_update_rail_chevron_insets_for_selection_ui(self) -> None:
        host = self.homePage
        if host is None:
            return

        overlay_rects: List[QRect] = []
        for overlay in (self._home_show_select_tray, self._home_show_select_toggle_btn):
            if overlay is None:
                continue
            try:
                if overlay.isVisible():
                    overlay_rects.append(QRect(overlay.geometry()))
            except Exception:
                continue

        for shell in list(getattr(self, "_home_rail_shells", []) or []):
            if shell is None or not hasattr(shell, "set_overlay_insets"):
                continue

            right_inset = 0
            try:
                top_left = shell.mapTo(host, QPoint(0, 0))
                shell_rect = QRect(top_left, shell.size())
            except Exception:
                shell_rect = QRect()

            if not shell_rect.isNull():
                for overlay_rect in overlay_rects:
                    if not shell_rect.intersects(overlay_rect):
                        continue
                    overlap = max(0, shell_rect.right() - overlay_rect.left() + 16)
                    right_inset = max(right_inset, int(overlap))

            try:
                shell.set_overlay_insets(right_px=int(right_inset))
            except Exception:
                pass

    def _home_set_show_select_mode(self, enabled: bool) -> None:
        self._home_select_mode_enabled = bool(enabled)

        btn = self._home_show_select_toggle_btn
        tray = self._home_show_select_tray

        if btn is not None:
            if self._home_select_mode_enabled:
                btn.setText("Selecting")
                btn.setStyleSheet(
                    "background: rgba(95,160,255,0.30); color: white;"
                    "border: 1px solid rgba(95,160,255,0.90); border-radius: 10px;"
                    "padding: 8px 14px;"
                )
            else:
                btn.setText("Select Shows")
                btn.setStyleSheet(
                    "background: rgba(0,0,0,0.70); color: white;"
                    "border: 1px solid rgba(255,255,255,0.24); border-radius: 10px;"
                    "padding: 8px 14px;"
                )
                btn.show()

        if tray is not None:
            if self._home_select_mode_enabled:
                tray.show()
                tray.raise_()
            else:
                tray.hide()

        self._home_position_show_selection_overlays()
        self._home_show_select_reserve_px = self._home_show_selection_reserved_width()
        try:
            self._home_update_center_lane_width()
        except Exception:
            pass
        if self._home_layout is not None and self.homeContent is not None:
            if self._home_is_active_page():
                try:
                    self._home_request_build()
                except Exception:
                    pass
            else:
                self._home_pending_hidden_build = True
        self._position_floating_bottom_dock()
        self._glass_apply_surface_chrome()

    def _home_toggle_show_select_mode(self) -> None:
        if not self._home_select_mode_enabled:
            self._home_close_inline_expander()
        self._home_set_show_select_mode(not self._home_select_mode_enabled)

    def _home_close_show_select_tray(self) -> None:
        self._home_set_show_select_mode(False)

    def _home_sender_show_payload(self, sender: object) -> Tuple[str, List[Path], str, Optional[Path], Optional[Path], str, str, Optional[Path]]:
        show_dirs: List[Path] = []
        show_dirs_json = sender.property("show_dirs") if hasattr(sender, "property") else None
        if show_dirs_json:
            try:
                arr = json.loads(str(show_dirs_json))
                if isinstance(arr, list):
                    show_dirs = [Path(str(x)) for x in arr if x]
            except Exception:
                show_dirs = []

        show_dir_str = sender.property("show_dir") if hasattr(sender, "property") else None
        if not show_dirs and show_dir_str:
            show_dirs = [Path(str(show_dir_str))]

        show_title = str(sender.property("show_title") or "") if hasattr(sender, "property") else ""
        rail_id = str(sender.property("rail_id") or "") if hasattr(sender, "property") else ""

        poster_path = None
        if hasattr(sender, "property"):
            raw = sender.property("show_poster")
            if raw:
                try:
                    p = Path(str(raw))
                    if p.exists():
                        poster_path = p
                except Exception:
                    poster_path = None

        backdrop_path = None
        if hasattr(sender, "property"):
            raw = sender.property("show_backdrop")
            if raw:
                try:
                    p = Path(str(raw))
                    if p.exists():
                        backdrop_path = p
                except Exception:
                    backdrop_path = None

        content_key = ""
        if hasattr(sender, "property"):
            content_key = str(sender.property("content_key") or "").strip()

        key = content_key
        if not key and hasattr(sender, "property"):
            key = str(sender.property("show_key") or "").strip()
        if not key:
            key = self._home_show_key_from_dirs(show_dirs, fallback_title=show_title)

        media_type = ""
        if hasattr(sender, "property"):
            media_type = str(sender.property("media_type") or "").strip().casefold()

        play_path = None
        if hasattr(sender, "property"):
            raw_play = sender.property("play_path")
            if raw_play:
                try:
                    p = Path(str(raw_play))
                    if p.exists() and p.is_file():
                        play_path = p
                except Exception:
                    play_path = None

        return key, show_dirs, show_title, poster_path, backdrop_path, rail_id, media_type, play_path

    def _home_resolve_group_from_payload(self, key: str, show_dirs: List[Path]) -> Optional[ShowGroup]:
        k = str(key or "").strip()
        if k:
            sg = self._home_items_by_key.get(k)
            if sg is not None:
                return sg

        for d in show_dirs:
            dk = self._home_canon_path_str(Path(str(d)))
            if not dk:
                continue
            gk = self._home_dir_to_key.get(dk)
            if not gk:
                continue
            sg = self._home_items_by_key.get(str(gk))
            if sg is not None:
                return sg

        return None

    def _home_make_stable_rail_id(self, title_text: str, show_items: List[ShowGroup]) -> str:
        """
        Build a deterministic rail id.

        Home used to key inline expansion off Python object ids, which changed on every
        rebuild. That made the expander feel glitchy during resize and rerender cycles.
        A stable rail id gives us an anchor we can safely restore into.
        """

        parts: List[str] = [str(title_text or "").strip().casefold()]
        for sg in list(show_items[:6]):
            key = str(getattr(sg, "content_key", "") or "").strip()
            if not key:
                key = self._home_canon_path_str(Path(str(getattr(sg, "primary_dir", ""))))
            if key:
                parts.append(key)
        digest = hashlib.sha1("|".join(parts).encode("utf-8", errors="ignore")).hexdigest()[:12]
        return f"rail::{digest}"

    def _home_current_inline_show_key(self) -> str:
        state = getattr(self, "_inline_expander_state", {})
        if isinstance(state, dict):
            return str(state.get("show_key") or "").strip()
        return ""

    def _home_store_inline_expander_state(self, *, keep_open: bool) -> None:
        exp = getattr(self, "_inline_expander_widget", None)
        state: Dict[str, Any] = dict(self._inline_expander_state) if isinstance(self._inline_expander_state, dict) else {}
        if exp is not None:
            state["show_key"] = str(exp.property("show_key") or state.get("show_key") or "").strip()
            state["rail_id"] = str(exp.property("rail_id") or state.get("rail_id") or "").strip()
            state["display_title"] = str(exp.property("display_title") or state.get("display_title") or "").strip()
            state["selected_season_label"] = str(exp.property("selected_season_label") or state.get("selected_season_label") or "").strip()
            state["selected_season_dirs_json"] = str(exp.property("selected_season_dirs_json") or state.get("selected_season_dirs_json") or "").strip()
            show_dirs_json = str(exp.property("show_dirs") or state.get("show_dirs_json") or "[]")
            state["show_dirs_json"] = show_dirs_json
        state["open"] = bool(keep_open) and bool(state.get("show_key") or state.get("show_dirs_json"))
        self._inline_expander_state = state
        self._inline_expander_restore_pending = bool(state.get("open", False))

    def _home_find_rail_id_for_show_key(self, show_key: str) -> str:
        key = str(show_key or "").strip()
        if not key:
            return ""
        for btn in list(self._home_show_card_click_targets.get(key, []) or []):
            try:
                rail_id = str(btn.property("rail_id") or "").strip()
                if rail_id:
                    return rail_id
            except Exception:
                pass
        return ""

    def _home_restore_inline_expander_if_needed(self) -> None:
        state = dict(self._inline_expander_state) if isinstance(self._inline_expander_state, dict) else {}
        if not bool(state.get("open", False)):
            return
        if getattr(self, "_inline_expander_widget", None) is not None:
            return

        show_key = str(state.get("show_key") or "").strip()
        rail_id = str(state.get("rail_id") or "").strip()
        if show_key:
            restored_rail_id = self._home_find_rail_id_for_show_key(show_key)
            if restored_rail_id:
                rail_id = restored_rail_id

        show_dirs_json = str(state.get("show_dirs_json") or "[]")
        try:
            show_dirs = [Path(str(x)) for x in json.loads(show_dirs_json) if str(x).strip()]
        except Exception:
            show_dirs = []
        if not rail_id or not show_dirs:
            return

        self._inline_expander_restore_pending = False
        self._home_activate_inline_expander(
            rail_id=rail_id,
            show_dirs=show_dirs,
            display_title=str(state.get("display_title") or "").strip(),
            show_key=show_key,
            restore_state=state,
        )

    def _home_on_show_clicked(self) -> None:
        sender = self.sender()
        if sender is None:
            dprint("[CLICK][WARN] sender() is None")
            return

        suggestion_key = str(sender.property("shuffle_suggestion_key") or sender.property("content_key") or "").strip() if hasattr(sender, "property") else ""
        if suggestion_key and self._home_is_shuffle_suggestion_key(suggestion_key):
            suggestion_mode = str(sender.property("shuffle_suggestion_mode") or "").strip().casefold() if hasattr(sender, "property") else ""
            self._home_start_shuffle_suggestion(suggestion_key, suggestion_mode)
            return

        mix_id = str(sender.property("mix_id") or "").strip() if hasattr(sender, "property") else ""
        if mix_id:
            self._saved_mix_resume(mix_id)
            return

        key, show_dirs, show_title, poster_path, backdrop_path, rail_id, media_type, play_path = self._home_sender_show_payload(sender)
        sg = self._home_resolve_group_from_payload(key, show_dirs)

        display_title = str(show_title).strip()
        if sg is not None:
            display_title = str(getattr(sg, "display_title", "") or display_title).strip()
            media_type = str(getattr(sg, "media_type", media_type or "tv") or "tv").strip().casefold()
        else:
            media_type = str(media_type or "tv").strip().casefold()

        if not display_title and show_dirs:
            primary = show_dirs[0]
            display_title = NameCleaner.clean(primary.name) or primary.name

        if self._home_select_mode_enabled:
            select_key = str(key or "").strip()
            if not select_key:
                select_key = self._home_show_key_from_dirs(show_dirs, fallback_title=display_title)

            if select_key in self._home_selected_shows:
                self._home_remove_selected_show(select_key)
            else:
                self._home_add_selected_show(
                    SelectedShowItem(
                        key=select_key,
                        title=display_title,
                        show_dirs=[Path(str(p)) for p in show_dirs],
                        poster_path=poster_path,
                        backdrop_path=backdrop_path,
                        title_id=str(getattr(sg, "title_id", "") or select_key),
                    )
                )
            self._home_apply_show_card_selection_state(select_key)
            return

        if media_type == "movie":
            if sg is not None:
                self._home_play_group(sg, resume=True)
                return
            if play_path is not None:
                self.play_path(str(play_path))
                return
            self._home_on_show_clicked_original()
            return

        if sg is not None and not show_dirs:
            try:
                show_dirs = [Path(str(p)) for p in (getattr(sg, "all_dirs", []) or []) if p is not None]
            except Exception:
                show_dirs = []
            if not show_dirs:
                show_dirs = [Path(str(getattr(sg, "primary_dir", "")))]

        if not show_dirs:
            if sg is not None:
                self._home_play_group(sg, resume=True)
                return
            self._home_on_show_clicked_original()
            return

        self._home_set_right_details_visible(False)
        show_key = str(key or "").strip()
        if not show_key:
            show_key = self._home_show_key_from_dirs(show_dirs, fallback_title=display_title)
        if show_key and show_key == self._home_current_inline_show_key() and getattr(self, "_inline_expander_widget", None) is not None:
            self._home_close_inline_expander()
            self._home_refresh_all_selection_highlights()
            return
        try:
            self._home_activate_inline_expander(str(rail_id), show_dirs, display_title, show_key=show_key)
        except Exception as e:
            dprint("[INLINE][WARN] Failed to activate expander:", e)

    def _home_register_show_card_click_target(self, key: str, click_btn: QPushButton) -> None:
        key = str(key).strip()
        if not key or click_btn is None:
            return

        arr = self._home_show_card_click_targets.setdefault(key, [])
        if click_btn not in arr:
            arr.append(click_btn)

        self._home_apply_show_card_selection_state(key)

    def _home_apply_show_card_selection_state(self, key: str) -> None:
        key = str(key).strip()
        if not key:
            return

        selected = key in self._home_selected_shows
        active_inline = key == self._home_current_inline_show_key()
        colors = dict(self._personalization.get("colors", {}) or {})
        primary_hex = self._personalization_norm_hex(str(colors.get("primary", "#5CA0FF") or "#5CA0FF"), "#5CA0FF")
        pr_rgb = self._personalization_hex_rgb(primary_hex, "#5CA0FF")
        style_inline = (
            f"background: rgba({pr_rgb[0]}, {pr_rgb[1]}, {pr_rgb[2]}, 40);"
            f"border: 2px solid rgba({pr_rgb[0]}, {pr_rgb[1]}, {pr_rgb[2]}, 234);"
            "border-radius: 16px;"
        )
        style_on = (
            f"background: rgba({pr_rgb[0]}, {pr_rgb[1]}, {pr_rgb[2]}, 52);"
            f"border: 2px solid rgba({pr_rgb[0]}, {pr_rgb[1]}, {pr_rgb[2]}, 242);"
            "border-radius: 16px;"
        )
        style_off = "background: transparent; border: none;"

        alive: List[QPushButton] = []
        for btn in self._home_show_card_click_targets.get(key, []):
            try:
                if btn is None or btn.parent() is None:
                    continue
                btn.setStyleSheet(style_on if selected else style_inline if active_inline else style_off)
                alive.append(btn)
            except Exception:
                pass

        self._home_show_card_click_targets[key] = alive

    def _home_refresh_all_selection_highlights(self) -> None:
        keys = set(self._home_show_card_click_targets.keys()) | set(self._home_selected_shows.keys())
        for key in keys:
            self._home_apply_show_card_selection_state(str(key))

    def _home_add_selected_show(self, item: SelectedShowItem) -> None:
        key = str(item.key).strip()
        if not key:
            return

        self._home_selected_shows[key] = item

        tray = self._home_show_select_tray
        if tray is not None:
            tray.upsert_item(item)
            tray.show()
            tray.raise_()

        self._home_apply_show_card_selection_state(key)
        self._home_position_show_selection_overlays()

    def _home_remove_selected_show(self, key: str) -> None:
        key = str(key).strip()
        if not key:
            return

        self._home_selected_shows.pop(key, None)

        tray = self._home_show_select_tray
        if tray is not None:
            tray.remove_item(key)

        self._home_apply_show_card_selection_state(key)

    def _home_on_show_select_remove_requested(self, key: str) -> None:
        self._home_remove_selected_show(key)

    def _home_clear_selected_shows(self) -> None:
        prev_keys = list(self._home_selected_shows.keys())
        self._home_selected_shows.clear()

        tray = self._home_show_select_tray
        if tray is not None:
            tray.clear_items()

        for key in prev_keys:
            self._home_apply_show_card_selection_state(key)

    def _saved_mix_content_key(self, mix_id: str) -> str:
        return f"saved_mix::{str(mix_id or '').strip()}"

    def _saved_mix_make_id(self, selected_items: List[SelectedShowItem]) -> str:
        parts: List[str] = []
        for item in list(selected_items or []):
            key = str(getattr(item, "key", "") or "").strip()
            title = str(getattr(item, "title", "") or "").strip().casefold()
            if key:
                parts.append(key)
            elif title:
                parts.append(title)
        if not parts:
            parts.append(str(int(time.time())))
        digest = hashlib.sha1("||".join(sorted(set(parts))).encode("utf-8", errors="ignore")).hexdigest()[:16]
        return f"mix-{digest}"

    def _saved_mix_default_title(self, selected_items: List[SelectedShowItem]) -> str:
        for item in list(selected_items or []):
            title = str(getattr(item, "title", "") or "").strip()
            if title:
                return title if title.casefold().endswith(" mix") else f"{title} Mix"
        return "Saved Mix"

    def _saved_mix_choose_art_path(self, selected_items: List[SelectedShowItem]) -> str:
        candidates: List[str] = []
        seen: set[str] = set()

        def add_candidate(raw_path: Optional[Path]) -> None:
            if raw_path is None:
                return
            try:
                p = Path(str(raw_path))
            except Exception:
                return
            if not p.exists():
                return
            canon = self._home_canon_path_str(p)
            if not canon or canon in seen:
                return
            seen.add(canon)
            candidates.append(str(p))

        for item in list(selected_items or []):
            add_candidate(getattr(item, "poster_path", None))
            key = str(getattr(item, "key", "") or "").strip()
            if not key:
                continue
            sg = self._home_items_by_key.get(key)
            if sg is None:
                continue
            add_candidate(getattr(sg, "poster_path", None))
            add_candidate(getattr(sg, "backdrop_path", None))

        if not candidates:
            return ""
        return str(random.choice(candidates))

    def _saved_mix_state_records(self) -> List[Dict[str, Any]]:
        raw = self._home_state.setdefault("saved_mixes", [])
        if not isinstance(raw, list):
            raw = []
            self._home_state["saved_mixes"] = raw

        cleaned: List[Dict[str, Any]] = []
        for record in list(raw):
            if not isinstance(record, dict):
                continue
            mix_id = str(record.get("id") or "").strip()
            if not mix_id:
                continue
            playlist_paths = [str(x).strip() for x in (record.get("playlist_paths") or []) if str(x).strip()]
            if not playlist_paths:
                continue
            playlist_content_keys = [str(x).strip() for x in (record.get("playlist_content_keys") or [])]
            if len(playlist_content_keys) < len(playlist_paths):
                playlist_content_keys.extend([""] * (len(playlist_paths) - len(playlist_content_keys)))
            elif len(playlist_content_keys) > len(playlist_paths):
                playlist_content_keys = playlist_content_keys[: len(playlist_paths)]
            seed_keys = [str(x).strip() for x in (record.get("seed_keys") or []) if str(x).strip()]
            seed_titles = [str(x).strip() for x in (record.get("seed_titles") or []) if str(x).strip()]
            title = str(record.get("title") or "").strip() or "Saved Mix"
            mode = str(record.get("mode") or "").strip() or "shuffle"
            mode_label = str(record.get("mode_label") or "").strip() or "Shuffle"
            created_at = int(record.get("created_at") or record.get("updated_at") or time.time())
            updated_at = int(record.get("updated_at") or created_at)
            current_index = int(record.get("current_index") or 0)
            current_path = str(record.get("current_path") or "").strip()
            current_position_ms = max(0, int(record.get("current_position_ms") or 0))
            current_duration_ms = max(0, int(record.get("current_duration_ms") or 0))
            art_path = str(record.get("art_path") or "").strip()
            cleaned.append(
                {
                    "id": mix_id,
                    "title": title,
                    "mode": mode,
                    "mode_label": mode_label,
                    "seed_keys": seed_keys,
                    "seed_titles": seed_titles,
                    "art_path": art_path,
                    "playlist_paths": playlist_paths,
                    "playlist_content_keys": playlist_content_keys,
                    "current_index": current_index,
                    "current_path": current_path,
                    "current_position_ms": current_position_ms,
                    "current_duration_ms": current_duration_ms,
                    "created_at": created_at,
                    "updated_at": updated_at,
                }
            )

        cleaned.sort(key=lambda item: int(item.get("updated_at") or 0), reverse=True)
        return cleaned[:24]

    def _saved_mix_find_record(self, mix_id: str) -> Optional[Dict[str, Any]]:
        wanted = str(mix_id or "").strip()
        if not wanted:
            return None
        for record in self._saved_mix_state_records():
            if str(record.get("id") or "") == wanted:
                return dict(record)
        return None

    def _saved_mix_is_active(self, mix_id: str) -> bool:
        wanted = str(mix_id or "").strip()
        return bool(
            wanted
            and wanted == str(getattr(self, "_saved_mix_active_id", "") or "").strip()
            and bool(self._shuffle_active)
            and bool(self._home_shuffle_queue)
        )

    def _saved_mix_current_queue_content_keys(self, queue_paths: Optional[List[str]] = None) -> List[str]:
        paths = [str(p).strip() for p in (queue_paths or self._home_shuffle_queue or []) if str(p).strip()]
        if not paths:
            return []
        if self._shuffle_plan and len(self._shuffle_plan) == len(paths):
            return [str(show_key or "") for show_key, _path in self._shuffle_plan]
        out: List[str] = []
        for path in paths:
            canon = self._home_canon_path_str(Path(path))
            out.append(str(self._shuffle_path_to_show.get(canon, "") or ""))
        return out

    def _saved_mix_sync_active_state(
        self,
        *,
        current_index: Optional[int] = None,
        current_path: Optional[str] = None,
        current_position_ms: Optional[int] = None,
        current_duration_ms: Optional[int] = None,
        save: bool = False,
        force: bool = False,
    ) -> None:
        mix_id = str(getattr(self, "_saved_mix_active_id", "") or "").strip()
        if not mix_id:
            return

        records = self._saved_mix_state_records()
        rec_index = next((idx for idx, item in enumerate(records) if str(item.get("id") or "") == mix_id), -1)
        if rec_index < 0:
            return

        record = dict(records[rec_index])
        changed = False

        queue_paths = [str(p).strip() for p in (self._home_shuffle_queue or []) if str(p).strip()]
        if queue_paths and list(record.get("playlist_paths") or []) != queue_paths:
            record["playlist_paths"] = list(queue_paths)
            changed = True

        queue_keys = self._saved_mix_current_queue_content_keys(queue_paths)
        if queue_keys and list(record.get("playlist_content_keys") or []) != queue_keys:
            record["playlist_content_keys"] = list(queue_keys)
            changed = True

        if current_index is not None:
            max_index = max(0, len(record.get("playlist_paths") or []) - 1)
            norm_index = max(0, min(int(current_index), max_index))
            if int(record.get("current_index") or 0) != norm_index:
                record["current_index"] = norm_index
                changed = True

        if current_path is not None:
            clean_path = str(current_path or "").strip()
            if clean_path != str(record.get("current_path") or ""):
                record["current_path"] = clean_path
                changed = True
            if clean_path and record.get("playlist_paths"):
                target_canon = self._home_canon_path_str(Path(clean_path))
                for idx, path_str in enumerate(record.get("playlist_paths") or []):
                    if self._home_canon_path_str(Path(path_str)) == target_canon:
                        if int(record.get("current_index") or 0) != idx:
                            record["current_index"] = idx
                            changed = True
                        break

        if current_position_ms is not None:
            pos_ms = max(0, int(current_position_ms))
            if int(record.get("current_position_ms") or 0) != pos_ms:
                record["current_position_ms"] = pos_ms
                changed = True

        if current_duration_ms is not None:
            dur_ms = max(0, int(current_duration_ms))
            if int(record.get("current_duration_ms") or 0) != dur_ms:
                record["current_duration_ms"] = dur_ms
                changed = True

        if not changed and not save:
            return

        record["updated_at"] = int(time.time())
        records[rec_index] = record
        records.sort(key=lambda item: int(item.get("updated_at") or 0), reverse=True)
        self._home_state["saved_mixes"] = records[:24]
        if save:
            self._home_state_save(force=bool(force))

    def _saved_mix_capture_active_snapshot(self, *, force_save: bool = False) -> None:
        mix_id = str(getattr(self, "_saved_mix_active_id", "") or "").strip()
        if not mix_id:
            return

        current_path = ""
        current_index: Optional[int] = None
        cur_ms: Optional[int] = None
        dur_ms: Optional[int] = None

        if isinstance(self._shuffle_last_playlist_pos, int) and self._shuffle_last_playlist_pos >= 0:
            current_index = int(self._shuffle_last_playlist_pos)

        if self._mpv is not None:
            try:
                path_raw = self._mpv.get_current_path()
            except Exception:
                path_raw = ""
            current_path = str(path_raw or "").strip()
            try:
                time_raw = self._mpv.get_time_raw()
                dur_raw = self._mpv.get_duration_raw()
                self._player_maybe_detect_unit(dur_raw)
                cur_ms = self._player_to_ms(time_raw)
                dur_ms = self._player_to_ms(dur_raw)
            except Exception:
                cur_ms = None
                dur_ms = None

        if not current_path:
            cp = getattr(self, "_current_path", None)
            if cp is not None:
                current_path = str(cp)

        self._saved_mix_sync_active_state(
            current_index=current_index,
            current_path=current_path,
            current_position_ms=cur_ms,
            current_duration_ms=dur_ms,
            save=True,
            force=bool(force_save),
        )

    def _saved_mix_register_session(
        self,
        *,
        mode: str,
        mode_label: str,
        selected_items: List[SelectedShowItem],
        queue_pairs: List[Tuple[str, str]],
    ) -> str:
        valid_pairs = [
            (str(show_key or "").strip(), str(path or "").strip())
            for show_key, path in list(queue_pairs or [])
            if str(path or "").strip()
        ]
        if not valid_pairs:
            return ""

        mix_id = self._saved_mix_make_id(selected_items)
        records = self._saved_mix_state_records()
        existing = self._saved_mix_find_record(mix_id)
        now = int(time.time())
        title = str(existing.get("title") or "").strip() if existing is not None else ""
        if not title:
            title = self._saved_mix_default_title(selected_items)
        art_path = self._saved_mix_choose_art_path(selected_items)
        if not art_path and existing is not None:
            art_path = str(existing.get("art_path") or "").strip()

        record = {
            "id": mix_id,
            "title": title,
            "mode": str(mode or "").strip() or "shuffle",
            "mode_label": str(mode_label or "").strip() or "Shuffle",
            "seed_keys": [str(getattr(item, "key", "") or "").strip() for item in list(selected_items or []) if str(getattr(item, "key", "") or "").strip()],
            "seed_titles": [str(getattr(item, "title", "") or "").strip() for item in list(selected_items or []) if str(getattr(item, "title", "") or "").strip()],
            "art_path": art_path,
            "playlist_paths": [path for _show_key, path in valid_pairs],
            "playlist_content_keys": [show_key for show_key, _path in valid_pairs],
            "current_index": 0,
            "current_path": valid_pairs[0][1],
            "current_position_ms": 0,
            "current_duration_ms": 0,
            "created_at": int(existing.get("created_at") or now) if existing is not None else now,
            "updated_at": now,
        }

        new_records = [record]
        for item in records:
            if str(item.get("id") or "") != mix_id:
                new_records.append(item)
        self._home_state["saved_mixes"] = new_records[:24]
        self._saved_mix_active_id = mix_id
        self._saved_mix_active_mode_label = str(record.get("mode_label") or "Shuffle")
        self._home_state_save(force=True)
        return mix_id

    def _saved_mix_remove(self, mix_id: str) -> bool:
        wanted = str(mix_id or "").strip()
        if not wanted:
            return False
        records = self._saved_mix_state_records()
        kept = [item for item in records if str(item.get("id") or "") != wanted]
        if len(kept) == len(records):
            return False
        self._home_state["saved_mixes"] = kept
        if wanted == str(getattr(self, "_saved_mix_active_id", "") or "").strip():
            self._saved_mix_active_id = ""
            self._saved_mix_active_mode_label = ""
        self._home_state_save(force=True)
        return True

    def _saved_mix_resolve_art_path(self, record: Dict[str, Any]) -> Optional[Path]:
        candidates: List[Path] = []

        art_path = str(record.get("art_path") or "").strip()
        if art_path:
            try:
                candidates.append(Path(art_path))
            except Exception:
                pass

        for key in list(record.get("seed_keys") or []) + list(record.get("playlist_content_keys") or []):
            sg = self._home_items_by_key.get(str(key))
            if sg is None:
                continue
            for raw_path in (getattr(sg, "poster_path", None), getattr(sg, "backdrop_path", None)):
                if raw_path is None:
                    continue
                try:
                    candidates.append(Path(str(raw_path)))
                except Exception:
                    continue

        for path in candidates:
            try:
                if path.exists():
                    return path
            except Exception:
                continue
        return None

    def _saved_mix_row_items(self) -> List[ShowGroup]:
        out: List[ShowGroup] = []
        for record in self._saved_mix_state_records():
            valid_pairs: List[Tuple[str, Path]] = []
            path_list = list(record.get("playlist_paths") or [])
            key_list = list(record.get("playlist_content_keys") or [])
            for idx, path_str in enumerate(path_list):
                try:
                    p = Path(str(path_str))
                except Exception:
                    continue
                if not p.exists() or not p.is_file():
                    continue
                key = key_list[idx] if idx < len(key_list) else ""
                valid_pairs.append((str(key or ""), p))
            if not valid_pairs:
                continue

            art_path = self._saved_mix_resolve_art_path(record)
            current_path = str(record.get("current_path") or "").strip()
            target_path: Optional[Path] = None
            if current_path:
                target_canon = self._home_canon_path_str(Path(current_path))
                for _show_key, candidate_path in valid_pairs:
                    if self._home_canon_path_str(candidate_path) == target_canon:
                        target_path = candidate_path
                        break
            if target_path is None:
                idx = max(0, min(int(record.get("current_index") or 0), len(valid_pairs) - 1))
                target_path = valid_pairs[idx][1]

            item_count = len(valid_pairs)
            seed_titles = list(record.get("seed_titles") or [])
            summary = f"{item_count} item{'s' if item_count != 1 else ''}"
            if seed_titles:
                summary = f"{summary} from {', '.join(seed_titles[:3])}"

            out.append(
                ShowGroup(
                    display_title=str(record.get("title") or "Saved Mix"),
                    primary_dir=target_path.parent if target_path is not None else self._cache_dir,
                    poster_path=art_path,
                    group_mtime=float(int(record.get("updated_at") or 0)),
                    all_dirs=[],
                    media_type="saved_mix",
                    play_path=target_path,
                    content_key=self._saved_mix_content_key(str(record.get("id") or "")),
                    overview=summary,
                    backdrop_path=art_path,
                    classification_reason="saved-mix",
                )
            )
        return out

    def _saved_mix_resume(self, mix_id: str) -> None:
        wanted = str(mix_id or "").strip()
        if not wanted:
            return

        if self._saved_mix_is_active(wanted):
            try:
                self.pages.setCurrentWidget(self.playerPage)
            except Exception:
                pass
            try:
                if self._mpv is not None and self._mpv.is_paused():
                    self._mpv.play()
            except Exception:
                pass
            return

        record = self._saved_mix_find_record(wanted)
        if record is None:
            QMessageBox.information(self.win, "Saved Mix", "That saved mix could not be found anymore.")
            return

        if str(record.get("mode") or "").strip().casefold() == "shuffle":
            selected_items = self._saved_mix_selected_items_from_record(record)
            if selected_items:
                if self._shuffle_start_from_selected_items(selected_items, mode_label=str(record.get("mode_label") or "Shuffle")):
                    return

        valid_pairs: List[Tuple[str, str]] = []
        raw_paths = list(record.get("playlist_paths") or [])
        raw_keys = list(record.get("playlist_content_keys") or [])
        for idx, path_str in enumerate(raw_paths):
            try:
                p = Path(str(path_str))
            except Exception:
                continue
            if not p.exists() or not p.is_file():
                continue
            show_key = raw_keys[idx] if idx < len(raw_keys) else self._home_resolve_media_key_for_path(p)
            valid_pairs.append((str(show_key or ""), str(p)))

        if not valid_pairs:
            QMessageBox.information(self.win, "Saved Mix", "No playable files were left in that saved mix.")
            return

        resume_index = max(0, min(int(record.get("current_index") or 0), len(valid_pairs) - 1))
        current_path = str(record.get("current_path") or "").strip()
        if current_path:
            target_canon = self._home_canon_path_str(Path(current_path))
            for idx, (_show_key, path_str) in enumerate(valid_pairs):
                if self._home_canon_path_str(Path(path_str)) == target_canon:
                    resume_index = idx
                    break

        resume_position_ms = max(0, int(record.get("current_position_ms") or 0))
        mode_label = str(record.get("mode_label") or "").strip() or "Shuffle"

        self._shuffle_deactivate(clear_queue=True)
        self._shuffle_plan = list(valid_pairs)
        self._home_shuffle_queue = [path for _show_key, path in valid_pairs]
        self._shuffle_path_to_show = {
            self._home_canon_path_str(Path(path)): str(show_key or "")
            for show_key, path in valid_pairs
        }
        self._shuffle_active = True
        self._shuffle_last_playlist_pos = None
        self._shuffle_last_path_key = ""
        self._saved_mix_active_id = wanted
        self._saved_mix_active_mode_label = mode_label
        self._player_set_playlist_drawer_open(False)
        self._player_playlist_signature = ""

        target_show_key, target_path_str = valid_pairs[resume_index]
        target_path = Path(target_path_str)
        self._current_path = target_path
        self._finish_mark_path_key = ""
        self._player_reset_segment_skip_state(self._home_canon_path_str(target_path))
        self._home_state_record_play_start(target_path)
        if target_show_key:
            self._shuffle_mark_leftoff(target_show_key, target_path)
        self._player_update_now_playing_title_label()
        self._player_update_playlist_drawer_contents()

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()

        if self._mpv is None:
            self._shuffle_deactivate(clear_queue=False)
            QMessageBox.warning(self.win, "Player Unavailable", "Saved mix loaded, but MPV is not available.")
            return

        try:
            self.pages.setCurrentWidget(self.playerPage)
        except Exception:
            pass

        try:
            if self.videoHost is not None:
                self._mpv.set_wid(int(self.videoHost.winId()))
        except Exception:
            pass

        self._player_release_seek_lock()
        self._pending_seek_ratio = None
        self._mpv_time_unit = None

        try:
            self._mpv.load_playlist(self._home_shuffle_queue, play_immediately=True)
        except Exception as e:
            dprint("[SAVED_MIX][WARN] Playlist load failed:", e)
            self._shuffle_deactivate(clear_queue=False)
            QMessageBox.warning(self.win, "Saved Mix", "Could not reopen that saved mix playlist.")
            return

        if resume_index > 0:
            QTimer.singleShot(180, lambda idx=resume_index: self._mpv.playlist_play_index(int(idx)) if self._mpv is not None else None)
        if resume_position_ms > 1500:
            QTimer.singleShot(420, lambda ms=resume_position_ms: self._player_seek_backend_ms(int(ms)))

        self._saved_mix_sync_active_state(
            current_index=resume_index,
            current_path=str(target_path),
            current_position_ms=resume_position_ms,
            save=True,
            force=True,
        )
        self._player_tick_ui()

    def _saved_mix_show_context_menu(self, sender: object, mix_id: str) -> bool:
        wanted = str(mix_id or "").strip()
        if not wanted:
            return False

        menu = QMenu(self.win)
        act_resume = menu.addAction("Return to Mix" if self._saved_mix_is_active(wanted) else "Resume Mix")
        act_remove = menu.addAction("Remove Saved Mix")

        if isinstance(sender, QWidget):
            chosen = menu.exec(sender.mapToGlobal(QPoint(sender.width() // 2, sender.height())))
        else:
            chosen = menu.exec(QCursor.pos())

        if chosen == act_resume:
            self._saved_mix_resume(wanted)
            return True
        if chosen == act_remove:
            if self._saved_mix_remove(wanted):
                self._home_build()
            return True
        return True

    def _shuffle_load_state(self) -> None:
        self._shuffle_resume_map = {}
        state_file = getattr(self, "_shuffle_state_file", None)
        if state_file is None:
            return

        try:
            if not state_file.exists() or not state_file.is_file():
                return
            raw = state_file.read_text(encoding="utf-8")
            data = json.loads(raw)
        except Exception:
            return

        if not isinstance(data, dict):
            return

        shows = data.get("shows", {})
        if not isinstance(shows, dict):
            return

        cleaned: Dict[str, str] = {}
        for raw_key, raw_path in shows.items():
            key = str(raw_key).strip()
            path = str(raw_path).strip()
            if not key or not path:
                continue
            cleaned[key] = path

        self._shuffle_resume_map = cleaned

    def _shuffle_save_state(self) -> None:
        state_file = getattr(self, "_shuffle_state_file", None)
        if state_file is None:
            return

        try:
            state_file.parent.mkdir(parents=True, exist_ok=True)
            payload = {"shows": dict(sorted(self._shuffle_resume_map.items()))}
            state_file.write_text(json.dumps(payload, indent=2), encoding="utf-8")
        except Exception as e:
            dprint("[SHUFFLE][WARN] Could not save state:", e)
    def _shuffle_deactivate(self, *, clear_queue: bool = False) -> None:
        self._saved_mix_capture_active_snapshot(force_save=bool(clear_queue or self._shuffle_active))
        self._shuffle_active = False
        self._shuffle_last_playlist_pos = None
        self._shuffle_last_path_key = ""
        self._shuffle_resume_seek_path_key = ""
        self._saved_mix_active_id = ""
        self._saved_mix_active_mode_label = ""
        self._smart_shuffle_session_state = None
        self._smart_shuffle_last_result = None
        self._smart_shuffle_last_logged_path_key = ""
        self._smart_shuffle_started_paths = set()
        self._smart_shuffle_finished_paths = set()
        self._smart_shuffle_pending_feedback = False
        if clear_queue:
            self._shuffle_plan = []
            self._shuffle_path_to_show = {}
            self._home_shuffle_queue = []
            self._player_playlist_signature = ""
        self._player_set_playlist_drawer_open(False)
        self._smart_shuffle_update_live_strip()
        self._player_update_playlist_drawer_contents()
        self._player_sync_playlist_drawer_visibility()

    def _shuffle_mark_leftoff(self, show_key: str, episode_path: Path) -> None:
        key = str(show_key).strip()
        if not key or episode_path is None:
            return

        try:
            canon_path = self._home_canon_path_str(Path(str(episode_path)))
        except Exception:
            canon_path = str(episode_path).strip()

        if not canon_path:
            return

        if self._shuffle_resume_map.get(key) == canon_path:
            return

        self._shuffle_resume_map[key] = canon_path
        self._shuffle_save_state()
    def _shuffle_sync_from_playlist_pos(self, pos: int) -> None:
        if pos < 0 or pos >= len(self._shuffle_plan):
            return

        show_key, path_str = self._shuffle_plan[pos]
        p = Path(path_str)
        self._current_path = p
        self._finish_mark_path_key = ""
        self._shuffle_last_path_key = self._home_canon_path_str(p)
        self._home_state_record_play_start(p)
        self._shuffle_mark_leftoff(show_key, p)
        self._shuffle_schedule_resume_seek(show_key, p)
        self._saved_mix_sync_active_state(
            current_index=int(pos),
            current_path=str(p),
            current_position_ms=0,
            save=True,
            force=True,
        )
        self._player_update_now_playing_title_label()
        self._player_update_playlist_drawer_contents()

    def _shuffle_sync_from_playback(self) -> None:
        with self._perf_track("player_shuffle_state"):
            if not self._shuffle_active or self._mpv is None:
                return

            playlist_pos = self._mpv.get_playlist_pos()
            if isinstance(playlist_pos, int) and playlist_pos >= 0:
                if playlist_pos != self._shuffle_last_playlist_pos:
                    self._shuffle_last_playlist_pos = playlist_pos
                    self._shuffle_sync_from_playlist_pos(int(playlist_pos))
                return

            path_raw = self._mpv.get_current_path()
            if not path_raw:
                return

            p = Path(str(path_raw))
            path_key = self._home_canon_path_str(p)
            if not path_key or path_key == self._shuffle_last_path_key:
                return

            self._shuffle_last_path_key = path_key
            self._current_path = p
            self._finish_mark_path_key = ""
            self._home_state_record_play_start(p)

            show_key = self._shuffle_path_to_show.get(path_key)
            if show_key:
                self._shuffle_mark_leftoff(show_key, p)
                self._shuffle_schedule_resume_seek(show_key, p)
            self._saved_mix_sync_active_state(
                current_path=str(p),
                current_position_ms=0,
                save=True,
                force=True,
            )
            self._player_update_now_playing_title_label()
            self._player_update_playlist_drawer_contents()

    def _shuffle_collect_show_episodes_from_items(
        self,
        selected_items: Sequence[SelectedShowItem],
    ) -> Dict[str, List[Path]]:
        show_episode_map: Dict[str, List[Path]] = {}
        seen_global: set[str] = set()

        for item in list(selected_items or []):
            show_dirs = [Path(str(p)) for p in (getattr(item, "show_dirs", []) or []) if p is not None]
            if not show_dirs:
                continue

            show_key = str(getattr(item, "key", "") or "").strip()
            if not show_key:
                show_key = self._home_show_key_from_dirs(show_dirs, fallback_title=str(getattr(item, "title", "") or ""))
            if not show_key:
                continue

            sg = self._home_items_by_key.get(show_key)
            pairs = self._home_explicit_episode_refs_for_group(sg)
            if not pairs:
                season_groups = self._home_find_season_groups_for_show_dirs(show_dirs)
                season_dirs: List[Path] = []
                for _label, dirs in season_groups:
                    season_dirs.extend([Path(str(p)) for p in dirs if p is not None])
                if not season_dirs:
                    season_dirs = list(show_dirs)

                pairs = self._home_list_episode_files_multi(season_dirs=season_dirs, show_dirs=show_dirs)
            episodes: List[Path] = []
            for ep in pairs:
                ep_path = Path(str(ep.episode_path))
                if not ep_path.exists() or not ep_path.is_file():
                    continue
                canon = self._home_canon_path_str(ep_path)
                if canon in seen_global:
                    continue
                seen_global.add(canon)
                episodes.append(ep_path)

            if episodes:
                show_episode_map[show_key] = episodes

        return show_episode_map

    def _shuffle_collect_selected_show_episodes(self) -> Dict[str, List[Path]]:
        return self._shuffle_collect_show_episodes_from_items(list(self._home_selected_shows.values()))

    def _shuffle_rotate_from_resume(self, show_key: str, episodes: List[Path]) -> List[Path]:
        ordered = [Path(str(p)) for p in episodes if p is not None]
        if not ordered:
            return []

        resume_path = self._shuffle_resume_map.get(str(show_key).strip(), "")
        if not resume_path:
            return ordered

        for idx, episode_path in enumerate(ordered):
            if self._home_canon_path_str(episode_path) == resume_path:
                return ordered[idx:] + ordered[:idx]

        return ordered

    def _shuffle_resume_position_ms(self, show_key: str, episode_path: Path) -> int:
        key = str(show_key or "").strip()
        if not key:
            return 0

        progress = self._home_state.get("watch_progress", {})
        if not isinstance(progress, dict):
            return 0

        progress_row = progress.get(key)
        if not isinstance(progress_row, dict):
            return 0

        raw_path = str(progress_row.get("path") or "").strip()
        if not raw_path:
            return 0

        try:
            current_key = self._home_canon_path_str(Path(raw_path))
        except Exception:
            current_key = raw_path
        target_key = self._home_canon_path_str(Path(str(episode_path)))
        if not current_key or current_key != target_key:
            return 0

        try:
            position_ms = max(0, int(progress_row.get("position_ms") or 0))
        except Exception:
            position_ms = 0
        try:
            ratio = float(progress_row.get("ratio", 0.0) or 0.0)
        except Exception:
            ratio = 0.0

        if position_ms <= 1500 or ratio >= 0.965:
            return 0
        return position_ms

    def _shuffle_apply_resume_seek_if_current(self, path_key: str, position_ms: int) -> None:
        if not self._shuffle_active or self._mpv is None or position_ms <= 0:
            return

        current_path = ""
        try:
            current_path = str(self._mpv.get_current_path() or "").strip()
        except Exception:
            current_path = ""
        if not current_path and getattr(self, "_current_path", None) is not None:
            current_path = str(self._current_path)

        if not current_path:
            return
        if self._home_canon_path_str(Path(current_path)) != str(path_key or "").strip():
            return

        self._player_seek_backend_ms(int(position_ms))

    def _shuffle_schedule_resume_seek(self, show_key: str, episode_path: Path, *, delay_ms: int = 420) -> int:
        path = Path(str(episode_path))
        path_key = self._home_canon_path_str(path)
        resume_ms = self._shuffle_resume_position_ms(show_key, path)
        if not path_key or resume_ms <= 0:
            return 0
        if str(getattr(self, "_shuffle_resume_seek_path_key", "") or "") == path_key:
            return resume_ms

        self._shuffle_resume_seek_path_key = path_key
        QTimer.singleShot(
            max(0, int(delay_ms)),
            lambda expected_path=path_key, ms=resume_ms: self._shuffle_apply_resume_seek_if_current(expected_path, ms),
        )
        return resume_ms

    def _shuffle_start_from_selected_items(
        self,
        selected_items: Sequence[SelectedShowItem],
        *,
        mode_label: str,
        empty_title: str = "No shows selected",
        empty_message: str = "Select at least one show first.",
    ) -> bool:
        items = [item for item in list(selected_items or []) if item is not None]
        if not items:
            QMessageBox.information(self.win, empty_title, empty_message)
            return False

        mix_id = self._saved_mix_make_id(items)
        if self._saved_mix_is_active(mix_id):
            try:
                self.pages.setCurrentWidget(self.playerPage)
            except Exception:
                pass
            try:
                if self._mpv is not None and self._mpv.is_paused():
                    self._mpv.play()
            except Exception:
                pass
            return True

        self._shuffle_deactivate(clear_queue=True)

        raw_map = self._shuffle_collect_show_episodes_from_items(items)
        if not raw_map:
            QMessageBox.information(
                self.win,
                "No episodes found",
                "No playable episodes were found for the selected shows.",
            )
            return False

        rotated_map: Dict[str, List[Path]] = {}
        for show_key, episodes in raw_map.items():
            rotated = self._shuffle_rotate_from_resume(show_key, episodes)
            if rotated:
                rotated_map[str(show_key)] = rotated

        plan = self._shuffle_build_interleaved_plan(rotated_map)
        if not plan:
            QMessageBox.information(self.win, "No episodes found", "Could not build a shuffle queue.")
            return False

        self._shuffle_plan = list(plan)
        self._home_shuffle_queue = [path for _show_key, path in self._shuffle_plan]
        self._shuffle_path_to_show = {
            self._home_canon_path_str(Path(path)): show_key
            for show_key, path in self._shuffle_plan
        }
        self._shuffle_active = True
        self._shuffle_last_playlist_pos = None
        self._shuffle_last_path_key = ""
        self._shuffle_resume_seek_path_key = ""
        self._saved_mix_register_session(
            mode="shuffle",
            mode_label=str(mode_label or "Shuffle"),
            selected_items=list(items),
            queue_pairs=self._shuffle_plan,
        )
        self._player_set_playlist_drawer_open(False)
        self._player_playlist_signature = ""

        first_show, first_path = self._shuffle_plan[0]
        first_episode = Path(first_path)
        self._current_path = first_episode
        self._finish_mark_path_key = ""
        self._player_reset_segment_skip_state(self._home_canon_path_str(first_episode))
        self._home_state_record_play_start(first_episode)
        self._shuffle_mark_leftoff(first_show, first_episode)
        self._player_update_now_playing_title_label()
        self._player_update_playlist_drawer_contents()

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()

        if self._mpv is None:
            self._shuffle_deactivate(clear_queue=False)
            QMessageBox.warning(
                self.win,
                "Player Unavailable",
                f"{mode_label} queue created, but MPV is not available.",
            )
            return False

        try:
            self.pages.setCurrentWidget(self.playerPage)
        except Exception:
            pass

        try:
            if self.videoHost is not None:
                self._mpv.set_wid(int(self.videoHost.winId()))
        except Exception:
            pass

        self._player_release_seek_lock()
        self._pending_seek_ratio = None
        self._mpv_time_unit = None

        try:
            self._mpv.load_playlist(self._home_shuffle_queue, play_immediately=True)
        except Exception as e:
            dprint("[SHUFFLE][WARN] Playlist load failed, falling back to first item:", e)
            self._shuffle_deactivate(clear_queue=True)
            self.play_path(first_path)
            return False

        self._shuffle_schedule_resume_seek(first_show, first_episode)
        self._player_tick_ui()
        return True

    def _shuffle_build_interleaved_plan(self, show_episode_map: Dict[str, List[Path]]) -> List[Tuple[str, str]]:
        queues: Dict[str, deque[Path]] = {
            str(k): deque(Path(str(p)) for p in eps if p is not None)
            for k, eps in show_episode_map.items()
            if eps
        }
        plan: List[Tuple[str, str]] = []
        last_show = ""
        consecutive = 0

        while True:
            available = [k for k, items in queues.items() if items]
            if not available:
                break

            candidates = [k for k in available if not (k == last_show and consecutive >= 2)]
            if not candidates:
                candidates = available

            if len(candidates) == 1:
                chosen = candidates[0]
            else:
                ranked = sorted(candidates, key=lambda key: (-len(queues[key]), random.random()))
                top_len = len(queues[ranked[0]])
                top = [key for key in ranked if len(queues[key]) == top_len]
                chosen = random.choice(top if top else ranked)

            ep_path = queues[chosen].popleft()
            plan.append((chosen, str(ep_path)))

            if chosen == last_show:
                consecutive += 1
            else:
                last_show = chosen
                consecutive = 1

        return plan

    def _smart_shuffle_group_dirs(self, sg: ShowGroup) -> List[Path]:
        dirs: List[Path] = []
        for cand_name in ("group_dirs", "dirs", "source_dirs", "all_dirs", "merged_dirs"):
            if hasattr(sg, cand_name):
                try:
                    dirs = [Path(str(p)) for p in list(getattr(sg, cand_name) or []) if p is not None]
                    if dirs:
                        break
                except Exception:
                    dirs = []
        if not dirs:
            dirs = [Path(str(getattr(sg, "primary_dir", Path(""))))]
        return dirs

    def _smart_shuffle_collect_sources_from_groups(
        self,
        groups: List[ShowGroup],
        *,
        restrict_to_verified: bool,
    ) -> List[SmartTitleSource]:
        selected_keys = {str(k).strip() for k in self._home_selected_shows.keys() if str(k).strip()}
        selected_dir_keys: set[str] = set()
        for item in self._home_selected_shows.values():
            for show_dir in list(getattr(item, "show_dirs", []) or []):
                try:
                    selected_dir_keys.add(self._home_canon_path_str(Path(str(show_dir))))
                except Exception:
                    pass

        out: List[SmartTitleSource] = []
        seen_keys: set[str] = set()
        max_preview = 6
        for sg in list(groups or []):
            key = str(getattr(sg, "content_key", "") or "").strip()
            if not key:
                key = self._home_canon_path_str(Path(str(getattr(sg, "primary_dir", ""))))
            if not key or key in seen_keys:
                continue
            seen_keys.add(key)
            if restrict_to_verified and not self._home_state_is_verified(key):
                continue

            dirs = self._smart_shuffle_group_dirs(sg)
            dir_match = any(self._home_canon_path_str(Path(str(p))) in selected_dir_keys for p in dirs)
            selected_by_user = key in selected_keys or dir_match
            media_type = str(getattr(sg, "media_type", "tv") or "tv").strip().casefold()
            title = str(getattr(sg, "display_title", "") or key)
            genres = tuple(str(x) for x in (getattr(sg, "genres", ()) or ()))
            overview = str(getattr(sg, "overview", "") or "")
            poster_path = str(getattr(sg, "poster_path", "") or "")
            backdrop_path = str(getattr(sg, "backdrop_path", "") or "")
            year = getattr(sg, "year", None)
            rating = getattr(sg, "rating", None)
            play_path = str(getattr(sg, "play_path", "") or "")
            next_episode_paths: Tuple[str, ...] = ()

            if media_type == "movie":
                if not play_path:
                    try:
                        pp = self._home_catalog._discover_play_path_for_movie(Path(str(getattr(sg, "primary_dir", ""))))
                        play_path = str(pp) if pp is not None else ""
                    except Exception:
                        play_path = ""
                if not play_path:
                    continue
            else:
                episode_refs = self._home_explicit_episode_refs_for_group(sg)
                if not episode_refs:
                    season_groups = self._home_find_season_groups_for_show_dirs(dirs)
                    season_dirs: List[Path] = []
                    for _label, folders in season_groups:
                        season_dirs.extend([Path(str(p)) for p in folders if p is not None])
                    episode_refs = self._home_list_episode_files_multi(season_dirs or dirs, dirs)
                episode_paths = [Path(str(ep.episode_path)) for ep in episode_refs if getattr(ep, "episode_path", None) is not None]
                rotated = self._shuffle_rotate_from_resume(key, episode_paths)
                next_episode_paths = tuple(str(p) for p in rotated[:max_preview] if p is not None)
                if not next_episode_paths:
                    continue

            out.append(
                SmartTitleSource(
                    content_key=key,
                    title=title,
                    media_type=media_type,
                    genres=genres,
                    overview=overview,
                    year=year if isinstance(year, int) else None,
                    rating=float(rating) if isinstance(rating, (int, float)) else None,
                    play_path=str(play_path),
                    show_dirs=tuple(str(p) for p in dirs if p is not None),
                    next_episode_paths=next_episode_paths,
                    poster_path=poster_path,
                    backdrop_path=backdrop_path,
                    selected_by_user=bool(selected_by_user),
                )
            )

        return out

    def _smart_shuffle_collect_sources(self) -> List[SmartTitleSource]:
        out = self._smart_shuffle_collect_sources_from_groups(
            list(self._home_catalog_items or []),
            restrict_to_verified=True,
        )
        self._smart_shuffle_sources = list(out)
        selected_count = sum(1 for source in out if bool(getattr(source, "selected_by_user", False)))
        dprint(f"[SMART_SHUFFLE][POOL] verified sources={len(out)} selected={selected_count}")
        return out

    def _smart_shuffle_build_result(self, intake):
        sources = list(self._smart_shuffle_sources or [])
        if not sources:
            sources = self._smart_shuffle_collect_sources()
        state = dict(self._home_state)
        state["profile_preferences"] = dict(self._viewer_profile_current_preferences())
        state["active_profile_id"] = str(getattr(self, "_viewer_active_profile_id", "") or "").strip()
        state["selected_show_keys"] = [str(k).strip() for k in self._home_selected_shows.keys() if str(k).strip()]
        result = self._smart_shuffle_engine.generate(sources=sources, intake=intake, state=state)
        self._smart_shuffle_last_result = result
        return result

    def _home_shuffle_suggestion_content_key(self, mode_name: str, *, view_mode: Optional[str] = None) -> str:
        mode = str(mode_name or "smart_shuffle").strip().casefold() or "smart_shuffle"
        view = str(view_mode or getattr(self, "_home_view_mode", "all") or "all").strip().casefold() or "all"
        return f"smart_shuffle_suggestion::{view}::{mode}"

    def _home_is_shuffle_suggestion_key(self, content_key: str) -> bool:
        return str(content_key or "").strip().startswith("smart_shuffle_suggestion::")

    def _home_shuffle_suggestion_mode_from_key(self, content_key: str) -> str:
        raw = str(content_key or "").strip()
        if not raw:
            return ""
        parts = raw.split("::")
        if len(parts) >= 3:
            return str(parts[2] or "").strip().casefold()
        return ""

    def _home_shuffle_suggestion_modes(
        self,
        *,
        view_mode: str,
        source_count: int,
        movie_count: int,
        tv_count: int,
        continue_count: int,
        recent_count: int,
        favorite_count: int,
        distinct_genres: int,
    ) -> List[str]:
        if source_count <= 0:
            return []

        chosen: List[str] = []

        def push(mode_name: str, *, enabled: bool = True) -> None:
            wanted = str(mode_name or "").strip().casefold()
            if not enabled or not wanted or wanted in chosen:
                return
            chosen.append(wanted)

        if view_mode == "movies":
            push("movie_night", enabled=movie_count > 0)
            push("smart_shuffle")
            push("trust_me")
            push("surprise", enabled=distinct_genres >= 3 or source_count >= 8)
        elif view_mode == "tv":
            push("continue_momentum", enabled=continue_count > 0 or recent_count > 0 or tv_count >= 4)
            push("smart_shuffle")
            push("trust_me")
            push("surprise", enabled=distinct_genres >= 4 or source_count >= 10)
            push("movie_night", enabled=movie_count >= max(2, tv_count // 2))
        elif view_mode == "favorites":
            push("continue_momentum", enabled=continue_count > 0 or recent_count > 0)
            push("trust_me", enabled=favorite_count > 0)
            push("smart_shuffle")
            push("movie_night", enabled=movie_count >= 2)
            push("surprise", enabled=distinct_genres >= 4 or favorite_count >= 4)
        else:
            push("continue_momentum", enabled=continue_count > 0)
            push("movie_night", enabled=movie_count >= max(3, int(round(source_count * 0.30))))
            push("smart_shuffle")
            push("trust_me")
            push("surprise", enabled=distinct_genres >= 5 or recent_count <= 1)

        for fallback_mode in ("smart_shuffle", "trust_me", "continue_momentum", "movie_night", "surprise"):
            push(
                fallback_mode,
                enabled=not (
                    fallback_mode == "continue_momentum" and tv_count <= 0 and continue_count <= 0 and recent_count <= 0
                ) and not (
                    fallback_mode == "movie_night" and movie_count <= 0
                ),
            )
            if len(chosen) >= 4:
                break

        return chosen[:4]

    def _home_shuffle_suggestion_intake(
        self,
        mode_name: str,
        *,
        view_mode: str,
        movie_count: int,
        tv_count: int,
        continue_count: int,
        favorite_count: int,
        distinct_genres: int,
    ):
        intake = self._smart_shuffle_engine.default_intake(str(mode_name or "smart_shuffle"))
        prefer_movies = view_mode == "movies" or (movie_count > max(2, tv_count) and str(mode_name) != "continue_momentum")
        prefer_tv = view_mode == "tv" or (tv_count > max(2, movie_count) and str(mode_name) == "continue_momentum")
        return replace(
            intake,
            prefer_movies_over_tv=bool(prefer_movies),
            prefer_tv_over_movies=bool(prefer_tv and not prefer_movies),
            protect_story_arcs=bool(getattr(intake, "protect_story_arcs", False) or (continue_count > 0 and str(mode_name) != "movie_night")),
            bring_back_forgotten_favorites=bool(getattr(intake, "bring_back_forgotten_favorites", False) or favorite_count > 0),
            show_hidden_gems=bool(getattr(intake, "show_hidden_gems", False) or distinct_genres >= 6 or str(mode_name) == "surprise"),
        )

    def _home_shuffle_suggestion_art_paths(self, result: Any) -> Tuple[Optional[Path], Optional[Path]]:
        chosen_backdrop: Optional[Path] = None
        chosen_poster: Optional[Path] = None
        for profile in list(getattr(result, "profiles", ()) or ()):
            raw_backdrop = str(getattr(profile, "backdrop_path", "") or "").strip()
            raw_poster = str(getattr(profile, "poster_path", "") or "").strip()
            if chosen_backdrop is None and raw_backdrop:
                try:
                    backdrop_path = Path(raw_backdrop)
                    if backdrop_path.exists():
                        chosen_backdrop = backdrop_path
                except Exception:
                    pass
            if chosen_poster is None and raw_poster:
                try:
                    poster_path = Path(raw_poster)
                    if poster_path.exists():
                        chosen_poster = poster_path
                except Exception:
                    pass
            if chosen_backdrop is not None and chosen_poster is not None:
                break
        if chosen_backdrop is None:
            chosen_backdrop = chosen_poster
        if chosen_poster is None:
            chosen_poster = chosen_backdrop
        return chosen_backdrop, chosen_poster

    def _home_build_shuffle_suggestion_items(
        self,
        *,
        view_mode: str,
        active_items: List[ShowGroup],
        continue_watching: List[ShowGroup],
        recently_watched: List[ShowGroup],
        favorites_row: List[ShowGroup],
    ) -> List[ShowGroup]:
        self._home_shuffle_suggestion_results = {}
        sources = self._smart_shuffle_collect_sources_from_groups(list(active_items or []), restrict_to_verified=False)
        if len(sources) <= 0:
            return []

        distinct_genres = len(
            {
                str(genre).strip().casefold()
                for item in list(active_items or [])
                for genre in (getattr(item, "genres", ()) or ())
                if str(genre).strip()
            }
        )
        source_movie_count = len([source for source in sources if str(getattr(source, "media_type", "")).casefold() == "movie"])
        source_tv_count = len([source for source in sources if str(getattr(source, "media_type", "")).casefold() != "movie"])
        candidate_modes = self._home_shuffle_suggestion_modes(
            view_mode=str(view_mode or "all"),
            source_count=len(sources),
            movie_count=source_movie_count,
            tv_count=source_tv_count,
            continue_count=len(list(continue_watching or [])),
            recent_count=len(list(recently_watched or [])),
            favorite_count=len(list(favorites_row or [])),
            distinct_genres=distinct_genres,
        )
        if not candidate_modes:
            return []

        base_state = dict(self._home_state)
        base_state["profile_preferences"] = dict(self._viewer_profile_current_preferences())
        base_state["active_profile_id"] = str(getattr(self, "_viewer_active_profile_id", "") or "").strip()
        base_state["selected_show_keys"] = [str(k).strip() for k in self._home_selected_shows.keys() if str(k).strip()]
        base_state["home_view_mode"] = str(view_mode or "all")

        results: Dict[str, Any] = {}
        cards: List[ShowGroup] = []
        stamp = float(time.time())
        for card_index, mode_name in enumerate(candidate_modes):
            intake = self._home_shuffle_suggestion_intake(
                mode_name,
                view_mode=str(view_mode or "all"),
                movie_count=source_movie_count,
                tv_count=source_tv_count,
                continue_count=len(list(continue_watching or [])),
                favorite_count=len(list(favorites_row or [])),
                distinct_genres=distinct_genres,
            )
            try:
                result = self._smart_shuffle_engine.generate(
                    sources=sources,
                    intake=intake,
                    state=dict(base_state),
                    remember_session=False,
                )
            except Exception as e:
                dprint("[HOME][SHUFFLE][WARN] suggestion generation failed:", mode_name, e)
                continue

            content_key = self._home_shuffle_suggestion_content_key(mode_name, view_mode=view_mode)
            results[content_key] = result

            plan = getattr(result, "plan", None)
            backdrop_path, poster_path = self._home_shuffle_suggestion_art_paths(result)
            rationale: List[str] = []
            summary_text = str(getattr(plan, "summary", "") or "").strip()
            if summary_text:
                rationale.append(summary_text)
            explanation_lines = list(getattr(plan, "explanation_lines", ()) or ())
            if explanation_lines:
                rationale.append(str(explanation_lines[0] or "").strip())
            segment_titles = [str(getattr(seg, "title", "") or "").strip() for seg in list(getattr(plan, "segments", ()) or ())[:2]]
            segment_titles = [title for title in segment_titles if title]
            if segment_titles:
                rationale.append(f"Starts with {' then '.join(segment_titles)}.")

            genre_bits: List[str] = []
            for profile in list(getattr(result, "profiles", ()) or ())[:3]:
                for genre in list(getattr(profile, "genres", ()) or ()):
                    genre_label = str(genre or "").strip()
                    if genre_label and genre_label not in genre_bits:
                        genre_bits.append(genre_label)
                    if len(genre_bits) >= 3:
                        break
                if len(genre_bits) >= 3:
                    break

            primary_dir = self._cache_dir
            art_anchor = backdrop_path or poster_path
            if art_anchor is not None:
                try:
                    primary_dir = art_anchor.parent
                except Exception:
                    primary_dir = self._cache_dir

            cards.append(
                ShowGroup(
                    display_title=str(getattr(plan, "session_name", "") or getattr(plan, "mode_label", "") or "Suggested Shuffle"),
                    primary_dir=primary_dir,
                    poster_path=poster_path,
                    group_mtime=stamp + float(card_index),
                    all_dirs=[],
                    media_type="smart_shuffle",
                    play_path=None,
                    content_key=content_key,
                    genres=tuple(genre_bits[:3]),
                    overview=" ".join(part for part in rationale if str(part).strip()),
                    backdrop_path=backdrop_path,
                    classification_reason=f"smart-shuffle-suggestion:{mode_name}",
                )
            )

        self._home_shuffle_suggestion_results = results
        return cards

    def _home_start_shuffle_suggestion(self, content_key: str, mode_name: str) -> None:
        wanted_key = str(content_key or "").strip()
        wanted_mode = str(mode_name or "").strip().casefold() or self._home_shuffle_suggestion_mode_from_key(wanted_key) or "smart_shuffle"
        result = None
        if isinstance(getattr(self, "_home_shuffle_suggestion_results", None), dict):
            result = self._home_shuffle_suggestion_results.get(wanted_key)
        if result is None:
            try:
                result = self._smart_shuffle_build_result(self._smart_shuffle_engine.default_intake(wanted_mode))
            except Exception as e:
                dprint("[HOME][SHUFFLE][WARN] suggestion fallback failed:", wanted_mode, e)
                self._smart_shuffle_open_dialog(wanted_mode)
                return
        self._smart_shuffle_start_result(result)

    def _smart_shuffle_segment_index_for_playlist_index(self, playlist_index: int) -> int:
        state = self._smart_shuffle_session_state
        if state is None:
            return 0
        cursor = 0
        for idx, seg in enumerate(state.plan.segments):
            cursor += max(1, len(seg.media_paths))
            if playlist_index < cursor:
                return idx
        return max(0, len(state.plan.segments) - 1)

    def _smart_shuffle_current_playlist_index(self) -> int:
        if self._mpv is not None:
            try:
                pos = self._mpv.get_playlist_pos()
                if isinstance(pos, int) and pos >= 0:
                    return int(pos)
            except Exception:
                pass
        state = self._smart_shuffle_session_state
        return int(getattr(state, "current_playlist_index", 0) or 0) if state is not None else 0

    def _smart_shuffle_update_live_strip(self) -> None:
        strip = self._smart_shuffle_live_strip
        state = self._smart_shuffle_session_state
        if strip is None:
            return
        if state is None:
            strip.setVisible(False)
            return
        idx = self._smart_shuffle_current_playlist_index()
        state.current_playlist_index = idx
        seg_idx = self._smart_shuffle_segment_index_for_playlist_index(idx)
        title = state.plan.segments[seg_idx].title if state.plan.segments else state.plan.session_name
        strip.set_plan(state.plan, seg_idx, current_title=title)
        strip.setVisible(True)

    def _smart_shuffle_start_result(self, result) -> None:
        plan = result.plan
        queue_pairs: List[Tuple[str, str]] = []
        for seg in plan.segments:
            for path in list(seg.media_paths or ()):
                if str(path).strip():
                    queue_pairs.append((str(seg.content_key), str(path)))
        if not queue_pairs:
            QMessageBox.information(self.win, "Smart Shuffle", "The generated session did not contain any playable items.")
            return

        self._shuffle_deactivate(clear_queue=True)
        self._shuffle_plan = list(queue_pairs)
        self._home_shuffle_queue = [path for _show_key, path in queue_pairs]
        self._shuffle_path_to_show = {
            self._home_canon_path_str(Path(path)): show_key
            for show_key, path in queue_pairs
        }
        self._shuffle_active = True
        self._shuffle_last_playlist_pos = None
        self._shuffle_last_path_key = ""
        self._smart_shuffle_session_state = SmartShuffleSessionState(
            plan=plan,
            playlist_paths=[path for _show_key, path in queue_pairs],
            playlist_content_keys=[show_key for show_key, _path in queue_pairs],
            current_playlist_index=0,
            source="smart_shuffle",
        )
        self._smart_shuffle_started_paths = set()
        self._smart_shuffle_finished_paths = set()
        self._smart_shuffle_last_logged_path_key = ""
        self._smart_shuffle_pending_feedback = True
        self._saved_mix_register_session(
            mode="smart_shuffle",
            mode_label=str(getattr(plan, "mode_label", "") or "Smart Shuffle"),
            selected_items=list(self._home_selected_shows.values()),
            queue_pairs=queue_pairs,
        )
        self._player_set_playlist_drawer_open(False)
        self._player_playlist_signature = ""

        first_show, first_path = queue_pairs[0]
        self._current_path = Path(first_path)
        self._finish_mark_path_key = ""
        self._player_reset_segment_skip_state(self._home_canon_path_str(Path(first_path)))
        self._home_state_record_play_start(Path(first_path))
        self._shuffle_mark_leftoff(first_show, Path(first_path))

        self._player_apply_elite_layout()
        self._player_apply_controls_chrome()

        if self._mpv is None:
            self._shuffle_deactivate(clear_queue=False)
            QMessageBox.warning(self.win, "Player Unavailable", "Smart Shuffle session created, but MPV is not available.")
            return

        try:
            self.pages.setCurrentWidget(self.playerPage)
        except Exception:
            pass

        try:
            if self.videoHost is not None:
                self._mpv.set_wid(int(self.videoHost.winId()))
        except Exception:
            pass

        self._player_release_seek_lock()
        self._pending_seek_ratio = None
        self._mpv_time_unit = None

        try:
            self._mpv.load_playlist(self._home_shuffle_queue, play_immediately=True)
        except Exception as e:
            dprint("[SMART_SHUFFLE][WARN] Playlist load failed, falling back to first item:", e)
            self._shuffle_deactivate(clear_queue=True)
            self.play_path(first_path)
            return

        self._smart_shuffle_update_live_strip()
        self._player_update_playlist_drawer_contents()
        self._player_tick_ui()

    def _smart_shuffle_playlist_meta(self, content_key: str) -> Dict[str, object]:
        result = self._smart_shuffle_last_result
        profile = None
        if result is not None:
            for item in list(getattr(result, "profiles", ()) or ()):
                if str(getattr(item, "content_key", "") or "") == str(content_key):
                    profile = item
                    break
        intake = getattr(result, "intake", None)
        cluster_size = 1
        state = self._smart_shuffle_session_state
        if state is not None:
            for seg in list(state.plan.segments or ()):
                if str(seg.content_key) == str(content_key):
                    cluster_size = max(cluster_size, len(seg.media_paths or ()))
        hour = int(time.strftime("%H"))
        return {
            "late_night": bool(hour >= 22 or hour <= 5),
            "dark": bool(getattr(profile, "darkness_level", 0.0) >= 0.55) if profile is not None else False,
            "tired": bool(getattr(intake, "current_energy", "") in {"drained", "low_okay"}) if intake is not None else False,
            "familiar": bool(getattr(profile, "user_familiarity_score", 0.0) >= 0.58) if profile is not None else False,
            "cluster_size": int(cluster_size),
        }

    def _smart_shuffle_record_event(self, event_type: str, content_key: str, path_key: str) -> None:
        if self._smart_shuffle_session_state is None:
            return
        title = str(content_key)
        result = self._smart_shuffle_last_result
        if result is not None:
            for item in list(getattr(result, "profiles", ()) or ()):
                if str(getattr(item, "content_key", "") or "") == str(content_key):
                    title = str(getattr(item, "title", content_key) or content_key)
                    break
        self._smart_shuffle_engine.learning.record_event(
            session_id=self._smart_shuffle_session_state.plan.session_id,
            event_type=str(event_type),
            content_key=str(content_key),
            title=title,
            metadata=self._smart_shuffle_playlist_meta(content_key),
        )
        dprint(f"[SMART_SHUFFLE][LEARN] {event_type} {content_key} {path_key}")

    def _smart_shuffle_on_queue_position_changed(self, pos: int, path: Path, show_key: str) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        path_key = self._home_canon_path_str(Path(str(path)))
        previous_key = str(self._smart_shuffle_last_logged_path_key or "")
        if previous_key and previous_key != path_key and previous_key not in self._smart_shuffle_finished_paths:
            try:
                prev_index = next(i for i, item in enumerate(state.playlist_paths) if self._home_canon_path_str(Path(item)) == previous_key)
                prev_content_key = state.playlist_content_keys[prev_index]
                self._smart_shuffle_record_event("skip", prev_content_key, previous_key)
            except Exception:
                pass
        state.current_playlist_index = int(pos)
        self._smart_shuffle_last_logged_path_key = path_key
        if path_key not in self._smart_shuffle_started_paths:
            self._smart_shuffle_started_paths.add(path_key)
            self._smart_shuffle_record_event("start", str(show_key or state.playlist_content_keys[pos]), path_key)
        self._smart_shuffle_update_live_strip()
        self._player_update_playlist_drawer_contents()
    def _smart_shuffle_on_finish(self, path_key: str) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        canon = str(path_key or "").strip()
        if not canon or canon in self._smart_shuffle_finished_paths:
            return
        try:
            index = next(i for i, item in enumerate(state.playlist_paths) if self._home_canon_path_str(Path(item)) == canon)
        except Exception:
            return
        self._smart_shuffle_finished_paths.add(canon)
        self._smart_shuffle_record_event("finish", state.playlist_content_keys[index], canon)
        if index >= len(state.playlist_paths) - 1 and self._smart_shuffle_pending_feedback:
            self._smart_shuffle_pending_feedback = False
            QTimer.singleShot(650, self._smart_shuffle_prompt_feedback)

    def _smart_shuffle_prompt_feedback(self) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        box = QMessageBox(self.win)
        box.setWindowTitle("Smart Shuffle Reflection")
        box.setText("How did that session feel?")
        box.setInformativeText("This stays local and quietly tunes future sessions.")
        btn_perfect = box.addButton("Perfect", QMessageBox.AcceptRole)
        btn_variety = box.addButton("Wanted more variety", QMessageBox.ActionRole)
        btn_continuity = box.addButton("Wanted more continuity", QMessageBox.ActionRole)
        btn_heavy = box.addButton("Too heavy", QMessageBox.DestructiveRole)
        btn_light = box.addButton("Too light", QMessageBox.ResetRole)
        box.addButton("Skip", QMessageBox.RejectRole)
        try:
            box.exec()
        except Exception:
            return
        clicked = box.clickedButton()
        verdict = ""
        notes: List[str] = []
        if clicked is btn_perfect:
            verdict = "perfect"
            notes = ["want more like this"]
        elif clicked is btn_variety:
            verdict = "more_variety"
            notes = ["wanted more variety"]
        elif clicked is btn_continuity:
            verdict = "more_continuity"
            notes = ["wanted more continuity"]
        elif clicked is btn_heavy:
            verdict = "too_heavy"
            notes = ["too heavy"]
        elif clicked is btn_light:
            verdict = "too_light"
            notes = ["too light"]
        if verdict:
            self._smart_shuffle_engine.learning.record_feedback(state.plan.session_id, verdict, notes)
    def _smart_shuffle_move_playlist_item(self, from_index: int, to_index: int) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        if from_index == to_index or from_index < 0 or to_index < 0:
            return
        if from_index >= len(self._shuffle_plan) or to_index >= len(self._shuffle_plan):
            return

        pair = self._shuffle_plan.pop(from_index)
        self._shuffle_plan.insert(to_index, pair)
        path = self._home_shuffle_queue.pop(from_index)
        self._home_shuffle_queue.insert(to_index, path)
        state_path = state.playlist_paths.pop(from_index)
        state.playlist_paths.insert(to_index, state_path)
        state_key = state.playlist_content_keys.pop(from_index)
        state.playlist_content_keys.insert(to_index, state_key)
        try:
            if self._mpv is not None:
                self._mpv.playlist_move(int(from_index), int(to_index))
        except Exception as e:
            dprint("[SMART_SHUFFLE][WARN] playlist move failed:", e)
        self._saved_mix_sync_active_state(save=True, force=True)
        self._player_update_playlist_drawer_contents()

    def _smart_shuffle_append_paths(self, content_key: str, paths: List[str]) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        for path in [str(p) for p in paths if str(p).strip()]:
            self._shuffle_plan.append((str(content_key), path))
            self._home_shuffle_queue.append(path)
            state.playlist_paths.append(path)
            state.playlist_content_keys.append(str(content_key))
            self._shuffle_path_to_show[self._home_canon_path_str(Path(path))] = str(content_key)
            try:
                if self._mpv is not None:
                    self._mpv.playlist_append(path)
            except Exception as e:
                dprint("[SMART_SHUFFLE][WARN] playlist append failed:", e)
        self._saved_mix_sync_active_state(save=True, force=True)
        self._player_update_playlist_drawer_contents()

    def _smart_shuffle_pick_remaining_index(self, *, current_index: int, score_fn) -> int:
        state = self._smart_shuffle_session_state
        if state is None:
            return -1
        best_index = -1
        best_score = -1.0
        for idx in range(current_index + 1, len(state.playlist_paths)):
            content_key = state.playlist_content_keys[idx]
            score = float(score_fn(str(content_key), idx))
            if score > best_score:
                best_score = score
                best_index = idx
        return best_index

    def _smart_shuffle_handle_live_action(self, action: str) -> None:
        state = self._smart_shuffle_session_state
        if state is None:
            return
        current_index = self._smart_shuffle_current_playlist_index()
        if current_index < 0 or current_index >= len(state.playlist_paths):
            return
        current_key = str(state.playlist_content_keys[current_index])
        result = self._smart_shuffle_last_result
        profile_map = {
            str(getattr(item, "content_key", "") or ""): item
            for item in list(getattr(result, "profiles", ()) or ())
        } if result is not None else {}

        if action == "stay_on_show":
            state.keep_continuity_bias = min(1.0, float(state.keep_continuity_bias) + 0.18)
            insertion = current_index + 1
            same_upcoming = [idx for idx in range(insertion, len(state.playlist_paths)) if str(state.playlist_content_keys[idx]) == current_key]
            for _idx in list(same_upcoming):
                next_same = next((cand for cand in range(insertion, len(state.playlist_paths)) if str(state.playlist_content_keys[cand]) == current_key), -1)
                if next_same < 0:
                    break
                self._smart_shuffle_move_playlist_item(next_same, insertion)
                insertion += 1
            if not same_upcoming:
                for source in list(self._smart_shuffle_sources or []):
                    if str(getattr(source, "content_key", "") or "") != current_key:
                        continue
                    used = {self._home_canon_path_str(Path(p)) for p in state.playlist_paths}
                    extras = [str(p) for p in list(getattr(source, "next_episode_paths", ()) or ()) if self._home_canon_path_str(Path(str(p))) not in used]
                    if extras:
                        self._smart_shuffle_append_paths(current_key, extras[:2])
                    break
        elif action == "switch_sooner":
            state.increase_variety_bias = min(1.0, float(state.increase_variety_bias) + 0.18)
            next_different = next((idx for idx in range(current_index + 1, len(state.playlist_paths)) if str(state.playlist_content_keys[idx]) != current_key), -1)
            if next_different >= 0:
                self._smart_shuffle_move_playlist_item(next_different, current_index + 1)
        elif action == "soft_landing":
            pick = self._smart_shuffle_pick_remaining_index(
                current_index=current_index,
                score_fn=lambda content_key, _idx: float(getattr(profile_map.get(content_key), "background_friendliness", 0.0))
                + float(getattr(profile_map.get(content_key), "late_night_friendliness", 0.0))
                + float(getattr(profile_map.get(content_key), "user_familiarity_score", 0.0))
                - float(getattr(profile_map.get(content_key), "darkness_level", 0.0)),
            )
            if pick >= 0:
                self._smart_shuffle_move_playlist_item(pick, len(state.playlist_paths) - 1)
        elif action == "more_familiar":
            pick = self._smart_shuffle_pick_remaining_index(
                current_index=current_index,
                score_fn=lambda content_key, _idx: float(getattr(profile_map.get(content_key), "user_familiarity_score", 0.0)) + float(getattr(profile_map.get(content_key), "comfort_score", 0.0)),
            )
            if pick >= 0:
                self._smart_shuffle_move_playlist_item(pick, current_index + 1)
        elif action == "more_adventurous":
            pick = self._smart_shuffle_pick_remaining_index(
                current_index=current_index,
                score_fn=lambda content_key, _idx: float(getattr(profile_map.get(content_key), "novelty_score", 0.0)) + float(getattr(profile_map.get(content_key), "energy_profile", 0.0)),
            )
            if pick >= 0:
                self._smart_shuffle_move_playlist_item(pick, current_index + 1)

        self._smart_shuffle_update_live_strip()
        self._player_update_playlist_drawer_contents()

    def _smart_shuffle_open_dialog(self, initial_mode: str = "smart_shuffle") -> None:
        sources = self._smart_shuffle_collect_sources()
        if not sources:
            QMessageBox.information(self.win, "Smart Shuffle", "No verified library items were available for Smart Shuffle.")
            return
        selected_titles = [str(item.title) for item in self._home_selected_shows.values() if str(getattr(item, "title", "") or "").strip()]
        dialog = SmartShuffleDialog(
            plan_builder=self._smart_shuffle_build_result,
            initial_mode=str(initial_mode or "smart_shuffle"),
            selected_titles=selected_titles,
            library_count=len(sources),
            parent=self.win,
        )
        try:
            accepted = dialog.exec() == QDialog.Accepted
        except Exception:
            accepted = False
        if not accepted:
            return
        result = dialog.selected_result()
        if result is None:
            return
        self._smart_shuffle_start_result(result)

    def _home_start_selected_smart_shuffle(self) -> None:
        self._smart_shuffle_open_dialog("smart_shuffle")

    def _home_start_selected_shuffle(self) -> None:
        self._home_start_selected_shuffle_common(mode_label="Shuffle")
    def _home_start_selected_shuffle_common(self, *, mode_label: str) -> None:
        self._shuffle_start_from_selected_items(
            list(self._home_selected_shows.values()),
            mode_label=str(mode_label or "Shuffle"),
        )
    # ============================================================
    # HOME MODULE: tools wiring + layout helpers + responsive profile
    # ============================================================

    def _home_wire_tools_actions(self) -> None:
        act = safe_find(self.win, "actionLibrary_Maintenance", QObject, required=False)
        if act is None:
            dprint("[TOOLS] actionLibrary_Maintenance not found (ok).")
        else:
            try:
                act.triggered.connect(self._library_ui_add_source)
                dprint("[TOOLS] Wired actionLibrary_Maintenance -> Add Library Source picker")
            except Exception as e:
                dprint("[TOOLS][WARN] Could not wire Library maintenance action:", e)

        manage = safe_find(self.win, "actionManage_Library_Folders", QObject, required=False)
        if manage is None:
            dprint("[TOOLS] actionManage_Library_Folders not found (ok).")
        else:
            try:
                manage.triggered.connect(self._library_ui_manage_sources_dialog)
                dprint("[TOOLS] Wired actionManage_Library_Folders -> source manager")
            except Exception as e:
                dprint("[TOOLS][WARN] Could not wire Library source manager action:", e)

        act2 = safe_find(self.win, "actionUpdate_Poster_Art", QObject, required=False)
        if act2 is None:
            dprint("[TOOLS] actionUpdate_Poster_Art not found (ok).")
            return
        try:
            act2.triggered.connect(self._ui_open_poster_art_dialog)
            dprint("[TOOLS] Wired actionUpdate_Poster_Art -> Poster Art dialog")
        except Exception as e:
            dprint("[TOOLS][WARN] Could not wire Update Poster Art action:", e)

    # ============================================================
    # SANDBOX-PROVEN: Fresh scroll host
    # ============================================================

    def _home_install_fresh_scroll_host(self) -> None:
        """
        Sandbox-proven fix for the "10,000px wide / black dead space" bug.

        Creates a brand-new QWidget and installs it as homeScrollArea's
        scroll widget, bypassing any stale Qt Designer widget geometry.
        Then builds a clean QVBoxLayout on it with AlignTop so vertical
        scroll content grows correctly.

        This is called from __init__ AFTER donor template capture but
        BEFORE any rail building.  It replaces _home_setup_center_lane +
        _home_ensure_vbox_layout for the common edge-to-edge use case.

        homeScrollContents and homeContent are both re-pointed to this
        fresh widget so all downstream _home_build / _home_make_row_block
        code continues to work without modification.
        """
