        self.homeScrollArea.setWidget(host)
        # Edge-to-edge: remove frames/margins and prevent any horizontal drift.
        try:
            self.homeScrollArea.setFrameShape(QFrame.NoFrame)
            self.homeScrollArea.setLineWidth(0)
            self.homeScrollArea.setMidLineWidth(0)
            self.homeScrollArea.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
            self.homeScrollArea.setAlignment(Qt.AlignLeft | Qt.AlignTop)
            self.homeScrollArea.setContentsMargins(0, 0, 0, 0)
            self.homeScrollArea.viewport().setContentsMargins(0, 0, 0, 0)
            self.homeScrollArea.setStyleSheet(self.homeScrollArea.styleSheet() + "\nQScrollArea{border:none; padding:0px;}")
            # Always start at x=0 so titles/cards are flush-left.
            self.homeScrollArea.horizontalScrollBar().setValue(0)
        except Exception:
            pass

        self.homeScrollArea.setWidgetResizable(True)
