    def _search_apply_selected_poster_art(self) -> None:
        sg = self._search_selected_group()
        candidate = self._search_selected_poster_candidate()
        if sg is None or candidate is None:
            return

        try:
            client = TMDBClient()
            size = "w1280" if str(candidate.kind) == "backdrop" else "w780"
            img_bytes = client.download_image_bytes(client.image_url(str(candidate.image_path), size=size))
        except Exception as exc:
            QMessageBox.warning(self.win, "Poster Browser", f"Could not download art.\n\n{type(exc).__name__}: {exc}")
            return

        targets = self._search_collect_target_dirs(sg)
        if not targets:
            QMessageBox.warning(self.win, "Poster Browser", "No writable media folders were found for this title.")
            return

        out_name = "backdrop.jpg" if str(candidate.kind) == "backdrop" else "poster.jpg"
        written = self._search_write_art_bytes_to_targets(targets, out_name, img_bytes)

        if written <= 0:
            QMessageBox.warning(self.win, "Poster Browser", "No poster files were updated.")
            return

        key = self._home_item_key(sg)
        self._search_refresh_after_local_art_change([key], reason="search-poster-change")
        self._search_set_poster_status(f"Applied {candidate.kind} art to {written} folder(s).")

