    def _search_update_details(self, key: str) -> None:
        sg = self._search_by_key.get(str(key or "").strip()) if hasattr(self, "_search_by_key") else None
        if sg is None:
            self._search_selected_key = ""
            self._search_poster_open_for_key = ""
            self._search_detail_title.setText("Select a title")
            self._search_detail_meta.setText("")
            self._search_detail_overview.setText("")
            self._search_detail_path.setText("")
            if self._search_selection_summary is not None:
                self._search_selection_summary.setText("Select one or more titles with drag, Shift, or Ctrl to work in batches.")
            self._search_render_current_card(None, 0)
            if self._search_btn_add_selected is not None:
                self._search_btn_add_selected.setText("Add")
                self._search_btn_add_selected.setEnabled(False)
            if self._search_btn_remove_selected is not None:
                self._search_btn_remove_selected.setText("Remove")
                self._search_btn_remove_selected.setEnabled(False)
            self._search_poster_candidates = []
            self._search_refresh_poster_browser_list()
            self._search_set_poster_status("Select a title to browse or refresh TMDB art here.")
            for btn in (
                self._search_btn_play, self._search_btn_details, self._search_btn_refresh_md,
                self._search_btn_change_poster, self._search_btn_watched, self._search_btn_favorite,
                self._search_btn_verify, self._search_btn_continue, self._search_btn_set_movie,
                self._search_btn_set_tv, self._search_btn_clear_type, self._search_btn_open_folder,
            ):
                btn.setEnabled(False)
            self._search_sync_manual_search_controls(None)
            self._search_update_batch_action_buttons()
            return

        self._search_selected_key = self._home_item_key(sg)
        title = str(getattr(sg, "display_title", "") or "Untitled")
        media = "MOVIE" if str(getattr(sg, "media_type", "")).casefold() == "movie" else "TV"
        year = getattr(sg, "year", None)
        rating = getattr(sg, "rating", None)
        genres = ", ".join(str(g) for g in (getattr(sg, "genres", ()) or ()) if str(g).strip())
        selection_keys = self._search_active_selection_keys()
        selection_count = len(selection_keys) if selection_keys else 1

        bits = [media]
        if year is not None:
            bits.append(str(year))
        if rating is not None:
            try:
                bits.append(f"{float(rating):.1f}/10")
            except Exception:
                pass
        if genres:
            bits.append(genres)

        self._search_detail_title.setText(title)
        self._search_detail_meta.setText("  |  ".join(bits))
        self._search_detail_overview.setText(str(getattr(sg, "overview", "") or "No overview available."))
        self._search_detail_path.setText(str(getattr(sg, "primary_dir", "") or ""))

        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}
        favorites = set(str(x) for x in (self._home_state.get("favorites", []) or []))
        all_watched = bool(selection_keys) and all(bool(watched_map.get(sel_key, False)) for sel_key in selection_keys)
        all_favorites = bool(selection_keys) and all(sel_key in favorites for sel_key in selection_keys)
        all_verified = bool(selection_keys) and all(self._home_state_is_verified(sel_key) for sel_key in selection_keys)

        source_label = "Discovered / Unadded" if self._search_selection_source == "discovered" else "Verified Library" if self._search_selection_source == "verified" else "Library"
        if self._search_selection_summary is not None:
            if selection_count > 1:
                self._search_selection_summary.setText(
                    f"{selection_count} selected in {source_label}. Batch actions apply to the full selection; preview, play, folder, and poster browsing follow the current row."
                )
            else:
                self._search_selection_summary.setText(
                    f"1 selected in {source_label}. Drag, Shift, or Ctrl to build a batch."
                )

        if selection_count > 1:
            self._search_btn_refresh_md.setText(f"Refresh ({selection_count})")
            self._search_btn_change_poster.setText("Art (Current)")
            self._search_btn_watched.setText("Watched")
            self._search_btn_favorite.setText("Favorite")
            self._search_btn_verify.setText("Library")
            self._search_btn_continue.setText("Continue")
            self._search_btn_set_movie.setText("Movie")
            self._search_btn_set_tv.setText("TV")
            self._search_btn_clear_type.setText(f"Clear Type ({selection_count})")
        else:
            self._search_btn_refresh_md.setText("Refresh")
            self._search_btn_change_poster.setText("Art")
            self._search_btn_watched.setText("Watched")
            self._search_btn_favorite.setText("Favorite")
            self._search_btn_verify.setText("Library")
            self._search_btn_continue.setText("Continue")
            self._search_btn_set_movie.setText("Movie")
            self._search_btn_set_tv.setText("TV")
            self._search_btn_clear_type.setText("Clear Type")

        if self._search_btn_add_selected is not None:
            discovered_selected = len(self._search_selected_keys_from_widget(self._search_discovered_list))
            self._search_btn_add_selected.setText(f"Add ({discovered_selected})" if discovered_selected > 1 else "Add")
            self._search_btn_add_selected.setEnabled(discovered_selected > 0)
        if self._search_btn_remove_selected is not None:
            verified_selected = len(self._search_selected_keys_from_widget(self._search_verified_list))
            self._search_btn_remove_selected.setText(f"Remove ({verified_selected})" if verified_selected > 1 else "Remove from Library")
            self._search_btn_remove_selected.setEnabled(verified_selected > 0)

        self._search_render_current_card(sg, selection_count)
        self._search_sync_manual_search_controls(sg)
        for btn in (
            self._search_btn_play, self._search_btn_details, self._search_btn_refresh_md,
            self._search_btn_change_poster, self._search_btn_watched, self._search_btn_favorite,
            self._search_btn_verify, self._search_btn_continue, self._search_btn_set_movie,
            self._search_btn_set_tv, self._search_btn_clear_type, self._search_btn_open_folder,
        ):
            btn.setEnabled(True)
        self._search_update_batch_action_buttons()

