    def _search_action_auto_match_all(self) -> None:
        unresolved_keys: List[str] = []
        for sg in list(self._search_all_items or self._home_catalog_items or []):
            if getattr(sg, "tmdb_id", None) is not None:
                continue
            key = self._home_item_key(sg)
            if not key:
                continue
            self._home_catalog.invalidate_item(key)
            unresolved_keys.append(key)

        if not unresolved_keys:
            dprint("[SEARCH] Auto Match All skipped; no unresolved titles found")
            return

        lookup_budget = min(max(24, len(unresolved_keys)), 84)
        dprint(
            f"[SEARCH] Auto Match All starting for {len(unresolved_keys)} unresolved titles "
            f"with max_network_lookups={lookup_budget}"
        )
        self._home_catalog_needs_refresh = True
        self._home_catalog_start_async_refresh(
            "search-auto-match-all",
            allow_network=True,
            max_network_lookups=lookup_budget,
        )

    def _search_action_refresh_unresolved(self) -> None:
        unresolved = 0
        for sg in list(self._search_all_items or self._home_catalog_items or []):
            if getattr(sg, "tmdb_id", None) is not None:
                continue
            key = self._home_item_key(sg)
            if not key:
                continue
            self._home_catalog.invalidate_item(key)
            unresolved += 1
        if unresolved > 0:
            dprint(f"[SEARCH] Refreshing unresolved metadata for {unresolved} titles")
            self._home_catalog_needs_refresh = True
            self._home_catalog_start_async_refresh(
                "search-refresh-unresolved",
                allow_network=True,
                max_network_lookups=min(max(24, unresolved), 84),
            )

    def _search_pick_best_tmdb_hit(self, query: str, media_hint: str, hits: List[TMDBHit]) -> Optional[TMDBHit]:
        clean_query = NameCleaner.clean(str(query or "")).casefold()
        if not clean_query:
            clean_query = str(query or "").strip().casefold()
        best_hit: Optional[TMDBHit] = None
        best_score = -1.0
        wanted_type = str(media_hint or "").strip().casefold()

        for hit in list(hits or []):
            clean_title = NameCleaner.clean(str(getattr(hit, "title", "") or "")).casefold()
            if not clean_title:
                clean_title = str(getattr(hit, "title", "") or "").strip().casefold()
            if not clean_title:
                continue
            score = SequenceMatcher(None, clean_query, clean_title).ratio()
            if clean_query == clean_title:
                score += 0.28
            elif clean_query and (clean_query in clean_title or clean_title in clean_query):
                score += 0.12
            if wanted_type in {"movie", "tv"} and str(getattr(hit, "media_type", "") or "").strip().casefold() == wanted_type:
                score += 0.2
            if score > best_score:
                best_score = score
                best_hit = hit

        if best_hit is None or best_score < 0.45:
            return None
        return best_hit

    def _search_action_batch_apply_backdrop_and_metadata(self) -> None:
        if self._search_batch_backdrop_match_running:
            return

        keys = self._search_selected_keys_from_widget(self._search_verified_list)
        if not keys:
            return

        work_items: List[Dict[str, Any]] = []
        for key in keys:
            sg = self._search_by_key.get(str(key)) if hasattr(self, "_search_by_key") else None
            if sg is None:
                continue
            work_items.append(
                {
                    "key": str(key),
                    "title": str(getattr(sg, "display_title", "") or "").strip(),
                    "media_hint": str(getattr(sg, "media_type", "") or "").strip().casefold(),
                    "targets": tuple(str(p) for p in self._search_collect_target_dirs(sg)),
                }
            )

        if not work_items:
            QMessageBox.information(self.win, "Backdrop + Match", "No verified titles were ready for batch processing.")
            return

        self._search_batch_backdrop_match_running = True
        self._search_batch_backdrop_match_token += 1
        token = int(self._search_batch_backdrop_match_token)
        self._search_batch_backdrop_match_summary = {
            "total": len(work_items),
            "processed": 0,
            "matched": 0,
            "metadata_applied": 0,
            "art_applied": 0,
            "changed_keys": [],
            "warnings": [],
            "errors": [],
        }
        self._search_update_batch_action_buttons()
        self._search_start_batch_backdrop_match_watch()
        if self._search_selection_summary is not None:
            self._search_selection_summary.setText(f"Applying first backdrops and best-match metadata to {len(work_items)} verified titles...")

        def _worker() -> None:
            def _cancelled() -> bool:
                if self._player_should_reduce_background_work():
                    return True
                return int(token) != int(getattr(self, "_search_batch_backdrop_match_token", 0) or 0)

            try:
                if _cancelled():
                    return
                client = TMDBClient()
            except Exception as exc:
                self._search_batch_backdrop_match_results.put(
                    (
                        token,
                        {
                            "type": "fatal",
                            "message": f"TMDB unavailable: {type(exc).__name__}: {exc}",
                        },
                    )
                )
                self._search_notify_batch_backdrop_results_ready()
                self._search_batch_backdrop_match_results.put((token, {"type": "done"}))
                self._search_notify_batch_backdrop_results_ready()
                return

            try:
                total = len(work_items)
                for index, item in enumerate(work_items, start=1):
                    if _cancelled():
                        break
                    payload: Dict[str, Any] = {
                        "type": "item",
                        "index": index,
                        "total": total,
                        "key": str(item.get("key") or ""),
                        "title": str(item.get("title") or "Untitled"),
                        "targets": tuple(item.get("targets") or ()),
                        "hit": None,
                        "backdrop_bytes": b"",
                        "warning": "",
                        "error": "",
                    }

                    query = str(item.get("title") or "").strip()
                    if not query:
                        payload["error"] = "The title has no searchable name."
                        self._search_batch_backdrop_match_results.put((token, payload))
                        self._search_notify_batch_backdrop_results_ready()
                        continue

                    try:
                        if _cancelled():
                            break
                        hits = list(client.search_multi(query, limit=10))
                        hit = self._search_pick_best_tmdb_hit(query, str(item.get("media_hint") or ""), hits)
                        if hit is None:
                            payload["error"] = "No confident TMDB match was found."
                            self._search_batch_backdrop_match_results.put((token, payload))
                            self._search_notify_batch_backdrop_results_ready()
                            continue
                        payload["hit"] = hit

                        image_path = ""
                        try:
                            if _cancelled():
                                break
                            images = client.get_item_images(str(hit.media_type), int(hit.id), limit=8)
                        except Exception as exc:
                            payload["warning"] = f"Backdrop lookup failed: {type(exc).__name__}: {exc}"
                            images = {}

                        backdrops = list(images.get("backdrops", []) or [])
                        if backdrops:
                            image_path = str(backdrops[0].get("file_path") or "").strip()
                        if not image_path:
                            image_path = str(getattr(hit, "backdrop_path", "") or "").strip()

                        if image_path:
                            try:
                                if _cancelled():
                                    break
                                payload["backdrop_bytes"] = client.download_image_bytes(
                                    client.image_url(image_path, size="w1280")
                                )
                            except Exception as exc:
                                payload["warning"] = f"Backdrop download failed: {type(exc).__name__}: {exc}"
                        elif not payload["warning"]:
                            payload["warning"] = "TMDB had no backdrop image for this title."
                    except Exception as exc:
                        payload["error"] = f"TMDB search failed: {type(exc).__name__}: {exc}"

                    if _cancelled():
                        break
                    self._search_batch_backdrop_match_results.put((token, payload))
                    self._search_notify_batch_backdrop_results_ready()
            finally:
                self._search_batch_backdrop_match_results.put((token, {"type": "done"}))
                self._search_notify_batch_backdrop_results_ready()

        threading.Thread(target=_worker, name="omega-search-batch-backdrop-match", daemon=True).start()

    def _search_poll_batch_backdrop_match_results(self) -> None:
        processed = 0
        while processed < 8:
            try:
                token, payload = self._search_batch_backdrop_match_results.get_nowait()
            except queue.Empty:
                break

            processed += 1
            if int(token) != int(getattr(self, "_search_batch_backdrop_match_token", 0) or 0):
                continue

            kind = str(payload.get("type") or "").strip().casefold()
            summary = self._search_batch_backdrop_match_summary if isinstance(self._search_batch_backdrop_match_summary, dict) else {}
            if kind == "fatal":
                msg = str(payload.get("message") or "").strip()
                if msg:
                    summary.setdefault("errors", []).append(msg)
                continue

            if kind == "item":
                key = str(payload.get("key") or "").strip()
                title = str(payload.get("title") or "Untitled").strip() or "Untitled"
                hit = payload.get("hit")
                warning = str(payload.get("warning") or "").strip()
                error = str(payload.get("error") or "").strip()
                targets = [Path(str(p)) for p in list(payload.get("targets") or []) if str(p).strip()]
                changed = False

                if isinstance(hit, TMDBHit) and key:
                    metadata = self._home_catalog.set_manual_match(key, hit)
                    if metadata:
                        summary["matched"] = int(summary.get("matched") or 0) + 1
                        summary["metadata_applied"] = int(summary.get("metadata_applied") or 0) + 1
                        changed = True
                    elif not error:
                        error = "TMDB metadata could not be linked."

                backdrop_bytes = bytes(payload.get("backdrop_bytes") or b"")
                if backdrop_bytes:
                    written = self._search_write_art_bytes_to_targets(targets, "backdrop.jpg", backdrop_bytes)
                    if written > 0:
                        summary["art_applied"] = int(summary.get("art_applied") or 0) + 1
                        changed = True
                    elif not error and targets:
                        error = "Backdrop download succeeded, but no backdrop files were written."
                elif not targets and not error:
                    warning = "No writable media folders were available for backdrop art."

                if key:
                    self._search_clear_poster_cache_for_item(key)
                if changed and key:
                    changed_keys = summary.setdefault("changed_keys", [])
                    if key not in changed_keys:
                        changed_keys.append(key)

                if warning:
                    summary.setdefault("warnings", []).append(f"{title}: {warning}")
                if error:
                    summary.setdefault("errors", []).append(f"{title}: {error}")

                summary["processed"] = int(summary.get("processed") or 0) + 1
                total = int(summary.get("total") or 0)
                done = int(summary.get("processed") or 0)
                if self._search_selection_summary is not None and total > 0:
                    self._search_selection_summary.setText(
                        f"Applying first backdrops and best-match metadata... {done}/{total} titles finished."
                    )
                continue

            if kind == "done":
                self._search_batch_backdrop_match_running = False
                self._search_stop_batch_backdrop_match_watch()
                self._search_update_batch_action_buttons()

                changed_keys = list(summary.get("changed_keys") or [])
                if changed_keys:
                    self._search_refresh_after_local_art_change(changed_keys, reason="search-batch-backdrop-match")
                else:
                    self._search_request_refresh()

                total = int(summary.get("total") or 0)
                metadata_applied = int(summary.get("metadata_applied") or 0)
                art_applied = int(summary.get("art_applied") or 0)
                warnings = list(summary.get("warnings") or [])
                errors = list(summary.get("errors") or [])
                message = (
                    f"Processed {total} title(s).\n"
                    f"Metadata linked: {metadata_applied}\n"
                    f"Backdrops applied: {art_applied}"
                )
                if warnings:
                    message += "\n\nWarnings:\n- " + "\n- ".join(warnings[:8])
                if errors:
                    message += "\n\nProblems:\n- " + "\n- ".join(errors[:8])
                if len(warnings) > 8 or len(errors) > 8:
                    message += "\n- Additional titles were omitted from this summary."

                if self._search_metadata_status is not None:
                    self._search_metadata_status.setText(
                        f"Batch backdrop + metadata complete. Linked {metadata_applied} title(s) and applied {art_applied} backdrop(s)."
                    )
                if self._search_selection_summary is not None:
                    self._search_selection_summary.setText(
                        f"Batch backdrop + metadata complete for {total} title(s)."
                    )
                QMessageBox.information(self.win, "Backdrop + Match", message)
                self._search_batch_backdrop_match_summary = {}
                return

        if (
            processed <= 0
            and not bool(getattr(self, "_search_batch_backdrop_match_running", False))
            and self._search_batch_backdrop_match_results.empty()
        ):
            self._search_stop_batch_backdrop_match_watch()
        elif not self._search_batch_backdrop_match_results.empty():
            self._search_start_batch_backdrop_match_watch()

    def _search_extract_season_number_from_name(self, name: str) -> Optional[int]:
        text = str(name or "").strip()
        if not text:
            return None
        match = re.search(r"(?:season\s*[_-]*\s*|^s)(\d{1,2})\b", text, re.IGNORECASE)
        if match:
            try:
                return int(match.group(1))
            except Exception:
                return None
        return None

    def _search_episode_identity(self, episode_path: Path) -> Tuple[Optional[int], Optional[int]]:
        season_num, episode_num = parse_season_episode(episode_path.stem)
        if season_num is None:
            season_num = self._search_extract_season_number_from_name(episode_path.parent.name)
        return season_num, episode_num

    def _search_episode_summary(self, episode_path: Path, season_num: Optional[int], episode_num: Optional[int]) -> str:
        if season_num is not None and episode_num is not None:
            slot = f"S{int(season_num):02d}E{int(episode_num):02d}"
        elif episode_num is not None:
            slot = f"Episode {int(episode_num)}"
        elif season_num is not None:
            slot = f"Season {int(season_num)}"
        else:
            slot = "Episode File"
        return f"{slot}  |  {episode_path.name}"

    def _search_collect_episode_refs_for_group(self, sg: ShowGroup) -> List[EpisodeRef]:
        explicit_refs = self._home_explicit_episode_refs_for_group(sg)
        if explicit_refs:
            return explicit_refs

        show_dirs = self._search_collect_target_dirs(sg)
        if not show_dirs:
            return []

        season_groups = self._home_find_season_groups_for_show_dirs(show_dirs)
        season_dirs: List[Path] = []
        for _label, dirs in season_groups:
            season_dirs.extend([Path(str(p)) for p in dirs if p is not None])
        if not season_dirs:
            season_dirs = list(show_dirs)

        refs = self._home_list_episode_files_multi(season_dirs=season_dirs, show_dirs=show_dirs)
        out: List[EpisodeRef] = []
        seen: set[str] = set()
        for ref in refs:
            episode_path = Path(str(getattr(ref, "episode_path", "")))
            if not episode_path.exists() or not episode_path.is_file():
                continue
            key = self._home_canon_path_str(episode_path)
            if not key or key in seen:
                continue
            seen.add(key)
            out.append(ref)
        return out

    def _search_group_contains_episode_candidates(self, sg: ShowGroup) -> bool:
        refs = self._search_collect_episode_refs_for_group(sg)
        if not refs:
            return False
        if str(getattr(sg, "media_type", "") or "").strip().casefold() != "movie":
            return True
        for ref in refs:
            season_num, episode_num = self._search_episode_identity(Path(str(ref.episode_path)))
            if episode_num is not None or season_num is not None:
                return True
        return False

    def _search_destination_path_key(self, path: Path) -> str:
        return str(path).rstrip("\\/").casefold()

    def _search_target_show_root(self, sg: ShowGroup) -> Optional[Path]:
        primary = Path(str(getattr(sg, "primary_dir", "")))
        if primary.exists() and primary.is_dir():
            return primary
        if primary.parent.exists() and primary.parent.is_dir():
            return primary.parent
        targets = self._search_collect_target_dirs(sg)
        return targets[0] if targets else None

    def _search_target_season_dir(self, show_root: Path, season_num: Optional[int]) -> Path:
        wanted = int(season_num) if season_num is not None and int(season_num) > 0 else 1
        try:
            for child in show_root.iterdir():
                if child.is_dir() and self._search_extract_season_number_from_name(child.name) == wanted:
                    return child
        except Exception:
            pass
        return show_root / f"Season {wanted}"

    def _search_normalize_episode_filename(self, raw_name: str, source_path: Path) -> str:
        name = str(raw_name or "").strip()
        if not name:
            name = source_path.name
        name = name.replace("/", " ").replace("\\", " ")
        name = re.sub(r'[<>:"|?*]', "", name).strip().rstrip(". ")
        if not name:
            name = source_path.stem
        suffix = Path(name).suffix
        if not suffix:
            name = f"{name}{source_path.suffix or '.mkv'}"
        return name

    def _search_unique_destination_path(self, dest_dir: Path, file_name: str) -> Path:
        candidate = dest_dir / str(file_name)
        stem = candidate.stem
        suffix = candidate.suffix
        counter = 2
        while candidate.exists():
            candidate = dest_dir / f"{stem} ({counter}){suffix}"
            counter += 1
        return candidate

    def _search_suggest_duplicate_episode_name(self, plan: SearchEpisodeMergePlan) -> str:
        base = Path(plan.source_path.name).stem
        suffix = plan.source_path.suffix or ".mkv"
        if plan.season_num is not None and plan.episode_num is not None:
            base = f"{base} (Alt Cut)"
        else:
            base = f"{base} (Duplicate)"
        return self._search_normalize_episode_filename(f"{base}{suffix}", plan.source_path)

    def _search_choose_episode_merge_target(self, source_groups: List[ShowGroup]) -> Optional[ShowGroup]:
        verified_tv = [
            sg
            for sg in list(self._search_all_items or self._home_catalog_items or [])
            if self._home_state_is_verified(self._home_item_key(sg))
            and str(getattr(sg, "media_type", "") or "").strip().casefold() != "movie"
        ]
        if not verified_tv:
            QMessageBox.information(self.win, "Merge Episodes", "No verified TV shows are available yet. Add the main show first.")
            return None

        verified_tv.sort(key=lambda sg: str(getattr(sg, "display_title", "") or "").casefold())
        source_title = ""
        if source_groups:
            source_title = NameCleaner.clean(str(getattr(source_groups[0], "display_title", "") or "")).casefold()

        options: List[str] = []
        best_index = 0
        best_score = -1.0
        for index, sg in enumerate(verified_tv):
            title = str(getattr(sg, "display_title", "") or "Untitled").strip() or "Untitled"
            year = getattr(sg, "year", None)
            root = self._search_target_show_root(sg)
            suffix = f" ({year})" if year is not None else ""
            label = f"{title}{suffix}  |  {str(root or getattr(sg, 'primary_dir', ''))}"
            options.append(label)
            score = 0.0
            clean_title = NameCleaner.clean(title).casefold()
            if source_title and clean_title:
                score = SequenceMatcher(None, source_title, clean_title).ratio()
                if source_title == clean_title:
                    score += 0.35
            if score > best_score:
                best_score = score
                best_index = index

        choice, ok = QInputDialog.getItem(
            self.win,
            "Merge Episodes",
            "Choose the verified show that should receive these episode files:",
            options,
            max(0, min(best_index, len(options) - 1)),
            False,
        )
        if not ok:
            return None
        try:
            picked_index = options.index(str(choice))
        except ValueError:
            return None
        return verified_tv[picked_index]

    def _search_build_episode_merge_plans(
        self,
        source_groups: List[ShowGroup],
        target_group: ShowGroup,
    ) -> Tuple[List[SearchEpisodeMergePlan], List[str]]:
        target_root = self._search_target_show_root(target_group)
        if target_root is None:
            return [], ["The target show does not have a writable root folder."]

        warnings: List[str] = []
        existing_refs = self._search_collect_episode_refs_for_group(target_group)
        existing_slots: Dict[Tuple[int, int], Path] = {}
        existing_destinations: Dict[str, Path] = {}
        for ref in existing_refs:
            existing_path = Path(str(ref.episode_path))
            season_num, episode_num = self._search_episode_identity(existing_path)
            if season_num is not None and episode_num is not None:
                existing_slots.setdefault((int(season_num), int(episode_num)), existing_path)
            existing_destinations[self._search_destination_path_key(existing_path)] = existing_path

        plans: List[SearchEpisodeMergePlan] = []
        incoming_slots: Dict[Tuple[int, int], Path] = {}
        incoming_destinations: Dict[str, Path] = {}

        for sg in source_groups:
            refs = self._search_collect_episode_refs_for_group(sg)
            if not refs:
                warnings.append(f"{str(getattr(sg, 'display_title', '') or 'Untitled')}: no episode files were found.")
                continue

            for ref in refs:
                source_path = Path(str(ref.episode_path))
                season_num, episode_num = self._search_episode_identity(source_path)
                dest_dir = self._search_target_season_dir(target_root, season_num)
                dest_name = source_path.name
                duplicate_path: Optional[Path] = None
                duplicate_label = ""

                slot_key = (
                    (int(season_num), int(episode_num))
                    if season_num is not None and episode_num is not None
                    else None
                )
                if slot_key is not None and slot_key in existing_slots:
                    duplicate_path = existing_slots[slot_key]
                    duplicate_label = f"Existing slot already present: {existing_slots[slot_key].name}"

                dest_key = self._search_destination_path_key(dest_dir / dest_name)
                if not duplicate_label and dest_key in existing_destinations:
                    duplicate_path = existing_destinations[dest_key]
                    duplicate_label = f"Existing file already present: {existing_destinations[dest_key].name}"

                if slot_key is not None and slot_key not in incoming_slots:
                    incoming_slots[slot_key] = source_path
                elif slot_key is not None and not duplicate_label:
                    duplicate_path = incoming_slots[slot_key]
                    duplicate_label = f"Another incoming episode uses this slot: {incoming_slots[slot_key].name}"

                if dest_key not in incoming_destinations:
                    incoming_destinations[dest_key] = source_path
                elif not duplicate_label:
                    duplicate_path = incoming_destinations[dest_key]
                    duplicate_label = f"Another incoming episode uses this filename: {incoming_destinations[dest_key].name}"

                plans.append(
                    SearchEpisodeMergePlan(
                        source_path=source_path,
                        dest_dir=dest_dir,
                        dest_name=dest_name,
                        season_num=season_num,
                        episode_num=episode_num,
                        summary=self._search_episode_summary(source_path, season_num, episode_num),
                        duplicate_label=duplicate_label,
                        duplicate_path=duplicate_path,
                    )
                )

        return plans, warnings

    def _search_review_episode_duplicates(self, plans: List[SearchEpisodeMergePlan]) -> bool:
        duplicates = [plan for plan in list(plans or []) if str(plan.duplicate_label or "").strip()]
        if not duplicates:
            return True

        dialog = QDialog(self.win)
        dialog.setWindowTitle("Review Duplicate Episodes")
        dialog.resize(980, max(360, min(720, 220 + (len(duplicates) * 38))))
        dialog_layout = QVBoxLayout(dialog)

        note = QLabel(
            "These episodes collide with files already in the target show or with duplicates in this merge batch. "
            "Skip them, or rename the incoming file before it is moved.",
            dialog,
        )
        note.setWordWrap(True)
        dialog_layout.addWidget(note)

        table = QTableWidget(len(duplicates), 4, dialog)
        table.setHorizontalHeaderLabels(["Incoming", "Duplicate", "Action", "Rename To"])
        table.verticalHeader().setVisible(False)
        table.setSelectionMode(QAbstractItemView.NoSelection)
        table.setEditTriggers(QAbstractItemView.NoEditTriggers)
        table.setAlternatingRowColors(True)
        table.horizontalHeader().setSectionResizeMode(0, QHeaderView.Stretch)
        table.horizontalHeader().setSectionResizeMode(1, QHeaderView.Stretch)
        table.horizontalHeader().setSectionResizeMode(2, QHeaderView.ResizeToContents)
        table.horizontalHeader().setSectionResizeMode(3, QHeaderView.Stretch)
        dialog_layout.addWidget(table, 1)

        row_bindings: List[Tuple[SearchEpisodeMergePlan, QComboBox, QLineEdit]] = []
        for row, plan in enumerate(duplicates):
            incoming_item = QTableWidgetItem(f"{plan.summary}\n{plan.source_path}")
            incoming_item.setFlags(Qt.ItemIsSelectable | Qt.ItemIsEnabled)
            duplicate_item = QTableWidgetItem(str(plan.duplicate_label))
            duplicate_item.setFlags(Qt.ItemIsSelectable | Qt.ItemIsEnabled)
            table.setItem(row, 0, incoming_item)
            table.setItem(row, 1, duplicate_item)

            action_combo = FocusSafeComboBox(table)
            action_combo.addItem("Skip incoming", "skip")
            action_combo.addItem("Rename incoming", "rename")
            rename_edit = QLineEdit(table)
            rename_edit.setText(self._search_suggest_duplicate_episode_name(plan))
            rename_edit.setEnabled(False)
            action_combo.currentIndexChanged.connect(
                lambda _i, combo=action_combo, edit=rename_edit: edit.setEnabled(str(combo.currentData()) == "rename")
            )
            table.setCellWidget(row, 2, action_combo)
            table.setCellWidget(row, 3, rename_edit)
            row_bindings.append((plan, action_combo, rename_edit))

        buttons = QDialogButtonBox(QDialogButtonBox.Ok | QDialogButtonBox.Cancel, dialog)
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        dialog_layout.addWidget(buttons)

        if dialog.exec() != QDialog.Accepted:
            return False

        for plan, action_combo, rename_edit in row_bindings:
            action = str(action_combo.currentData() or "skip")
            if action == "skip":
                plan.dest_name = ""
                continue
            plan.dest_name = self._search_normalize_episode_filename(rename_edit.text(), plan.source_path)

        return True

    def _search_action_merge_discovered_episodes(self) -> None:
        keys = self._search_selected_keys_from_widget(self._search_discovered_list)
        if not keys:
            return

        source_groups: List[ShowGroup] = []
        skipped_titles: List[str] = []
        for key in keys:
            sg = self._search_by_key.get(str(key)) if hasattr(self, "_search_by_key") else None
            if sg is None:
                continue
            if not self._search_group_contains_episode_candidates(sg):
                skipped_titles.append(str(getattr(sg, "display_title", "") or "Untitled").strip() or "Untitled")
                continue
            source_groups.append(sg)

        if not source_groups:
            message = "No discovered episode bundles were available to merge."
            if skipped_titles:
                message += "\n\nSkipped:\n- " + "\n- ".join(skipped_titles[:8])
            QMessageBox.information(self.win, "Merge Episodes", message)
            return

        target_group = self._search_choose_episode_merge_target(source_groups)
        if target_group is None:
            return

        plans, warnings = self._search_build_episode_merge_plans(source_groups, target_group)
        if skipped_titles:
            warnings = list(warnings) + [
                f"{title}: skipped because it did not look like a loose episode bundle."
                for title in skipped_titles
            ]
        if not plans:
            message = "No episode files were ready to move into the selected show."
            if warnings:
                message += "\n\n" + "\n".join(f"- {warning}" for warning in warnings[:8])
            QMessageBox.information(self.win, "Merge Episodes", message)
            return

        if not self._search_review_episode_duplicates(plans):
            return

        moved = 0
        skipped = 0
        errors: List[str] = []
        for plan in plans:
            if not str(plan.dest_name or "").strip():
                skipped += 1
                continue

            source_path = Path(str(plan.source_path))
            if not source_path.exists() or not source_path.is_file():
                errors.append(f"{source_path.name}: source file no longer exists.")
                continue

            try:
                plan.dest_dir.mkdir(parents=True, exist_ok=True)
                normalized_name = self._search_normalize_episode_filename(plan.dest_name, source_path)
                dest_path = self._search_unique_destination_path(plan.dest_dir, normalized_name)
                if self._search_destination_path_key(source_path) == self._search_destination_path_key(dest_path):
                    skipped += 1
                    continue
                shutil.move(str(source_path), str(dest_path))
                moved += 1
            except Exception as exc:
                errors.append(f"{source_path.name}: {type(exc).__name__}: {exc}")

        if moved > 0:
            self._home_catalog_needs_refresh = True
            self._home_catalog_start_async_refresh("search-merge-episodes", allow_network=False)
            self._home_build()
            self._search_request_refresh()

        target_title = str(getattr(target_group, "display_title", "") or "the selected show").strip()
        summary = f"Moved {moved} episode(s) into {target_title}."
        if skipped:
            summary += f"\nSkipped: {skipped}"
        if warnings:
            summary += "\n\nNotes:\n- " + "\n- ".join(warnings[:8])
        if errors:
            summary += "\n\nProblems:\n- " + "\n- ".join(errors[:8])
        if len(warnings) > 8 or len(errors) > 8:
            summary += "\n- Additional items were omitted from this summary."

        if errors:
            QMessageBox.warning(self.win, "Merge Episodes", summary)
        else:
            QMessageBox.information(self.win, "Merge Episodes", summary)

    def _search_populate_list(self, widget: Optional[QListWidget], items: List[ShowGroup], *, source: str = "") -> None:
        if widget is None:
            return

        desired_source = str(source or "").strip()
        selected_keys = set(self._search_selected_keys)
        anchor_key = str(self._search_selected_key or "").strip()
        if desired_source and self._search_selection_source != desired_source:
            selected_keys = {anchor_key} if anchor_key else set()
            anchor_key = anchor_key if anchor_key in selected_keys else ""

        desired_payload: List[Tuple[str, str]] = []
        for sg in items:
            key = self._home_item_key(sg)
            if not key:
                continue
            year = getattr(sg, "year", None)
            media_text = "MOVIE" if str(getattr(sg, "media_type", "")).casefold() == "movie" else "TV"
            suffix = f" ({year})" if year is not None else ""
            desired_payload.append((key, f"{str(getattr(sg, 'display_title', '') or 'Untitled')}{suffix}  |  {media_text}"))

        payload_key = desired_source or widget.objectName() or str(id(widget))
        cached_payload = self._search_list_payloads.get(payload_key)
        payload_tuple = tuple(desired_payload)

        widget.blockSignals(True)
        widget.setUpdatesEnabled(False)
        try:
            first_selected: Optional[QListWidgetItem] = None
            anchor_item: Optional[QListWidgetItem] = None

            if cached_payload != payload_tuple:
                widget.clear()
                for key, label in desired_payload:
                    item = QListWidgetItem(label)
                    item.setData(Qt.UserRole, key)
                    widget.addItem(item)
                self._search_list_payloads[payload_key] = payload_tuple

            for idx in range(widget.count()):
                item = widget.item(idx)
                if item is None:
                    continue
                key = str(item.data(Qt.UserRole) or "").strip()
                is_selected = key in selected_keys
                item.setSelected(is_selected)
                if is_selected and first_selected is None:
                    first_selected = item
                if anchor_key and key == anchor_key:
                    anchor_item = item

            if anchor_item is not None:
                widget.setCurrentItem(anchor_item)
            elif first_selected is not None:
                widget.setCurrentItem(first_selected)
            else:
                widget.setCurrentItem(None)
        finally:
            widget.setUpdatesEnabled(True)
            widget.blockSignals(False)

    def _search_selected_keys_from_widget(self, widget: Optional[QListWidget]) -> List[str]:
        if widget is None:
            return []
        out: List[str] = []
        seen: set[str] = set()
        for item in widget.selectedItems() or []:
            key = str(item.data(Qt.UserRole) or "").strip()
            if key and key not in seen:
                seen.add(key)
                out.append(key)
        return out

    def _search_active_selection_keys(self) -> List[str]:
        keys = [key for key in list(self._search_selected_keys or []) if key in getattr(self, "_search_by_key", {})]
        if keys:
            return keys
        key = str(getattr(self, "_search_selected_key", "") or "").strip()
        if key and key in getattr(self, "_search_by_key", {}):
            return [key]
        return []

    def _search_handle_selection_change(self, source: str) -> None:
        primary = self._search_discovered_list if source == "discovered" else self._search_verified_list
        secondary = self._search_verified_list if source == "discovered" else self._search_discovered_list
        keys = self._search_selected_keys_from_widget(primary)

        if keys:
            if secondary is not None:
                secondary.blockSignals(True)
                secondary.clearSelection()
                secondary.blockSignals(False)
            current_item = primary.currentItem() if primary is not None else None
            anchor_key = str(current_item.data(Qt.UserRole) or "").strip() if current_item is not None and current_item.isSelected() else keys[0]
            self._search_selection_source = source
            self._search_selected_keys = keys
            self._search_selected_key = anchor_key
            self._search_update_details(anchor_key)
            if self._search_poster_browser is not None and self._search_poster_browser.isVisible():
                self._search_show_poster_browser(force_refresh=False)
            return

        if secondary is not None and secondary.selectedItems():
            return

        self._search_selection_source = ""
        self._search_selected_keys = []
        self._search_selected_key = ""
        self._search_update_details("")

    def _search_prepare_context_menu_selection(
        self,
        source: str,
        pos: QPoint,
    ) -> Tuple[Optional[QListWidget], Optional[QListWidgetItem], List[str], Optional[ShowGroup]]:
        widget = self._search_discovered_list if source == "discovered" else self._search_verified_list
        if widget is None:
            return None, None, [], None

        item = widget.itemAt(pos)
        if item is not None:
            should_sync = False
            widget.blockSignals(True)
            try:
                if not item.isSelected():
                    widget.clearSelection()
                    item.setSelected(True)
                    should_sync = True
                current_item = widget.currentItem()
                if current_item is not item:
                    widget.setCurrentItem(item)
                    should_sync = True
            finally:
                widget.blockSignals(False)
            if should_sync:
                self._search_handle_selection_change(source)
        elif str(self._search_selection_source or "").strip() != str(source or "").strip():
            return widget, None, [], None

        keys = self._search_active_selection_keys()
        if not keys:
            return widget, item, [], None
        sg = self._search_selected_group()
        if sg is None:
            return widget, item, [], None
        return widget, item, keys, sg

    def _search_copy_text_to_clipboard(self, text: str) -> None:
        txt = str(text or "")
        if not txt:
            return
        try:
            clip = QApplication.clipboard()
        except Exception:
            clip = None
        if clip is not None:
            try:
                clip.setText(txt)
            except Exception:
                pass

    def _search_action_search_metadata_for_current(self) -> None:
        sg = self._search_selected_group()
        if sg is None:
            return
        if self._search_metadata_query is not None:
            self._search_metadata_query.setText(str(getattr(sg, "display_title", "") or "").strip())
        self._search_run_metadata_lookup()

    def _search_action_rename_current_title(self) -> None:
        sg = self._search_selected_group()
        if sg is None:
            return
        key = self._home_item_key(sg)
        if not key:
            QMessageBox.information(self.win, "Rename Title", "This title does not have a stable library key to rename yet.")
            return

        current_title = str(getattr(sg, "display_title", "") or "").strip()
        if not current_title:
            primary_dir = getattr(sg, "primary_dir", None)
            if primary_dir is not None:
                current_title = NameCleaner.clean(Path(str(primary_dir)).name) or str(Path(str(primary_dir)).name or "Untitled")
            else:
                current_title = "Untitled"

        new_title, accepted = QInputDialog.getText(
            self.win,
            "Rename Title",
            "Display title in Omega:",
            text=current_title,
        )
        if not accepted:
            return

        cleaned = str(new_title or "").strip()
        if not cleaned:
            QMessageBox.information(self.win, "Rename Title", "Title cannot be blank.")
            return
        if cleaned == current_title:
            return

        self._home_state_set_title_override(key, cleaned)
        self._search_manual_context_key = ""
        self._home_reindex_catalog_items_with_state(source="title-override")
        self._home_build()
        self._search_request_refresh()

    def _search_action_clear_current_title_override(self) -> None:
        sg = self._search_selected_group()
        if sg is None:
            return
        key = self._home_item_key(sg)
        if not key or not self._home_state_has_title_override(key):
            return
        self._home_state_clear_title_override(key)
        self._search_manual_context_key = ""
        self._home_reindex_catalog_items_with_state(source="title-override-clear")
        self._home_build()
        self._search_request_refresh()

    def _search_show_list_context_menu(self, source: str, pos: QPoint) -> None:
        widget, _item, keys, sg = self._search_prepare_context_menu_selection(source, pos)
        if widget is None or not keys or sg is None:
            return

        selection_count = len(keys)
        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}
        progress_map = self._home_state.get("watch_progress", {}) if isinstance(self._home_state.get("watch_progress"), dict) else {}
        favorites = set(str(x) for x in (self._home_state.get("favorites", []) or []))
        type_overrides = self._home_state.get("type_overrides", {}) if isinstance(self._home_state.get("type_overrides"), dict) else {}

        selection_groups = [self._search_by_key.get(key) for key in keys]
        selection_groups = [group for group in selection_groups if group is not None]
        selection_types = {
            str(getattr(group, "media_type", "") or "").strip().casefold()
            for group in selection_groups
            if group is not None
        }
        all_verified = all(self._home_state_is_verified(key) for key in keys)
        all_watched = all(bool(watched_map.get(key, False)) for key in keys)
        all_favorites = all(key in favorites for key in keys)
        has_continue = any(key in progress_map for key in keys)
        has_type_override = any(str(type_overrides.get(key) or "").strip() for key in keys)
        has_title_override = self._home_state_has_title_override(self._home_item_key(sg))
        current_media_type = str(getattr(sg, "media_type", "") or "").strip().casefold()
        current_title = str(getattr(sg, "display_title", "") or "Untitled").strip() or "Untitled"
        current_path = str(getattr(sg, "primary_dir", "") or "").strip()
        current_play_label = "Play Current" if selection_count > 1 else ("Play" if current_media_type == "movie" else "Play / Resume")

        menu = QMenu(self.win)
        act_play = menu.addAction(current_play_label)
        act_details = menu.addAction("Show Current Details" if selection_count > 1 else "Show Details")
        act_rename = menu.addAction("Rename Current Title..." if selection_count > 1 else "Rename Title...")
        act_reset_title = menu.addAction("Reset Custom Title")
        act_reset_title.setEnabled(bool(has_title_override))
        menu.addSeparator()
        act_search_metadata = menu.addAction("Search Metadata for Current" if selection_count > 1 else "Search Metadata")
        act_change_art = menu.addAction("Change Art for Current..." if selection_count > 1 else "Change Art...")
        act_refresh_metadata = menu.addAction(
            f"Refresh Metadata for Selected ({selection_count})" if selection_count > 1 else "Refresh Metadata"
        )
        if source == "verified":
            act_special = menu.addAction(
                f"Backdrop + Match Selected ({selection_count})" if selection_count > 1 else "Backdrop + Match"
            )
            act_special.setEnabled(not self._search_batch_backdrop_match_running)
        else:
            act_special = menu.addAction(
                f"Merge Episodes to Show ({selection_count})" if selection_count > 1 else "Merge Episodes to Show"
            )
            act_special.setEnabled(any(self._search_group_contains_episode_candidates(group) for group in selection_groups))
        menu.addSeparator()
        act_verify = menu.addAction(
            f"Remove Selected from Library ({selection_count})" if all_verified and selection_count > 1 else
            "Remove from Library" if all_verified else
            f"Add Selected to Library ({selection_count})" if selection_count > 1 else
            "Add to Library"
        )
        act_toggle_watched = menu.addAction(
            f"Mark Selected Unwatched ({selection_count})" if all_watched and selection_count > 1 else
            "Mark as Unwatched" if all_watched else
            f"Mark Selected Watched ({selection_count})" if selection_count > 1 else
            "Mark as Watched"
        )
        act_toggle_favorite = menu.addAction(
            f"Remove Selected from My List ({selection_count})" if all_favorites and selection_count > 1 else
            "Remove from My List" if all_favorites else
            f"Add Selected to My List ({selection_count})" if selection_count > 1 else
            "Add to My List"
        )
        act_remove_continue = menu.addAction(
            f"Remove Continue from Selected ({selection_count})" if selection_count > 1 else "Remove from Continue Watching"
        )
        act_remove_continue.setEnabled(has_continue)
        menu.addSeparator()
        act_set_movie = menu.addAction(
            f"Set Selected as Movie ({selection_count})" if selection_count > 1 else "Set as Movie"
        )
        act_set_tv = menu.addAction(
            f"Set Selected as TV Show ({selection_count})" if selection_count > 1 else "Set as TV Show"
        )
        act_clear_type = menu.addAction(
            f"Clear Type Override for Selected ({selection_count})" if selection_count > 1 else "Clear Type Override"
        )
        act_set_movie.setEnabled(selection_types != {"movie"})
        act_set_tv.setEnabled(selection_types != {"tv"})
        act_clear_type.setEnabled(has_type_override)
        menu.addSeparator()
        act_open_folder = menu.addAction("Open Current Folder" if selection_count > 1 else "Open Folder")
        act_copy_title = menu.addAction("Copy Current Title" if selection_count > 1 else "Copy Title")
        act_copy_path = menu.addAction("Copy Current Path" if selection_count > 1 else "Copy Path")
        act_copy_title.setEnabled(bool(current_title))
        act_copy_path.setEnabled(bool(current_path))

        chosen = menu.exec(widget.viewport().mapToGlobal(pos))
        if chosen is None:
            return

        if chosen == act_play:
            self._search_action_play()
            return
        if chosen == act_details:
            self._search_action_show_details()
            return
        if chosen == act_rename:
            self._search_action_rename_current_title()
            return
        if chosen == act_reset_title:
            self._search_action_clear_current_title_override()
            return
        if chosen == act_search_metadata:
            self._search_action_search_metadata_for_current()
            return
        if chosen == act_change_art:
            self._search_action_change_poster()
            return
        if chosen == act_refresh_metadata:
            self._search_action_refresh_metadata()
            return
        if chosen == act_special:
            if source == "verified":
                self._search_action_batch_apply_backdrop_and_metadata()
            else:
                self._search_action_merge_discovered_episodes()
            return
        if chosen == act_verify:
            self._search_action_verify_selected()
            return
        if chosen == act_toggle_watched:
            self._search_action_toggle_watched()
            return
        if chosen == act_toggle_favorite:
            self._search_action_toggle_favorite()
            return
        if chosen == act_remove_continue:
            self._search_action_remove_continue()
            return
        if chosen == act_set_movie:
            self._search_action_set_type("movie")
            return
        if chosen == act_set_tv:
            self._search_action_set_type("tv")
            return
        if chosen == act_clear_type:
            self._search_action_clear_type_override()
            return
        if chosen == act_open_folder:
            self._search_action_open_folder()
            return
        if chosen == act_copy_title:
            self._search_copy_text_to_clipboard(current_title)
            return
        if chosen == act_copy_path:
            self._search_copy_text_to_clipboard(current_path)
            return

    def _search_on_discovered_selection(self) -> None:
        self._search_handle_selection_change("discovered")

    def _search_on_verified_selection(self) -> None:
        self._search_handle_selection_change("verified")

    def _search_set_poster_status(self, text: str) -> None:
        if self._search_poster_status is not None:
            self._search_poster_status.setText(str(text or "").strip())

    def _search_hide_poster_browser(self) -> None:
        if self._search_poster_browser is not None:
            self._search_poster_browser.hide()
        try:
            self._glass_refresh_surface_backdrops()
        except Exception:
            pass
        self._search_poster_open_for_key = ""
        self._search_poster_request_key = ""
        self._search_update_details(self._search_selected_key)

    def _search_render_current_card(self, sg: Optional[ShowGroup], selection_count: int) -> None:
        if self._search_current_art_label is None or self._search_current_card_title is None or self._search_current_card_meta is None:
            return

        self._search_current_art_label.setPixmap(QPixmap())
        self._search_current_art_label.setText("Select a title to preview current art." if sg is None else "")
        self._search_current_art_label.setStyleSheet(
            "background: rgba(255,255,255,12); border: 1px solid rgba(255,255,255,28); border-radius: 18px;"
        )

        if sg is None:
            self._search_current_card_title.setText("No title selected")
            self._search_current_card_meta.setText("")
            return

        title = str(getattr(sg, "display_title", "") or "Untitled")
        media = "Movie" if str(getattr(sg, "media_type", "")).casefold() == "movie" else "TV Show"
        year = getattr(sg, "year", None)
        art_path_obj = getattr(sg, "backdrop_path", None) or getattr(sg, "poster_path", None)
        art_path = Path(str(art_path_obj)) if art_path_obj is not None else None
        meta_bits = [media]
        if year is not None:
            meta_bits.append(str(year))
        if selection_count > 1:
            meta_bits.append(f"Current row of {selection_count} selected")
        meta_bits.append("Backdrop" if getattr(sg, "backdrop_path", None) is not None else "Poster" if getattr(sg, "poster_path", None) is not None else "No local art")
        self._search_current_card_title.setText(title)
        self._search_current_card_meta.setText("  |  ".join(meta_bits))

        if art_path is None or not art_path.exists():
            self._search_current_art_label.setText("No local poster or backdrop found yet.")
            return

        current_key = self._home_item_key(sg)

        def _apply_preview() -> None:
            if self._search_current_art_label is None:
                return
            if str(getattr(self, "_search_selected_key", "") or "").strip() != current_key:
                return
            try:
                pixmap = QPixmap(str(art_path))
                if pixmap.isNull():
                    raise ValueError("art pixmap is null")
                bounds = self._search_current_art_label.contentsRect().size()
                if bounds.width() <= 0 or bounds.height() <= 0:
                    bounds = self._search_current_art_label.size()
                scaled = pixmap.scaled(
                    max(1, int(bounds.width())),
                    max(1, int(bounds.height())),
                    Qt.KeepAspectRatio,
                    Qt.SmoothTransformation,
                )
                if scaled.isNull():
                    raise ValueError("scaled art pixmap is null")
                self._search_current_art_label.setText("")
                self._search_current_art_label.setPixmap(scaled)
            except Exception:
                self._search_current_art_label.setText("Current art preview unavailable.")

        QTimer.singleShot(0, _apply_preview)

    def _search_refresh_poster_browser_list(self) -> None:
        if self._search_poster_list is None:
            return

        desired_kind = str(self._search_poster_kind_combo.currentData() or "poster") if self._search_poster_kind_combo is not None else "poster"
        self._search_poster_thumb_labels = {}
        self._search_poster_list.blockSignals(True)
        self._search_poster_list.clear()

        visible_count = 0
        for index, candidate in enumerate(list(self._search_poster_candidates or [])):
            if desired_kind != "all" and str(candidate.kind) != desired_kind:
                continue
            thumb_size = self._search_poster_thumbnail_box_size(candidate.kind)
            row_height = max(thumb_size.height() + 18, 112)
            item = QListWidgetItem()
            item.setData(Qt.UserRole, int(index))
            item.setSizeHint(QSize(0, row_height))
            dims = f"{int(candidate.width)}x{int(candidate.height)}" if candidate.width and candidate.height else "Preview"
            item.setToolTip(f"{candidate.kind.title()}  |  {dims}")
            self._search_poster_list.addItem(item)
            row = QWidget(self._search_poster_list)
            row.setAttribute(Qt.WA_StyledBackground, True)
            row.setAttribute(Qt.WA_TransparentForMouseEvents, True)
            row.setStyleSheet("background: transparent;")
            row_l = QHBoxLayout(row)
            row_l.setContentsMargins(6, 4, 8, 4)
            row_l.setSpacing(10)

            thumb = QLabel(row)
            thumb.setAttribute(Qt.WA_TransparentForMouseEvents, True)
            thumb.setAlignment(Qt.AlignCenter)
            thumb.setFixedSize(thumb_size)
            thumb.setWordWrap(True)
            thumb.setStyleSheet(
                "background: rgba(255,255,255,10);"
                "border: 1px solid rgba(255,255,255,28);"
                "border-radius: 12px;"
                "color: rgba(255,255,255,132);"
                "padding: 4px;"
            )
            thumb.setText("Loading art...")
            self._search_set_poster_thumb_preview(thumb, candidate.preview_bytes, candidate.kind)
            row_l.addWidget(thumb, 0, Qt.AlignVCenter)

            text_box = QVBoxLayout()
            text_box.setContentsMargins(0, 0, 0, 0)
            text_box.setSpacing(4)

            title = QLabel(str(candidate.label or candidate.kind.title()), row)
            title.setAttribute(Qt.WA_TransparentForMouseEvents, True)
            title.setWordWrap(True)
            title.setStyleSheet(
                "background: transparent;"
                "color: rgba(248,250,255,232);"
                "font-size: 12px;"
                "font-weight: 700;"
            )
            text_box.addWidget(title)

            detail = QLabel(f"{candidate.kind.title()} preview", row)
            detail.setAttribute(Qt.WA_TransparentForMouseEvents, True)
            detail.setWordWrap(True)
            detail.setStyleSheet(
                "background: transparent;"
                "color: rgba(205,214,232,170);"
                "font-size: 11px;"
            )
            text_box.addWidget(detail)
            text_box.addStretch(1)

            row_l.addLayout(text_box, 1)
            self._search_poster_list.setItemWidget(item, row)
            self._search_poster_thumb_labels[int(index)] = thumb
            visible_count += 1

        if self._search_poster_list.count() > 0:
            self._search_poster_list.setCurrentRow(0)

        self._search_poster_list.blockSignals(False)
        if self._search_poster_apply_btn is not None:
            self._search_poster_apply_btn.setEnabled(visible_count > 0)
        if visible_count <= 0 and self._search_poster_candidates:
            self._search_set_poster_status("No art matched this filter. Try Posters, Backdrops, or All Art.")

    def _search_selected_poster_candidate(self) -> Optional[SearchPosterArtCandidate]:
        if self._search_poster_list is None:
            return None
        current = self._search_poster_list.currentItem()
        if current is None:
            return None
        try:
            index = int(current.data(Qt.UserRole))
        except Exception:
            return None
        if index < 0 or index >= len(self._search_poster_candidates):
            return None
        return self._search_poster_candidates[index]

    def _search_poster_preview_size(self, kind: str) -> str:
        return "w185" if str(kind or "").strip().casefold() == "poster" else "w300"

    def _search_poster_preview_cache_key(self, image_path: str, kind: str) -> str:
        return f"{self._search_poster_preview_size(kind)}::{str(image_path or '').strip()}"

    def _cache_touch(self, mapping: Dict[str, Any], key: str) -> Any:
        if not isinstance(mapping, dict):
            return None
        norm_key = str(key or "")
        if norm_key not in mapping:
            return None
        try:
            value = mapping.pop(norm_key)
            mapping[norm_key] = value
            return value
        except Exception:
            return mapping.get(norm_key)

    def _trim_cache_mapping(self, mapping: Dict[str, Any], max_items: int) -> None:
        if not isinstance(mapping, dict):
            return
        limit = max(1, int(max_items))
        while len(mapping) > limit:
            try:
                mapping.pop(next(iter(mapping)))
            except Exception:
                break

    def _search_store_poster_cache(self, request_key: str, candidates: List[SearchPosterArtCandidate]) -> None:
        cache = getattr(self, "_search_poster_cache", None)
        if not isinstance(cache, dict):
            return
        cache[str(request_key or "")] = list(candidates or [])
        self._trim_cache_mapping(cache, 24)

    def _search_store_poster_preview_cache(self, image_path: str, kind: str, preview_bytes: bytes) -> None:
        if not preview_bytes:
            return
        cache = getattr(self, "_search_poster_preview_cache", None)
        if not isinstance(cache, dict):
            return
        cache[self._search_poster_preview_cache_key(image_path, kind)] = bytes(preview_bytes)
        self._trim_cache_mapping(cache, 192)

    def _search_cached_poster_preview_bytes(self, image_path: str, kind: str) -> bytes:
        cache_key = self._search_poster_preview_cache_key(image_path, kind)
        cached = self._cache_touch(getattr(self, "_search_poster_preview_cache", {}), cache_key)
        return bytes(cached or b"")

    def _search_poster_prefetch_order(self, candidates: List[SearchPosterArtCandidate]) -> List[int]:
        desired_kind = (
            str(self._search_poster_kind_combo.currentData() or "poster")
            if self._search_poster_kind_combo is not None
            else "poster"
        ).strip().casefold()
        primary: List[int] = []
        secondary: List[int] = []
        for index, candidate in enumerate(list(candidates or [])):
            if candidate.preview_bytes:
                continue
            if desired_kind == "all" or str(candidate.kind or "").strip().casefold() == desired_kind:
                primary.append(int(index))
            else:
                secondary.append(int(index))
        return primary + secondary

    def _search_get_poster_preview_executor(self) -> ThreadPoolExecutor:
        with self._search_poster_preview_executor_lock:
            pool = getattr(self, "_search_poster_preview_executor", None)
            if pool is None:
                pool = ThreadPoolExecutor(max_workers=3, thread_name_prefix="omega-art-preview")
                self._search_poster_preview_executor = pool
        return pool

    def _search_start_poster_preview_prefetch(
        self,
        token: int,
        key: str,
        candidates: List[SearchPosterArtCandidate],
    ) -> None:
        ordered_indexes = self._search_poster_prefetch_order(list(candidates or []))
        if not ordered_indexes:
            return
        self._search_adjust_async_watch_count("_search_poster_preview_inflight", +1)
        self._search_start_poster_result_watch()

        def _worker() -> None:
            def _cancelled() -> bool:
                if self._player_should_reduce_background_work():
                    return True
                if int(token) != int(getattr(self, "_search_poster_fetch_token", 0) or 0):
                    return True
                return str(key or "").strip() != str(getattr(self, "_search_poster_request_key", "") or "").strip()

            if _cancelled():
                self._search_adjust_async_watch_count("_search_poster_preview_inflight", -1)
                return
            try:
                client = TMDBClient()
            except Exception:
                self._search_adjust_async_watch_count("_search_poster_preview_inflight", -1)
                return

            try:
                pending_indexes: List[int] = []
                for index in ordered_indexes:
                    if _cancelled():
                        return
                    if index < 0 or index >= len(candidates):
                        continue
                    candidate = candidates[index]
                    cached_preview = self._search_cached_poster_preview_bytes(candidate.image_path, candidate.kind)
                    if cached_preview:
                        self._search_poster_preview_results.put((token, key, int(index), cached_preview))
                        self._search_notify_poster_results_ready()
                    else:
                        pending_indexes.append(int(index))

                if not pending_indexes:
                    return

                max_workers = 1 if len(pending_indexes) <= 2 else (2 if len(pending_indexes) <= 6 else 3)

                def _download(index: int) -> Tuple[int, bytes]:
                    if _cancelled():
                        return index, b""
                    if index < 0 or index >= len(candidates):
                        return index, b""
                    candidate = candidates[index]
                    try:
                        preview_bytes = client.download_image_bytes(
                            client.image_url(candidate.image_path, size=self._search_poster_preview_size(candidate.kind))
                        )
                    except Exception:
                        preview_bytes = b""
                    return index, preview_bytes

                pool = self._search_get_poster_preview_executor()
                in_flight: Dict[Any, int] = {}
                pending_iter = iter(pending_indexes)

                def _submit_next() -> bool:
                    try:
                        next_index = int(next(pending_iter))
                    except StopIteration:
                        return False
                    future = pool.submit(_download, next_index)
                    in_flight[future] = next_index
                    return True

                try:
                    for _ in range(max_workers):
                        if not _submit_next():
                            break

                    while in_flight:
                        if _cancelled():
                            break
                        done, _ = wait(
                            tuple(in_flight.keys()),
                            timeout=0.15,
                            return_when=FIRST_COMPLETED,
                        )
                        if not done:
                            continue
                        for future in done:
                            in_flight.pop(future, None)
                            if _cancelled():
                                continue
                            try:
                                index, preview_bytes = future.result()
                            except Exception:
                                continue
                            if preview_bytes and 0 <= int(index) < len(candidates):
                                candidate = candidates[index]
                                self._search_store_poster_preview_cache(
                                    candidate.image_path,
                                    candidate.kind,
                                    preview_bytes,
                                )
                                self._search_poster_preview_results.put((token, key, int(index), preview_bytes))
                                self._search_notify_poster_results_ready()
                            if not _cancelled():
                                _submit_next()
                finally:
                    for future in list(in_flight.keys()):
                        try:
                            future.cancel()
                        except Exception:
                            pass
            finally:
                self._search_adjust_async_watch_count("_search_poster_preview_inflight", -1)

        threading.Thread(target=_worker, name="omega-search-poster-preview", daemon=True).start()

    def _search_poster_thumbnail_box_size(self, kind: str) -> QSize:
        return QSize(136, 204) if str(kind or "").strip().casefold() == "poster" else QSize(224, 126)

    def _search_set_poster_thumb_preview(self, label: Optional[QLabel], preview_bytes: bytes, kind: str) -> bool:
        if label is None:
            return False
        label.setPixmap(QPixmap())
        if not preview_bytes:
            label.setText("Loading art...")
            return False
        pixmap = QPixmap()
        pixmap.loadFromData(preview_bytes)
        if pixmap.isNull():
            label.setText("Preview unavailable")
            return False
        scaled = pixmap.scaled(
            label.size(),
            Qt.KeepAspectRatio,
            Qt.SmoothTransformation,
        )
        label.setText("")
        label.setPixmap(scaled)
        return True

    def _search_apply_preview_icon_to_visible_item(self, candidate_index: int) -> None:
        if candidate_index < 0 or candidate_index >= len(self._search_poster_candidates):
            return
        candidate = self._search_poster_candidates[candidate_index]
        thumb = self._search_poster_thumb_labels.get(int(candidate_index))
        if thumb is None:
            return
        self._search_set_poster_thumb_preview(thumb, candidate.preview_bytes, candidate.kind)

    def _search_format_tmdb_hit_label(self, hit: TMDBHit) -> str:
        media = "Movie" if str(getattr(hit, "media_type", "") or "").strip().casefold() == "movie" else "TV"
        bits = [str(getattr(hit, "title", "") or "Untitled").strip() or "Untitled"]
        year = str(getattr(hit, "year", "") or "").strip()
        if year:
            bits.append(year)
        bits.append(media)
        return "  |  ".join(bits)

    def _search_populate_tmdb_hit_combo(
        self,
        combo: Optional[QComboBox],
        hits: List[TMDBHit],
        empty_label: str,
    ) -> None:
        if combo is None:
            return
        combo.blockSignals(True)
        combo.clear()
        combo.addItem(str(empty_label), -1)
        for index, hit in enumerate(list(hits or [])):
            combo.addItem(self._search_format_tmdb_hit_label(hit), int(index))
        combo.setCurrentIndex(1 if hits else 0)
        combo.blockSignals(False)

    def _search_clear_poster_cache_for_item(self, content_key: str) -> None:
        prefix = f"{str(content_key or '').strip()}::"
        if not prefix.strip(":"):
            return
        doomed = [key for key in list(self._search_poster_cache.keys()) if str(key).startswith(prefix)]
        for key in doomed:
            self._search_poster_cache.pop(key, None)

    def _search_sync_manual_search_controls(self, sg: Optional[ShowGroup]) -> None:
        key = self._home_item_key(sg) if sg is not None else ""
        if sg is None:
            self._search_manual_context_key = ""
            self._search_metadata_hits = []
            self._search_poster_hits = []
            self._search_poster_active_hit = None
            self._search_poster_request_key = ""
            self._search_populate_tmdb_hit_combo(self._search_metadata_hit_combo, [], "Search to choose a TMDB result")
            self._search_populate_tmdb_hit_combo(self._search_poster_hit_combo, [], "Use the current title or search TMDB above")
            if self._search_metadata_query is not None:
                self._search_metadata_query.clear()
                self._search_metadata_query.setEnabled(False)
            if self._search_poster_query is not None:
                self._search_poster_query.clear()
                self._search_poster_query.setEnabled(False)
            if self._search_metadata_search_btn is not None:
                self._search_metadata_search_btn.setEnabled(False)
            if self._search_metadata_apply_btn is not None:
                self._search_metadata_apply_btn.setEnabled(False)
            if self._search_poster_search_btn is not None:
                self._search_poster_search_btn.setEnabled(False)
            if self._search_poster_load_btn is not None:
                self._search_poster_load_btn.setEnabled(False)
            if self._search_poster_apply_btn is not None:
                self._search_poster_apply_btn.setEnabled(False)
            if self._search_poster_close_btn is not None:
                self._search_poster_close_btn.setEnabled(False)
            if self._search_metadata_status is not None:
                self._search_metadata_status.setText("Pick a title, search TMDB, then link the right match to this media.")
            return

        if str(key) != str(self._search_manual_context_key or ""):
            default_query = str(getattr(sg, "display_title", "") or "").strip()
            self._search_manual_context_key = str(key)
            self._search_metadata_hits = []
            self._search_poster_hits = []
            self._search_poster_active_hit = None
            self._search_poster_request_key = f"{key}::default"
            self._search_populate_tmdb_hit_combo(self._search_metadata_hit_combo, [], "Search to choose a TMDB result")
            self._search_populate_tmdb_hit_combo(self._search_poster_hit_combo, [], "Use the current title or search TMDB above")
            if self._search_metadata_query is not None:
                self._search_metadata_query.setText(default_query)
                self._search_metadata_query.setEnabled(True)
            if self._search_poster_query is not None:
                self._search_poster_query.setText(default_query)
                self._search_poster_query.setEnabled(True)

        if self._search_metadata_search_btn is not None:
            self._search_metadata_search_btn.setEnabled(True)
        if self._search_poster_search_btn is not None:
            self._search_poster_search_btn.setEnabled(True)
        if self._search_metadata_apply_btn is not None:
            self._search_metadata_apply_btn.setEnabled(bool(self._search_metadata_hits))
        if self._search_poster_load_btn is not None:
            self._search_poster_load_btn.setEnabled(bool(self._search_poster_hits))
        if self._search_poster_close_btn is not None:
            self._search_poster_close_btn.setEnabled(True)

        if self._search_metadata_status is not None:
            if getattr(sg, "tmdb_id", None) is not None:
                self._search_metadata_status.setText(
                    f"Current linked metadata: {str(getattr(sg, 'display_title', '') or 'Untitled').strip()}  |  TMDB {int(getattr(sg, 'tmdb_id', 0) or 0)}"
                )
            else:
                self._search_metadata_status.setText("No TMDB match is locked yet. Search and link the right title for this media.")

    def _search_run_metadata_lookup(self) -> None:
        sg = self._search_selected_group()
        if sg is None:
            return
        query = str(self._search_metadata_query.text() if self._search_metadata_query is not None else "").strip()
        if not query:
            query = str(getattr(sg, "display_title", "") or "").strip()
        if not query:
            return

        if self._search_metadata_status is not None:
            self._search_metadata_status.setText(f"Searching TMDB for metadata matches: {query}")

        try:
            hits = self._home_catalog.search_tmdb_hits(query, limit=8, media_hint=str(getattr(sg, "media_type", "") or ""))
        except Exception as exc:
            hits = []
            if self._search_metadata_status is not None:
                self._search_metadata_status.setText(f"TMDB search failed: {type(exc).__name__}: {exc}")

        self._search_metadata_hits = list(hits or [])
        self._search_populate_tmdb_hit_combo(self._search_metadata_hit_combo, self._search_metadata_hits, "Choose a TMDB result")
        if self._search_metadata_apply_btn is not None:
            self._search_metadata_apply_btn.setEnabled(bool(self._search_metadata_hits))
        if self._search_metadata_status is not None and hits:
            self._search_metadata_status.setText(f"Found {len(hits)} TMDB matches. Pick the right title and link it to this media.")
        elif self._search_metadata_status is not None and not hits:
            self._search_metadata_status.setText("TMDB returned no metadata matches for that search.")

    def _search_apply_selected_metadata_match(self) -> None:
        sg = self._search_selected_group()
        if sg is None or self._search_metadata_hit_combo is None:
            return
        try:
            hit_index = int(self._search_metadata_hit_combo.currentData())
        except Exception:
            hit_index = -1
        if hit_index < 0 or hit_index >= len(self._search_metadata_hits):
            return

        hit = self._search_metadata_hits[hit_index]
        key = self._home_item_key(sg)
        if not key:
            return

        if self._search_metadata_status is not None:
            self._search_metadata_status.setText(f"Linking metadata: {self._search_format_tmdb_hit_label(hit)}")

        metadata = self._home_catalog.set_manual_match(key, hit)
        if not metadata:
            QMessageBox.warning(self.win, "Metadata Match", "TMDB metadata could not be linked for this title.")
            return

        self._search_clear_poster_cache_for_item(key)
        self._search_poster_active_hit = None
        self._home_catalog_needs_refresh = True
        self._home_catalog_start_async_refresh("search-manual-metadata", allow_network=False)
        self._home_request_build()
        self._search_request_refresh()

        if self._search_metadata_status is not None:
            self._search_metadata_status.setText(f"Linked metadata: {self._search_format_tmdb_hit_label(hit)}")

    def _search_run_poster_lookup(self) -> None:
        sg = self._search_selected_group()
        if sg is None:
            return
        query = str(self._search_poster_query.text() if self._search_poster_query is not None else "").strip()
        if not query:
            query = str(getattr(sg, "display_title", "") or "").strip()
        if not query:
            return

        self._search_set_poster_status(f"Searching TMDB art matches: {query}")
        try:
            hits = self._home_catalog.search_tmdb_hits(query, limit=8, media_hint=str(getattr(sg, "media_type", "") or ""))
        except Exception as exc:
            hits = []
            self._search_set_poster_status(f"TMDB search failed: {type(exc).__name__}: {exc}")

        self._search_poster_hits = list(hits or [])
        self._search_populate_tmdb_hit_combo(self._search_poster_hit_combo, self._search_poster_hits, "Choose a TMDB title for art")
        if self._search_poster_load_btn is not None:
            self._search_poster_load_btn.setEnabled(bool(self._search_poster_hits))
        if not hits:
            self._search_set_poster_status("TMDB returned no art-source matches for that search.")
            return

        self._search_set_poster_status(f"Found {len(hits)} TMDB matches. Loading art for the first result.")
        self._search_load_selected_poster_hit()

    def _search_load_selected_poster_hit(self) -> None:
        sg = self._search_selected_group()
        if sg is None or self._search_poster_hit_combo is None:
            return
        try:
            hit_index = int(self._search_poster_hit_combo.currentData())
        except Exception:
            hit_index = -1
        if hit_index < 0 or hit_index >= len(self._search_poster_hits):
            return
        self._search_poster_active_hit = self._search_poster_hits[hit_index]
        self._search_set_poster_status(f"Loading art for {self._search_format_tmdb_hit_label(self._search_poster_active_hit)}")
        self._search_show_poster_browser(force_refresh=False)

    def _search_collect_target_dirs(self, sg: ShowGroup) -> List[Path]:
        targets: List[Path] = []
        seen: set[str] = set()
        raw_dirs = list(getattr(sg, "all_dirs", []) or []) + [getattr(sg, "primary_dir", None)]
        for raw in raw_dirs:
            if raw is None:
                continue
            path = Path(str(raw))
            folder = path if path.is_dir() else path.parent
            if not folder.exists() or not folder.is_dir():
                continue
            canon = self._home_canon_path_str(folder)
            if not canon or canon in seen:
                continue
            seen.add(canon)
            targets.append(folder)
        return targets

    def _search_write_art_bytes_to_targets(self, targets: List[Path], out_name: str, art_bytes: bytes) -> int:
        written = 0
        for folder in list(targets or []):
            try:
                folder.mkdir(parents=True, exist_ok=True)
                (folder / str(out_name)).write_bytes(art_bytes)
                written += 1
            except Exception:
                pass
        return written

    def _search_refresh_after_local_art_change(self, content_keys: List[str], *, reason: str) -> None:
        seen: set[str] = set()
        for raw_key in list(content_keys or []):
            key = str(raw_key or "").strip()
            if not key or key in seen:
                continue
            seen.add(key)
            self._search_clear_poster_cache_for_item(key)
        self._home_catalog_needs_refresh = True
        self._home_catalog_start_async_refresh(str(reason), allow_network=False)
        self._home_request_build()
        self._search_request_refresh()

    def _search_build_tmdb_image_candidates(
        self,
        client: TMDBClient,
        images: Dict[str, Any],
    ) -> List[SearchPosterArtCandidate]:
        out: List[SearchPosterArtCandidate] = []
        seen: set[Tuple[str, str]] = set()
        for kind_key, label_prefix in (("posters", "Poster"), ("backdrops", "Backdrop")):
            for raw in list(images.get(kind_key, []) or []):
                if not isinstance(raw, dict):
                    continue
                image_path = str(raw.get("file_path") or "").strip()
                kind = str(raw.get("kind") or kind_key[:-1]).strip().casefold()
                if not image_path or (kind, image_path) in seen:
                    continue
                seen.add((kind, image_path))
                width = int(raw.get("width") or 0)
                height = int(raw.get("height") or 0)
                lang = str(raw.get("language") or "").strip().upper()
                dims = f"{width}x{height}" if width and height else "TMDB"
                label = f"{label_prefix}  |  {dims}"
                if lang:
                    label = f"{label}  |  {lang}"
                out.append(
                    SearchPosterArtCandidate(
                        image_path=image_path,
                        kind=kind,
                        label=label,
                        preview_bytes=self._search_cached_poster_preview_bytes(image_path, kind),
                        width=width,
                        height=height,
                    )
        )
        return out

    def _saved_mix_selected_items_from_record(self, record: Dict[str, Any]) -> List[SelectedShowItem]:
        source = record if isinstance(record, dict) else {}
        seed_keys = [str(x or "").strip() for x in list(source.get("seed_keys") or []) if str(x or "").strip()]
        queue_paths = [str(x or "").strip() for x in list(source.get("playlist_paths") or []) if str(x or "").strip()]
        queue_keys = [str(x or "").strip() for x in list(source.get("playlist_content_keys") or []) if str(x or "").strip()]

        ordered_keys: List[str] = []
        seen: set[str] = set()
        for key in seed_keys + queue_keys:
            if key and key not in seen:
                seen.add(key)
                ordered_keys.append(key)
        if not ordered_keys:
            for path_str in queue_paths:
                try:
                    resolved = self._home_resolve_media_key_for_path(Path(path_str))
                except Exception:
                    resolved = ""
                if resolved and resolved not in seen:
                    seen.add(resolved)
                    ordered_keys.append(resolved)

        items: List[SelectedShowItem] = []
        for key in ordered_keys:
            sg = self._home_items_by_key.get(str(key))
            if sg is None:
                continue

            show_dirs = [Path(str(p)) for p in (getattr(sg, "all_dirs", []) or []) if p is not None]
            if not show_dirs:
                primary_dir = getattr(sg, "primary_dir", None)
                if primary_dir is not None:
                    show_dirs = [Path(str(primary_dir))]
            if not show_dirs:
                continue

            poster_raw = getattr(sg, "poster_path", None)
            backdrop_raw = getattr(sg, "backdrop_path", None)
            items.append(
                SelectedShowItem(
                    key=str(key),
                    title=str(getattr(sg, "display_title", "") or key),
                    show_dirs=show_dirs,
                    poster_path=Path(str(poster_raw)) if poster_raw is not None else None,
                    backdrop_path=Path(str(backdrop_raw)) if backdrop_raw is not None else None,
                    title_id=str(getattr(sg, "title_id", "") or key),
                )
            )

        return items

    def _search_build_search_hit_candidates(
        self,
        client: TMDBClient,
        sg: ShowGroup,
    ) -> List[SearchPosterArtCandidate]:
        query = str(getattr(sg, "display_title", "") or "").strip()
        if not query:
            return []

        out: List[SearchPosterArtCandidate] = []
        seen: set[Tuple[str, str]] = set()
        for hit in client.search_multi(query, limit=10):
            hit_label = f"{hit.title} ({hit.year})".strip()
            for kind, image_path in (
                ("poster", str(getattr(hit, "poster_path", "") or "").strip()),
                ("backdrop", str(getattr(hit, "backdrop_path", "") or "").strip()),
            ):
                if not image_path or (kind, image_path) in seen:
                    continue
                seen.add((kind, image_path))
                out.append(
                    SearchPosterArtCandidate(
                        image_path=image_path,
                        kind=kind,
                        label=f"{hit_label}  |  {kind.title()}",
                        preview_bytes=self._search_cached_poster_preview_bytes(image_path, kind),
                    )
                )
                if len(out) >= 12:
                    return out
        return out

    def _search_build_direct_hit_candidates(self, hits: List[TMDBHit]) -> List[SearchPosterArtCandidate]:
        out: List[SearchPosterArtCandidate] = []
        seen: set[Tuple[str, str]] = set()
        for hit in list(hits or []):
            hit_label = f"{hit.title} ({hit.year})".strip()
            for kind, image_path in (
                ("poster", str(getattr(hit, "poster_path", "") or "").strip()),
                ("backdrop", str(getattr(hit, "backdrop_path", "") or "").strip()),
            ):
                if not image_path or (kind, image_path) in seen:
                    continue
                seen.add((kind, image_path))
                out.append(
                    SearchPosterArtCandidate(
                        image_path=image_path,
                        kind=kind,
                        label=f"{hit_label}  |  {kind.title()}",
                        preview_bytes=self._search_cached_poster_preview_bytes(image_path, kind),
                    )
                )
                if len(out) >= 12:
                    return out
        return out

    def _search_show_poster_browser(self, *, force_refresh: bool = False) -> None:
        sg = self._search_selected_group()
        if sg is None or self._search_poster_browser is None:
            return

        key = self._home_item_key(sg)
        active_hit = self._search_poster_active_hit
        request_key = (
            f"{key}::manual::{str(getattr(active_hit, 'media_type', '') or '').strip()}:{int(getattr(active_hit, 'id', 0) or 0)}"
            if active_hit is not None
            else f"{key}::default"
        )
        self._search_poster_open_for_key = key
        self._search_poster_request_key = request_key
        self._search_poster_fetch_token += 1
        token = int(self._search_poster_fetch_token)
        self._search_poster_browser.show()
        self._search_poster_browser.updateGeometry()
        try:
            self._glass_refresh_surface_backdrops()
        except Exception:
            pass

        cached_candidates = self._cache_touch(getattr(self, "_search_poster_cache", {}), request_key)
        if not force_refresh and cached_candidates is not None:
            self._search_poster_candidates = list(cached_candidates or [])
            self._search_refresh_poster_browser_list()
            total = len(self._search_poster_candidates)
            self._search_set_poster_status(
                "No TMDB art was found for this title."
                if total <= 0
                else f"Loaded {total} TMDB art choices for {'the chosen TMDB title' if active_hit is not None else 'the current title'}."
            )
            if any(not c.preview_bytes for c in self._search_poster_candidates):
                self._search_start_poster_preview_prefetch(token, request_key, list(self._search_poster_candidates))
            self._search_update_details(key)
            return

        self._search_poster_candidates = []
        self._search_refresh_poster_browser_list()
        self._search_set_poster_status(
            f"Loading art choices from TMDB for {self._search_format_tmdb_hit_label(active_hit)}..."
            if active_hit is not None
            else "Loading art choices from TMDB..."
        )
        self._search_update_details(key)

        def _worker() -> None:
            payload: Dict[str, Any] = {"candidates": [], "error": ""}
            client: Optional[TMDBClient] = None

            def _cancelled() -> bool:
                if self._player_should_reduce_background_work():
                    return True
                if int(token) != int(getattr(self, "_search_poster_fetch_token", 0) or 0):
                    return True
                return str(request_key or "").strip() != str(getattr(self, "_search_poster_request_key", "") or "").strip()

            try:
                if _cancelled():
                    return
                try:
                    client = TMDBClient()
                    if _cancelled():
                        return
                    candidates: List[SearchPosterArtCandidate] = []
                    if active_hit is not None:
                        try:
                            if _cancelled():
                                return
                            images = client.get_item_images(str(active_hit.media_type), int(active_hit.id), limit=12)
                            candidates = self._search_build_tmdb_image_candidates(client, images)
                        except Exception as exc:
                            dprint("[SEARCH][POSTER][WARN] manual-hit image fetch failed:", exc)
                        if not candidates:
                            candidates = self._search_build_direct_hit_candidates([active_hit])
                    else:
                        tmdb_id = getattr(sg, "tmdb_id", None)
                        media_type = str(getattr(sg, "tmdb_media_type", "") or getattr(sg, "media_type", "") or "").strip().casefold()
                        if tmdb_id is not None and media_type in {"movie", "tv"}:
                            try:
                                if _cancelled():
                                    return
                                images = client.get_item_images(media_type, int(tmdb_id), limit=12)
                                candidates = self._search_build_tmdb_image_candidates(client, images)
                            except Exception as exc:
                                dprint("[SEARCH][POSTER][WARN] item-image fetch failed:", exc)
                        if not candidates:
                            if _cancelled():
                                return
                            candidates = self._search_build_search_hit_candidates(client, sg)
                    payload["candidates"] = candidates
                    if not candidates:
                        payload["error"] = "TMDB returned no poster options for this title."
                except Exception as exc:
                    payload["error"] = f"TMDB unavailable: {type(exc).__name__}: {exc}"

                if _cancelled():
                    return
                self._search_poster_results.put((token, request_key, payload))
                self._search_notify_poster_results_ready()
                candidates = list(payload.get("candidates", []) or [])
                if not candidates or _cancelled():
                    return
                self._search_start_poster_preview_prefetch(token, request_key, candidates)
            finally:
                self._search_adjust_async_watch_count("_search_poster_result_inflight", -1)

        self._search_adjust_async_watch_count("_search_poster_result_inflight", +1)
        self._search_start_poster_result_watch()
        threading.Thread(target=_worker, name="omega-search-poster-fetch", daemon=True).start()

    def _search_poll_poster_results(self) -> None:
        processed = 0
        while processed < 6:
            try:
                token, key, payload = self._search_poster_results.get_nowait()
            except queue.Empty:
                break
            processed += 1

            candidates = list(payload.get("candidates", []) or [])
            if candidates:
                self._search_store_poster_cache(str(key), candidates)
            if int(token) != int(getattr(self, "_search_poster_fetch_token", 0) or 0):
                continue
            if str(key or "").strip() != str(getattr(self, "_search_poster_request_key", "") or "").strip():
                continue

            self._search_poster_candidates = list(candidates)
            self._search_refresh_poster_browser_list()
            error = str(payload.get("error") or "").strip()
            if error:
                self._search_set_poster_status(error)
            else:
                self._search_set_poster_status(
                    f"Loaded {len(candidates)} TMDB art choices for {'the chosen TMDB title' if self._search_poster_active_hit is not None else 'the current title'}."
                )

        preview_processed = 0
        while preview_processed < 12:
            try:
                token, key, index, preview_bytes = self._search_poster_preview_results.get_nowait()
            except queue.Empty:
                break
            preview_processed += 1

            if preview_bytes:
                cached = self._cache_touch(getattr(self, "_search_poster_cache", {}), str(key)) or []
                if 0 <= int(index) < len(cached):
                    cached[int(index)] = replace(cached[int(index)], preview_bytes=preview_bytes)
            if int(token) != int(getattr(self, "_search_poster_fetch_token", 0) or 0):
                continue
            if str(key or "").strip() != str(getattr(self, "_search_poster_request_key", "") or "").strip():
                continue
            if 0 <= int(index) < len(self._search_poster_candidates):
                self._search_poster_candidates[int(index)] = replace(
                    self._search_poster_candidates[int(index)],
                    preview_bytes=preview_bytes,
                )
                self._search_apply_preview_icon_to_visible_item(int(index))
        if processed <= 0 and preview_processed <= 0 and not self._search_has_poster_async_work():
            self._search_stop_poster_result_watch()
        elif not self._search_poster_results.empty() or not self._search_poster_preview_results.empty():
            self._search_start_poster_result_watch()

    def _search_refresh_lists(self) -> None:
        if not self._search_initialized:
            return
        if not self._search_is_active_page():
            self._search_refresh_deferred = True
            return
        self._search_refresh_deferred = False

        entries = list(self._home_catalog_static_entries or [])
        verified_keys = self._home_state_verified_set()
        favorites = set(str(x) for x in (self._home_state.get("favorites", []) or []))
        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}

        self._search_by_key = dict(self._home_items_by_key)

        filter_sig = (
            int(getattr(self, "_home_catalog_revision", 0) or 0),
            tuple(self._home_catalog_filter_genres),
            tuple(self._home_catalog_filter_years),
        )

        if self._search_genre_filter is not None and self._search_last_filter_options_signature != filter_sig:
            cur = self._search_genre_filter.currentText()
            self._search_genre_filter.blockSignals(True)
            self._search_genre_filter.clear()
            self._search_genre_filter.addItem("All Genres")
            for g in self._home_catalog_filter_genres:
                self._search_genre_filter.addItem(g)
            idx = self._search_genre_filter.findText(cur)
            self._search_genre_filter.setCurrentIndex(idx if idx >= 0 else 0)
            self._search_genre_filter.blockSignals(False)

        if self._search_year_filter is not None and self._search_last_filter_options_signature != filter_sig:
            cur_y = self._search_year_filter.currentText()
            self._search_year_filter.blockSignals(True)
            self._search_year_filter.clear()
            self._search_year_filter.addItem("All Years")
            for y in self._home_catalog_filter_years:
                self._search_year_filter.addItem(str(y))
            idx_y = self._search_year_filter.findText(cur_y)
            self._search_year_filter.setCurrentIndex(idx_y if idx_y >= 0 else 0)
            self._search_year_filter.blockSignals(False)
        self._search_last_filter_options_signature = filter_sig

        query = str(self._search_query.text() or "").strip().casefold() if self._search_query is not None else ""
        type_filter = self._search_type_filter.currentText() if self._search_type_filter is not None else "All Types"
        status_filter = self._search_status_filter.currentText() if self._search_status_filter is not None else "All"
        genre_filter = self._search_genre_filter.currentText() if self._search_genre_filter is not None else "All Genres"
        year_filter = self._search_year_filter.currentText() if self._search_year_filter is not None else "All Years"
        refresh_sig = (
            int(getattr(self, "_home_catalog_revision", 0) or 0),
            int(getattr(self, "_home_state_revision", 0) or 0),
            query,
            type_filter,
            status_filter,
            genre_filter,
            year_filter,
        )
        if self._search_last_refresh_signature == refresh_sig:
            self._library_refresh_hq(force=False)
            return
        self._search_last_refresh_signature = refresh_sig

        genre_filter_cf = str(genre_filter).strip().casefold()
        year_filter_text = str(year_filter).strip()

        verified: List[ShowGroup] = []
        discovered: List[ShowGroup] = []
        for entry in entries:
            key = str(entry.get("key") or "")
            if not key:
                continue
            is_verified = key in verified_keys
            if query and query not in str(entry.get("search_blob") or ""):
                continue

            media_type = str(entry.get("media_type") or "")
            if type_filter == "Movies" and media_type != "movie":
                continue
            if type_filter == "TV Shows" and media_type == "movie":
                continue
            if genre_filter != "All Genres" and genre_filter_cf not in entry.get("genres_cf", frozenset()):
                continue
            if year_filter != "All Years" and str(entry.get("year_text") or "") != year_filter_text:
                continue
            if status_filter == "Verified" and not is_verified:
                continue
            if status_filter == "Discovered" and is_verified:
                continue
            if status_filter == "Unresolved" and bool(entry.get("has_tmdb")):
                continue
            if status_filter == "Favorites" and key not in favorites:
                continue
            if status_filter == "Watched" and not bool(watched_map.get(key, False)):
                continue
            if status_filter == "Unwatched" and bool(watched_map.get(key, False)):
                continue

            sg = entry.get("sg")
            if sg is None:
                continue
            if is_verified:
                verified.append(sg)
            else:
                discovered.append(sg)

        self._search_populate_list(self._search_verified_list, verified, source="verified")
        self._search_populate_list(self._search_discovered_list, discovered, source="discovered")

        visible_keys = {self._home_item_key(sg) for sg in verified + discovered if self._home_item_key(sg)}
        self._search_selected_keys = [key for key in self._search_selected_keys if key in visible_keys]
        if self._search_selected_key and self._search_selected_key not in visible_keys:
            self._search_selected_key = self._search_selected_keys[0] if self._search_selected_keys else ""
        if self._search_selection_source and not self._search_selected_keys:
            self._search_selection_source = ""

        unresolved = sum(1 for sg in discovered if getattr(sg, "tmdb_id", None) is None)
        if self._search_stats_label is not None:
            self._search_stats_label.setText(
                f"Verified: {len(verified)}  |  Discovered: {len(discovered)}  |  Unresolved: {unresolved}"
            )

        if self._search_selected_key:
            self._search_update_details(self._search_selected_key)
        else:
            self._search_update_details("")

        dprint(f"[SEARCH] refresh verified={len(verified)} discovered={len(discovered)} unresolved={unresolved} query={query!r}")
        self._library_refresh_hq(force=False)
    def _personalization_state_preset_name(self) -> str:
        active = self._personalization if isinstance(getattr(self, "_personalization", None), dict) else {}
        wanted = str(active.get("preset") or "").strip()
        if wanted in OMEGA_THEME_PRESETS:
            return wanted
        raw = self._home_state.get("personalization", {}) if isinstance(getattr(self, "_home_state", None), dict) else {}
        if isinstance(raw, dict):
            wanted = str(raw.get("preset") or "").strip()
            if wanted in OMEGA_THEME_PRESETS:
                return wanted
        return "Aurora"

    def _personalization_preset_payload(self, name: str = "") -> Dict[str, Any]:
        wanted = str(name or self._personalization_state_preset_name() or "Aurora").strip()
        payload = OMEGA_THEME_PRESETS.get(wanted) or OMEGA_THEME_PRESETS["Aurora"]
        return deepcopy(payload)

    def _personalization_presets(self) -> Dict[str, Dict[str, str]]:
        return {
            str(name): dict(payload.get("colors", {}) or {})
            for name, payload in OMEGA_THEME_PRESETS.items()
        }

    def _personalization_preset_description(self, name: str = "") -> str:
        payload = self._personalization_preset_payload(name)
        return str(payload.get("description") or "").strip()

    def _theme_experience_payload(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        payload = self._personalization_preset_payload(str(preset_name or self._personalization_state_preset_name() or "Aurora"))
        raw = payload.get("experience", {}) if isinstance(payload.get("experience"), dict) else {}
        return dict(raw or {})

    def _theme_curated_sort_key(self, name: str) -> Tuple[int, int, str]:
        featured_order = {
            "Aurora": 0,
            "Starlight Parade": 1,
            "Gilded Noir": 2,
            "Deep Sea Opera": 3,
            "Rose Theater": 4,
            "Moonstone Lounge": 5,
            "Monorail Sunset": 6,
            "Winter Palace": 7,
        }
        if name in featured_order:
            return (0, int(featured_order.get(name, 0)), str(name).casefold())
        return (1, 999, str(name).casefold())

    def _theme_picker_subtitle(self, payload: Dict[str, Any]) -> str:
        experience = payload.get("experience", {}) if isinstance(payload.get("experience"), dict) else {}
        caption = str(experience.get("preview_caption", "") or "").strip()
        suffix = str(experience.get("brand_meta_suffix", "") or "").strip()
        description = str(payload.get("description", "") or "").strip()
        line = caption or suffix or description or "Flagship atmosphere"
        if line:
            line = line[0].upper() + line[1:]
        if len(line) > 42:
            line = line[:39].rstrip() + "..."
        return line

    def _theme_picker_item_text(self, name: str, payload: Dict[str, Any]) -> str:
        return f"{str(name)}\n{self._theme_picker_subtitle(payload)}"

    def _theme_picker_item_tooltip(self, payload: Dict[str, Any]) -> str:
        description = str(payload.get("description", "") or "").strip()
        experience = payload.get("experience", {}) if isinstance(payload.get("experience"), dict) else {}
        caption = str(experience.get("preview_caption", "") or "").strip()
        suffix = str(experience.get("brand_meta_suffix", "") or "").strip()
        lines = [line for line in (description, caption, suffix) if line]
        return "\n".join(lines)

    def _background_presentation_default(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        presentation = {
            "image_fit": "contain",
            "video_fit": "contain",
            "anchor": "center",
            "matte": "#000000",
            "blur_strength": 2,
        }
        payload = self._personalization_preset_payload(str(preset_name or self._personalization_state_preset_name() or "Aurora"))
        bg = payload.get("background", {}) if isinstance(payload.get("background"), dict) else {}
        if isinstance(bg.get("presentation"), dict):
            presentation = self._background_presentation_from_config({"presentation": bg.get("presentation", {})})
        return presentation

    def _background_norm_image_fit(self, value: str) -> str:
        key = str(value or "").strip().casefold().replace(" ", "_").replace("-", "_")
        allowed = {item[0] for item in _BG_IMAGE_FIT_CHOICES}
        return key if key in allowed else "contain"

    def _background_norm_video_fit(self, value: str) -> str:
        key = str(value or "").strip().casefold().replace(" ", "_").replace("-", "_")
        allowed = {item[0] for item in _BG_VIDEO_FIT_CHOICES}
        return key if key in allowed else "contain"

    def _background_norm_anchor(self, value: str) -> str:
        key = str(value or "").strip().casefold().replace(" ", "_").replace("-", "_")
        allowed = {item[0] for item in _BG_ANCHOR_CHOICES}
        return key if key in allowed else "center"

    def _background_norm_matte(self, value: str) -> str:
        return self._personalization_norm_hex(str(value or ""), "#000000")

    def _background_norm_blur_strength(self, value: Any) -> int:
        try:
            return max(0, min(20, int(value)))
        except Exception:
            return 2

    def _background_overlay_opacity(self, value: Any = None) -> int:
        # Keep the art fully visible. If we later want a cinematic veil again,
        # this is the single place to reintroduce it intentionally.
        _ = value
        return 0

    def _background_presentation_from_config(self, bg_cfg: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        bg = bg_cfg if isinstance(bg_cfg, dict) else {}
        raw = bg.get("presentation", {}) if isinstance(bg.get("presentation"), dict) else {}
        return {
            "image_fit": self._background_norm_image_fit(str(raw.get("image_fit", "contain") or "contain")),
            "video_fit": self._background_norm_video_fit(str(raw.get("video_fit", "contain") or "contain")),
            "anchor": self._background_norm_anchor(str(raw.get("anchor", "center") or "center")),
            "matte": self._background_norm_matte(str(raw.get("matte", "#000000") or "#000000")),
            "blur_strength": self._background_norm_blur_strength(raw.get("blur_strength", 2)),
        }

    def _background_select_combo_value(self, combo: Optional[QComboBox], key: str) -> None:
        if combo is None:
            return
        idx = combo.findData(str(key or ""))
        combo.setCurrentIndex(idx if idx >= 0 else 0)

    def _player_chrome_scope_token(
        self,
        scope: Optional[str] = None,
        *,
        fullscreen: Optional[bool] = None,
    ) -> str:
        raw = str(scope or "").strip().casefold()
        if raw in {"windowed", "fullscreen"}:
            return raw
        if bool(fullscreen):
            return "fullscreen"
        return "windowed"

    def _player_chrome_scope_state_key(
        self,
        scope: Optional[str] = None,
        *,
        fullscreen: Optional[bool] = None,
    ) -> str:
        return "player_chrome_fullscreen" if self._player_chrome_scope_token(scope, fullscreen=fullscreen) == "fullscreen" else "player_chrome_windowed"

    def _player_chrome_active_scope(self) -> str:
        combo = getattr(self, "_player_chrome_scope_combo", None)
        if combo is None:
            return self._player_chrome_scope_token(getattr(self, "_player_chrome_edit_scope", "windowed"))
        return self._player_chrome_scope_token(str(combo.currentData() or getattr(self, "_player_chrome_edit_scope", "windowed")))

    def _player_chrome_selected_preset_name(self) -> str:
        list_widget = getattr(self, "_player_chrome_preset_list", None)
        if list_widget is not None:
            item = list_widget.currentItem()
            if item is not None:
                selected = str(item.data(Qt.UserRole) or item.text() or "").strip()
                if selected in OMEGA_THEME_PRESETS:
                    return selected
        wanted = self._studio_theme_selected_name()
        return wanted if wanted in OMEGA_THEME_PRESETS else "Aurora"

    def _player_chrome_select_preset_list_item(self, name: str) -> None:
        list_widget = getattr(self, "_player_chrome_preset_list", None)
        if list_widget is None:
            return
        target = str(name or "Aurora").strip()
        list_widget.blockSignals(True)
        for index in range(list_widget.count()):
            item = list_widget.item(index)
            if item is None:
                continue
            if str(item.data(Qt.UserRole) or item.text() or "").strip() == target:
                list_widget.setCurrentRow(index)
                break
        list_widget.blockSignals(False)

    def _player_chrome_update_scope_label(self, scope: Optional[str] = None) -> None:
        label = getattr(self, "_player_chrome_scope_label", None)
        if label is None:
            return
        token = self._player_chrome_scope_token(scope if scope is not None else self._player_chrome_active_scope())
        name = "Fullscreen player" if token == "fullscreen" else "Windowed player"
        label.setText(f"Editing {name} chrome. Load any theme preset into this scope, then fine-tune the shell colors and bar finish below.")

    def _player_chrome_default(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        payload = self._personalization_preset_payload(str(preset_name or self._personalization_state_preset_name() or "Aurora"))
        raw = payload.get("player_chrome", {}) if isinstance(payload.get("player_chrome"), dict) else {}
        return self._player_chrome_from_config(raw, preset_name=preset_name)

    def _player_chrome_norm_int(self, value: Any, minimum: int, maximum: int, fallback: int) -> int:
        try:
            return max(int(minimum), min(int(maximum), int(round(float(value)))))
        except Exception:
            return int(fallback)

    def _player_chrome_from_config(self, raw: Any, *, preset_name: Optional[str] = None) -> Dict[str, Any]:
        payload = self._personalization_preset_payload(str(preset_name or self._personalization_state_preset_name() or "Aurora"))
        base_any = payload.get("player_chrome", {}) if isinstance(payload.get("player_chrome"), dict) else {}
        base = dict(base_any or {})
        source = raw if isinstance(raw, dict) else {}
        out = {
            "bar_top": self._personalization_norm_hex(source.get("bar_top", base.get("bar_top", "#1A1E28")), base.get("bar_top", "#1A1E28")),
            "bar_bottom": self._personalization_norm_hex(source.get("bar_bottom", base.get("bar_bottom", "#0A0D14")), base.get("bar_bottom", "#0A0D14")),
            "panel": self._personalization_norm_hex(source.get("panel", base.get("panel", "#0B1118")), base.get("panel", "#0B1118")),
            "panel_alt": self._personalization_norm_hex(source.get("panel_alt", base.get("panel_alt", "#121A24")), base.get("panel_alt", "#121A24")),
            "text": self._personalization_norm_hex(source.get("text", base.get("text", "#F4F7FF")), base.get("text", "#F4F7FF")),
            "muted_text": self._personalization_norm_hex(source.get("muted_text", base.get("muted_text", "#B4C0D8")), base.get("muted_text", "#B4C0D8")),
            "border": self._personalization_norm_hex(source.get("border", base.get("border", "#2A3449")), base.get("border", "#2A3449")),
            "primary": self._personalization_norm_hex(source.get("primary", base.get("primary", "#5CA0FF")), base.get("primary", "#5CA0FF")),
            "accent": self._personalization_norm_hex(source.get("accent", base.get("accent", "#4FD4B3")), base.get("accent", "#4FD4B3")),
            "danger": self._personalization_norm_hex(source.get("danger", base.get("danger", "#E46666")), base.get("danger", "#E46666")),
            "surface_alpha": self._player_chrome_norm_int(source.get("surface_alpha", base.get("surface_alpha", 236)), 0, 255, int(base.get("surface_alpha", 236))),
            "panel_alpha": self._player_chrome_norm_int(source.get("panel_alpha", base.get("panel_alpha", 228)), 0, 255, int(base.get("panel_alpha", 228))),
            "button_alpha": self._player_chrome_norm_int(source.get("button_alpha", base.get("button_alpha", 20)), 0, 255, int(base.get("button_alpha", 20))),
            "radius": self._player_chrome_norm_int(source.get("radius", base.get("radius", 14)), 8, 28, int(base.get("radius", 14))),
            "shadow_alpha": self._player_chrome_norm_int(source.get("shadow_alpha", base.get("shadow_alpha", 150)), 0, 255, int(base.get("shadow_alpha", 150))),
        }
        return out

    def _player_chrome_update_color_button(self, key: str, value: str) -> None:
        btn = (self._player_chrome_color_swatches or {}).get(str(key))
        if btn is None:
            return
        hx = self._personalization_norm_hex(str(value or ""), "#5CA0FF")
        r, g, b = self._personalization_hex_rgb(hx, hx)
        luminance = (0.299 * float(r)) + (0.587 * float(g)) + (0.114 * float(b))
        fg = "#09111B" if luminance >= 170 else "#F6FAFF"
        btn.setText(hx)
        btn.setStyleSheet(
            f"background: {hx}; color: {fg}; border: 1px solid rgba(255,255,255,0.20); "
            "border-radius: 14px; padding: 10px 12px; font-weight: 800;"
        )

    def _player_chrome_make_color_card(self, parent: QWidget, key: str, label: str, detail: str) -> QWidget:
        frame = QFrame(parent)
        frame.setObjectName("themeColorCard")
        h = QHBoxLayout(frame)
        h.setContentsMargins(14, 12, 14, 12)
        h.setSpacing(12)

        swatch = QPushButton("#000000", frame)
        swatch.setObjectName("themeColorSwatch")
        swatch.setCursor(Qt.PointingHandCursor)
        swatch.setFocusPolicy(Qt.NoFocus)
        swatch.clicked.connect(lambda _=False, k=key: self._player_chrome_pick_color(k))
        h.addWidget(swatch, 0)

        text_col = QVBoxLayout()
        text_col.setContentsMargins(0, 0, 0, 0)
        text_col.setSpacing(2)
        title = QLabel(label, frame)
        title.setStyleSheet("font-size: 14px; font-weight: 800; background: transparent;")
        desc = QLabel(detail, frame)
        desc.setObjectName("studioGroupLead")
        desc.setWordWrap(True)
        text_col.addWidget(title)
        text_col.addWidget(desc)
        h.addLayout(text_col, 1)

        self._player_chrome_color_inputs[key] = swatch
        self._player_chrome_color_swatches[key] = swatch
        return frame

    def _player_chrome_pick_color(self, key: str) -> None:
        inp = (self._player_chrome_color_inputs or {}).get(str(key))
        if inp is None:
            return
        try:
            base = str(inp.text() or "#5CA0FF")
        except Exception:
            base = "#5CA0FF"
        c = QColorDialog.getColor(QColor(base), self.win, "Pick Player Chrome Color")
        if not c.isValid():
            return
        hx = str(c.name()).upper()
        try:
            inp.setText(hx)
        except Exception:
            pass
        self._player_chrome_update_color_button(key, hx)
        self._studio_refresh_live_previews()

    def _player_chrome_sync_inputs_from_config(self, cfg: Optional[Dict[str, Any]] = None, *, scope: Optional[str] = None) -> None:
        scope_token = self._player_chrome_scope_token(scope if scope is not None else self._player_chrome_active_scope())
        source = self._player_chrome_from_config(
            cfg if isinstance(cfg, dict) else self._personalization.get(self._player_chrome_scope_state_key(scope_token), {})
        )
        for key, btn in (self._player_chrome_color_inputs or {}).items():
            if btn is None:
                continue
            hx = str(source.get(key, "#5CA0FF") or "#5CA0FF")
            btn.setText(hx)
            self._player_chrome_update_color_button(key, hx)
        for key, ctrl in (self._player_chrome_metric_inputs or {}).items():
            if ctrl is None:
                continue
            value = int(source.get(key, 0) or 0)
            if isinstance(ctrl, QSpinBox):
                ctrl.setValue(value)
        self._player_chrome_edit_scope = scope_token
        self._player_chrome_update_scope_label(scope_token)

    def _player_chrome_read_inputs(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        cfg = self._player_chrome_default(preset_name)
        for key, btn in (self._player_chrome_color_inputs or {}).items():
            if btn is None or key not in cfg:
                continue
            cfg[key] = self._personalization_norm_hex(btn.text() if hasattr(btn, "text") else "", cfg[key])
        for key, ctrl in (self._player_chrome_metric_inputs or {}).items():
            if ctrl is None or key not in cfg:
                continue
            if isinstance(ctrl, QSpinBox):
                cfg[key] = int(ctrl.value())
        return self._player_chrome_from_config(cfg, preset_name=preset_name)

    def _player_chrome_commit_scope_inputs(self, scope: Optional[str] = None) -> None:
        scope_token = self._player_chrome_scope_token(scope if scope is not None else self._player_chrome_edit_scope)
        self._personalization[self._player_chrome_scope_state_key(scope_token)] = self._player_chrome_read_inputs(self._studio_theme_selected_name())

    def _player_chrome_current_cfg(self, *, scope: Optional[str] = None, fullscreen: Optional[bool] = None) -> Dict[str, Any]:
        scope_token = self._player_chrome_scope_token(scope, fullscreen=fullscreen)
        return self._player_chrome_from_config(
            self._personalization.get(self._player_chrome_scope_state_key(scope_token), {}),
            preset_name=str(self._personalization.get("preset", self._personalization_state_preset_name()) or "Aurora"),
        )

    def _player_chrome_load_scope_preset(self, preset_name: str, *, scope: Optional[str] = None) -> None:
        wanted = str(preset_name or "Aurora").strip()
        if wanted not in OMEGA_THEME_PRESETS:
            wanted = "Aurora"
        scope_token = self._player_chrome_scope_token(scope if scope is not None else self._player_chrome_active_scope())
        cfg = self._player_chrome_default(wanted)
        self._personalization[self._player_chrome_scope_state_key(scope_token)] = dict(cfg)
        self._player_chrome_sync_inputs_from_config(cfg, scope=scope_token)
        self._studio_refresh_live_previews()

    def _player_chrome_on_scope_changed(self) -> None:
        if bool(getattr(self, "_personalization_syncing_inputs", False)):
            self._player_chrome_edit_scope = self._player_chrome_active_scope()
            self._player_chrome_update_scope_label(self._player_chrome_edit_scope)
            return
        previous_scope = self._player_chrome_scope_token(getattr(self, "_player_chrome_edit_scope", "windowed"))
        self._player_chrome_commit_scope_inputs(previous_scope)
        next_scope = self._player_chrome_active_scope()
        self._player_chrome_sync_inputs_from_config(scope=next_scope)
        self._studio_refresh_live_previews()

    def _player_chrome_on_preset_list_changed(self) -> None:
        if bool(getattr(self, "_personalization_syncing_inputs", False)):
            return
        self._player_chrome_load_scope_preset(self._player_chrome_selected_preset_name(), scope=self._player_chrome_active_scope())

    def _player_chrome_copy_scope_to_other(self) -> None:
        source_scope = self._player_chrome_active_scope()
        target_scope = "fullscreen" if source_scope == "windowed" else "windowed"
        self._player_chrome_commit_scope_inputs(source_scope)
        copied = dict(self._personalization.get(self._player_chrome_scope_state_key(source_scope), {}) or {})
        self._personalization[self._player_chrome_scope_state_key(target_scope)] = self._player_chrome_from_config(
            copied,
            preset_name=self._studio_theme_selected_name(),
        )
        self._studio_refresh_live_previews()

    def _home_chrome_default(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        payload = self._personalization_preset_payload(str(preset_name or self._personalization_state_preset_name() or "Aurora"))
        source = payload.get("home_chrome", {}) if isinstance(payload.get("home_chrome"), dict) else {}
        base = {
            "top_nav_position": "left",
            "dock_position": "bottom",
            "top_nav_variant": "default",
            "dock_variant": "default",
        }
        for key, value in source.items():
            base[str(key)] = value
        return self._home_chrome_from_config(base)

    def _home_chrome_from_config(self, raw: Any) -> Dict[str, Any]:
        source = raw if isinstance(raw, dict) else {}
        positions = {"top", "bottom", "left", "right"}
        variants = {"default", "cinema", "neon", "minimal", "luxe", "editorial", "signal"}
        return {
            "top_nav_position": str(source.get("top_nav_position", "top") or "top").strip().casefold() if str(source.get("top_nav_position", "top") or "top").strip().casefold() in positions else "top",
            "dock_position": str(source.get("dock_position", "bottom") or "bottom").strip().casefold() if str(source.get("dock_position", "bottom") or "bottom").strip().casefold() in positions else "bottom",
            "top_nav_variant": str(source.get("top_nav_variant", "default") or "default").strip().casefold() if str(source.get("top_nav_variant", "default") or "default").strip().casefold() in variants else "default",
            "dock_variant": str(source.get("dock_variant", "default") or "default").strip().casefold() if str(source.get("dock_variant", "default") or "default").strip().casefold() in variants else "default",
        }

    def _home_chrome_current_cfg(self) -> Dict[str, Any]:
        return self._home_chrome_from_config(self._personalization.get("home_chrome", {}))

    def _personalization_default(self, preset_name: Optional[str] = None) -> Dict[str, Any]:
        default_name = str(preset_name or self._personalization_state_preset_name() or "Aurora")
        payload = self._personalization_preset_payload(default_name)
        bg_payload = payload.get("background", {}) if isinstance(payload.get("background"), dict) else {}
        overlay_opacity = self._background_overlay_opacity(bg_payload.get("overlay_opacity", 0))
        return {
            "preset": default_name,
            "colors": dict(payload.get("colors", {}) or {}),
            "background": {
                "overlay_opacity": overlay_opacity,
                "presentation": self._background_presentation_default(default_name),
                "global": {"image": "", "video": ""},
                "pages": {
                    "home": {"image": "", "video": ""},
                    "search": {"image": "", "video": ""},
                    "player": {"image": "", "video": ""},
                },
            },
            "glass": self._glass_default(default_name),
            "home_chrome": self._home_chrome_default(default_name),
            "player_chrome_windowed": self._player_chrome_default(default_name),
            "player_chrome_fullscreen": self._player_chrome_default(default_name),
            "typography": {"family": str(self.T.typography.preferred_family or "Segoe UI"), "scale": 100, "weight": 500, "density": "Balanced"},
            "intro_animation": {"enabled": True, "style": "Rail Cascade", "duration": "Balanced", "play_once": True},
        }

    def _personalization_merge_from_state(self) -> None:
        raw = self._home_state.get("personalization", {})
        self._bg_trace("merge-state", f"raw-type={type(raw).__name__}")
        if not isinstance(raw, dict):
            self._bg_trace("merge-state", "raw-not-dict")
            return

        raw_preset = str(raw.get("preset") or self._personalization_state_preset_name() or "Aurora")
        base = self._personalization_default(raw_preset)
        out = dict(base)
        out["preset"] = str(raw_preset or base.get("preset") or "Aurora")

        colors = dict(base.get("colors", {}))
        if isinstance(raw.get("colors"), dict):
            for k, v in raw.get("colors", {}).items():
                colors[str(k)] = str(v)
        out["colors"] = colors

        bg = dict(base.get("background", {}))
        bg["presentation"] = self._background_presentation_default()
        if isinstance(raw.get("background"), dict):
            rb = raw.get("background", {})
            bg["overlay_opacity"] = self._background_overlay_opacity(rb.get("overlay_opacity", bg.get("overlay_opacity", 0)))
            bg["presentation"] = self._background_presentation_from_config(rb)
            if isinstance(rb.get("global"), dict):
                bg["global"] = {
                    "image": str(rb.get("global", {}).get("image", "") or ""),
                    "video": str(rb.get("global", {}).get("video", "") or ""),
                }
            pages = bg.get("pages", {}) if isinstance(bg.get("pages"), dict) else {}
            if isinstance(rb.get("pages"), dict):
                for page in ("home", "search", "player"):
                    src = rb.get("pages", {}).get(page, {}) if isinstance(rb.get("pages", {}).get(page, {}), dict) else {}
                    pages[page] = {
                        "image": str(src.get("image", "") or ""),
                        "video": str(src.get("video", "") or ""),
                    }
                bg["pages"] = pages
        out["background"] = bg
        out["glass"] = self._glass_from_config(raw.get("glass", base.get("glass", {})))
        out["home_chrome"] = self._home_chrome_from_config(raw.get("home_chrome", base.get("home_chrome", {})))
        out["home_chrome"]["top_nav_position"] = "left"
        legacy_player = raw.get("player_chrome", base.get("player_chrome_windowed", {}))
        windowed_player = raw.get("player_chrome_windowed", legacy_player)
        fullscreen_player = raw.get("player_chrome_fullscreen", windowed_player)
        out["player_chrome_windowed"] = self._player_chrome_from_config(windowed_player)
        out["player_chrome_fullscreen"] = self._player_chrome_from_config(fullscreen_player)
        typography = base.get("typography", {}) if isinstance(base.get("typography"), dict) else {}
        if isinstance(raw.get("typography"), dict):
            typography = dict(typography)
            typography["family"] = str(raw.get("typography", {}).get("family") or typography.get("family") or "Segoe UI")
            try:
                typography["scale"] = int(max(80, min(130, int(raw.get("typography", {}).get("scale", typography.get("scale", 100)) or 100))))
            except Exception:
                typography["scale"] = 100
            try:
                typography["weight"] = int(max(300, min(800, int(raw.get("typography", {}).get("weight", typography.get("weight", 500)) or 500))))
            except Exception:
                typography["weight"] = 500
            typography["density"] = str(raw.get("typography", {}).get("density") or typography.get("density") or "Balanced")
        out["typography"] = typography
        intro = base.get("intro_animation", {}) if isinstance(base.get("intro_animation"), dict) else {}
        if isinstance(raw.get("intro_animation"), dict):
            intro = dict(intro)
            intro["enabled"] = bool(raw.get("intro_animation", {}).get("enabled", intro.get("enabled", True)))
            intro["style"] = str(raw.get("intro_animation", {}).get("style") or intro.get("style") or "Rail Cascade")
            intro["duration"] = str(raw.get("intro_animation", {}).get("duration") or intro.get("duration") or "Balanced")
            intro["play_once"] = bool(raw.get("intro_animation", {}).get("play_once", intro.get("play_once", True)))
        out["intro_animation"] = intro

        self._personalization = out
        try:
            glob = bg.get("global", {}) if isinstance(bg.get("global"), dict) else {}
            pages = bg.get("pages", {}) if isinstance(bg.get("pages"), dict) else {}
            pres = self._background_presentation_from_config(bg)
            self._bg_trace(
                "merge-state",
                f"preset={out.get('preset', '')}",
                f"global_image={str(glob.get('image', '') or '').strip()}",
                f"global_video={str(glob.get('video', '') or '').strip()}",
                f"home_image={str((pages.get('home', {}) if isinstance(pages.get('home', {}), dict) else {}).get('image', '') or '').strip()}",
                f"search_image={str((pages.get('search', {}) if isinstance(pages.get('search', {}), dict) else {}).get('image', '') or '').strip()}",
                f"player_image={str((pages.get('player', {}) if isinstance(pages.get('player', {}), dict) else {}).get('image', '') or '').strip()}",
                f"image_fit={pres.get('image_fit', '')}",
                f"video_fit={pres.get('video_fit', '')}",
                f"anchor={pres.get('anchor', '')}",
                f"matte={pres.get('matte', '')}",
                f"blur={pres.get('blur_strength', '')}",
                f"overlay={bg.get('overlay_opacity', '')}",
            )
        except Exception:
            pass

    def _personalization_save(self) -> None:
        self._home_state["personalization"] = self._personalization
        self._home_state_save()
        try:
            bg = self._personalization.get("background", {}) if isinstance(self._personalization.get("background"), dict) else {}
            glob = bg.get("global", {}) if isinstance(bg.get("global"), dict) else {}
            pres = self._background_presentation_from_config(bg)
            self._bg_trace(
                "personalization-save",
                f"global_image={str(glob.get('image', '') or '').strip()}",
                f"global_video={str(glob.get('video', '') or '').strip()}",
                f"image_fit={pres.get('image_fit', '')}",
                f"video_fit={pres.get('video_fit', '')}",
                f"anchor={pres.get('anchor', '')}",
                f"matte={pres.get('matte', '')}",
                f"blur={pres.get('blur_strength', '')}",
                f"overlay={bg.get('overlay_opacity', '')}",
            )
        except Exception:
            pass

    def _personalization_norm_hex(self, value: str, fallback: str) -> str:
        s = str(value or "").strip()
        if not s:
            return str(fallback)
        if not s.startswith("#"):
            s = "#" + s
        if len(s) != 7:
            return str(fallback)
        try:
            int(s[1:], 16)
            return s.upper()
        except Exception:
            return str(fallback)

    def _personalization_hex_rgb(self, value: str, fallback: str) -> Tuple[int, int, int]:
        hx = self._personalization_norm_hex(value, fallback)
        return int(hx[1:3], 16), int(hx[3:5], 16), int(hx[5:7], 16)

