    def _install_global_undo_shortcuts(self) -> None:
        try:
            self._undo_shortcut = QShortcut(QKeySequence.Undo, self.win)
            self._undo_shortcut.setContext(Qt.ApplicationShortcut)
            self._undo_shortcut.activated.connect(self._handle_global_undo)
        except Exception:
            self._undo_shortcut = None

    def _native_widget_undo_targets(self, widget: Optional[QWidget]) -> List[QWidget]:
        if widget is None:
            return []
        targets: List[QWidget] = [widget]
        try:
            line_edit = widget.lineEdit() if hasattr(widget, "lineEdit") else None
        except Exception:
            line_edit = None
        if isinstance(line_edit, QWidget) and line_edit is not widget:
            targets.append(line_edit)
        return targets

    def _try_native_widget_undo(self, widget: Optional[QWidget]) -> bool:
        seen: set[int] = set()
        for target in self._native_widget_undo_targets(widget):
            ident = id(target)
            if ident in seen:
                continue
            seen.add(ident)
            undo = getattr(target, "undo", None)
            if not callable(undo):
                continue
            try:
                undo()
                return True
            except Exception:
                continue
        return False

    def _handle_global_undo(self) -> None:
        try:
            focused = QApplication.focusWidget()
        except Exception:
            focused = None
        if self._try_native_widget_undo(focused if isinstance(focused, QWidget) else None):
            return

        for editor_name, refresh in (
            ("_discover_layout_editor_canvas", lambda: (self._discover_layout_inventory_refresh(), self._discover_layout_refresh_hint())),
            ("_settings_layout_editor_canvas", lambda: (self._settings_layout_inventory_refresh(), self._settings_layout_refresh_hint())),
            ("_player_layout_editor_canvas", lambda: (self._player_layout_inventory_refresh(), self._player_layout_refresh_hint())),
        ):
            editor = getattr(self, editor_name, None)
            if editor is None:
                continue
            try:
                editor_has_focus = bool(editor.hasFocus() or editor.isAncestorOf(QApplication.focusWidget()))
            except Exception:
                editor_has_focus = False
            if not editor_has_focus:
                continue
            try:
                if editor.undo_last_change():
                    refresh()
                    self._studio_refresh_live_previews()
                    return
            except Exception:
                pass

