    def _page_layouts_settings_config(self) -> Dict[str, Any]:
        raw = self._page_layouts.get("settings", {}) if isinstance(getattr(self, "_page_layouts", None), dict) else {}
        return self._settings_layout_from_raw(raw)

    def _page_layouts_merge_from_state(self) -> None:
        raw = self._home_state.get("page_layouts", {})
        library_raw = self._page_layouts_default()["library"]
        if isinstance(raw, dict):
            if isinstance(raw.get("library"), dict):
                library_raw = raw.get("library", {})
            elif isinstance(raw.get("discover"), dict):
                library_raw = raw.get("discover", {})
        settings_raw = raw.get("settings", {}) if isinstance(raw, dict) and isinstance(raw.get("settings"), dict) else self._page_layouts_default()["settings"]
        player_raw = raw.get("player", {}) if isinstance(raw, dict) and isinstance(raw.get("player"), dict) else self._page_layouts_default()["player"]
        migrated = False
        if self._discover_layout_needs_schema_reset(library_raw):
            migrated = True
        if self._settings_layout_needs_schema_reset(settings_raw):
            migrated = True
        if self._player_layout_needs_schema_reset(player_raw):
            migrated = True
        library_cfg = self._discover_layout_from_raw(library_raw)
        settings_cfg = self._settings_layout_from_raw(settings_raw)
        player_cfg = self._player_layout_from_raw(player_raw)
        if self._discover_layout_matches_legacy_default(library_cfg):
            library_cfg = self._discover_layout_from_raw(self._page_layouts_default()["library"])
            migrated = True
        elif self._discover_layout_matches_compact_default(library_cfg):
            library_cfg = self._discover_layout_from_raw(self._page_layouts_default()["library"])
            migrated = True
        if self._settings_layout_matches_legacy_default(settings_cfg):
            settings_cfg = self._settings_layout_from_raw(self._page_layouts_default()["settings"])
            migrated = True
        self._page_layouts = {
            "library": library_cfg,
            "settings": settings_cfg,
            "player": player_cfg,
        }
        self._home_state["discover_dock_state"] = ""
        self._home_state["discover_split_sizes"] = [360, 360, 420]
        if migrated:
            self._home_state["page_layouts"] = deepcopy(self._page_layouts)
            try:
                self._home_state_save(force=True)
            except Exception:
                pass

    def _page_layouts_save(self) -> None:
        self._page_layouts["library"] = self._page_layouts_discover_config()
        self._page_layouts["settings"] = self._page_layouts_settings_config()
        self._page_layouts["player"] = self._page_layouts_player_config()
        self._home_state["page_layouts"] = deepcopy(self._page_layouts)
        self._home_state["discover_dock_state"] = ""
        self._home_state["discover_split_sizes"] = [360, 360, 420]
        self._home_state_save(force=True)

