    def _discover_layout_sync_editor_from_state(self) -> None:
        cfg = self._page_layouts_discover_config()
        self._page_layouts["library"] = deepcopy(cfg)
        canvas = getattr(self, "_discover_layout_editor_canvas", None)
        if canvas is not None:
            try:
                colors = self._studio_current_theme_colors(self._studio_theme_selected_name())
            except Exception:
                colors = dict(self._personalization.get("colors", {}) or {})
            component_labels = {key: self._discover_layout_component_label(key) for key in self._discover_layout_component_keys(cfg["spacer_count"])}
            canvas.set_items(
                cfg["items"],
                colors=colors,
                component_labels=component_labels,
                canvas_cols=int(cfg.get("canvas_cols", DISCOVER_LAYOUT_COLS) or DISCOVER_LAYOUT_COLS),
                canvas_rows=int(cfg.get("canvas_rows", DISCOVER_LAYOUT_ROWS) or DISCOVER_LAYOUT_ROWS),
            )
        self._discover_layout_update_size_labels()
        self._discover_layout_inventory_refresh()
        self._discover_layout_refresh_hint()
        self._studio_refresh_live_previews()

