    def _discover_layout_remove_unused_spacers(self) -> None:
        cfg = self._page_layouts_discover_config()
        used = [str(item.get("component", "") or "") for item in self._discover_layout_editor_items() if str(item.get("component", "") or "").startswith("spacer_")]
        highest = 1
        for key in used:
            try:
                highest = max(highest, int(key.split("_", 1)[1]))
            except Exception:
                continue
        cfg["spacer_count"] = self._discover_layout_sanitized_spacer_count(highest, fallback=1)
        self._page_layouts["library"] = cfg
        self._discover_layout_inventory_refresh()
        self._studio_refresh_live_previews()

