    def _discover_layout_editor_apply(self) -> None:
        cfg = self._page_layouts_discover_config()
        cfg["items"] = self._discover_layout_sanitize_items(self._discover_layout_editor_items(), cfg["spacer_count"])
        cfg["canvas_rows"] = max(
            int(cfg.get("canvas_rows", DISCOVER_LAYOUT_ROWS) or DISCOVER_LAYOUT_ROWS),
            int(validate_layout(cfg["items"], canvas_cols=int(cfg.get("canvas_cols", DISCOVER_LAYOUT_COLS) or DISCOVER_LAYOUT_COLS), canvas_rows=DISCOVER_LAYOUT_ROWS).content_bounds[3]),
        )
        used_spacer = 1
        for item in cfg["items"]:
            component = str(item.get("component", "") or "")
            if component.startswith("spacer_"):
                try:
                    used_spacer = max(used_spacer, int(component.split("_", 1)[1]))
                except Exception:
                    continue
        cfg["spacer_count"] = self._discover_layout_sanitized_spacer_count(max(cfg["spacer_count"], used_spacer), fallback=cfg["spacer_count"])
        self._page_layouts["library"] = cfg
        self._page_layouts_save()
        self._search_apply_discover_layout_config(save=False)
        self._discover_layout_update_size_labels()
        self._discover_layout_inventory_refresh()
        self._discover_layout_refresh_hint()
        self._studio_refresh_live_previews()

    def _discover_layout_editor_reset(self) -> None:
        self._page_layouts["library"] = deepcopy(self._page_layouts_default()["library"])
        self._page_layouts_save()
        self._discover_layout_sync_editor_from_state()
        self._search_apply_discover_layout_config(save=False)

