        used = [str(item.get("component", "") or "") for item in self._settings_layout_editor_items() if str(item.get("component", "") or "").startswith("spacer_")]
        highest = 1
        for key in used:
            try:
                highest = max(highest, int(key.split("_", 1)[1]))
            except Exception:
                continue
        cfg["spacer_count"] = self._discover_layout_sanitized_spacer_count(highest, fallback=1)
        self._page_layouts["settings"] = cfg
        self._settings_layout_inventory_refresh()
        self._studio_refresh_live_previews()

