    def _page_layout_render_items_for_host(
        self,
        page_id: str,
        cfg: Dict[str, Any],
        host: Optional[QWidget],
        *,
        default_cols: int,
        default_rows: int,
    ) -> Tuple[List[Dict[str, Any]], int, int]:
        source_cols = max(1, int(cfg.get("canvas_cols", default_cols) or default_cols))
        source_rows = max(1, int(cfg.get("canvas_rows", default_rows) or default_rows))
        host_width = 0
        if host is not None:
            try:
                host_width = int(host.width())
            except Exception:
                host_width = 0
        target_cols = breakpoint_cols_for_width(host_width, source_cols)
        source_items = [dict(item) for item in cfg.get("items", []) if isinstance(item, dict)]
        if target_cols != source_cols:
            render_items, render_rows = derive_responsive_layout(
                source_items,
                source_cols=source_cols,
                target_cols=target_cols,
                canvas_rows=source_rows,
            )
            note = f"responsive {source_cols}->{target_cols}"
        else:
            render_items = normalize_layout_items(
                source_items,
                canvas_cols=target_cols,
                canvas_rows=source_rows,
                compact=True,
            )
            validation = validate_layout(render_items, canvas_cols=target_cols, canvas_rows=source_rows)
            render_rows = max(source_rows, int(validation.content_bounds[3]))
            note = "wide"
        render_items = [dict(item) for item in render_items if not bool(item.get("hidden", False))]
        dprint(
            layout_debug_report(
                page_id,
                render_items,
                canvas_cols=target_cols,
                canvas_rows=render_rows,
                viewport_size=(host_width, int(host.height()) if host is not None else 0),
                canvas_size=(target_cols, render_rows),
                note=note,
            )
        )
        return render_items, target_cols, render_rows

    def _page_layouts_reflow_runtime(self) -> None:
        try:
            self._search_apply_discover_layout_config(save=False)
        except Exception as e:
            dprint("[LAYOUT][WARN] library runtime reflow failed:", e)
        try:
            self._settings_apply_layout_config()
        except Exception as e:
            dprint("[LAYOUT][WARN] settings runtime reflow failed:", e)

    def _settings_build_layout_spacer_widget(self, parent: QWidget, component_key: str) -> QWidget:
        frame = QFrame(parent)
        frame.setObjectName("discoverSpacerPanel")
        title = QLabel(self._settings_layout_component_label(component_key), frame)
        title.setAlignment(Qt.AlignLeft | Qt.AlignTop)
        subtitle = QLabel("Flexible spacer block for breathing room inside the Settings grid.", frame)
        subtitle.setStyleSheet("color: rgba(206,216,230,0.50); font-size: 11px; font-weight: 600;")
        subtitle.setWordWrap(True)
        frame.setStyleSheet(
            "QFrame#discoverSpacerPanel {"
            "background: rgba(255,255,255,0.028);"
            "border: 1px dashed rgba(255,255,255,0.14);"
            "border-radius: 16px;"
            "}"
            "QLabel { background: transparent; color: rgba(230,236,246,0.74); font-size: 12px; font-weight: 700; }"
        )
        lay = QVBoxLayout(frame)
        lay.setContentsMargins(14, 14, 14, 14)
        lay.setSpacing(8)
        lay.addWidget(title)
        lay.addWidget(subtitle)
        lay.addStretch(1)
        return frame

    def _settings_apply_layout_config(self) -> None:
        grid_layout = getattr(self, "_settings_layout_grid_layout", None)
        panels = getattr(self, "_settings_layout_panels", {})
        if grid_layout is None or not isinstance(panels, dict) or not panels:
            return

        while grid_layout.count():
            item = grid_layout.takeAt(0)
            widget = item.widget()
            if widget is not None:
                widget.hide()
        for widget in list((self._settings_layout_spacers or {}).values()):
            try:
                widget.setParent(None)
                widget.deleteLater()
            except Exception:
                pass
        self._settings_layout_spacers = {}

        cfg = self._page_layouts_settings_config()
        assigned: set[str] = set()
        host = getattr(self, "_settings_layout_grid_host", None)
        render_items, canvas_cols, canvas_rows = self._page_layout_render_items_for_host(
            "settings",
            cfg,
            host,
            default_cols=SETTINGS_LAYOUT_COLS,
            default_rows=SETTINGS_LAYOUT_ROWS,
        )
        for row in range(max(64, canvas_rows)):
            try:
                grid_layout.setRowStretch(row, 1 if row < canvas_rows else 0)
                grid_layout.setRowMinimumHeight(row, 0)
            except Exception:
                pass
        for col in range(max(32, canvas_cols)):
            try:
                grid_layout.setColumnStretch(col, 1 if col < canvas_cols else 0)
                grid_layout.setColumnMinimumWidth(col, 0)
            except Exception:
                pass

        if host is not None:
            try:
                host.setMinimumHeight(max(int(SETTINGS_MODULAR_GRID_MIN_HEIGHT_PX), int(canvas_rows * SETTINGS_MODULAR_GRID_ROW_PX)))
            except Exception:
                pass
        for item in render_items:
            component_key = str(item.get("component", "") or "").strip()
            item_id = str(item.get("id", component_key) or component_key).strip()
            widget = panels.get(component_key)
            if widget is None or (component_key in assigned and not component_key.startswith("spacer_")):
                widget = self._settings_build_layout_spacer_widget(host or self.searchPage, component_key or "spacer_1")
                self._settings_layout_spacers[item_id] = widget
            else:
                assigned.add(component_key)
            try:
                grid_layout.addWidget(
                    widget,
                    int(item.get("y", 0) or 0),
                    int(item.get("x", 0) or 0),
                    max(1, int(item.get("h", 1) or 1)),
                    max(1, int(item.get("w", 1) or 1)),
                )
                widget.show()
            except Exception:
                continue

    def _search_build_discover_spacer_widget(self, parent: QWidget, component_key: str) -> QWidget:
        frame = QFrame(parent)
        frame.setObjectName("discoverSpacerPanel")
        label = self._discover_layout_component_label(component_key)
        frame.setStyleSheet(
            "QFrame#discoverSpacerPanel {"
            "background: rgba(255,255,255,0.028);"
            "border: 1px dashed rgba(255,255,255,0.14);"
            "border-radius: 16px;"
            "}"
            "QLabel { background: transparent; color: rgba(230,236,246,0.74); font-size: 12px; font-weight: 700; }"
        )
        lay = QVBoxLayout(frame)
        lay.setContentsMargins(14, 14, 14, 14)
        lay.setSpacing(8)
        title = QLabel(label, frame)
        title.setAlignment(Qt.AlignLeft | Qt.AlignTop)
        subtitle = QLabel("Flexible spacer block for breathing room inside the Library grid.", frame)
        subtitle.setStyleSheet("color: rgba(206,216,230,0.50); font-size: 11px; font-weight: 600;")
        subtitle.setWordWrap(True)
        lay.addWidget(title)
        lay.addWidget(subtitle)
        lay.addStretch(1)
        return frame

    def _search_apply_discover_layout_config(self, *, save: bool = False) -> None:
        grid_layout = getattr(self, "_search_discover_grid_layout", None)
        panels = getattr(self, "_search_discover_panels", {})
        if grid_layout is not None and isinstance(panels, dict) and panels:
            while grid_layout.count():
                item = grid_layout.takeAt(0)
                widget = item.widget()
                if widget is not None:
                    widget.hide()
            for widget in list((self._search_discover_spacers or {}).values()):
                try:
                    widget.setParent(None)
                    widget.deleteLater()
                except Exception:
                    pass
            self._search_discover_spacers = {}

            cfg = self._page_layouts_discover_config()
            render_items, canvas_cols, canvas_rows = self._page_layout_render_items_for_host(
                "library",
                cfg,
                getattr(self, "_search_discover_grid_host", None),
                default_cols=DISCOVER_LAYOUT_COLS,
                default_rows=DISCOVER_LAYOUT_ROWS,
            )
            assigned: set[str] = set()
            for row in range(max(48, canvas_rows)):
                try:
                    grid_layout.setRowStretch(row, 1 if row < canvas_rows else 0)
                    grid_layout.setRowMinimumHeight(row, 0)
                except Exception:
                    pass
            for col in range(max(32, canvas_cols)):
                try:
                    grid_layout.setColumnStretch(col, 1 if col < canvas_cols else 0)
                    grid_layout.setColumnMinimumWidth(col, 0)
                except Exception:
                    pass

            host = getattr(self, "_search_discover_grid_host", None)
            if host is not None:
                try:
                    host.setMinimumHeight(max(int(LIBRARY_PAGE_GRID_MIN_HEIGHT_PX), int(canvas_rows * LIBRARY_PAGE_GRID_ROW_PX)))
                except Exception:
                    pass

            for item in render_items:
                component_key = str(item.get("component", "") or "").strip()
                item_id = str(item.get("id", component_key) or component_key).strip()
                widget = panels.get(component_key)
                if widget is None or (component_key in assigned and not component_key.startswith("spacer_")):
                    spacer = self._search_build_discover_spacer_widget(self._search_discover_grid_host, component_key or "spacer_1")
                    self._search_discover_spacers[item_id] = spacer
                    widget = spacer
                else:
                    assigned.add(component_key)
                try:
                    grid_layout.addWidget(
                        widget,
                        int(item.get("y", 0) or 0),
                        int(item.get("x", 0) or 0),
                        max(1, int(item.get("h", 1) or 1)),
                        max(1, int(item.get("w", 1) or 1)),
                    )
                    widget.show()
                except Exception:
                    continue

            self._home_state["discover_dock_state"] = ""
            self._home_state["discover_split_sizes"] = [360, 360, 420]
            if save:
                self._page_layouts_save()
            return

        splitter = getattr(self, "_search_discover_splitter", None)
        panels = getattr(self, "_search_discover_panels", {})
        if splitter is None or not isinstance(panels, dict) or not panels:
            return

        cfg = self._page_layouts_discover_config()
        order = [key for key in ("discovered", "verified", "details") if key in panels]
        if not order:
            return

        for index, key in enumerate(order):
            widget = panels.get(key)
            if widget is None:
                continue
            splitter.insertWidget(index, widget)
            widget.show()

        legacy_sizes = [360, 360, 420]
        sizes = legacy_sizes[: len(order)]
        if len(sizes) == splitter.count():
            splitter.setSizes(sizes)

        self._home_state["discover_dock_state"] = ""
        self._home_state["discover_split_sizes"] = list(sizes)
        if save:
            self._page_layouts_save()

    def _app_customization_add_numeric_control(
        self,
        form: QFormLayout,
        parent: QWidget,
        *,
        section: str,
        key: str,
        label: str,
        minimum: float,
        maximum: float,
        step: float,
        suffix: str = "",
        display_factor: float = 1.0,
    ) -> QWidget:
        if display_factor != 1.0:
            ctrl = SuffixSafeDoubleSpinBox(parent)
            ctrl.setDecimals(0)
            ctrl.setRange(float(minimum), float(maximum))
            ctrl.setSingleStep(float(step))
        else:
            ctrl = SuffixSafeSpinBox(parent)
            ctrl.setRange(int(minimum), int(maximum))
            ctrl.setSingleStep(int(step))
        if suffix:
            ctrl.setSuffix(suffix)
        form.addRow(label, ctrl)
        self._app_customization_controls[f"{section}.{key}"] = {
            "control": ctrl,
            "section": str(section),
            "key": str(key),
            "display_factor": float(display_factor),
        }
        try:
            ctrl.valueChanged.connect(lambda _value=0: self._studio_refresh_live_previews())
        except Exception:
            pass
        return ctrl

    def _app_customization_apply_tuning(self) -> None:
        base = getattr(self, "_default_tuning", OmegaTuning())
        home_updates = dict(self._app_customization.get("home", {}) or {})
        overlay_updates = dict(self._app_customization.get("overlays", {}) or {})
        inline_updates = dict(self._app_customization.get("inline", {}) or {})
        player_updates = dict(self._app_customization.get("player", {}) or {})
        self.T = OmegaTuning(
            home=replace(base.home, **home_updates),
            viewport=base.viewport,
            overlays=replace(base.overlays, **overlay_updates),
            inline=replace(base.inline, **inline_updates),
            player=replace(base.player, **player_updates),
            shell=base.shell,
        )
        try:
            self._thumb_pump_timer.setInterval(int(self.T.home.thumbs_pump_interval_ms))
        except Exception:
            pass
        try:
            if hasattr(self, "_home_deferred_row_timer") and self._home_deferred_row_timer is not None:
                self._home_deferred_row_timer.setInterval(int(self.T.home.home_deferred_rows_interval_ms))
        except Exception:
            pass

    def _app_customization_collect_from_inputs(self, preset_name: Optional[str] = None) -> Dict[str, Dict[str, Any]]:
        cfg = self._app_customization_default(preset_name)
        for payload in (self._app_customization_controls or {}).values():
            ctrl = payload.get("control")
            section = str(payload.get("section") or "")
            key = str(payload.get("key") or "")
            factor = float(payload.get("display_factor") or 1.0)
            if ctrl is None or section not in cfg or key not in cfg[section]:
                continue
            if isinstance(ctrl, QDoubleSpinBox):
                cfg[section][key] = float(ctrl.value()) / factor if factor != 1.0 else float(ctrl.value())
            elif isinstance(ctrl, QSpinBox):
                cfg[section][key] = int(ctrl.value())
        return cfg

    def _app_customization_sync_inputs_from_config(self, cfg: Optional[Dict[str, Dict[str, Any]]] = None) -> None:
        defaults = self._app_customization_default()
        source_cfg = cfg if isinstance(cfg, dict) else self._app_customization
        for payload in (self._app_customization_controls or {}).values():
            ctrl = payload.get("control")
            section = str(payload.get("section") or "")
            key = str(payload.get("key") or "")
            factor = float(payload.get("display_factor") or 1.0)
            if ctrl is None or not section or not key:
                continue
            value = (source_cfg.get(section, {}) if isinstance(source_cfg.get(section), dict) else {}).get(key, defaults.get(section, {}).get(key))
            if isinstance(ctrl, QDoubleSpinBox):
                ctrl.setValue(float(value) * factor)
            elif isinstance(ctrl, QSpinBox):
                ctrl.setValue(int(value))

    def _app_customization_apply_from_inputs(self) -> None:
        cfg = self._app_customization_collect_from_inputs(self._studio_theme_selected_name())
        self._app_customization = cfg
        self._app_customization_apply_tuning()
        self._app_customization_save()
        self._app_customization_sync_inputs_from_config()
        self._app_customization_refresh_live_layout()

    def _app_customization_reset_default(self) -> None:
        self._app_customization = self._app_customization_default()
        self._app_customization_apply_tuning()
        self._app_customization_save()
        self._app_customization_sync_inputs_from_config()
        self._app_customization_refresh_live_layout()

    def _app_customization_refresh_live_layout(self) -> None:
        try:
            self._home_close_inline_expander()
        except Exception:
            pass
        try:
            cur = self.pages.currentWidget()
        except Exception:
            cur = None
        if cur is self.homePage:
            try:
                self._home_build()
            except Exception as e:
                dprint("[CUSTOMIZE][WARN] home rebuild failed:", e)
        else:
            try:
                self._home_update_center_lane_width()
            except Exception:
                pass
        self._studio_refresh_live_previews()

    def _studio_theme_selected_name(self) -> str:
        list_widget = getattr(self, "_theme_preset_list", None)
        if list_widget is not None:
            item = list_widget.currentItem()
            if item is not None:
                key = str(item.data(Qt.UserRole) or item.text() or "").strip()
                if key in OMEGA_THEME_PRESETS:
                    return key
        combo = getattr(self, "_theme_preset_combo", None)
        if combo is not None:
            key = str(combo.currentText() or "").strip()
            if key in OMEGA_THEME_PRESETS:
                return key
        key = str(self._personalization.get("preset", self._personalization_state_preset_name()) or "Aurora").strip()
        return key if key in OMEGA_THEME_PRESETS else "Aurora"

    def _studio_current_theme_colors(self, preset_name: Optional[str] = None) -> Dict[str, str]:
        payload = self._personalization_preset_payload(str(preset_name or self._studio_theme_selected_name() or "Aurora"))
        colors = dict(payload.get("colors", {}) or {})
        current = self._personalization.get("colors", {}) if isinstance(self._personalization.get("colors"), dict) else {}
        for key, value in current.items():
            colors[str(key)] = self._personalization_norm_hex(value, colors.get(str(key), "#5CA0FF"))
        for key, inp in (self._theme_color_inputs or {}).items():
            try:
                raw = str(inp.text() or "")
            except Exception:
                raw = ""
            colors[str(key)] = self._personalization_norm_hex(raw, colors.get(str(key), "#5CA0FF"))
        return colors

    def _studio_refresh_live_previews(self) -> None:
        preset_name = self._studio_theme_selected_name()
        colors = self._studio_current_theme_colors(preset_name)
        experience = self._theme_experience_payload(preset_name)
        home_chrome_cfg = self._personalization_read_home_chrome_inputs() if self._home_chrome_top_variant_combo is not None else self._home_chrome_default(preset_name)
        layout_cfg = self._app_customization_collect_from_inputs(preset_name) if self._app_customization_controls else self._app_customization_default(preset_name)
        glass_cfg = self._personalization_read_glass_inputs() if self._glass_radius_spin is not None else self._glass_default(preset_name)

        if self._theme_preview_widget is not None:
            self._theme_preview_widget.set_preview(
                theme_name=preset_name,
                colors=colors,
                glass=glass_cfg,
                experience=experience,
                home_chrome=home_chrome_cfg,
                customization=layout_cfg,
            )

        if self._home_layout_preview_widget is not None:
            self._home_layout_preview_widget.set_preview(
                colors=colors,
                home=layout_cfg.get("home", {}),
                overlays=layout_cfg.get("overlays", {}),
                inline=layout_cfg.get("inline", {}),
            )

        player_chrome_cfg = self._player_chrome_read_inputs(preset_name) if (self._player_chrome_color_inputs or self._player_chrome_metric_inputs) else self._player_chrome_default(preset_name)
        if self._player_chrome_preview_widget is not None:
            self._player_chrome_preview_widget.set_preview(colors=colors, chrome=player_chrome_cfg)

        page_cfg = self._page_layouts_discover_config()
        items = self._discover_layout_editor_items()
        if self._page_layout_preview_widget is not None:
            component_labels = {key: self._discover_layout_component_label(key) for key in self._discover_layout_component_keys(page_cfg["spacer_count"])}
            self._page_layout_preview_widget.set_preview(
                colors=colors,
                items=items,
                component_labels=component_labels,
                canvas_cols=int(page_cfg.get("canvas_cols", DISCOVER_LAYOUT_COLS) or DISCOVER_LAYOUT_COLS),
                canvas_rows=int(page_cfg.get("canvas_rows", DISCOVER_LAYOUT_ROWS) or DISCOVER_LAYOUT_ROWS),
                title="Library layout",
                footer_note="Live library canvas preview driven by the modular composer.",
            )

        settings_cfg = self._page_layouts_settings_config()
        settings_items = self._settings_layout_editor_items()
        if self._settings_layout_preview_widget is not None:
            settings_labels = {key: self._settings_layout_component_label(key) for key in self._settings_layout_component_keys(settings_cfg["spacer_count"])}
            self._settings_layout_preview_widget.set_preview(
                colors=colors,
                items=settings_items,
                component_labels=settings_labels,
                canvas_cols=int(settings_cfg.get("canvas_cols", SETTINGS_LAYOUT_COLS) or SETTINGS_LAYOUT_COLS),
                canvas_rows=int(settings_cfg.get("canvas_rows", SETTINGS_LAYOUT_ROWS) or SETTINGS_LAYOUT_ROWS),
                title="Settings layout",
                footer_note="Drag the real settings modules into a cleaner studio flow.",
            )
        player_cfg = self._page_layouts_player_config()
        player_items = self._player_layout_editor_items()
        if self._player_layout_preview_widget is not None:
            player_labels = {key: self._player_layout_component_label(key) for key in self._player_layout_component_keys(player_cfg["spacer_count"])}
            self._player_layout_preview_widget.set_preview(
                colors=colors,
                items=player_items,
                component_labels=player_labels,
                canvas_cols=int(player_cfg.get("canvas_cols", PLAYER_LAYOUT_COLS) or PLAYER_LAYOUT_COLS),
                canvas_rows=int(player_cfg.get("canvas_rows", PLAYER_LAYOUT_ROWS) or PLAYER_LAYOUT_ROWS),
                title="Player layout",
                footer_note="Drag the player modules into your ideal viewing layout.",
            )
        self._discover_layout_refresh_hint()
        self._discover_layout_update_size_labels()
        self._discover_layout_inventory_refresh()
        self._settings_layout_refresh_hint()
        self._settings_layout_inventory_refresh()
        self._player_layout_refresh_hint()
        self._player_layout_inventory_refresh()

    def _personalization_select_theme_list_item(self, name: str) -> None:
        list_widget = getattr(self, "_theme_preset_list", None)
        if list_widget is None:
            return
        target = str(name or "Aurora").strip()
        list_widget.blockSignals(True)
        for index in range(list_widget.count()):
            item = list_widget.item(index)
            if item is None:
                continue
            if str(item.data(Qt.UserRole) or item.text() or "").strip() == target:
                list_widget.setCurrentRow(index)
                break
        list_widget.blockSignals(False)

    # ── Theme category management ──────────────────────────────────
    def _theme_category_changed(self, category: str) -> None:
        self._theme_category = category
        for k, btn in self._theme_category_buttons.items():
            btn.setChecked(k == category)
        self._theme_populate_list_for_category()

    def _theme_populate_list_for_category(self) -> None:
        list_widget = getattr(self, "_theme_preset_list", None)
        combo = getattr(self, "_theme_preset_combo", None)
        if list_widget is None:
            return
        list_widget.blockSignals(True)
        list_widget.clear()
        if combo is not None:
            combo.blockSignals(True)
            combo.clear()
        cat = self._theme_category
        curated_names = set(OMEGA_CURATED_THEME_NAMES or [])
        for name in sorted(OMEGA_THEME_PRESETS.keys(), key=self._theme_curated_sort_key):
            preset = OMEGA_THEME_PRESETS[name]
            if curated_names and name not in curated_names:
                continue
            if str(preset.get("category", "dark_transparent")) != cat:
                continue
            if combo is not None:
                combo.addItem(name)
            item = QListWidgetItem(self._theme_picker_item_text(name, preset))
            item.setData(Qt.UserRole, name)
            item.setToolTip(self._theme_picker_item_tooltip(preset))
            item.setSizeHint(QSize(220, 68))
            list_widget.addItem(item)
        if combo is not None:
            combo.blockSignals(False)
        list_widget.blockSignals(False)
        if list_widget.count() > 0:
            list_widget.setCurrentRow(0)

    def _theme_category_for_preset(self, preset_name: str) -> str:
        preset = OMEGA_THEME_PRESETS.get(str(preset_name or "Aurora"), {})
        return str(preset.get("category", "dark_transparent"))

    def _theme_category_is_solid(self, category: Optional[str]) -> bool:
        return str(category or "").strip().casefold() in ("dark", "light")

    def _theme_category_is_light(self, category: Optional[str]) -> bool:
        return str(category or "").strip().casefold().startswith("light")

    def _theme_font_family_css(self) -> str:
        typography = self._typography_settings() if isinstance(getattr(self, "_personalization", None), dict) else {}
        preferred = str(typography.get("family") or self.T.typography.preferred_family or "Segoe UI").strip()
        fallback = str(self.T.typography.fallback_family or "Inter").strip()
        return f"'{preferred}', '{fallback}', 'Arial'"

    def _app_apply_typography(self) -> None:
        app = QApplication.instance()
        if app is None:
            return
        typography = self._typography_settings() if isinstance(getattr(self, "_personalization", None), dict) else {}
        scale = float(typography.get("scale", 100) or 100) / 100.0
        font = QFont(str(typography.get("family") or self.T.typography.preferred_family or "Segoe UI"))
        font.setPointSize(max(8, int(round(float(self.T.typography.base_point_size) * scale))))
        try:
            font.setWeight(QFont.Weight(int(typography.get("weight", 500) or 500)))
        except Exception:
            try:
                font.setBold(int(typography.get("weight", 500) or 500) >= 650)
            except Exception:
                pass
        app.setFont(font)

    def _current_theme_category(self) -> str:
        preset_name = str(self._personalization.get("preset", "Aurora") or "Aurora")
        return self._theme_category_for_preset(preset_name)

    def _current_theme_is_solid(self) -> bool:
        return self._theme_category_is_solid(self._current_theme_category())

    def _current_theme_is_transparent(self) -> bool:
        return not self._current_theme_is_solid()

    def _current_theme_is_light(self) -> bool:
        return self._theme_category_is_light(self._current_theme_category())

    def _personalization_load_preset_into_inputs(self, name: str) -> None:
        wanted = str(name or "Aurora").strip()
        if wanted not in OMEGA_THEME_PRESETS:
            wanted = "Aurora"

        payload = self._personalization_default(wanted)
        colors = dict(payload.get("colors", {}) or {})
        glass = payload.get("glass", {}) if isinstance(payload.get("glass"), dict) else {}
        player_chrome_windowed = payload.get("player_chrome_windowed", payload.get("player_chrome", {}))
        if not isinstance(player_chrome_windowed, dict):
            player_chrome_windowed = {}
        player_chrome_fullscreen = payload.get("player_chrome_fullscreen", player_chrome_windowed)
        if not isinstance(player_chrome_fullscreen, dict):
            player_chrome_fullscreen = dict(player_chrome_windowed)
        layout_cfg = self._app_customization_default(wanted)

        self._personalization_syncing_inputs = True
        try:
            self._personalization["player_chrome_windowed"] = self._player_chrome_from_config(player_chrome_windowed, preset_name=wanted)
            self._personalization["player_chrome_fullscreen"] = self._player_chrome_from_config(player_chrome_fullscreen, preset_name=wanted)
            if self._theme_preset_combo is not None:
                self._theme_preset_combo.blockSignals(True)
                idx = self._theme_preset_combo.findText(wanted)
                self._theme_preset_combo.setCurrentIndex(idx if idx >= 0 else 0)
                self._theme_preset_combo.blockSignals(False)
            self._personalization_select_theme_list_item(wanted)
            self._player_chrome_select_preset_list_item(wanted)
            for key, button in (self._theme_color_inputs or {}).items():
                if button is None:
                    continue
                hx = self._personalization_norm_hex(colors.get(key, "#5CA0FF"), "#5CA0FF")
                button.setText(hx)
                self._personalization_update_color_button(key, hx)
            self._personalization_sync_glass_inputs(glass)
            self._personalization_sync_home_chrome_inputs(payload.get("home_chrome", {}))
            self._player_chrome_sync_inputs_from_config(scope=self._player_chrome_active_scope())
            self._app_customization_sync_inputs_from_config(layout_cfg)
        finally:
            self._personalization_syncing_inputs = False
        self._personalization_update_preset_summary()
        self._studio_refresh_live_previews()

    def _personalization_on_theme_list_changed(self) -> None:
        if bool(getattr(self, "_personalization_syncing_inputs", False)):
            return
        name = self._studio_theme_selected_name()
        self._personalization_load_preset_into_inputs(name)

    def _viewer_profile_build_studio(self, parent: QWidget, host_layout: QVBoxLayout) -> None:
        group = QGroupBox("My Profile Studio", parent)
        group.setObjectName("layoutStudioGroup")
        root = QVBoxLayout(group)
        root.setContentsMargins(16, 16, 16, 16)
        root.setSpacing(14)

        preview_card = QFrame(group)
        preview_card.setObjectName("profileStudioPreviewCard")
        preview_l = QVBoxLayout(preview_card)
        preview_l.setContentsMargins(18, 18, 18, 18)
        preview_l.setSpacing(10)

        self._viewer_profile_preview_art = ProfileArtWidget(name="Profile", accent_color="#5CA0FF", parent=preview_card)
        preview_l.addWidget(self._viewer_profile_preview_art, 0, Qt.AlignHCenter)

        self._viewer_profile_summary_name_label = QLabel("Profile", preview_card)
        self._viewer_profile_summary_name_label.setObjectName("profileStudioSummaryName")
        self._viewer_profile_summary_name_label.setAlignment(Qt.AlignHCenter)
        preview_l.addWidget(self._viewer_profile_summary_name_label)

        self._viewer_profile_summary_meta_label = QLabel("", preview_card)
        self._viewer_profile_summary_meta_label.setObjectName("profileStudioSummaryMeta")
        self._viewer_profile_summary_meta_label.setAlignment(Qt.AlignHCenter)
        self._viewer_profile_summary_meta_label.setWordWrap(True)
        preview_l.addWidget(self._viewer_profile_summary_meta_label)

        stats_wrap = QWidget(preview_card)
        stats_grid = QGridLayout(stats_wrap)
        stats_grid.setContentsMargins(0, 6, 0, 0)
        stats_grid.setHorizontalSpacing(12)
        stats_grid.setVerticalSpacing(12)
        self._viewer_profile_stats_labels = {}
        stat_defs = [
            ("favorites", "My List"),
            ("continue", "Continue"),
            ("saved_mixes", "Saved Mixes"),
            ("recent", "Recent Plays"),
        ]
        for index, (key, label_text) in enumerate(stat_defs):
            card = QFrame(stats_wrap)
            card.setStyleSheet("background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.08); border-radius: 16px;")
            card_l = QVBoxLayout(card)
            card_l.setContentsMargins(14, 12, 14, 12)
            card_l.setSpacing(2)
            value_lbl = QLabel("0", card)
            value_lbl.setObjectName("profileStudioStatValue")
            text_lbl = QLabel(label_text, card)
            text_lbl.setObjectName("profileStudioStatLabel")
            card_l.addWidget(value_lbl)
            card_l.addWidget(text_lbl)
            row = int(index // 2)
            col = int(index % 2)
            stats_grid.addWidget(card, row, col)
            self._viewer_profile_stats_labels[key] = value_lbl
        preview_l.addWidget(stats_wrap)
        preview_l.addStretch(1)

        controls = QWidget(group)
        controls_l = QVBoxLayout(controls)
        controls_l.setContentsMargins(0, 0, 0, 0)
        controls_l.setSpacing(10)

        lead = QLabel(
            "Manage profile identity, startup behavior, home row visibility, subtitles-on-load, and profile artwork from one place.",
            controls,
        )
        lead.setObjectName("studioGroupLead")
        lead.setWordWrap(True)
        controls_l.addWidget(lead)

        target_row = QGridLayout()
        target_row.setHorizontalSpacing(8)
        target_row.setVerticalSpacing(8)
        self._viewer_profile_target_combo = FocusSafeComboBox(controls)
        target_row.addWidget(self._viewer_profile_target_combo, 0, 0, 1, 3)
        btn_switch = QPushButton("Switch Now", controls)
        btn_switch.clicked.connect(self._viewer_profile_switch_selected)
        target_row.addWidget(btn_switch, 1, 0)
        btn_add = QPushButton("Add Profile", controls)
        btn_add.clicked.connect(self._viewer_profile_add_from_studio)
        target_row.addWidget(btn_add, 1, 1)
        btn_delete = QPushButton("Delete", controls)
        btn_delete.clicked.connect(self._viewer_profile_delete_selected)
        target_row.addWidget(btn_delete, 1, 2)
        controls_l.addLayout(target_row)

        form = QFormLayout()
        form.setContentsMargins(0, 0, 0, 0)
        form.setSpacing(8)

        self._viewer_profile_name_input = QLineEdit(controls)
        self._viewer_profile_name_input.setPlaceholderText("Profile name")
        form.addRow("Display Name", self._viewer_profile_name_input)

        accent_row = QWidget(controls)
        accent_l = QHBoxLayout(accent_row)
        accent_l.setContentsMargins(0, 0, 0, 0)
        accent_l.setSpacing(8)
        self._viewer_profile_accent_input = QLineEdit(accent_row)
        self._viewer_profile_accent_input.setPlaceholderText("#5CA0FF")
        accent_l.addWidget(self._viewer_profile_accent_input, 1)
        accent_pick = QPushButton("Pick Accent", accent_row)
        accent_pick.clicked.connect(self._viewer_profile_pick_accent)
        accent_l.addWidget(accent_pick)
        form.addRow("Profile Accent", accent_row)

        avatar_row = QWidget(controls)
        avatar_l = QHBoxLayout(avatar_row)
        avatar_l.setContentsMargins(0, 0, 0, 0)
        avatar_l.setSpacing(8)
        self._viewer_profile_avatar_input = QLineEdit(avatar_row)
        self._viewer_profile_avatar_input.setClearButtonEnabled(True)
        self._viewer_profile_avatar_input.setPlaceholderText("Square profile card art")
        avatar_l.addWidget(self._viewer_profile_avatar_input, 1)
        avatar_browse = QPushButton("Browse", avatar_row)
        avatar_browse.clicked.connect(self._viewer_profile_browse_avatar)
        avatar_l.addWidget(avatar_browse)
        avatar_clear = QPushButton("Clear", avatar_row)
        avatar_clear.clicked.connect(self._viewer_profile_clear_avatar)
        avatar_l.addWidget(avatar_clear)
        form.addRow("Profile Art", avatar_row)

        background_row = QWidget(controls)
        background_l = QHBoxLayout(background_row)
        background_l.setContentsMargins(0, 0, 0, 0)
        background_l.setSpacing(8)
        self._viewer_profile_background_input = QLineEdit(background_row)
        self._viewer_profile_background_input.setClearButtonEnabled(True)
        self._viewer_profile_background_input.setPlaceholderText("Lobby background image used on startup")
        background_l.addWidget(self._viewer_profile_background_input, 1)
        background_browse = QPushButton("Browse", background_row)
        background_browse.clicked.connect(self._viewer_profile_browse_background)
        background_l.addWidget(background_browse)
        background_clear = QPushButton("Clear", background_row)
        background_clear.clicked.connect(self._viewer_profile_clear_background)
        background_l.addWidget(background_clear)
        form.addRow("Lobby Background", background_row)

        self._viewer_profile_default_page_combo = FocusSafeComboBox(controls)
        self._viewer_profile_default_page_combo.addItem("Home", "home")
        self._viewer_profile_default_page_combo.addItem("Library", "library")
        self._viewer_profile_default_page_combo.addItem("My List", "mylist")
        form.addRow("Launch Into", self._viewer_profile_default_page_combo)
        controls_l.addLayout(form)

        prefs_box = QGroupBox("Behavior Presets", controls)
        prefs_l = QVBoxLayout(prefs_box)
        prefs_l.setSpacing(6)
        self._viewer_profile_hero_rotate_check = QCheckBox("Auto-rotate the home hero", prefs_box)
        self._viewer_profile_background_video_check = QCheckBox("Allow animated background video", prefs_box)
        self._viewer_profile_continue_check = QCheckBox("Show Continue Watching rail", prefs_box)
        self._viewer_profile_saved_mixes_check = QCheckBox("Show Saved Mixes rail", prefs_box)
        self._viewer_profile_recent_watched_check = QCheckBox("Show Recently Watched rail", prefs_box)
        self._viewer_profile_recent_added_check = QCheckBox("Show Recently Added rail", prefs_box)
        self._viewer_profile_search_memory_check = QCheckBox("Remember search filters for this profile", prefs_box)
        self._viewer_profile_subtitles_on_load_check = QCheckBox("Enable subtitles on playback start", prefs_box)
        for check in (
            self._viewer_profile_hero_rotate_check,
            self._viewer_profile_background_video_check,
            self._viewer_profile_continue_check,
            self._viewer_profile_saved_mixes_check,
            self._viewer_profile_recent_watched_check,
            self._viewer_profile_recent_added_check,
            self._viewer_profile_search_memory_check,
            self._viewer_profile_subtitles_on_load_check,
        ):
            check.setObjectName("profileStudioCheck")
            prefs_l.addWidget(check)
        controls_l.addWidget(prefs_box)

        actions = QHBoxLayout()
        save_btn = QPushButton("Save Profile", controls)
        save_btn.clicked.connect(self._viewer_profile_apply_from_inputs)
        actions.addWidget(save_btn)
        reset_btn = QPushButton("Reset Profile Prefs", controls)
        reset_btn.clicked.connect(self._viewer_profile_reset_preferences)
        actions.addWidget(reset_btn)
        actions.addStretch(1)
        controls_l.addLayout(actions)
        controls_l.addStretch(1)

        root.addWidget(preview_card)
        root.addWidget(controls)
        host_layout.addWidget(group)
        self._viewer_profile_studio_group = group

        self._viewer_profile_target_combo.currentIndexChanged.connect(self._viewer_profile_on_target_changed)
        self._viewer_profile_name_input.textChanged.connect(lambda _text: self._viewer_profile_refresh_preview())
        self._viewer_profile_accent_input.textChanged.connect(lambda _text: self._viewer_profile_refresh_preview())
        self._viewer_profile_avatar_input.textChanged.connect(lambda _text: self._viewer_profile_refresh_preview())
        self._viewer_profile_background_input.textChanged.connect(lambda _text: self._viewer_profile_refresh_preview())

        self._viewer_profile_refresh_target_combo(selected_id=self._viewer_active_profile_id)
        self._viewer_profile_sync_inputs_from_state()

    def _personalization_build_tab(self, tab: QWidget) -> None:
        tab.setObjectName("personalizationStudio")
        tab.setStyleSheet(
            """
            QWidget#personalizationStudio {
                background: transparent;
            }
            QFrame#studioHeroCard {
                background: qlineargradient(x1:0,y1:0,x2:1,y2:1,
                    stop:0 rgba(18, 28, 42, 220),
                    stop:0.55 rgba(11, 18, 28, 210),
                    stop:1 rgba(24, 37, 31, 220));
                border: 1px solid rgba(255,255,255,28);
                border-radius: 24px;
            }
            QFrame#themeColorCard {
                background: rgba(255,255,255,0.04);
                border: 1px solid rgba(255,255,255,0.08);
                border-radius: 18px;
            }
            QFrame#profileStudioPreviewCard {
                background: qlineargradient(x1:0,y1:0,x2:1,y2:1,
                    stop:0 rgba(16, 24, 38, 228),
                    stop:1 rgba(8, 12, 20, 214));
                border: 1px solid rgba(255,255,255,0.10);
                border-radius: 22px;
            }
            QLabel#profileStudioSummaryName {
                color: #FFFFFF;
                font-size: 22px;
                font-weight: 900;
                background: transparent;
            }
            QLabel#profileStudioSummaryMeta {
                color: rgba(231, 238, 248, 182);
                background: transparent;
            }
            QLabel#profileStudioStatValue {
                color: #FFFFFF;
                font-size: 18px;
                font-weight: 900;
                background: transparent;
            }
            QLabel#profileStudioStatLabel {
                color: rgba(231, 238, 248, 168);
                background: transparent;
            }
            QCheckBox#profileStudioCheck {
                color: rgba(242,247,255,220);
                spacing: 10px;
            }
            QLabel#studioEyebrow {
                color: rgba(173, 215, 255, 220);
                font-size: 11px;
                font-weight: 800;
                letter-spacing: 1px;
            }
            QLabel#studioTitle {
                color: #F6FAFF;
                font-size: 28px;
                font-weight: 900;
            }
            QLabel#studioSubtitle, QLabel#studioGroupLead {
                color: rgba(231, 238, 248, 205);
                background: transparent;
            }
            QPushButton#themeColorSwatch {
                min-width: 168px;
                min-height: 48px;
                border-radius: 14px;
                font-weight: 800;
            }
            QScrollArea#personalizationScroll {
                background: transparent;
                border: none;
            }
            QWidget#personalizationCanvas {
                background: transparent;
            }
            QListWidget#themePresetList,
            QListWidget#discoverLayoutOrderList {
                background: rgba(255,255,255,0.03);
                border: 1px solid rgba(255,255,255,0.10);
                border-radius: 16px;
                padding: 8px;
                outline: none;
            }
            QListWidget#themePresetList::item,
            QListWidget#discoverLayoutOrderList::item {
                background: rgba(255,255,255,0.04);
                border: 1px solid rgba(255,255,255,0.08);
                border-radius: 14px;
                margin: 4px;
                padding: 10px 12px;
                min-height: 28px;
                color: rgba(245,250,255,220);
                font-weight: 700;
            }
            QListWidget#themePresetList::item:selected,
            QListWidget#discoverLayoutOrderList::item:selected {
                background: rgba(92,160,255,0.22);
                border: 1px solid rgba(150,205,255,0.46);
                color: #FFFFFF;
            }
            QGroupBox#layoutStudioGroup {
                border: 1px solid rgba(255,255,255,0.10);
                border-radius: 18px;
                margin-top: 16px;
                background: rgba(255,255,255,0.03);
                padding-top: 8px;
            }
            QGroupBox#layoutStudioGroup::title {
                subcontrol-origin: margin;
                left: 12px;
                padding: 0 6px;
                color: #F4F7FF;
                font-weight: 800;
            }
            QPushButton#themeCategoryTab {
                background: rgba(255,255,255,0.05);
                color: rgba(245,250,255,180);
                border: 1px solid rgba(255,255,255,0.10);
                border-radius: 14px;
                padding: 8px 16px;
                font-weight: 700;
                font-size: 12px;
                min-width: 80px;
            }
            QPushButton#themeCategoryTab:checked {
                background: rgba(92,160,255,0.28);
                color: #FFFFFF;
                border: 1px solid rgba(130,190,255,0.6);
                font-weight: 800;
            }
            QPushButton#themeCategoryTab:hover:!checked {
                background: rgba(255,255,255,0.08);
                border: 1px solid rgba(255,255,255,0.18);
            }
            """
        )

        lay = QVBoxLayout(tab)
        lay.setContentsMargins(0, 0, 0, 0)
        lay.setSpacing(0)

        scroll = QScrollArea(tab)
        scroll.setObjectName("personalizationScroll")
        scroll.setWidgetResizable(True)
        scroll.setFrameShape(QFrame.NoFrame)
        scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        scroll.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        lay.addWidget(scroll)

        canvas = QWidget(scroll)
        canvas.setObjectName("personalizationCanvas")
        scroll.setWidget(canvas)

        canvas_l = QVBoxLayout(canvas)
        canvas_l.setContentsMargins(16, 16, 16, 16)
        canvas_l.setSpacing(12)

        hero = QFrame(canvas)
        hero.setObjectName("studioHeroCard")
        hero_l = QVBoxLayout(hero)
        hero_l.setContentsMargins(22, 18, 22, 18)
        hero_l.setSpacing(6)
        eyebrow = QLabel("OMEGA SETTINGS STUDIO", hero)
        eyebrow.setObjectName("studioEyebrow")
        title = QLabel("Personalize the lobby. Tune playback. Shape the app.", hero)
        title.setObjectName("studioTitle")
        title.setWordWrap(True)
        subtitle = QLabel(
            "Profiles, library health, playback defaults, themes, layout, and glass all live here now. Dial in the living-room experience without digging through code or scattered menus.",
            hero,
        )
        subtitle.setObjectName("studioSubtitle")
        subtitle.setWordWrap(True)
        hero_l.addWidget(eyebrow)
        hero_l.addWidget(title)
        hero_l.addWidget(subtitle)
        canvas_l.addWidget(hero)

        self._settings_build_overview(canvas, canvas_l)
        self._viewer_profile_build_studio(canvas, canvas_l)

        theme_group = QGroupBox("Theme Theater", canvas)
        theme_group.setObjectName("layoutStudioGroup")
        theme_group.setMinimumHeight(460)
        theme_root = QVBoxLayout(theme_group)
        theme_root.setContentsMargins(16, 16, 16, 16)
        theme_root.setSpacing(14)

        theme_left = QVBoxLayout()
        theme_left.setSpacing(10)
        theme_lead = QLabel(
            "Flip through presets like a product shelf. The miniature mock window updates as you browse so you can see the full lobby mood before you commit.",
            theme_group,
        )
        theme_lead.setObjectName("studioGroupLead")
        theme_lead.setWordWrap(True)
        theme_left.addWidget(theme_lead)

        # ── Category filter bar ────────────────────────────────
        category_bar = QHBoxLayout()
        category_bar.setSpacing(6)
        self._theme_category_buttons = {}
        current_preset = str(self._personalization.get("preset", "Aurora") or "Aurora")
        current_preset_data = OMEGA_THEME_PRESETS.get(current_preset, OMEGA_THEME_PRESETS.get("Aurora", {}))
        self._theme_category = str(current_preset_data.get("category", "dark_transparent"))
        for cat_key, cat_label in THEME_CATEGORIES.items():
            btn = QPushButton(cat_label, theme_group)
            btn.setCheckable(True)
            btn.setChecked(cat_key == self._theme_category)
            btn.setObjectName("themeCategoryTab")
            btn.clicked.connect(lambda _checked=False, k=cat_key: self._theme_category_changed(k))
            category_bar.addWidget(btn)
            self._theme_category_buttons[cat_key] = btn
        category_bar.addStretch()
        theme_left.addLayout(category_bar)

        self._theme_preset_combo = FocusSafeComboBox(theme_group)
        self._theme_preset_combo.hide()
        self._theme_preset_list = QListWidget(theme_group)
        self._theme_preset_list.setObjectName("themePresetList")
        self._theme_preset_list.setMinimumWidth(0)
        self._theme_preset_list.setMinimumHeight(220)
        self._theme_preset_list.setAlternatingRowColors(False)
        self._theme_populate_list_for_category()
        theme_left.addWidget(self._theme_preset_list, 1)

        theme_actions = QHBoxLayout()
        btn_apply_preset = QPushButton("Apply Theme + Layout", theme_group)
        btn_apply_preset.clicked.connect(self._personalization_apply_selected_preset)
        theme_actions.addWidget(btn_apply_preset)
        btn_reload_preset = QPushButton("Reload Preset Draft", theme_group)
        btn_reload_preset.clicked.connect(lambda _=False: self._personalization_load_preset_into_inputs(self._studio_theme_selected_name()))
        theme_actions.addWidget(btn_reload_preset)
        theme_left.addLayout(theme_actions)

        theme_right = QVBoxLayout()
        theme_right.setSpacing(10)
        self._theme_preset_summary = QLabel("", theme_group)
        self._theme_preset_summary.setObjectName("studioGroupLead")
        self._theme_preset_summary.setWordWrap(True)
        theme_right.addWidget(self._theme_preset_summary)
        self._theme_preview_widget = ThemeMiniPreview(theme_group)
        self._theme_preview_widget.setMinimumHeight(240)
        theme_right.addWidget(self._theme_preview_widget, 1)

        theme_root.addLayout(theme_left)
        theme_root.addLayout(theme_right)
        canvas_l.addWidget(theme_group)

        self._theme_color_inputs = {}
        self._theme_color_swatches = {}
        color_group = QGroupBox("Palette Console", canvas)
        color_l = QVBoxLayout(color_group)
        color_l.setSpacing(10)
        color_notes = {
            "primary": "Main action color for hero buttons and highlights.",
            "secondary": "Secondary accent for companion moments.",
            "background": "Deep canvas behind the app.",
            "background_alt": "Elevated panels and secondary surfaces.",
            "text": "Primary copy and titles.",
            "muted_text": "Metadata and supporting copy.",
            "card": "Cards, list items, and input surfaces.",
            "overlay": "Dim layers and cinematic masks.",
            "highlight": "Bright trim for active states.",
            "border": "Outlines, separators, and structure.",
            "glow": "Aura around accent moments.",
            "surface_soft": "Primary pane fill for softer modular surfaces.",
            "surface_strong": "Stronger shell fill for command cards and overlays.",
            "chip": "Compact supporting surfaces like chips and tags.",
            "success": "Positive states, ready signals, and green-room moments.",
            "warning": "Caution and needs-attention emphasis.",
            "danger": "Critical states and destructive action emphasis.",
        }
        color_labels = {
            "primary": "Primary Accent",
            "secondary": "Secondary Accent",
            "background": "Background",
            "background_alt": "Background Alt",
            "text": "Text",
            "muted_text": "Muted Text",
            "card": "Card Surface",
            "overlay": "Overlay",
            "highlight": "Highlight",
            "border": "Border",
            "glow": "Glow",
            "surface_soft": "Soft Surface",
            "surface_strong": "Strong Surface",
            "chip": "Chip Surface",
            "success": "Success",
            "warning": "Warning",
            "danger": "Danger",
        }
        for key in [
            "primary",
            "secondary",
            "background",
            "background_alt",
            "text",
            "muted_text",
            "card",
            "overlay",
            "highlight",
            "border",
            "glow",
            "surface_soft",
            "surface_strong",
            "chip",
            "success",
            "warning",
            "danger",
        ]:
            color_l.addWidget(self._personalization_make_color_card(canvas, key, color_labels[key], color_notes[key]))
        canvas_l.addWidget(color_group)

        bg_group = QGroupBox("Background Image / Video", canvas)
        bg_form = QFormLayout(bg_group)
        self._bg_global_image_input = QLineEdit(bg_group)
        self._bg_global_image_input.setClearButtonEnabled(True)
        self._bg_global_image_input.setPlaceholderText("Whole-app background image")
        self._bg_global_video_input = QLineEdit(bg_group)
        self._bg_global_video_input.setClearButtonEnabled(True)
        self._bg_global_video_input.setPlaceholderText("Whole-app background video")
        self._bg_page_scope_combo = FocusSafeComboBox(bg_group)
        self._bg_page_scope_combo.addItems(["Home", "Search", "Player"])
        self._bg_page_image_input = QLineEdit(bg_group)
        self._bg_page_image_input.setClearButtonEnabled(True)
        self._bg_page_video_input = QLineEdit(bg_group)
        self._bg_page_video_input.setClearButtonEnabled(True)
        self._bg_image_fit_combo = FocusSafeComboBox(bg_group)
        for key, label in _BG_IMAGE_FIT_CHOICES:
            self._bg_image_fit_combo.addItem(label, key)
        self._bg_video_fit_combo = FocusSafeComboBox(bg_group)
        for key, label in _BG_VIDEO_FIT_CHOICES:
            self._bg_video_fit_combo.addItem(label, key)
        self._bg_anchor_combo = FocusSafeComboBox(bg_group)
        for key, label in _BG_ANCHOR_CHOICES:
            self._bg_anchor_combo.addItem(label, key)
        self._bg_matte_input = QLineEdit(bg_group)
        self._bg_matte_input.setClearButtonEnabled(True)
        self._bg_matte_input.setPlaceholderText("#000000")
        self._bg_blur_spin = SuffixSafeSpinBox(bg_group)
        self._bg_blur_spin.setRange(0, 20)
        self._bg_blur_spin.setSingleStep(1)
        self._bg_blur_spin.setSuffix(" blur")
        matte_row = QWidget(bg_group)
        matte_row_l = QHBoxLayout(matte_row)
        matte_row_l.setContentsMargins(0, 0, 0, 0)
        matte_row_l.setSpacing(8)
        matte_row_l.addWidget(self._bg_matte_input, 1)
        matte_pick = QPushButton("Pick Matte", matte_row)
        matte_pick.clicked.connect(self._personalization_pick_bg_matte_color)
        matte_row_l.addWidget(matte_pick)
        self._bg_overlay_slider = PassiveWheelSlider(Qt.Horizontal, bg_group)
        self._bg_overlay_slider.setRange(0, 85)
        bg_form.addRow("Global Image", self._bg_global_image_input)
        bg_form.addRow("Global Video", self._bg_global_video_input)
        bg_form.addRow("Page Scope", self._bg_page_scope_combo)
        bg_form.addRow("Page Image", self._bg_page_image_input)
