    def _ui_open_poster_art_dialog(self) -> None:
        try:
            shows = self._home_list_shows_merged()
        except Exception:
            shows = []

        items: List[MissingArtItem] = []
        path_to_content_key: Dict[str, str] = {}
        for sg in shows:
            primary = getattr(sg, "primary_dir", None)
            title = getattr(sg, "display_title", None)
            if primary is None:
                continue
            content_key = str(getattr(sg, "content_key", "") or "").strip()
            if content_key:
                path_to_content_key[self._home_canon_path_str(Path(str(primary)))] = content_key
            dirs = None
            for cand in ("group_dirs", "dirs", "source_dirs", "all_dirs", "merged_dirs"):
                if hasattr(sg, cand):
                    try:
                        v = getattr(sg, cand)
                        if v:
                            dirs = list(v)
                            break
                    except Exception:
                        dirs = None
            if not dirs:
                dirs = [primary]
            items.append(MissingArtItem(
                display_title=str(title) if title else str(primary.name),
                primary_dir=Path(str(primary)),
                all_dirs=[Path(str(p)) for p in dirs],
            ))

        if not items:
            QMessageBox.information(self.win, "No library items", "No shows were found in your library.")
            return

        try:
            dlg = PosterArtDialog(items, parent=self.win)
            dlg.exec()
        except Exception as e:
            QMessageBox.critical(self.win, "Poster Art Dialog Error", f"{type(e).__name__}: {e}")
            return

        try:
            rename_map = getattr(dlg, "rename_map", None)
        except Exception:
            rename_map = None

        if isinstance(rename_map, dict) and rename_map:
            applied = 0
            for k, new_title in rename_map.items():
                try:
                    p = Path(str(k))
                    t = str(new_title).strip()
                    if not t:
                        continue
                    content_key = str(path_to_content_key.get(self._home_canon_path_str(p)) or "").strip()
                    if not content_key:
                        continue
                    self._home_state_set_title_override(content_key, t)
                    applied += 1
                except Exception:
                    pass
            if applied:
                dprint(f"[POSTERS] Applied {applied} rename override(s).")

        self._home_reindex_catalog_items_with_state(source="poster-rename")
        self._home_build()

    def _library_ui_initial_browse_dir(self) -> str:
        raw = str(self._home_state.get("library_last_browse_dir", "") or "").strip()
        if raw:
            try:
                saved = Path(raw).expanduser()
            except Exception:
                saved = None
            if saved is not None:
                if saved.exists() and saved.is_dir():
                    return str(saved)
                try:
                    parent = saved.parent
                except Exception:
                    parent = None
                if parent is not None and parent.exists() and parent.is_dir():
                    return str(parent)
        return str(Path.home())

    def _library_ui_choose_source_dirs(self) -> List[Path]:
        start_dir = self._library_ui_initial_browse_dir()
        dialog = QFileDialog(self.win, "Select Media Folder(s)", start_dir)
        dialog.setFileMode(QFileDialog.Directory)
        dialog.setOption(QFileDialog.ShowDirsOnly, True)
        dialog.setOption(QFileDialog.DontUseNativeDialog, True)
        dialog.setDirectory(start_dir)
        dialog.setLabelText(QFileDialog.Accept, "Add Selected Folders")

        views: List[QAbstractItemView] = []
        try:
            views.extend(dialog.findChildren(QListView))
        except Exception:
            pass
        try:
            views.extend(dialog.findChildren(QTreeView))
        except Exception:
            pass
        for view in views:
            try:
                view.setSelectionMode(QAbstractItemView.ExtendedSelection)
            except Exception:
                pass

        if not dialog.exec():
            return []

        chosen_paths: List[Path] = []
        seen: set[str] = set()
        for raw_path in dialog.selectedFiles() or []:
            try:
                chosen = Path(str(raw_path)).expanduser()
            except Exception:
                continue
            try:
                chosen = chosen.resolve()
            except Exception:
                pass
            if not chosen.exists() or not chosen.is_dir():
                continue
            key = str(chosen).rstrip("\\/").casefold()
            if key in seen:
                continue
            seen.add(key)
            chosen_paths.append(chosen)

        try:
            browse_dir = str(dialog.directory().absolutePath() or "").strip()
        except Exception:
            browse_dir = ""
        if browse_dir:
            self._home_state["library_last_browse_dir"] = browse_dir
            self._home_state_save(force=True)

        return chosen_paths

    def _library_ui_add_source(self) -> None:
        chosen_paths = self._library_ui_choose_source_dirs()
        if not chosen_paths:
            return

        dprint("[LIBRARY] User selected:", ", ".join(str(p) for p in chosen_paths))

        added, duplicates, invalid = self._library.add_sources([str(p) for p in chosen_paths])
        if not added:
            details: List[str] = []
            if duplicates:
                details.append(f"{len(duplicates)} folder(s) were already in your library.")
            if invalid:
                details.append(f"{len(invalid)} folder(s) could not be added because they were invalid.")
            if not details:
                details.append("No folders were added.")
            QMessageBox.information(self.win, "No New Folders Added", "\n\n".join(details))
            return

        dprint(
            f"[SOURCE][ADD] added={len(added)} duplicates={len(duplicates)} invalid={len(invalid)} "
            f"sources={[str(p) for p in added]}"
        )
        self._home_catalog_needs_refresh = True
        self._home_catalog_start_async_refresh("source-added", allow_network=True)
        self._home_request_build()

        details = [f"Added {len(added)} folder(s) to your library."]
        if duplicates:
            details.append(f"Skipped {len(duplicates)} folder(s) that were already added.")
        if invalid:
            details.append(f"Skipped {len(invalid)} invalid folder selection(s).")
        details.append(
            "Shows, movies, local art, subtitles, and the rest of your usual library behavior will be picked up on refresh."
        )
        QMessageBox.information(self.win, "Library Updated", "\n\n".join(details))

