    def _library_path_within(self, candidate: Path, root: Path) -> bool:
        try:
            cand = Path(str(candidate)).expanduser()
            base = Path(str(root)).expanduser()
        except Exception:
            return False
        try:
            cand = cand.resolve()
        except Exception:
            pass
        try:
            base = base.resolve()
        except Exception:
            pass
        try:
            cand.relative_to(base)
            return True
        except Exception:
            return False

    def _library_source_title_count(self, path: Path, items: List[ShowGroup]) -> int:
        seen: set[str] = set()
        source = Path(str(path))
        for sg in list(items or []):
            key = self._home_item_key(sg)
            if not key or key in seen:
                continue
            dirs = [Path(str(getattr(sg, "primary_dir", "")))]
            dirs.extend(Path(str(p)) for p in (getattr(sg, "all_dirs", []) or []) if p is not None)
            if any(self._library_path_within(media_dir, source) for media_dir in dirs):
                seen.add(key)
        return len(seen)

    def _library_make_list_item(self, title: str, subtitle: str, payload: Optional[Dict[str, Any]] = None) -> QListWidgetItem:
        item = QListWidgetItem()
        clean_title = str(title or "").strip()
        clean_subtitle = str(subtitle or "").strip()
        item.setText(clean_title if not clean_subtitle else f"{clean_title}\n{clean_subtitle}")
        item.setData(Qt.UserRole, dict(payload or {}))
        if clean_subtitle:
            item.setToolTip(clean_subtitle)
        return item

    def _library_populate_action_list(self, widget: Optional[QListWidget], rows: List[Tuple[str, str, Dict[str, Any]]]) -> None:
        if widget is None:
            return
        widget.clear()
        for title, subtitle, payload in list(rows or []):
            widget.addItem(self._library_make_list_item(title, subtitle, payload))

    def _library_hq_jump_to_discover(self) -> None:
        self._nav_go_discover()
        combo = getattr(self, "_search_status_filter", None)
        if combo is not None:
            idx = combo.findText("Unresolved")
            if idx >= 0:
                combo.setCurrentIndex(idx)
        self._search_request_refresh()

    def _library_hq_handle_item_activation(self, item: Optional[QListWidgetItem]) -> None:
        if item is None:
            return
        payload = item.data(Qt.UserRole)
        if not isinstance(payload, dict):
            return
        action = str(payload.get("action") or "").strip()
        if action == "play":
            key = str(payload.get("key") or "").strip()
            sg = self._home_items_by_key.get(key)
            if sg is not None:
                self._home_play_group(sg, resume=True)
            return
        if action == "show_details":
            key = str(payload.get("key") or "").strip()
            sg = self._home_items_by_key.get(key)
            if sg is not None:
                self._home_show_item_details(sg)
            return
        if action == "open_folder":
            key = str(payload.get("key") or "").strip()
            sg = self._home_items_by_key.get(key)
            if sg is not None:
                self._home_context_open_folder(sg, getattr(sg, "play_path", None))
                return
            raw_path = str(payload.get("path") or "").strip()
            if raw_path:
                try:
                    os.startfile(raw_path)  # type: ignore[attr-defined]
                except Exception:
                    pass
            return
        if action == "discover_unresolved":
            self._library_hq_jump_to_discover()
            return
        if action == "manage_sources":
            self._library_ui_manage_sources_dialog()

    def _library_refresh_hq(self, *, force: bool = False) -> None:
        stat_values = getattr(self, "_library_hq_stat_values", None)
        if not isinstance(stat_values, dict) or not stat_values:
            return

        sources = list(self._library.list_sources(enabled_only=False))
        enabled_sources = [src for src in sources if bool(getattr(src, "enabled", True))]
        items = list(getattr(self, "_home_catalog_items", []) or [])
        if not items:
            try:
                items = list(self._library.load_title_groups())
            except Exception:
                items = []
        health = self._library_health_snapshot()
        verified_keys = self._home_state_verified_set()
        favorites = [str(x).strip() for x in (self._home_state.get("favorites", []) or []) if str(x).strip()]
        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}
        recent_entries = [rec for rec in (self._home_state.get("recently_played", []) or []) if isinstance(rec, dict)]
        metadata_ready = sum(1 for sg in items if getattr(sg, "tmdb_id", None) is not None)
        art_ready = sum(1 for sg in items if getattr(sg, "poster_path", None) is not None or getattr(sg, "backdrop_path", None) is not None)
        unresolved = [sg for sg in items if getattr(sg, "tmdb_id", None) is None]
        missing_art = [sg for sg in items if getattr(sg, "poster_path", None) is None and getattr(sg, "backdrop_path", None) is None]
        signature = (
            int(getattr(self, "_home_catalog_revision", 0) or 0),
            int(getattr(self, "_home_state_revision", 0) or 0),
            int(len(sources)),
            tuple((str(getattr(src, "path", "") or ""), bool(getattr(src, "enabled", True))) for src in sources),
            int(len(items)),
            int(health.get("total_titles", len(items)) or 0),
            int(health.get("available_sources", len(enabled_sources)) or 0),
            int(health.get("unavailable_sources", max(0, len(sources) - len(enabled_sources))) or 0),
            int(len(verified_keys)),
            int(metadata_ready),
            int(art_ready),
            int(len(favorites)),
            int(sum(1 for value in watched_map.values() if bool(value))),
            tuple((str(rec.get("key") or ""), int(rec.get("at") or 0)) for rec in recent_entries[:8]),
        )
        if not force and signature == tuple(getattr(self, "_library_hq_last_signature", tuple()) or tuple()):
            return
        self._library_hq_last_signature = signature

        total_titles = len(items)
        verified_count = sum(1 for sg in items if self._home_item_key(sg) in verified_keys)
        watched_count = sum(1 for value in watched_map.values() if bool(value))
        source_ratio = (len(enabled_sources) / len(sources)) if sources else 1.0
        verified_ratio = (verified_count / total_titles) if total_titles else 1.0
        metadata_ratio = (metadata_ready / total_titles) if total_titles else 1.0
        art_ratio = (art_ready / total_titles) if total_titles else 1.0
        readiness = max(0.0, min(1.0, (source_ratio + verified_ratio + metadata_ratio + art_ratio) / 4.0))

        progress = getattr(self, "_library_hq_progress_bar", None)
        if progress is not None:
            progress.setValue(int(round(readiness * 1000.0)))
        progress_label = getattr(self, "_library_hq_progress_label", None)
        if progress_label is not None:
            latest_errors = list(health.get("latest_errors", ()) or [])
            latest_error = latest_errors[0] if latest_errors else ""
            progress_text_value = (
                "{pct}% ready: {verified} verified, {meta} metadata-rich, {art} with art. Ingest: {ingest}.".format(
                    pct=int(round(readiness * 100.0)),
                    verified=verified_count,
                    meta=metadata_ready,
                    art=art_ready,
                    ingest=str(health.get("active_ingestion_status", "idle") or "idle"),
                )
            )
            if latest_error:
                progress_text_value += f" Latest error: {latest_error}"
            progress_label.setText(progress_text_value)

        stat_values["titles"].setText(str(int(health.get("total_titles", total_titles) or total_titles)))
        stat_values["verified"].setText(f"{verified_count} staged")
        stat_values["sources"].setText(
            f"{int(health.get('available_sources', len(enabled_sources)) or len(enabled_sources))}/{int(health.get('total_sources', len(sources)) or len(sources))} live"
        )
        stat_values["metadata"].setText(f"{metadata_ready}/{total_titles}" if total_titles else "0/0")
        stat_values["art"].setText(f"{art_ready}/{total_titles}" if total_titles else "0/0")
        stat_values["favorites"].setText(f"{len(favorites)} list / {watched_count} watched")

        table = getattr(self, "_library_hq_source_table", None)
        if table is not None:
            table.setRowCount(len(sources))
            for row, source in enumerate(sources):
                src_path = Path(str(getattr(source, "path", "") or ""))
                related = [
                    sg for sg in items
                    if any(
                        self._library_path_within(media_dir, src_path)
                        for media_dir in [Path(str(getattr(sg, "primary_dir", "")))] + [Path(str(p)) for p in (getattr(sg, "all_dirs", []) or []) if p is not None]
                    )
                ]
                title_count = len({self._home_item_key(sg) for sg in related if self._home_item_key(sg)})
                ready_count = sum(1 for sg in related if getattr(sg, "tmdb_id", None) is not None)
                local_art_count = sum(1 for sg in related if getattr(sg, "poster_path", None) is not None or getattr(sg, "backdrop_path", None) is not None)
                note_bits: List[str] = []
                if title_count == 0:
                    note_bits.append("No indexed titles")
                if ready_count < title_count:
                    note_bits.append(f"{title_count - ready_count} still need metadata")
                if local_art_count < title_count:
                    note_bits.append(f"{title_count - local_art_count} missing local art")
                if not note_bits:
                    note_bits.append("Healthy")
                coverage_text = f"{ready_count}/{title_count} md | {local_art_count}/{title_count} art" if title_count else "No titles yet"
                if not src_path.exists():
                    status_text = "Unavailable"
                    dprint(f"[SOURCE][UNAVAILABLE] path={src_path}")
                else:
                    status_text = "Enabled" if bool(getattr(source, "enabled", True)) else "Paused"
                folder_item = QTableWidgetItem(str(src_path))
                folder_item.setData(Qt.UserRole, str(src_path))
                table.setItem(row, 0, folder_item)
                table.setItem(row, 1, QTableWidgetItem(status_text))
                table.setItem(row, 2, QTableWidgetItem(str(title_count)))
                table.setItem(row, 3, QTableWidgetItem(coverage_text))
                table.setItem(row, 4, QTableWidgetItem("; ".join(note_bits)))

        attention_rows: List[Tuple[str, str, Dict[str, Any]]] = []
        if not sources:
            attention_rows.append(
                ("No source folders connected", "Add your first media folder to start building the library.", {"action": "manage_sources"})
            )
        for source in sources:
            src_path = str(getattr(source, "path", "") or "")
            title_count = self._library_source_title_count(Path(src_path), items) if src_path else 0
            if not bool(getattr(source, "enabled", True)):
                attention_rows.append(("Paused source", src_path, {"action": "open_folder", "path": src_path}))
            elif src_path and not Path(src_path).exists():
                attention_rows.append(("Unavailable source", src_path, {"action": "open_folder", "path": src_path}))
            elif title_count == 0:
                attention_rows.append(("Empty source", src_path, {"action": "open_folder", "path": src_path}))
        for sg in unresolved[:4]:
            key = self._home_item_key(sg)
            attention_rows.append(
                (
                    f"Metadata gap: {str(getattr(sg, 'display_title', '') or 'Untitled')}",
                    "Still unresolved in Library and Manage.",
                    {"action": "show_details", "key": key},
                )
            )
        if unresolved:
            attention_rows.append(
                ("Open unresolved queue", f"{len(unresolved)} title(s) still need matching.", {"action": "discover_unresolved"})
            )
        self._library_populate_action_list(getattr(self, "_library_hq_attention_list", None), attention_rows[:10])

        momentum_rows: List[Tuple[str, str, Dict[str, Any]]] = []
        seen_keys: set[str] = set()
        progress_map = self._home_state.get("watch_progress", {}) if isinstance(self._home_state.get("watch_progress"), dict) else {}
        for rec in recent_entries[:8]:
            key = str(rec.get("key") or "").strip()
            sg = self._home_items_by_key.get(key)
            if sg is None or key in seen_keys:
                continue
            seen_keys.add(key)
            payload = progress_map.get(key) if isinstance(progress_map, dict) else {}
            ratio = 0
            if isinstance(payload, dict):
                try:
                    ratio = int(round(float(payload.get("ratio", 0.0) or 0.0) * 100.0))
                except Exception:
                    ratio = 0
            momentum_rows.append(
                (
                    str(getattr(sg, "display_title", "") or "Untitled"),
                    f"Recent activity, {ratio}% through." if ratio > 0 else "Recently played from this collection.",
                    {"action": "play", "key": key},
                )
            )
        if not momentum_rows:
            discovered_at = self._home_state.get("discovered_at", {}) if isinstance(self._home_state.get("discovered_at"), dict) else {}
            for key, _ts in sorted(((str(k), int(v or 0)) for k, v in discovered_at.items()), key=lambda pair: pair[1], reverse=True)[:6]:
                sg = self._home_items_by_key.get(key)
                if sg is None:
                    continue
                momentum_rows.append(
                    (
                        str(getattr(sg, "display_title", "") or "Untitled"),
                        "Freshly discovered in the library.",
                        {"action": "show_details", "key": key},
                    )
                )
        self._library_populate_action_list(getattr(self, "_library_hq_momentum_list", None), momentum_rows[:8])

        ranked = sorted(
            list(items),
            key=lambda sg: (
                float(getattr(sg, "rating", 0.0) or 0.0),
                float(getattr(sg, "group_mtime", 0.0) or 0.0),
            ),
            reverse=True,
        )
        spotlight_item = ranked[0] if ranked else None
        spotlight_title = getattr(self, "_library_hq_spotlight_title", None)
        spotlight_meta = getattr(self, "_library_hq_spotlight_meta", None)
        spotlight_summary = getattr(self, "_library_hq_spotlight_summary", None)
        if spotlight_item is None:
            if spotlight_title is not None:
                spotlight_title.setText("Add source folders to unlock curation.")
            if spotlight_meta is not None:
                spotlight_meta.setText("")
            if spotlight_summary is not None:
                spotlight_summary.setText("Once media is indexed, Library will spotlight standouts, gaps, and recent energy in the catalog.")
        else:
            if spotlight_title is not None:
                spotlight_title.setText(str(getattr(spotlight_item, "display_title", "") or "Untitled"))
            meta_bits: List[str] = []
            media_type = str(getattr(spotlight_item, "media_type", "") or "").strip().casefold()
            meta_bits.append("Movie" if media_type == "movie" else "TV Show")
            if getattr(spotlight_item, "year", None) is not None:
                meta_bits.append(str(getattr(spotlight_item, "year", "")))
            if getattr(spotlight_item, "rating", None) is not None:
                try:
                    meta_bits.append(f"{float(getattr(spotlight_item, 'rating', 0.0) or 0.0):.1f}/10")
                except Exception:
                    pass
            if spotlight_meta is not None:
                spotlight_meta.setText(" | ".join(meta_bits))
            if spotlight_summary is not None:
                summary = str(getattr(spotlight_item, "overview", "") or "").strip()
                if not summary:
                    summary = "This title currently stands out because it carries the strongest combination of rating, recency, and catalog readiness."
                spotlight_summary.setText(summary)

        top_shelf_rows: List[Tuple[str, str, Dict[str, Any]]] = []
        for sg in ranked[:8]:
            key = self._home_item_key(sg)
            rating = getattr(sg, "rating", None)
            subtitle_bits: List[str] = []
            if rating is not None:
                try:
                    subtitle_bits.append(f"{float(rating):.1f}/10")
                except Exception:
                    pass
            if getattr(sg, "year", None) is not None:
                subtitle_bits.append(str(getattr(sg, "year", "")))
            if key in verified_keys:
                subtitle_bits.append("Verified")
            if key in favorites:
                subtitle_bits.append("My List")
            if not subtitle_bits and sg in missing_art:
                subtitle_bits.append("Needs art")
            top_shelf_rows.append(
                (
                    str(getattr(sg, "display_title", "") or "Untitled"),
                    " | ".join(subtitle_bits),
                    {"action": "show_details", "key": key},
                )
                )
        self._library_populate_action_list(getattr(self, "_library_hq_top_shelf_list", None), top_shelf_rows)

        latest_errors = list(health.get("latest_errors", ()) or [])
        if latest_errors:
            dprint(f"[LIBRARY][ERROR] latest={latest_errors[0]}")

    def _library_ui_manage_sources_dialog(self) -> None:
        dialog = QDialog(self.win)
        dialog.setWindowTitle("Manage Library Folders")
        dialog.resize(980, 560)
        dialog_l = QVBoxLayout(dialog)
        dialog_l.setContentsMargins(16, 16, 16, 16)
        dialog_l.setSpacing(10)

        intro = QLabel(
                "Pause noisy folders, remove stale locations, add new shelves, and refresh the catalog without leaving Library.",
            dialog,
        )
        intro.setWordWrap(True)
        dialog_l.addWidget(intro)

        table = QTableWidget(0, 4, dialog)
        table.setHorizontalHeaderLabels(["Folder", "Enabled", "Titles", "Status"])
        table.setSelectionBehavior(QAbstractItemView.SelectRows)
        table.setSelectionMode(QAbstractItemView.ExtendedSelection)
        table.setEditTriggers(QAbstractItemView.NoEditTriggers)
        table.verticalHeader().setVisible(False)
        table.horizontalHeader().setSectionResizeMode(0, QHeaderView.Stretch)
        table.horizontalHeader().setSectionResizeMode(1, QHeaderView.ResizeToContents)
        table.horizontalHeader().setSectionResizeMode(2, QHeaderView.ResizeToContents)
        table.horizontalHeader().setSectionResizeMode(3, QHeaderView.Stretch)
        dialog_l.addWidget(table, 1)

        status_label = QLabel("", dialog)
        status_label.setWordWrap(True)
        dialog_l.addWidget(status_label)

        def selected_paths() -> List[str]:
            rows = sorted({index.row() for index in table.selectionModel().selectedRows()}) if table.selectionModel() is not None else []
            out: List[str] = []
            for row in rows:
                cell = table.item(row, 0)
                raw_path = str(cell.data(Qt.UserRole) if cell is not None else "")
                if raw_path:
                    out.append(raw_path)
            return out

        def refresh_table(message: str = "") -> None:
            sources = list(self._library.list_sources(enabled_only=False))
            items = list(getattr(self, "_home_catalog_items", []) or [])
            table.setRowCount(len(sources))
            for row, source in enumerate(sources):
                raw_path = str(getattr(source, "path", "") or "")
                enabled = bool(getattr(source, "enabled", True))
                title_count = self._library_source_title_count(Path(raw_path), items) if raw_path else 0
                folder_item = QTableWidgetItem(raw_path)
                folder_item.setData(Qt.UserRole, raw_path)
                table.setItem(row, 0, folder_item)
                table.setItem(row, 1, QTableWidgetItem("Yes" if enabled else "No"))
                table.setItem(row, 2, QTableWidgetItem(str(title_count)))
                status_bits = ["Enabled" if enabled else "Paused"]
                if title_count == 0:
                    status_bits.append("No indexed titles")
                table.setItem(row, 3, QTableWidgetItem("; ".join(status_bits)))
            enabled_count = len([src for src in sources if bool(getattr(src, "enabled", True))])
            status_label.setText(str(message or f"{enabled_count}/{len(sources)} sources currently enabled."))

        def kick_refresh(reason: str) -> None:
            self._home_catalog_needs_refresh = True
            self._home_catalog_start_async_refresh(reason, allow_network=True)
            self._home_request_build()
            self._search_request_refresh()
            self._library_refresh_hq(force=True)
            self._settings_refresh_overview(force=True)

        buttons = QHBoxLayout()
        buttons.setSpacing(8)

        add_btn = QPushButton("Add Folders", dialog)
        buttons.addWidget(add_btn)
        toggle_btn = QPushButton("Enable / Pause", dialog)
        buttons.addWidget(toggle_btn)
        remove_btn = QPushButton("Remove", dialog)
        buttons.addWidget(remove_btn)
        open_btn = QPushButton("Open Folder", dialog)
        buttons.addWidget(open_btn)
        refresh_btn = QPushButton("Refresh Catalog", dialog)
        buttons.addWidget(refresh_btn)
        buttons.addStretch(1)
        dialog_l.addLayout(buttons)

        close_box = QDialogButtonBox(QDialogButtonBox.Close, dialog)
        close_box.rejected.connect(dialog.reject)
        dialog_l.addWidget(close_box)

        def on_add() -> None:
            chosen = self._library_ui_choose_source_dirs()
            if not chosen:
                return
            added, duplicates, invalid = self._library.add_sources([str(path) for path in chosen])
            if added:
                kick_refresh("library-source-manager-add")
                refresh_table(
                    f"Added {len(added)} folder(s). {len(duplicates)} duplicate(s) skipped. {len(invalid)} invalid selection(s)."
                )
                return
            refresh_table(
                f"No new folders added. {len(duplicates)} duplicate(s) skipped. {len(invalid)} invalid selection(s)."
            )

        def on_toggle() -> None:
            paths = selected_paths()
            if not paths:
                refresh_table("Select one or more rows first.")
                return
            records = {str(getattr(src, 'path', '') or ''): bool(getattr(src, 'enabled', True)) for src in self._library.list_sources(enabled_only=False)}
            enable_target = not all(bool(records.get(path, False)) for path in paths)
            changed = 0
            for path in paths:
                changed += 1 if self._library.set_source_enabled(path, enable_target) else 0
            if changed:
                kick_refresh("library-source-manager-toggle")
            refresh_table(f"{'Enabled' if enable_target else 'Paused'} {max(changed, 0)} source(s).")

        def on_remove() -> None:
            paths = selected_paths()
            if not paths:
                refresh_table("Select one or more rows first.")
                return
            confirmed = QMessageBox.question(
                dialog,
                "Remove Source Folders",
                f"Remove {len(paths)} source folder(s) from Omega?\n\nThe media files stay on disk; only the library connection is removed.",
                QMessageBox.Yes | QMessageBox.No,
                QMessageBox.No,
            )
            if confirmed != QMessageBox.Yes:
                return
            changed = 0
            for path in paths:
                changed += 1 if self._library.remove_source(path) else 0
            if changed:
                kick_refresh("library-source-manager-remove")
            refresh_table(f"Removed {changed} source(s).")

        def on_open() -> None:
            paths = selected_paths()
            if not paths:
                refresh_table("Select a source row first.")
                return
            try:
                os.startfile(paths[0])  # type: ignore[attr-defined]
            except Exception as exc:
                refresh_table(f"Could not open folder: {type(exc).__name__}")

        add_btn.clicked.connect(on_add)
        toggle_btn.clicked.connect(on_toggle)
        remove_btn.clicked.connect(on_remove)
        open_btn.clicked.connect(on_open)

        def _request_catalog_refresh() -> None:
            kick_refresh("library-source-manager-refresh")
            refresh_table("Catalog refresh requested.")

        refresh_btn.clicked.connect(_request_catalog_refresh)
        table.itemDoubleClicked.connect(lambda _item: on_open())

        refresh_table()
        dialog.exec()

    def _player_current_show_group(self) -> Optional[ShowGroup]:
        path = getattr(self, "_current_path", None)
        if path is None:
            return None
        p = Path(str(path))
        key = self._home_resolve_media_key_for_path(p)
        if not key:
            key = str(self._shuffle_path_to_show.get(self._home_canon_path_str(p), "") or "").strip()
        return self._home_items_by_key.get(key) if key else None

    def _player_toggle_current_favorite(self) -> None:
        sg = self._player_current_show_group()
        if sg is None:
            return
        self._home_state_toggle_favorite(self._home_item_key(sg))
        self._home_request_build()
        self._search_request_refresh()
        self._library_refresh_hq(force=True)
        self._settings_refresh_overview(force=True)
        self._player_update_command_center(
            int(getattr(self, "_player_last_progress_snapshot_ms", 0) or 0),
            int(getattr(self, "_player_last_progress_snapshot_dur_ms", 0) or 0),
        )

    def _player_toggle_current_watched(self) -> None:
        sg = self._player_current_show_group()
        if sg is None:
            return
        key = self._home_item_key(sg)
        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}
        self._home_state_set_watched(key, not bool(watched_map.get(key, False)))
        self._home_request_build()
        self._search_request_refresh()
        self._library_refresh_hq(force=True)
        self._settings_refresh_overview(force=True)
        self._player_update_command_center(
            int(getattr(self, "_player_last_progress_snapshot_ms", 0) or 0),
            int(getattr(self, "_player_last_progress_snapshot_dur_ms", 0) or 0),
        )

    def _player_init_command_center(self) -> None:
        if self.playerPage is None or getattr(self, "_player_command_center", None) is not None:
            return

        panel = QFrame(self.playerPage)
        panel.setObjectName("playerCommandCenter")
        panel_l = QVBoxLayout(panel)
        panel_l.setContentsMargins(14, 14, 14, 14)
        panel_l.setSpacing(10)

        hero_row = QHBoxLayout()
        hero_row.setContentsMargins(0, 0, 0, 0)
        hero_row.setSpacing(12)

        art = QLabel("Artwork loads here during playback.", panel)
        art.setAlignment(Qt.AlignCenter)
        art.setWordWrap(True)
        art.setFixedSize(
            int(self.T.player.command_center_art_w_px),
            int(self.T.player.command_center_art_h_px),
        )
        art.setStyleSheet("background: rgba(255,255,255,0.05); border-radius: 14px;")
        hero_row.addWidget(art, 0)

        text_col = QVBoxLayout()
        text_col.setContentsMargins(0, 0, 0, 0)
        text_col.setSpacing(6)

        title = QLabel("Nothing playing", panel)
        title.setObjectName("playerCommandTitle")
        title.setTextFormat(Qt.PlainText)
        title.setWordWrap(True)
        text_col.addWidget(title)

        meta = QLabel("", panel)
        meta.setObjectName("playerCommandMeta")
        meta.setTextFormat(Qt.PlainText)
        meta.setWordWrap(True)
        text_col.addWidget(meta)

        status = QLabel("", panel)
        status.setObjectName("playerCommandBody")
        status.setTextFormat(Qt.PlainText)
        status.setWordWrap(True)
        text_col.addWidget(status)

        tech = QLabel("", panel)
        tech.setObjectName("playerCommandBody")
        tech.setTextFormat(Qt.PlainText)
        tech.setWordWrap(True)
        text_col.addWidget(tech)

        next_up = QLabel("", panel)
        next_up.setObjectName("playerCommandBody")
        next_up.setTextFormat(Qt.PlainText)
        next_up.setWordWrap(True)
        text_col.addWidget(next_up)

        text_col.addStretch(1)
        hero_row.addLayout(text_col, 1)
        panel_l.addLayout(hero_row)

        progress = JumpSlider(Qt.Horizontal, panel)
        progress.setRange(0, 1000)
        progress.setTracking(False)
        progress.setFixedHeight(12)
        progress.jumpRequested.connect(
            lambda value: self._player_request_seek_ratio(self._player_ratio_from_slider_value(int(value), progress))
        )
        panel_l.addWidget(progress)

        actions = QGridLayout()
        actions.setHorizontalSpacing(8)
        actions.setVerticalSpacing(8)
        actions.setColumnStretch(0, 1)
        actions.setColumnStretch(1, 1)
        favorite_btn = QPushButton("My List", panel)
        favorite_btn.clicked.connect(self._player_toggle_current_favorite)
        configure_control_button(
            favorite_btn,
            role="ghost",
            text="My List",
            min_w=int(self.T.player.command_center_action_btn_min_w_px),
            tooltip="Add or remove the current title from My List",
        )
        actions.addWidget(favorite_btn, 0, 0)
        watched_btn = QPushButton("Watched", panel)
        watched_btn.clicked.connect(self._player_toggle_current_watched)
        configure_control_button(
            watched_btn,
            role="ghost",
            text="Watched",
            min_w=int(self.T.player.command_center_action_btn_min_w_px),
            tooltip="Toggle watched status for the current title",
        )
        actions.addWidget(watched_btn, 0, 1)
        subtitles_btn = QPushButton("Subtitles", panel)
        subtitles_btn.clicked.connect(self._player_open_subtitle_settings_dialog)
        configure_control_button(
            subtitles_btn,
            role="accent",
            text="Subtitles",
            min_w=int(self.T.player.command_center_action_btn_min_w_px),
            tooltip="Open subtitle styling and track controls",
        )
        actions.addWidget(subtitles_btn, 1, 0)
        queue_btn = QPushButton("Queue", panel)
        queue_btn.clicked.connect(self._player_toggle_playlist_drawer)
        configure_control_button(
            queue_btn,
            role="transport",
            text="Queue",
            min_w=int(self.T.player.command_center_action_btn_min_w_px),
            tooltip="Show or hide the current queue",
        )
        actions.addWidget(queue_btn, 1, 1)
        panel_l.addLayout(actions)

        chapter_panel = QFrame(self.playerPage)
        chapter_panel.setObjectName("playerCommandChapterPanel")
        chapter_panel_l = QVBoxLayout(chapter_panel)
        chapter_panel_l.setContentsMargins(14, 14, 14, 14)
        chapter_panel_l.setSpacing(10)

        chapter_title = QLabel("Chapter Jump", chapter_panel)
        chapter_title.setObjectName("playerCommandMeta")
        chapter_title.setTextFormat(Qt.PlainText)
        chapter_panel_l.addWidget(chapter_title)

        chapter_host = QWidget(chapter_panel)
        chapter_l = QVBoxLayout(chapter_host)
        chapter_l.setContentsMargins(0, 0, 0, 0)
        chapter_l.setSpacing(8)
        chapter_panel_l.addWidget(chapter_host)

        panel.hide()
        chapter_panel.hide()
        self._player_command_center = panel
        self._player_command_art = art
        self._player_command_title = title
        self._player_command_meta = meta
        self._player_command_progress = progress
        self._player_command_status = status
        self._player_command_tech = tech
        self._player_command_next_up = next_up
        self._player_command_favorite_btn = favorite_btn
        self._player_command_watched_btn = watched_btn
        self._player_command_queue_btn = queue_btn
        self._player_command_chapter_panel = chapter_panel
        self._player_command_chapter_host = chapter_host
        self._player_command_chapter_layout = chapter_l
        self._player_command_chapter_buttons = []
        self._player_command_chapter_hovered = False
        self._player_command_chapter_hide_timer = QTimer(self)
        self._player_command_chapter_hide_timer.setSingleShot(True)
        self._player_command_chapter_hide_timer.setInterval(220)
        self._player_command_chapter_hide_timer.timeout.connect(self._player_finalize_chapter_panel_visibility)
        self._player_install_command_center_event_filters(panel)
        self._player_install_command_center_event_filters(chapter_panel)
        for activity_widget in (
            getattr(self, "videoFrame", None),
            getattr(self, "videoHost", None),
            getattr(self, "playerControlsBar", None),
        ):
            self._player_install_command_center_event_filters(activity_widget)
        try:
            page = getattr(self, "playerPage", None)
            if page is not None:
                page.setMouseTracking(True)
        except Exception:
            pass
        self._player_ensure_command_center_opacity_effect()

    def _player_install_command_center_event_filters(self, widget: Optional[QWidget]) -> None:
        if widget is None:
            return
        try:
            widget.setMouseTracking(True)
        except Exception:
            pass
        try:
            widget.installEventFilter(self)
        except Exception:
            pass
        for child in widget.findChildren(QWidget):
            try:
                child.setMouseTracking(True)
            except Exception:
                pass
            try:
                child.installEventFilter(self)
            except Exception:
                pass

    def _player_is_command_center_widget(self, widget: Optional[QWidget]) -> bool:
        panel = getattr(self, "_player_command_center", None)
        return bool(panel is not None and widget is not None and (widget is panel or panel.isAncestorOf(widget)))

    def _player_is_command_chapter_widget(self, widget: Optional[QWidget]) -> bool:
        panel = getattr(self, "_player_command_chapter_panel", None)
        return bool(panel is not None and widget is not None and (widget is panel or panel.isAncestorOf(widget)))

    def _player_is_command_center_activity_widget(self, widget: Optional[QWidget]) -> bool:
        if widget is None:
            return False
        for activity_widget in (
            getattr(self, "playerPage", None),
            getattr(self, "videoFrame", None),
            getattr(self, "videoHost", None),
            getattr(self, "playerControlsBar", None),
        ):
            if activity_widget is None:
                continue
            if widget is activity_widget or activity_widget.isAncestorOf(widget):
                return True
        return False

    def _player_ensure_command_center_opacity_effect(self) -> Optional[QGraphicsOpacityEffect]:
        panel = getattr(self, "_player_command_center", None)
        if panel is None:
            return None
        effect = getattr(self, "_player_command_opacity_effect", None)
        if effect is None:
            effect = QGraphicsOpacityEffect(panel)
            effect.setOpacity(1.0)
            self._player_command_opacity_effect = effect
        try:
            if panel.graphicsEffect() is not effect:
                panel.setGraphicsEffect(effect)
        except Exception:
            return None
        return effect

    def _player_stop_command_center_fade(self) -> None:
        anim = getattr(self, "_player_command_fade_anim", None)
        if anim is None:
            return
        try:
            anim.stop()
        except Exception:
            pass

    def _player_animate_command_center_opacity(self, target_opacity: float, duration_ms: int) -> None:
        effect = self._player_ensure_command_center_opacity_effect()
        panel = getattr(self, "_player_command_center", None)
        if effect is None or panel is None:
            return

        target = max(0.18, min(1.0, float(target_opacity)))
        if not panel.isVisible():
            self._player_stop_command_center_fade()
            try:
                effect.setOpacity(1.0)
            except Exception:
                pass
            return

        current = float(effect.opacity())
        if abs(current - target) < 0.01:
            try:
                effect.setOpacity(target)
            except Exception:
                pass
            return

        anim = getattr(self, "_player_command_fade_anim", None)
        if anim is None:
            anim = QPropertyAnimation(effect, b"opacity", self)
            anim.setEasingCurve(QEasingCurve.OutCubic)
            self._player_command_fade_anim = anim
        else:
            try:
                anim.stop()
            except Exception:
                pass

        anim.setDuration(max(80, int(duration_ms)))
        anim.setStartValue(current)
        anim.setEndValue(target)
        anim.start()

    def _player_restart_command_center_idle_timer(self) -> None:
        timer = getattr(self, "_player_command_idle_timer", None)
        panel = getattr(self, "_player_command_center", None)
        if timer is None:
            return
        if panel is None or not panel.isVisible() or bool(getattr(self, "_player_command_hovered", False)):
            try:
                timer.stop()
            except Exception:
                pass
            return
        try:
            timer.start()
        except Exception:
            pass

    def _player_begin_command_center_idle_fade(self) -> None:
        panel = getattr(self, "_player_command_center", None)
        if panel is None or not panel.isVisible():
            return

        hovered_widget = None
        try:
            hovered_widget = QApplication.widgetAt(QCursor.pos())
        except Exception:
            hovered_widget = None
        if self._player_is_command_center_widget(hovered_widget if isinstance(hovered_widget, QWidget) else None):
            self._player_command_hovered = True
            self._player_restart_command_center_idle_timer()
            return

        self._player_command_hovered = False
        self._player_animate_command_center_opacity(0.34, 220)

    def _player_end_command_center_idle_fade(self, restart_timer: bool = True) -> None:
        panel = getattr(self, "_player_command_center", None)
        if panel is None:
            return
        self._player_animate_command_center_opacity(1.0, 140)
        if restart_timer:
            self._player_restart_command_center_idle_timer()
        else:
            timer = getattr(self, "_player_command_idle_timer", None)
            if timer is not None:
                try:
                    timer.stop()
                except Exception:
                    pass

    def _player_overlay_host_rect(self) -> QRect:
        if self.videoFrame is not None and self.videoFrame.isVisible():
            try:
                rect = self.videoFrame.geometry()
                if rect.width() > 0 and rect.height() > 0:
                    return rect
            except Exception:
                pass
        if self.playerPage is not None:
            return self.playerPage.rect()
        return QRect()

    def _player_overlay_bottom_limit_y(self, margin: int) -> int:
        host_rect = self._player_overlay_host_rect()
        bottom = int(host_rect.y() + host_rect.height() - max(0, int(margin)))
        controls = getattr(self, "playerControlsBar", None)
        if controls is not None and controls.isVisible():
            try:
                bottom = min(bottom, int(controls.geometry().top()) - max(0, int(margin)))
            except Exception:
                pass
        return max(int(host_rect.y() + max(0, int(margin))), bottom)

    def _player_update_command_center_geometry(self) -> None:
        panel = getattr(self, "_player_command_center", None)
        if panel is None or self.playerPage is None:
            return
        host_rect = self._player_overlay_host_rect()
        margin = int(self.T.player.command_center_margin_px)
        bottom_limit = self._player_overlay_bottom_limit_y(margin)
        available_w = max(1, int(host_rect.width() - (margin * 2)))
        available_h = max(1, int(bottom_limit - (host_rect.y() + margin)))
        min_w = min(int(self.T.player.command_center_min_width_px), available_w)
        max_w = max(min_w, min(int(self.T.player.command_center_max_width_px), available_w))
        min_h = min(int(self.T.player.command_center_min_height_px), available_h)
        max_h = max(min_h, min(int(self.T.player.command_center_max_height_px), available_h))
        width = max(min_w, min(max_w, int(host_rect.width() * float(self.T.player.command_center_width_ratio))))
        height = max(min_h, min(max_h, int(host_rect.height() * float(self.T.player.command_center_height_ratio))))
        x = int(host_rect.x() + margin)
        y = int(host_rect.y() + margin)
        panel.setGeometry(x, y, width, height)
        self._player_command_last_art_path = ""
        if panel.isVisible():
            panel.raise_()
        self._player_update_chapter_panel_geometry()

    def _player_update_chapter_panel_geometry(self) -> None:
        panel = getattr(self, "_player_command_chapter_panel", None)
        if panel is None or self.playerPage is None:
            return
        host_rect = self._player_overlay_host_rect()
        margin = int(self.T.player.command_center_margin_px)
        bottom_limit = self._player_overlay_bottom_limit_y(margin)
        available_w = max(1, int(host_rect.width() - (margin * 2)))
        available_h = max(1, int(bottom_limit - (host_rect.y() + margin)))
        min_w = min(int(self.T.player.chapter_panel_min_width_px), available_w)
        max_w = max(min_w, min(int(self.T.player.chapter_panel_max_width_px), available_w))
        min_h = min(int(self.T.player.chapter_panel_min_height_px), available_h)
        max_h = max(min_h, min(int(self.T.player.chapter_panel_max_height_px), available_h))
        width = max(min_w, min(max_w, int(host_rect.width() * float(self.T.player.chapter_panel_width_ratio))))
        height = max(min_h, min(max_h, int(host_rect.height() * float(self.T.player.chapter_panel_height_ratio))))
        x = int(host_rect.x() + margin)
        y = max(int(host_rect.y() + margin), int(bottom_limit - height))
        panel.setGeometry(x, y, width, height)
        if panel.isVisible():
            panel.raise_()

    def _player_sync_command_center_visibility(self) -> None:
        panel = getattr(self, "_player_command_center", None)
        if panel is None:
            return
        was_visible = panel.isVisible()
        try:
            on_player_page = self.pages.currentWidget() is self.playerPage
        except Exception:
            on_player_page = False
        controls_visible = bool(self.playerControlsBar is not None and self.playerControlsBar.isVisible())
        has_media = bool(getattr(self, "_current_path", None) is not None)
        fullscreen = getattr(self, "_fs_window", None) is not None
        visible = bool(on_player_page and controls_visible and has_media and not fullscreen)
        panel.setVisible(visible)
        if visible:
            self._player_update_command_center_geometry()
            panel.raise_()
            if not was_visible:
                self._player_command_hovered = False
                self._player_end_command_center_idle_fade(restart_timer=True)
        elif was_visible:
            self._player_command_hovered = False
            self._player_stop_command_center_fade()
            effect = self._player_ensure_command_center_opacity_effect()
            if effect is not None:
                try:
                    effect.setOpacity(1.0)
                except Exception:
                    pass
            timer = getattr(self, "_player_command_idle_timer", None)
            if timer is not None:
                try:
                    timer.stop()
                except Exception:
                    pass
        self._player_sync_chapter_panel_visibility(force_hide=not visible)

    def _player_chapter_panel_can_show(self) -> bool:
        panel = getattr(self, "_player_command_chapter_panel", None)
        if panel is None:
            return False
        try:
            on_player_page = self.pages.currentWidget() is self.playerPage
        except Exception:
            on_player_page = False
        controls_visible = bool(self.playerControlsBar is not None and self.playerControlsBar.isVisible())
        has_media = bool(getattr(self, "_current_path", None) is not None)
        fullscreen = getattr(self, "_fs_window", None) is not None
        has_chapters = bool(tuple(getattr(self, "_player_cached_chapters", ()) or ()))
        return bool(on_player_page and controls_visible and has_media and not fullscreen and has_chapters)

    def _player_set_chapter_panel_hovered(self, hovered: bool) -> None:
        self._player_command_chapter_hovered = bool(hovered)
        timer = getattr(self, "_player_command_chapter_hide_timer", None)
        if bool(hovered):
            if timer is not None:
                try:
                    timer.stop()
                except Exception:
                    pass
            self._player_sync_chapter_panel_visibility(force_show=True)
            return
        if timer is not None:
            try:
                timer.start()
            except Exception:
                pass

    def _player_finalize_chapter_panel_visibility(self) -> None:
        if bool(getattr(self, "_player_command_chapter_hovered", False)):
            self._player_sync_chapter_panel_visibility(force_show=True)
            return
        self._player_sync_chapter_panel_visibility(force_hide=True)

    def _player_sync_chapter_panel_visibility(self, *, force_show: bool = False, force_hide: bool = False) -> None:
        panel = getattr(self, "_player_command_chapter_panel", None)
        if panel is None:
            return
        if force_hide or not self._player_chapter_panel_can_show():
            panel.hide()
            return
        if not (force_show or bool(getattr(self, "_player_command_chapter_hovered", False))):
            panel.hide()
            return
        self._player_update_chapter_panel_geometry()
        panel.show()
        panel.raise_()

    def _player_update_command_center_art(self, art_path: Optional[Path]) -> None:
        label = getattr(self, "_player_command_art", None)
        if label is None:
            return
        normalized = str(art_path or "")
        if normalized == str(getattr(self, "_player_command_last_art_path", "") or ""):
            return
        self._player_command_last_art_path = normalized
        label.setPixmap(QPixmap())
        if not normalized:
            label.setText("No local artwork found for this title yet.")
            return
        pixmap = QPixmap(normalized)
        if pixmap.isNull():
            label.setText("Artwork preview unavailable.")
            return
        bounds = label.contentsRect().size()
        if bounds.width() <= 0 or bounds.height() <= 0:
            bounds = label.size()
        scaled = pixmap.scaled(
            max(1, int(bounds.width())),
            max(1, int(bounds.height())),
            Qt.KeepAspectRatio,
            Qt.SmoothTransformation,
        )
        label.setText("")
        label.setPixmap(scaled)

    def _player_update_command_center_chapters(self, cur_ms: int = 0) -> None:
        host = getattr(self, "_player_command_chapter_host", None)
        layout = getattr(self, "_player_command_chapter_layout", None)
        if host is None or layout is None:
            return

        chapters = tuple(getattr(self, "_player_cached_chapters", ()) or ())
        current_idx = 0
        for idx, chapter in enumerate(chapters):
            start_ms = int(chapter.get("start_ms", 0) or 0)
            if start_ms <= int(cur_ms):
                current_idx = idx
            else:
                break

        start_idx = 0
        if len(chapters) > 6:
            start_idx = max(0, min(len(chapters) - 6, current_idx - 2))
        visible = list(chapters[start_idx:start_idx + 6])
        chapter_sig = (
            str(getattr(self, "_current_path", "") or ""),
            tuple(
                (int(item.get("start_ms", 0) or 0), str(item.get("title", "") or ""))
                for item in chapters
                if isinstance(item, dict)
            ),
            int(current_idx),
            int(start_idx),
        )
        if chapter_sig == tuple(getattr(self, "_player_command_last_chapter_sig", tuple()) or tuple()):
            return
        self._player_command_last_chapter_sig = chapter_sig

        while layout.count():
            item = layout.takeAt(0)
            widget = item.widget()
            if widget is not None:
                widget.deleteLater()

        if not chapters:
            empty = QLabel("No chapter markers detected for this file.", host)
            empty.setWordWrap(True)
            empty.setObjectName("playerCommandBody")
            layout.addWidget(empty)
            self._player_command_chapter_buttons = []
            self._player_sync_chapter_panel_visibility(force_hide=True)
            return

        buttons: List[QPushButton] = []
        for idx, chapter in enumerate(visible, start=start_idx):
            start_ms = int(chapter.get("start_ms", 0) or 0)
            title = _ui_text(chapter.get("title", "") or "") or f"Chapter {idx + 1}"
            btn = QPushButton(f"{fmt_ms(start_ms)} - {title}", host)
            btn.setMinimumHeight(32)
            btn.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Fixed)
            btn.setStyleSheet("text-align: left; padding: 6px 10px;")
            if idx == current_idx:
                btn.setStyleSheet("text-align: left; padding: 6px 10px; font-weight: 800;")
            btn.clicked.connect(lambda _checked=False, ms=start_ms: (self._player_engage_seek_lock(int(ms)), self._player_seek_backend_ms(int(ms))))
            self._player_install_command_center_event_filters(btn)
            layout.addWidget(btn)
            buttons.append(btn)
        self._player_command_chapter_buttons = buttons
        self._player_sync_chapter_panel_visibility(force_show=bool(getattr(self, "_player_command_chapter_hovered", False)))

    def _player_update_command_center(self, cur_ms: int, dur_ms: int) -> None:
        panel = getattr(self, "_player_command_center", None)
        if panel is None:
            return

        path = getattr(self, "_current_path", None)
        if path is None:
            title = getattr(self, "_player_command_title", None)
            meta = getattr(self, "_player_command_meta", None)
            status = getattr(self, "_player_command_status", None)
            tech = getattr(self, "_player_command_tech", None)
            next_up = getattr(self, "_player_command_next_up", None)
            progress = getattr(self, "_player_command_progress", None)
            if title is not None:
                title.setText("Nothing playing")
            if meta is not None:
                meta.setText("")
            if status is not None:
                status.setText("")
            if tech is not None:
                tech.setText("")
            if next_up is not None:
                next_up.setText("")
            if progress is not None:
                progress.setValue(0)
            self._player_command_last_sig = tuple()
            self._player_update_command_center_art(None)
            self._player_update_command_center_chapters(0)
            self._player_sync_command_center_visibility()
            return

        if dur_ms <= 0:
            dur_ms = int(getattr(self, "_player_last_progress_snapshot_dur_ms", 0) or 0)
        if cur_ms < 0:
            cur_ms = 0

        p = Path(str(path))
        sg = self._player_current_show_group()
        key = self._home_item_key(sg) if sg is not None else self._home_resolve_media_key_for_path(p)
        heading = _ui_text(getattr(self._player_episode_title_label, "text", lambda: "")() or "") if getattr(self, "_player_episode_title_label", None) is not None else ""
        if not heading:
            heading = _ui_text(NameCleaner.clean(p.stem) or p.stem)

        meta_bits: List[str] = []
        if sg is not None:
            show_title = _ui_text(getattr(sg, "display_title", "") or "")
            if show_title and show_title.casefold() not in heading.casefold():
                meta_bits.append(show_title)
            media_type = str(getattr(sg, "media_type", "") or "").strip().casefold()
            meta_bits.append("Movie" if media_type == "movie" else "TV Show")
            if getattr(sg, "year", None) is not None:
                meta_bits.append(str(getattr(sg, "year", "")))
            if getattr(sg, "rating", None) is not None:
                try:
                    meta_bits.append(f"{float(getattr(sg, 'rating', 0.0) or 0.0):.1f}/10")
                except Exception:
                    pass
            genres = [_ui_text(g) for g in (getattr(sg, "genres", ()) or ())]
            genres = [genre for genre in genres if genre]
            if genres:
                meta_bits.append(", ".join(genres[:2]))
        else:
            meta_bits.append(_ui_text(str(p.parent.name or "Local file")))

        watched_map = self._home_state.get("watched", {}) if isinstance(self._home_state.get("watched"), dict) else {}
        favorites = {str(x).strip() for x in (self._home_state.get("favorites", []) or []) if str(x).strip()}
        favorite_on = bool(key and key in favorites)
        watched_on = bool(key and watched_map.get(key, False))
        paused = False
        try:
            paused = bool(self._mpv.is_paused()) if self._mpv is not None else False
        except Exception:
            paused = False

        queue_len = len(self._home_shuffle_queue or [])
        queue_idx = self._smart_shuffle_current_playlist_index() if self._shuffle_active and queue_len > 0 else -1
        next_up_text = _ui_text("Playing directly from the library.")
        if self._shuffle_active and queue_len > 0:
            if 0 <= (queue_idx + 1) < queue_len:
                next_path = str(self._home_shuffle_queue[queue_idx + 1])
                next_key = str(self._shuffle_path_to_show.get(self._home_canon_path_str(Path(next_path)), "") or "").strip()
                next_title = self._player_playlist_entry_title(queue_idx + 1, next_path, next_key)
                next_up_text = _ui_text(f"Next up: {next_title}")
            else:
                next_up_text = _ui_text(f"Queue complete after this item. {queue_len} item session.")

        auto_intro = bool(self._segment_skip_store.get_auto_skip("intro"))
        auto_outro = bool(self._segment_skip_store.get_auto_skip("outro"))
        chapter_count = len(tuple(getattr(self, "_player_cached_chapters", ()) or ()))
        status_text = _ui_text(
            f"{'Paused' if paused else 'Playing'}  {fmt_ms(cur_ms)} / {fmt_ms(dur_ms)}"
            if dur_ms > 0
            else ("Paused" if paused else "Playing")
        )
        tech_text = _ui_text("Auto intro {intro} | Auto outro {outro} | Chapters {chapters}".format(
            intro="on" if auto_intro else "off",
            outro="on" if auto_outro else "off",
            chapters=chapter_count,
        ))
        if queue_len > 0:
            tech_text = _ui_text(
                f"{tech_text} | Queue {max(1, queue_idx + 1) if queue_idx >= 0 else 1}/{queue_len}"
            )

        signature = (
            str(p),
            heading,
            tuple(meta_bits),
            int(cur_ms // 1000),
            int(dur_ms // 1000),
            bool(paused),
            bool(favorite_on),
            bool(watched_on),
            next_up_text,
            tech_text,
            int(queue_len),
            int(queue_idx),
        )
        self._player_command_last_sig = signature

        title_label = getattr(self, "_player_command_title", None)
        if title_label is not None:
            title_label.setText(heading)
        meta_label = getattr(self, "_player_command_meta", None)
        if meta_label is not None:
            meta_label.setText(_ui_join(meta_bits))
        status_label = getattr(self, "_player_command_status", None)
        if status_label is not None:
            status_label.setText(status_text)
        tech_label = getattr(self, "_player_command_tech", None)
        if tech_label is not None:
            tech_label.setText(tech_text)
        next_label = getattr(self, "_player_command_next_up", None)
        if next_label is not None:
            next_label.setText(next_up_text)
        progress_bar = getattr(self, "_player_command_progress", None)
        if progress_bar is not None:
            ratio = (float(cur_ms) / float(max(1, dur_ms))) if dur_ms > 0 else 0.0
            progress_bar.setValue(int(max(0.0, min(1.0, ratio)) * 1000.0))

        favorite_btn = getattr(self, "_player_command_favorite_btn", None)
        if favorite_btn is not None:
            favorite_btn.setText("Remove My List" if favorite_on else "Add My List")
        watched_btn = getattr(self, "_player_command_watched_btn", None)
        if watched_btn is not None:
            watched_btn.setText("Mark Unwatched" if watched_on else "Mark Watched")
        queue_btn = getattr(self, "_player_command_queue_btn", None)
        if queue_btn is not None:
            queue_btn.setVisible(queue_len > 0)
            queue_btn.setText("Hide Queue" if bool(getattr(self, "_player_playlist_drawer_open", False)) else "Show Queue")

        art_path_obj = None
        if sg is not None:
            art_path_obj = getattr(sg, "backdrop_path", None) or getattr(sg, "poster_path", None)
        self._player_update_command_center_art(Path(str(art_path_obj)) if art_path_obj is not None else None)
        self._player_update_command_center_chapters(cur_ms)
        self._player_sync_command_center_visibility()
